namespace Pathfinding
{
	[UniqueComponent(tag = "ai.destination")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_a_i_destination_setter.php")]
	public class AIDestinationSetter : VersionedMonoBehaviour
	{
		public Transform target;

		private IAstarAI ai;

		private void OnEnable()
		{
			ai = GetComponent<IAstarAI>();
			if (ai != null)
			{
				IAstarAI astarAI = ai;
				astarAI.onSearchPath = (Action)Delegate.Combine(astarAI.onSearchPath, new Action(Update));
			}
		}

		private void OnDisable()
		{
			if (ai != null)
			{
				IAstarAI astarAI = ai;
				astarAI.onSearchPath = (Action)Delegate.Remove(astarAI.onSearchPath, new Action(Update));
			}
		}

		private void Update()
		{
			if (target != null && ai != null)
			{
				ai.destination = target.position;
			}
		}
	}
	[UniqueComponent(tag = "ai.destination")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_patrol.php")]
	public class Patrol : VersionedMonoBehaviour
	{
		public Transform[] targets;

		public float delay;

		private int index;

		private IAstarAI agent;

		private float switchTime = float.PositiveInfinity;

		protected override void Awake()
		{
			base.Awake();
			agent = GetComponent<IAstarAI>();
		}

		private void Update()
		{
			if (targets.Length != 0)
			{
				bool flag = false;
				if (agent.reachedEndOfPath && !agent.pathPending && float.IsPositiveInfinity(switchTime))
				{
					switchTime = Time.time + delay;
				}
				if (Time.time >= switchTime)
				{
					index++;
					flag = true;
					switchTime = float.PositiveInfinity;
				}
				index %= targets.Length;
				agent.destination = targets[index].position;
				if (flag)
				{
					agent.SearchPath();
				}
			}
		}
	}
	[RequireComponent(typeof(Seeker))]
	public abstract class AIBase : VersionedMonoBehaviour
	{
		public float radius = 0.5f;

		public float height = 2f;

		public bool canMove = true;

		[FormerlySerializedAs("speed")]
		public float maxSpeed = 1f;

		public Vector3 gravity = new Vector3(float.NaN, float.NaN, float.NaN);

		public LayerMask groundMask = -1;

		[SerializeField]
		[HideInInspector]
		[FormerlySerializedAs("centerOffset")]
		private float centerOffsetCompatibility = float.NaN;

		[SerializeField]
		[HideInInspector]
		[FormerlySerializedAs("repathRate")]
		private float repathRateCompatibility = float.NaN;

		[SerializeField]
		[HideInInspector]
		[FormerlySerializedAs("canSearch")]
		[FormerlySerializedAs("repeatedlySearchPaths")]
		private bool canSearchCompability;

		[FormerlySerializedAs("rotationIn2D")]
		public OrientationMode orientation;

		public bool enableRotation = true;

		protected Vector3 simulatedPosition;

		protected Quaternion simulatedRotation;

		private Vector3 accumulatedMovementDelta = Vector3.zero;

		protected Vector2 velocity2D;

		protected float verticalVelocity;

		protected Seeker seeker;

		protected Transform tr;

		protected Rigidbody rigid;

		protected Rigidbody2D rigid2D;

		protected CharacterController controller;

		protected RVOController rvoController;

		public IMovementPlane movementPlane = GraphTransform.identityTransform;

		[NonSerialized]
		public bool updatePosition = true;

		[NonSerialized]
		public bool updateRotation = true;

		public AutoRepathPolicy autoRepath = new AutoRepathPolicy();

		protected float lastDeltaTime;

		protected int prevFrame;

		protected Vector3 prevPosition1;

		protected Vector3 prevPosition2;

		protected Vector2 lastDeltaPosition;

		protected bool waitingForPathCalculation;

		[FormerlySerializedAs("target")]
		[SerializeField]
		[HideInInspector]
		private Transform targetCompatibility;

		private bool startHasRun;

		public static readonly Color ShapeGizmoColor = new Color(0.9411765f, 71f / 85f, 0.11764706f);

		public float repathRate
		{
			get
			{
				return autoRepath.period;
			}
			set
			{
				autoRepath.period = value;
			}
		}

		public bool canSearch
		{
			get
			{
				return autoRepath.mode != AutoRepathPolicy.Mode.Never;
			}
			set
			{
				if (value)
				{
					if (autoRepath.mode == AutoRepathPolicy.Mode.Never)
					{
						autoRepath.mode = AutoRepathPolicy.Mode.EveryNSeconds;
					}
				}
				else
				{
					autoRepath.mode = AutoRepathPolicy.Mode.Never;
				}
			}
		}

		[Obsolete("Use the height property instead (2x this value)")]
		public float centerOffset
		{
			get
			{
				return height * 0.5f;
			}
			set
			{
				height = value * 2f;
			}
		}

		[Obsolete("Use orientation instead")]
		public bool rotationIn2D
		{
			get
			{
				return orientation == OrientationMode.YAxisForward;
			}
			set
			{
				orientation = (value ? OrientationMode.YAxisForward : OrientationMode.ZAxisForward);
			}
		}

		public Vector3 position
		{
			get
			{
				if (!updatePosition)
				{
					return simulatedPosition;
				}
				return tr.position;
			}
		}

		public Quaternion rotation
		{
			get
			{
				if (!updateRotation)
				{
					return simulatedRotation;
				}
				return tr.rotation;
			}
			set
			{
				if (updateRotation)
				{
					tr.rotation = value;
				}
				else
				{
					simulatedRotation = value;
				}
			}
		}

		protected bool usingGravity { get; set; }

		[Obsolete("Use the destination property or the AIDestinationSetter component instead")]
		public Transform target
		{
			get
			{
				AIDestinationSetter component = GetComponent<AIDestinationSetter>();
				if (!(component != null))
				{
					return null;
				}
				return component.target;
			}
			set
			{
				targetCompatibility = null;
				AIDestinationSetter aIDestinationSetter = GetComponent<AIDestinationSetter>();
				if (aIDestinationSetter == null)
				{
					aIDestinationSetter = base.gameObject.AddComponent<AIDestinationSetter>();
				}
				aIDestinationSetter.target = value;
				destination = ((value != null) ? value.position : new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity));
			}
		}

		public Vector3 destination { get; set; }

		public Vector3 velocity
		{
			get
			{
				if (!(lastDeltaTime > 1E-06f))
				{
					return Vector3.zero;
				}
				return (prevPosition1 - prevPosition2) / lastDeltaTime;
			}
		}

		public Vector3 desiredVelocity
		{
			get
			{
				if (!(lastDeltaTime > 1E-05f))
				{
					return Vector3.zero;
				}
				return movementPlane.ToWorld(lastDeltaPosition / lastDeltaTime, verticalVelocity);
			}
		}

		public bool isStopped { get; set; }

		public Action onSearchPath { get; set; }

		protected virtual bool shouldRecalculatePath
		{
			get
			{
				if (!waitingForPathCalculation)
				{
					return autoRepath.ShouldRecalculatePath(position, radius, destination);
				}
				return false;
			}
		}

		protected AIBase()
		{
			destination = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
		}

		public virtual void FindComponents()
		{
			tr = base.transform;
			seeker = GetComponent<Seeker>();
			rvoController = GetComponent<RVOController>();
			controller = GetComponent<CharacterController>();
			rigid = GetComponent<Rigidbody>();
			rigid2D = GetComponent<Rigidbody2D>();
		}

		protected virtual void OnEnable()
		{
			FindComponents();
			Seeker obj = seeker;
			obj.pathCallback = (OnPathDelegate)Delegate.Combine(obj.pathCallback, new OnPathDelegate(OnPathComplete));
			Init();
		}

		protected virtual void Start()
		{
			startHasRun = true;
			Init();
		}

		private void Init()
		{
			if (startHasRun)
			{
				if (canMove)
				{
					Teleport(position, clearPath: false);
				}
				autoRepath.Reset();
				if (shouldRecalculatePath)
				{
					SearchPath();
				}
			}
		}

		public virtual void Teleport(Vector3 newPosition, bool clearPath = true)
		{
			if (clearPath)
			{
				ClearPath();
			}
			prevPosition1 = (prevPosition2 = (simulatedPosition = newPosition));
			if (updatePosition)
			{
				tr.position = newPosition;
			}
			if (rvoController != null)
			{
				rvoController.Move(Vector3.zero);
			}
			if (clearPath)
			{
				SearchPath();
			}
		}

		protected void CancelCurrentPathRequest()
		{
			waitingForPathCalculation = false;
			if (seeker != null)
			{
				seeker.CancelCurrentPathRequest();
			}
		}

		protected virtual void OnDisable()
		{
			ClearPath();
			Seeker obj = seeker;
			obj.pathCallback = (OnPathDelegate)Delegate.Remove(obj.pathCallback, new OnPathDelegate(OnPathComplete));
			velocity2D = Vector3.zero;
			accumulatedMovementDelta = Vector3.zero;
			verticalVelocity = 0f;
			lastDeltaTime = 0f;
		}

		protected virtual void Update()
		{
			if (shouldRecalculatePath)
			{
				SearchPath();
			}
			usingGravity = !(gravity == Vector3.zero) && (!updatePosition || ((rigid == null || rigid.isKinematic) && (rigid2D == null || rigid2D.isKinematic)));
			if (rigid == null && rigid2D == null && canMove)
			{
				MovementUpdate(Time.deltaTime, out var nextPosition, out var nextRotation);
				FinalizeMovement(nextPosition, nextRotation);
			}
		}

		protected virtual void FixedUpdate()
		{
			if ((!(rigid == null) || !(rigid2D == null)) && canMove)
			{
				MovementUpdate(Time.fixedDeltaTime, out var nextPosition, out var nextRotation);
				FinalizeMovement(nextPosition, nextRotation);
			}
		}

		public void MovementUpdate(float deltaTime, out Vector3 nextPosition, out Quaternion nextRotation)
		{
			lastDeltaTime = deltaTime;
			MovementUpdateInternal(deltaTime, out nextPosition, out nextRotation);
		}

		protected abstract void MovementUpdateInternal(float deltaTime, out Vector3 nextPosition, out Quaternion nextRotation);

		protected virtual void CalculatePathRequestEndpoints(out Vector3 start, out Vector3 end)
		{
			start = GetFeetPosition();
			end = destination;
		}

		public virtual void SearchPath()
		{
			if (!float.IsPositiveInfinity(destination.x))
			{
				if (onSearchPath != null)
				{
					onSearchPath();
				}
				CalculatePathRequestEndpoints(out var start, out var end);
				ABPath path = ABPath.Construct(start, end);
				SetPath(path, updateDestinationFromPath: false);
			}
		}

		public virtual Vector3 GetFeetPosition()
		{
			return position;
		}

		protected abstract void OnPathComplete(Path newPath);

		protected abstract void ClearPath();

		public void SetPath(Path path, bool updateDestinationFromPath = true)
		{
			if (updateDestinationFromPath && path is ABPath aBPath && !(path is RandomPath))
			{
				destination = aBPath.originalEndPoint;
			}
			if (path == null)
			{
				CancelCurrentPathRequest();
				ClearPath();
				return;
			}
			if (path.PipelineState == PathState.Created)
			{
				waitingForPathCalculation = true;
				seeker.CancelCurrentPathRequest();
				seeker.StartPath(path);
				autoRepath.DidRecalculatePath(destination);
				return;
			}
			if (path.PipelineState == PathState.Returned)
			{
				if (seeker.GetCurrentPath() != path)
				{
					seeker.CancelCurrentPathRequest();
					OnPathComplete(path);
					return;
				}
				throw new ArgumentException("If you calculate the path using seeker.StartPath then this script will pick up the calculated path anyway as it listens for all paths the Seeker finishes calculating. You should not call SetPath in that case.");
			}
			throw new ArgumentException("You must call the SetPath method with a path that either has been completely calculated or one whose path calculation has not been started at all. It looks like the path calculation for the path you tried to use has been started, but is not yet finished.");
		}

		protected void ApplyGravity(float deltaTime)
		{
			if (usingGravity)
			{
				velocity2D += movementPlane.ToPlane(deltaTime * (float.IsNaN(gravity.x) ? Physics.gravity : gravity), out var elevation);
				verticalVelocity += elevation;
			}
			else
			{
				verticalVelocity = 0f;
			}
		}

		protected Vector2 CalculateDeltaToMoveThisFrame(Vector2 position, float distanceToEndOfPath, float deltaTime)
		{
			if (rvoController != null && rvoController.enabled)
			{
				return movementPlane.ToPlane(rvoController.CalculateMovementDelta(movementPlane.ToWorld(position), deltaTime));
			}
			return Vector2.ClampMagnitude(velocity2D * deltaTime, distanceToEndOfPath);
		}

		public Quaternion SimulateRotationTowards(Vector3 direction, float maxDegrees)
		{
			return SimulateRotationTowards(movementPlane.ToPlane(direction), maxDegrees);
		}

		protected Quaternion SimulateRotationTowards(Vector2 direction, float maxDegrees)
		{
			if (direction != Vector2.zero)
			{
				Quaternion to = Quaternion.LookRotation(movementPlane.ToWorld(direction), movementPlane.ToWorld(Vector2.zero, 1f));
				if (orientation == OrientationMode.YAxisForward)
				{
					to *= Quaternion.Euler(90f, 0f, 0f);
				}
				return Quaternion.RotateTowards(simulatedRotation, to, maxDegrees);
			}
			return simulatedRotation;
		}

		public virtual void Move(Vector3 deltaPosition)
		{
			accumulatedMovementDelta += deltaPosition;
		}

		public virtual void FinalizeMovement(Vector3 nextPosition, Quaternion nextRotation)
		{
			if (enableRotation)
			{
				FinalizeRotation(nextRotation);
			}
			FinalizePosition(nextPosition);
		}

		private void FinalizeRotation(Quaternion nextRotation)
		{
			simulatedRotation = nextRotation;
			if (updateRotation)
			{
				if (rigid != null)
				{
					rigid.MoveRotation(nextRotation);
				}
				else if (rigid2D != null)
				{
					rigid2D.MoveRotation(nextRotation.eulerAngles.z);
				}
				else
				{
					tr.rotation = nextRotation;
				}
			}
		}

		private void FinalizePosition(Vector3 nextPosition)
		{
			Vector3 vector = simulatedPosition;
			bool flag = false;
			if (controller != null && controller.enabled && updatePosition)
			{
				tr.position = vector;
				controller.Move(nextPosition - vector + accumulatedMovementDelta);
				vector = tr.position;
				if (controller.isGrounded)
				{
					verticalVelocity = 0f;
				}
			}
			else
			{
				movementPlane.ToPlane(vector, out var elevation);
				vector = nextPosition + accumulatedMovementDelta;
				if (usingGravity)
				{
					vector = RaycastPosition(vector, elevation);
				}
				flag = true;
			}
			bool positionChanged = false;
			vector = ClampToNavmesh(vector, out positionChanged);
			if ((flag || positionChanged) && updatePosition)
			{
				if (rigid != null)
				{
					rigid.MovePosition(vector);
				}
				else if (rigid2D != null)
				{
					rigid2D.MovePosition(vector);
				}
				else
				{
					tr.position = vector;
				}
			}
			accumulatedMovementDelta = Vector3.zero;
			simulatedPosition = vector;
			UpdateVelocity();
		}

		protected void UpdateVelocity()
		{
			int frameCount = Time.frameCount;
			if (frameCount != prevFrame)
			{
				prevPosition2 = prevPosition1;
			}
			prevPosition1 = position;
			prevFrame = frameCount;
		}

		protected virtual Vector3 ClampToNavmesh(Vector3 position, out bool positionChanged)
		{
			positionChanged = false;
			return position;
		}

		protected Vector3 RaycastPosition(Vector3 position, float lastElevation)
		{
			movementPlane.ToPlane(position, out var elevation);
			float num = tr.localScale.y * height * 0.5f + Mathf.Max(0f, lastElevation - elevation);
			Vector3 vector = movementPlane.ToWorld(Vector2.zero, num);
			if (Physics.Raycast(position + vector, -vector, out var hitInfo, num, groundMask, QueryTriggerInteraction.Ignore))
			{
				verticalVelocity *= Math.Max(0f, 1f - 5f * lastDeltaTime);
				return hitInfo.point;
			}
			return position;
		}

		protected virtual void OnDrawGizmosSelected()
		{
			if (Application.isPlaying)
			{
				FindComponents();
			}
		}

		protected virtual void OnDrawGizmos()
		{
			if (!Application.isPlaying || !base.enabled)
			{
				FindComponents();
			}
			Color shapeGizmoColor = ShapeGizmoColor;
			if (rvoController != null && rvoController.locked)
			{
				shapeGizmoColor *= 0.5f;
			}
			if (orientation == OrientationMode.YAxisForward)
			{
				Draw.Gizmos.Cylinder(position, Vector3.forward, 0f, radius * tr.localScale.x, shapeGizmoColor);
			}
			else
			{
				Draw.Gizmos.Cylinder(position, rotation * Vector3.up, tr.localScale.y * height, radius * tr.localScale.x, shapeGizmoColor);
			}
			if (!float.IsPositiveInfinity(destination.x) && Application.isPlaying)
			{
				Draw.Gizmos.CircleXZ(destination, 0.2f, Color.blue);
			}
			autoRepath.DrawGizmos(position, radius);
		}

		protected override void Reset()
		{
			ResetShape();
			base.Reset();
		}

		private void ResetShape()
		{
			CharacterController component = GetComponent<CharacterController>();
			if (component != null)
			{
				radius = component.radius;
				height = Mathf.Max(radius * 2f, component.height);
			}
		}

		protected override int OnUpgradeSerializedData(int version, bool unityThread)
		{
			if (unityThread && !float.IsNaN(centerOffsetCompatibility))
			{
				height = centerOffsetCompatibility * 2f;
				ResetShape();
				RVOController component = GetComponent<RVOController>();
				if (component != null)
				{
					radius = component.radiusBackingField;
				}
				centerOffsetCompatibility = float.NaN;
			}
			if (unityThread && targetCompatibility != null)
			{
				target = targetCompatibility;
			}
			if (version <= 3)
			{
				repathRate = repathRateCompatibility;
				canSearch = canSearchCompability;
			}
			return 5;
		}
	}
	[RequireComponent(typeof(Seeker))]
	[AddComponentMenu("Pathfinding/AI/AILerp (2D,3D)")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_a_i_lerp.php")]
	public class AILerp : VersionedMonoBehaviour, IAstarAI
	{
		public AutoRepathPolicy autoRepath = new AutoRepathPolicy();

		public bool canMove = true;

		public float speed = 3f;

		[FormerlySerializedAs("rotationIn2D")]
		public OrientationMode orientation;

		public bool enableRotation = true;

		public float rotationSpeed = 10f;

		public bool interpolatePathSwitches = true;

		public float switchPathInterpolationSpeed = 5f;

		[NonSerialized]
		public bool updatePosition = true;

		[NonSerialized]
		public bool updateRotation = true;

		protected Seeker seeker;

		protected Transform tr;

		protected ABPath path;

		protected bool canSearchAgain = true;

		protected Vector3 previousMovementOrigin;

		protected Vector3 previousMovementDirection;

		protected float pathSwitchInterpolationTime;

		protected PathInterpolator interpolator = new PathInterpolator();

		private bool startHasRun;

		private Vector3 previousPosition1;

		private Vector3 previousPosition2;

		private Vector3 simulatedPosition;

		private Quaternion simulatedRotation;

		[FormerlySerializedAs("target")]
		[SerializeField]
		[HideInInspector]
		private Transform targetCompatibility;

		[SerializeField]
		[HideInInspector]
		[FormerlySerializedAs("repathRate")]
		private float repathRateCompatibility = float.NaN;

		[SerializeField]
		[HideInInspector]
		[FormerlySerializedAs("canSearch")]
		private bool canSearchCompability;

		public float repathRate
		{
			get
			{
				return autoRepath.period;
			}
			set
			{
				autoRepath.period = value;
			}
		}

		public bool canSearch
		{
			get
			{
				return autoRepath.mode != AutoRepathPolicy.Mode.Never;
			}
			set
			{
				autoRepath.mode = (value ? AutoRepathPolicy.Mode.EveryNSeconds : AutoRepathPolicy.Mode.Never);
			}
		}

		[Obsolete("Use orientation instead")]
		public bool rotationIn2D
		{
			get
			{
				return orientation == OrientationMode.YAxisForward;
			}
			set
			{
				orientation = (value ? OrientationMode.YAxisForward : OrientationMode.ZAxisForward);
			}
		}

		public bool reachedEndOfPath { get; private set; }

		public bool reachedDestination
		{
			get
			{
				if (!reachedEndOfPath || !interpolator.valid)
				{
					return false;
				}
				Vector3 vector = destination - interpolator.endPoint;
				if (orientation == OrientationMode.YAxisForward)
				{
					vector.z = 0f;
				}
				else
				{
					vector.y = 0f;
				}
				if (remainingDistance + vector.magnitude >= 0.05f)
				{
					return false;
				}
				return true;
			}
		}

		public Vector3 destination { get; set; }

		[Obsolete("Use the destination property or the AIDestinationSetter component instead")]
		public Transform target
		{
			get
			{
				AIDestinationSetter component = GetComponent<AIDestinationSetter>();
				if (!(component != null))
				{
					return null;
				}
				return component.target;
			}
			set
			{
				targetCompatibility = null;
				AIDestinationSetter aIDestinationSetter = GetComponent<AIDestinationSetter>();
				if (aIDestinationSetter == null)
				{
					aIDestinationSetter = base.gameObject.AddComponent<AIDestinationSetter>();
				}
				aIDestinationSetter.target = value;
				destination = ((value != null) ? value.position : new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity));
			}
		}

		public Vector3 position
		{
			get
			{
				if (!updatePosition)
				{
					return simulatedPosition;
				}
				return tr.position;
			}
		}

		public Quaternion rotation
		{
			get
			{
				if (!updateRotation)
				{
					return simulatedRotation;
				}
				return tr.rotation;
			}
			set
			{
				if (updateRotation)
				{
					tr.rotation = value;
				}
				else
				{
					simulatedRotation = value;
				}
			}
		}

		float IAstarAI.radius
		{
			get
			{
				return 0f;
			}
			set
			{
			}
		}

		float IAstarAI.height
		{
			get
			{
				return 0f;
			}
			set
			{
			}
		}

		float IAstarAI.maxSpeed
		{
			get
			{
				return speed;
			}
			set
			{
				speed = value;
			}
		}

		bool IAstarAI.canSearch
		{
			get
			{
				return canSearch;
			}
			set
			{
				canSearch = value;
			}
		}

		bool IAstarAI.canMove
		{
			get
			{
				return canMove;
			}
			set
			{
				canMove = value;
			}
		}

		public Vector3 velocity
		{
			get
			{
				if (!(Time.deltaTime > 1E-05f))
				{
					return Vector3.zero;
				}
				return (previousPosition1 - previousPosition2) / Time.deltaTime;
			}
		}

		Vector3 IAstarAI.desiredVelocity => ((IAstarAI)this).velocity;

		Vector3 IAstarAI.steeringTarget
		{
			get
			{
				if (!interpolator.valid)
				{
					return simulatedPosition;
				}
				return interpolator.position + interpolator.tangent;
			}
		}

		public float remainingDistance
		{
			get
			{
				return Mathf.Max(interpolator.remainingDistance, 0f);
			}
			set
			{
				interpolator.remainingDistance = Mathf.Max(value, 0f);
			}
		}

		public bool hasPath => interpolator.valid;

		public bool pathPending => !canSearchAgain;

		public bool isStopped { get; set; }

		public Action onSearchPath { get; set; }

		protected virtual bool shouldRecalculatePath
		{
			get
			{
				if (canSearchAgain)
				{
					return autoRepath.ShouldRecalculatePath(position, 0f, destination);
				}
				return false;
			}
		}

		void IAstarAI.Move(Vector3 deltaPosition)
		{
		}

		protected AILerp()
		{
			destination = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
		}

		protected override void Awake()
		{
			base.Awake();
			tr = base.transform;
			seeker = GetComponent<Seeker>();
			seeker.startEndModifier.adjustStartPoint = () => simulatedPosition;
		}

		protected virtual void Start()
		{
			startHasRun = true;
			Init();
		}

		protected virtual void OnEnable()
		{
			Seeker obj = seeker;
			obj.pathCallback = (OnPathDelegate)Delegate.Combine(obj.pathCallback, new OnPathDelegate(OnPathComplete));
			Init();
		}

		private void Init()
		{
			if (startHasRun)
			{
				Teleport(position, clearPath: false);
				autoRepath.Reset();
				if (shouldRecalculatePath)
				{
					SearchPath();
				}
			}
		}

		public void OnDisable()
		{
			ClearPath();
			Seeker obj = seeker;
			obj.pathCallback = (OnPathDelegate)Delegate.Remove(obj.pathCallback, new OnPathDelegate(OnPathComplete));
		}

		public void GetRemainingPath(List<Vector3> buffer, out bool stale)
		{
			buffer.Clear();
			if (!interpolator.valid)
			{
				buffer.Add(position);
				stale = true;
			}
			else
			{
				stale = false;
				interpolator.GetRemainingPath(buffer);
				buffer[0] = position;
			}
		}

		public void Teleport(Vector3 position, bool clearPath = true)
		{
			if (clearPath)
			{
				ClearPath();
			}
			simulatedPosition = (previousPosition1 = (previousPosition2 = position));
			if (updatePosition)
			{
				tr.position = position;
			}
			reachedEndOfPath = false;
			if (clearPath)
			{
				SearchPath();
			}
		}

		[Obsolete("Use SearchPath instead")]
		public virtual void ForceSearchPath()
		{
			SearchPath();
		}

		public virtual void SearchPath()
		{
			if (!float.IsPositiveInfinity(destination.x))
			{
				if (onSearchPath != null)
				{
					onSearchPath();
				}
				Vector3 feetPosition = GetFeetPosition();
				canSearchAgain = false;
				SetPath(ABPath.Construct(feetPosition, destination), updateDestinationFromPath: false);
			}
		}

		public virtual void OnTargetReached()
		{
		}

		protected virtual void OnPathComplete(Path _p)
		{
			if (!(_p is ABPath aBPath))
			{
				throw new Exception("This function only handles ABPaths, do not use special path types");
			}
			canSearchAgain = true;
			aBPath.Claim(this);
			if (aBPath.error)
			{
				aBPath.Release(this);
				return;
			}
			if (interpolatePathSwitches)
			{
				ConfigurePathSwitchInterpolation();
			}
			ABPath aBPath2 = path;
			path = aBPath;
			reachedEndOfPath = false;
			if (path is RandomPath randomPath)
			{
				destination = randomPath.originalEndPoint;
			}
			else if (path is MultiTargetPath multiTargetPath)
			{
				destination = multiTargetPath.originalEndPoint;
			}
			if (path.vectorPath != null && path.vectorPath.Count == 1)
			{
				path.vectorPath.Insert(0, GetFeetPosition());
			}
			ConfigureNewPath();
			aBPath2?.Release(this);
			if (interpolator.remainingDistance < 0.0001f && !reachedEndOfPath)
			{
				reachedEndOfPath = true;
				OnTargetReached();
			}
		}

		protected virtual void ClearPath()
		{
			if (seeker != null)
			{
				seeker.CancelCurrentPathRequest();
			}
			canSearchAgain = true;
			reachedEndOfPath = false;
			if (path != null)
			{
				path.Release(this);
			}
			path = null;
			interpolator.SetPath(null);
		}

		public void SetPath(Path path, bool updateDestinationFromPath = true)
		{
			if (updateDestinationFromPath && path is ABPath aBPath && !(path is RandomPath))
			{
				destination = aBPath.originalEndPoint;
			}
			if (path == null)
			{
				ClearPath();
				return;
			}
			if (path.PipelineState == PathState.Created)
			{
				canSearchAgain = false;
				seeker.CancelCurrentPathRequest();
				seeker.StartPath(path);
				autoRepath.DidRecalculatePath(destination);
				return;
			}
			if (path.PipelineState == PathState.Returned)
			{
				if (seeker.GetCurrentPath() != path)
				{
					seeker.CancelCurrentPathRequest();
					OnPathComplete(path);
					return;
				}
				throw new ArgumentException("If you calculate the path using seeker.StartPath then this script will pick up the calculated path anyway as it listens for all paths the Seeker finishes calculating. You should not call SetPath in that case.");
			}
			throw new ArgumentException("You must call the SetPath method with a path that either has been completely calculated or one whose path calculation has not been started at all. It looks like the path calculation for the path you tried to use has been started, but is not yet finished.");
		}

		protected virtual void ConfigurePathSwitchInterpolation()
		{
			bool flag = interpolator.valid && interpolator.remainingDistance < 0.0001f;
			if (interpolator.valid && !flag)
			{
				previousMovementOrigin = interpolator.position;
				previousMovementDirection = interpolator.tangent.normalized * interpolator.remainingDistance;
				pathSwitchInterpolationTime = 0f;
			}
			else
			{
				previousMovementOrigin = Vector3.zero;
				previousMovementDirection = Vector3.zero;
				pathSwitchInterpolationTime = float.PositiveInfinity;
			}
		}

		public virtual Vector3 GetFeetPosition()
		{
			return position;
		}

		protected virtual void ConfigureNewPath()
		{
			bool valid = interpolator.valid;
			Vector3 vector = (valid ? interpolator.tangent : Vector3.zero);
			interpolator.SetPath(path.vectorPath);
			interpolator.MoveToClosestPoint(GetFeetPosition());
			if (interpolatePathSwitches && switchPathInterpolationSpeed > 0.01f && valid)
			{
				float num = Mathf.Max(0f - Vector3.Dot(vector.normalized, interpolator.tangent.normalized), 0f);
				interpolator.distance -= speed * num * (1f / switchPathInterpolationSpeed);
			}
		}

		protected virtual void Update()
		{
			if (shouldRecalculatePath)
			{
				SearchPath();
			}
			if (canMove)
			{
				MovementUpdate(Time.deltaTime, out var nextPosition, out var nextRotation);
				FinalizeMovement(nextPosition, nextRotation);
			}
		}

		public void MovementUpdate(float deltaTime, out Vector3 nextPosition, out Quaternion nextRotation)
		{
			if (updatePosition)
			{
				simulatedPosition = tr.position;
			}
			if (updateRotation)
			{
				simulatedRotation = tr.rotation;
			}
			nextPosition = CalculateNextPosition(out var direction, isStopped ? 0f : deltaTime);
			if (enableRotation)
			{
				nextRotation = SimulateRotationTowards(direction, deltaTime);
			}
			else
			{
				nextRotation = simulatedRotation;
			}
		}

		public void FinalizeMovement(Vector3 nextPosition, Quaternion nextRotation)
		{
			previousPosition2 = previousPosition1;
			previousPosition1 = (simulatedPosition = nextPosition);
			simulatedRotation = nextRotation;
			if (updatePosition)
			{
				tr.position = nextPosition;
			}
			if (updateRotation)
			{
				tr.rotation = nextRotation;
			}
		}

		private Quaternion SimulateRotationTowards(Vector3 direction, float deltaTime)
		{
			if (direction != Vector3.zero)
			{
				Quaternion b = Quaternion.LookRotation(direction, (orientation == OrientationMode.YAxisForward) ? Vector3.back : Vector3.up);
				if (orientation == OrientationMode.YAxisForward)
				{
					b *= Quaternion.Euler(90f, 0f, 0f);
				}
				return Quaternion.Slerp(simulatedRotation, b, deltaTime * rotationSpeed);
			}
			return simulatedRotation;
		}

		protected virtual Vector3 CalculateNextPosition(out Vector3 direction, float deltaTime)
		{
			if (!interpolator.valid)
			{
				direction = Vector3.zero;
				return simulatedPosition;
			}
			interpolator.distance += deltaTime * speed;
			if (interpolator.remainingDistance < 0.0001f && !reachedEndOfPath)
			{
				reachedEndOfPath = true;
				OnTargetReached();
			}
			direction = interpolator.tangent;
			pathSwitchInterpolationTime += deltaTime;
			float num = switchPathInterpolationSpeed * pathSwitchInterpolationTime;
			if (interpolatePathSwitches && num < 1f)
			{
				return Vector3.Lerp(previousMovementOrigin + Vector3.ClampMagnitude(previousMovementDirection, speed * pathSwitchInterpolationTime), interpolator.position, num);
			}
			return interpolator.position;
		}

		protected override int OnUpgradeSerializedData(int version, bool unityThread)
		{
			if (unityThread && targetCompatibility != null)
			{
				target = targetCompatibility;
			}
			if (version <= 3)
			{
				repathRate = repathRateCompatibility;
				canSearch = canSearchCompability;
			}
			return 4;
		}

		public virtual void OnDrawGizmos()
		{
			tr = base.transform;
			autoRepath.DrawGizmos(position, 0f);
		}
	}
	[AddComponentMenu("Pathfinding/AI/AIPath (2D,3D)")]
	public class AIPath : AIBase, IAstarAI
	{
		public float maxAcceleration = -2.5f;

		[FormerlySerializedAs("turningSpeed")]
		public float rotationSpeed = 360f;

		public float slowdownDistance = 0.6f;

		public float pickNextWaypointDist = 2f;

		public float endReachedDistance = 0.2f;

		public bool alwaysDrawGizmos;

		public bool slowWhenNotFacingTarget = true;

		public CloseToDestinationMode whenCloseToDestination;

		public bool constrainInsideGraph;

		protected Path path;

		protected PathInterpolator interpolator = new PathInterpolator();

		private static NNConstraint cachedNNConstraint = NNConstraint.Default;

		public float remainingDistance
		{
			get
			{
				if (!interpolator.valid)
				{
					return float.PositiveInfinity;
				}
				return interpolator.remainingDistance + movementPlane.ToPlane(interpolator.position - base.position).magnitude;
			}
		}

		public bool reachedDestination
		{
			get
			{
				if (!reachedEndOfPath)
				{
					return false;
				}
				if (!interpolator.valid || remainingDistance + movementPlane.ToPlane(base.destination - interpolator.endPoint).magnitude > endReachedDistance)
				{
					return false;
				}
				if (orientation != OrientationMode.YAxisForward)
				{
					movementPlane.ToPlane(base.destination - base.position, out var elevation);
					float num = tr.localScale.y * height;
					if (elevation > num || (double)elevation < (double)(0f - num) * 0.5)
					{
						return false;
					}
				}
				return true;
			}
		}

		public bool reachedEndOfPath { get; protected set; }

