		public override void Teleport(Vector3 newPosition, bool clearPath = true)
		{
			NNInfo nNInfo = ((AstarPath.active != null) ? AstarPath.active.GetNearest(newPosition) : default(NNInfo));
			movementPlane.ToPlane(newPosition, out var elevation);
			newPosition = movementPlane.ToWorld(movementPlane.ToPlane((nNInfo.node != null) ? nNInfo.position : newPosition), elevation);
			base.Teleport(newPosition, clearPath);
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			traversingOffMeshLink = false;
			StopAllCoroutines();
		}

		public override void SearchPath()
		{
			if (traversingOffMeshLink)
			{
				delayUpdatePath = true;
			}
			else
			{
				base.SearchPath();
			}
		}

		protected override void OnPathComplete(Path p)
		{
			waitingForPathCalculation = false;
			p.Claim(this);
			if (p.error)
			{
				p.Release(this);
				return;
			}
			if (traversingOffMeshLink)
			{
				delayUpdatePath = true;
			}
			else
			{
				if (p is RandomPath randomPath)
				{
					base.destination = randomPath.originalEndPoint;
				}
				else if (p is MultiTargetPath multiTargetPath)
				{
					base.destination = multiTargetPath.originalEndPoint;
				}
				richPath.Initialize(seeker, p, mergePartEndpoints: true, funnelSimplification);
				if (richPath.GetCurrentPart() is RichFunnel fn)
				{
					if (updatePosition)
					{
						simulatedPosition = tr.position;
					}
					Vector2 vector = movementPlane.ToPlane(UpdateTarget(fn));
					steeringTarget = nextCorners[0];
					Vector2 vector2 = movementPlane.ToPlane(steeringTarget);
					distanceToSteeringTarget = (vector2 - vector).magnitude;
					if (lastCorner && nextCorners.Count == 1 && distanceToSteeringTarget <= endReachedDistance)
					{
						NextPart();
					}
				}
			}
			p.Release(this);
		}

		protected override void ClearPath()
		{
			CancelCurrentPathRequest();
			richPath.Clear();
			lastCorner = false;
			delayUpdatePath = false;
			distanceToSteeringTarget = float.PositiveInfinity;
		}

		protected void NextPart()
		{
			if (!richPath.CompletedAllParts)
			{
				if (!richPath.IsLastPart)
				{
					lastCorner = false;
				}
				richPath.NextPart();
				if (richPath.CompletedAllParts)
				{
					OnTargetReached();
				}
			}
		}

		public void GetRemainingPath(List<Vector3> buffer, out bool stale)
		{
			richPath.GetRemainingPath(buffer, simulatedPosition, out stale);
		}

		protected virtual void OnTargetReached()
		{
		}

		protected virtual Vector3 UpdateTarget(RichFunnel fn)
		{
			nextCorners.Clear();
			bool requiresRepath;
			Vector3 result = fn.Update(simulatedPosition, nextCorners, 2, out lastCorner, out requiresRepath);
			if (requiresRepath && !waitingForPathCalculation && base.canSearch)
			{
				SearchPath();
			}
			return result;
		}

		protected override void MovementUpdateInternal(float deltaTime, out Vector3 nextPosition, out Quaternion nextRotation)
		{
			if (updatePosition)
			{
				simulatedPosition = tr.position;
			}
			if (updateRotation)
			{
				simulatedRotation = tr.rotation;
			}
			RichPathPart currentPart = richPath.GetCurrentPart();
			if (currentPart is RichSpecial)
			{
				if (!traversingOffMeshLink && !richPath.CompletedAllParts)
				{
					StartCoroutine(TraverseSpecial(currentPart as RichSpecial));
				}
				Vector3 vector = (steeringTarget = simulatedPosition);
				nextPosition = vector;
				nextRotation = base.rotation;
			}
			else if (currentPart is RichFunnel fn && !base.isStopped)
			{
				TraverseFunnel(fn, deltaTime, out nextPosition, out nextRotation);
			}
			else
			{
				velocity2D -= Vector2.ClampMagnitude(velocity2D, acceleration * deltaTime);
				FinalMovement(simulatedPosition, deltaTime, float.PositiveInfinity, 1f, out nextPosition, out nextRotation);
				steeringTarget = simulatedPosition;
			}
		}

		private void TraverseFunnel(RichFunnel fn, float deltaTime, out Vector3 nextPosition, out Quaternion nextRotation)
		{
			Vector3 vector = UpdateTarget(fn);
			float elevation;
			Vector2 vector2 = movementPlane.ToPlane(vector, out elevation);
			if (Time.frameCount % 5 == 0 && wallForce > 0f && wallDist > 0f)
			{
				wallBuffer.Clear();
				fn.FindWalls(wallBuffer, wallDist);
			}
			steeringTarget = nextCorners[0];
			Vector2 vector3 = movementPlane.ToPlane(steeringTarget);
			Vector2 vector4 = vector3 - vector2;
			Vector2 vector5 = VectorMath.Normalize(vector4, out distanceToSteeringTarget);
			Vector2 vector6 = CalculateWallForce(vector2, elevation, vector5);
			Vector2 targetVelocity;
			if (approachingPartEndpoint)
			{
				targetVelocity = ((slowdownTime > 0f) ? Vector2.zero : (vector5 * maxSpeed));
				vector6 *= Math.Min(distanceToSteeringTarget / 0.5f, 1f);
				if (distanceToSteeringTarget <= endReachedDistance)
				{
					NextPart();
				}
			}
			else
			{
				targetVelocity = (((nextCorners.Count > 1) ? movementPlane.ToPlane(nextCorners[1]) : (vector2 + 2f * vector4)) - vector3).normalized * maxSpeed;
			}
			Vector2 forwardsVector = movementPlane.ToPlane(simulatedRotation * ((orientation == OrientationMode.YAxisForward) ? Vector3.up : Vector3.forward));
			Vector2 vector7 = MovementUtilities.CalculateAccelerationToReachPoint(vector3 - vector2, targetVelocity, velocity2D, acceleration, rotationSpeed, maxSpeed, forwardsVector);
			velocity2D += (vector7 + vector6 * wallForce) * deltaTime;
			float num = distanceToSteeringTarget + Vector3.Distance(steeringTarget, fn.exactEnd);
			float slowdownFactor = ((num < maxSpeed * slowdownTime) ? Mathf.Sqrt(num / (maxSpeed * slowdownTime)) : 1f);
			FinalMovement(vector, deltaTime, num, slowdownFactor, out nextPosition, out nextRotation);
		}

		private void FinalMovement(Vector3 position3D, float deltaTime, float distanceToEndOfPath, float slowdownFactor, out Vector3 nextPosition, out Quaternion nextRotation)
		{
			Vector2 forward = movementPlane.ToPlane(simulatedRotation * ((orientation == OrientationMode.YAxisForward) ? Vector3.up : Vector3.forward));
			velocity2D = MovementUtilities.ClampVelocity(velocity2D, maxSpeed, slowdownFactor, slowWhenNotFacingTarget && enableRotation, forward);
			ApplyGravity(deltaTime);
			if (rvoController != null && rvoController.enabled)
			{
				Vector3 pos = position3D + movementPlane.ToWorld(Vector2.ClampMagnitude(velocity2D, distanceToEndOfPath));
				rvoController.SetTarget(pos, velocity2D.magnitude, maxSpeed);
			}
			Vector2 vector = (lastDeltaPosition = CalculateDeltaToMoveThisFrame(movementPlane.ToPlane(position3D), distanceToEndOfPath, deltaTime));
			float num = (approachingPartEndpoint ? Mathf.Clamp01(1.1f * slowdownFactor - 0.1f) : 1f);
			nextRotation = (enableRotation ? SimulateRotationTowards(vector, rotationSpeed * num * deltaTime) : simulatedRotation);
			nextPosition = position3D + movementPlane.ToWorld(vector, verticalVelocity * deltaTime);
		}

		protected override Vector3 ClampToNavmesh(Vector3 position, out bool positionChanged)
		{
			if (richPath != null && richPath.GetCurrentPart() is RichFunnel richFunnel)
			{
				Vector3 vector = richFunnel.ClampToNavmesh(position);
				Vector2 vector2 = movementPlane.ToPlane(vector - position);
				float sqrMagnitude = vector2.sqrMagnitude;
				if (sqrMagnitude > 1.0000001E-06f)
				{
					velocity2D -= vector2 * Vector2.Dot(vector2, velocity2D) / sqrMagnitude;
					if (rvoController != null && rvoController.enabled)
					{
						rvoController.SetCollisionNormal(vector2);
					}
					positionChanged = true;
					return position + movementPlane.ToWorld(vector2);
				}
			}
			positionChanged = false;
			return position;
		}

		private Vector2 CalculateWallForce(Vector2 position, float elevation, Vector2 directionToTarget)
		{
			if (wallForce <= 0f || wallDist <= 0f)
			{
				return Vector2.zero;
			}
			float num = 0f;
			float num2 = 0f;
			Vector3 vector = movementPlane.ToWorld(position, elevation);
			for (int i = 0; i < wallBuffer.Count; i += 2)
			{
				float sqrMagnitude = (VectorMath.ClosestPointOnSegment(wallBuffer[i], wallBuffer[i + 1], vector) - vector).sqrMagnitude;
				if (!(sqrMagnitude > wallDist * wallDist))
				{
					Vector2 normalized = movementPlane.ToPlane(wallBuffer[i + 1] - wallBuffer[i]).normalized;
					float num3 = Vector2.Dot(directionToTarget, normalized);
					float num4 = 1f - Math.Max(0f, 2f * (sqrMagnitude / (wallDist * wallDist)) - 1f);
					if (num3 > 0f)
					{
						num2 = Math.Max(num2, num3 * num4);
					}
					else
					{
						num = Math.Max(num, (0f - num3) * num4);
					}
				}
			}
			return new Vector2(directionToTarget.y, 0f - directionToTarget.x) * (num2 - num);
		}

		protected virtual IEnumerator TraverseSpecial(RichSpecial link)
		{
			traversingOffMeshLink = true;
			velocity2D = Vector3.zero;
			IEnumerator routine = ((onTraverseOffMeshLink != null) ? onTraverseOffMeshLink(link) : TraverseOffMeshLinkFallback(link));
			yield return StartCoroutine(routine);
			traversingOffMeshLink = false;
			NextPart();
			if (delayUpdatePath)
			{
				delayUpdatePath = false;
				if (base.canSearch)
				{
					SearchPath();
				}
			}
		}

		protected IEnumerator TraverseOffMeshLinkFallback(RichSpecial link)
		{
			float duration = ((maxSpeed > 0f) ? (Vector3.Distance(link.second.position, link.first.position) / maxSpeed) : 1f);
			float startTime = Time.time;
			while (true)
			{
				Vector3 vector = Vector3.Lerp(link.first.position, link.second.position, Mathf.InverseLerp(startTime, startTime + duration, Time.time));
				if (updatePosition)
				{
					tr.position = vector;
				}
				else
				{
					simulatedPosition = vector;
				}
				if (!(Time.time >= startTime + duration))
				{
					yield return null;
					continue;
				}
				break;
			}
		}

		protected override void OnDrawGizmos()
		{
			base.OnDrawGizmos();
			if (tr != null)
			{
				Gizmos.color = GizmoColorPath;
				Vector3 vector = base.position;
				for (int i = 0; i < nextCorners.Count; i++)
				{
					Gizmos.DrawLine(vector, nextCorners[i]);
					vector = nextCorners[i];
				}
			}
		}

		protected override int OnUpgradeSerializedData(int version, bool unityThread)
		{
			if (unityThread && animCompatibility != null)
			{
				anim = animCompatibility;
			}
			return base.OnUpgradeSerializedData(version, unityThread);
		}

		[Obsolete("Use SearchPath instead. [AstarUpgradable: 'UpdatePath' -> 'SearchPath']")]
		public void UpdatePath()
		{
			SearchPath();
		}
	}
	public class RichPath
	{
		private int currentPart;

		private readonly List<RichPathPart> parts = new List<RichPathPart>();

		public Seeker seeker;

		public ITransform transform;

		public Vector3 Endpoint { get; private set; }

		public bool CompletedAllParts => currentPart >= parts.Count;

		public bool IsLastPart => currentPart >= parts.Count - 1;

		public RichPath()
		{
			Clear();
		}

		public void Clear()
		{
			parts.Clear();
			currentPart = 0;
			Endpoint = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
		}

		public void Initialize(Seeker seeker, Path path, bool mergePartEndpoints, bool simplificationMode)
		{
			if (path.error)
			{
				throw new ArgumentException("Path has an error");
			}
			List<GraphNode> path2 = path.path;
			if (path2.Count == 0)
			{
				throw new ArgumentException("Path traverses no nodes");
			}
			this.seeker = seeker;
			for (int i = 0; i < parts.Count; i++)
			{
				RichFunnel obj = parts[i] as RichFunnel;
				RichSpecial obj2 = parts[i] as RichSpecial;
				if (obj != null)
				{
					ObjectPool<RichFunnel>.Release(ref obj);
				}
				else if (obj2 != null)
				{
					ObjectPool<RichSpecial>.Release(ref obj2);
				}
			}
			Clear();
			Endpoint = path.vectorPath[path.vectorPath.Count - 1];
			for (int j = 0; j < path2.Count; j++)
			{
				if (path2[j] is TriangleMeshNode)
				{
					if (!(AstarData.GetGraph(path2[j]) is NavmeshBase graph))
					{
						throw new Exception("Found a TriangleMeshNode that was not in a NavmeshBase graph");
					}
					RichFunnel richFunnel = ObjectPool<RichFunnel>.Claim().Initialize(this, graph);
					richFunnel.funnelSimplification = simplificationMode;
					int num = j;
					for (uint graphIndex = path2[num].GraphIndex; j < path2.Count && (path2[j].GraphIndex == graphIndex || path2[j] is NodeLink3Node); j++)
					{
					}
					j--;
					if (num == 0)
					{
						richFunnel.exactStart = path.vectorPath[0];
					}
					else
					{
						richFunnel.exactStart = (Vector3)path2[mergePartEndpoints ? (num - 1) : num].position;
					}
					if (j == path2.Count - 1)
					{
						richFunnel.exactEnd = path.vectorPath[path.vectorPath.Count - 1];
					}
					else
					{
						richFunnel.exactEnd = (Vector3)path2[mergePartEndpoints ? (j + 1) : j].position;
					}
					richFunnel.BuildFunnelCorridor(path2, num, j);
					parts.Add(richFunnel);
				}
				else if (NodeLink2.GetNodeLink(path2[j]) != null)
				{
					NodeLink2 nodeLink = NodeLink2.GetNodeLink(path2[j]);
					int num2 = j;
					uint graphIndex2 = path2[num2].GraphIndex;
					for (j++; j < path2.Count && path2[j].GraphIndex == graphIndex2; j++)
					{
					}
					j--;
					if (j - num2 > 1)
					{
						throw new Exception("NodeLink2 path length greater than two (2) nodes. " + (j - num2));
					}
					if (j - num2 != 0)
					{
						RichSpecial item = ObjectPool<RichSpecial>.Claim().Initialize(nodeLink, path2[num2]);
						parts.Add(item);
					}
				}
				else if (!(path2[j] is PointNode))
				{
					throw new InvalidOperationException("The RichAI movment script can only be used on recast/navmesh graphs. A node of type " + path2[j].GetType().Name + " was in the path.");
				}
			}
		}

		public void NextPart()
		{
			currentPart = Mathf.Min(currentPart + 1, parts.Count);
		}

		public RichPathPart GetCurrentPart()
		{
			if (parts.Count == 0)
			{
				return null;
			}
			if (currentPart >= parts.Count)
			{
				return parts[parts.Count - 1];
			}
			return parts[currentPart];
		}

		public void GetRemainingPath(List<Vector3> buffer, Vector3 currentPosition, out bool requiresRepath)
		{
			buffer.Clear();
			buffer.Add(currentPosition);
			requiresRepath = false;
			for (int i = currentPart; i < parts.Count; i++)
			{
				RichPathPart richPathPart = parts[i];
				if (richPathPart is RichFunnel richFunnel)
				{
					if (i != 0)
					{
						buffer.Add(richFunnel.exactStart);
					}
					richFunnel.Update((i == 0) ? currentPosition : richFunnel.exactStart, buffer, int.MaxValue, out var _, out requiresRepath);
					if (requiresRepath)
					{
						break;
					}
				}
				else
				{
					_ = richPathPart is RichSpecial;
				}
			}
		}
	}
	public abstract class RichPathPart : IAstarPooledObject
	{
		public abstract void OnEnterPool();
	}
	public class RichFunnel : RichPathPart
	{
		private readonly List<Vector3> left;

		private readonly List<Vector3> right;

		private List<TriangleMeshNode> nodes;

		public Vector3 exactStart;

		public Vector3 exactEnd;

		private NavmeshBase graph;

		private int currentNode;

		private Vector3 currentPosition;

		private int checkForDestroyedNodesCounter;

		private RichPath path;

		private int[] triBuffer = new int[3];

		public bool funnelSimplification = true;

		private static Queue<TriangleMeshNode> navmeshClampQueue = new Queue<TriangleMeshNode>();

		private static List<TriangleMeshNode> navmeshClampList = new List<TriangleMeshNode>();

		private static Dictionary<TriangleMeshNode, TriangleMeshNode> navmeshClampDict = new Dictionary<TriangleMeshNode, TriangleMeshNode>();

		public TriangleMeshNode CurrentNode
		{
			get
			{
				TriangleMeshNode triangleMeshNode = nodes[currentNode];
				if (!triangleMeshNode.Destroyed)
				{
					return triangleMeshNode;
				}
				return null;
			}
		}

		public float DistanceToEndOfPath
		{
			get
			{
				Vector3 vector = CurrentNode?.ClosestPointOnNode(currentPosition) ?? currentPosition;
				return (exactEnd - vector).magnitude;
			}
		}

		public RichFunnel()
		{
			left = ListPool<Vector3>.Claim();
			right = ListPool<Vector3>.Claim();
			nodes = new List<TriangleMeshNode>();
			graph = null;
		}

		public RichFunnel Initialize(RichPath path, NavmeshBase graph)
		{
			if (graph == null)
			{
				throw new ArgumentNullException("graph");
			}
			if (this.graph != null)
			{
				throw new InvalidOperationException("Trying to initialize an already initialized object. " + graph);
			}
			this.graph = graph;
			this.path = path;
			return this;
		}

		public override void OnEnterPool()
		{
			left.Clear();
			right.Clear();
			nodes.Clear();
			graph = null;
			currentNode = 0;
			checkForDestroyedNodesCounter = 0;
		}

		public void BuildFunnelCorridor(List<GraphNode> nodes, int start, int end)
		{
			exactStart = (nodes[start] as MeshNode).ClosestPointOnNode(exactStart);
			exactEnd = (nodes[end] as MeshNode).ClosestPointOnNode(exactEnd);
			left.Clear();
			right.Clear();
			left.Add(exactStart);
			right.Add(exactStart);
			this.nodes.Clear();
			if (funnelSimplification)
			{
				List<GraphNode> list = ListPool<GraphNode>.Claim(end - start);
				SimplifyPath(graph, nodes, start, end, list, exactStart, exactEnd);
				if (this.nodes.Capacity < list.Count)
				{
					this.nodes.Capacity = list.Count;
				}
				for (int i = 0; i < list.Count; i++)
				{
					if (list[i] is TriangleMeshNode item)
					{
						this.nodes.Add(item);
					}
				}
				ListPool<GraphNode>.Release(ref list);
			}
			else
			{
				if (this.nodes.Capacity < end - start)
				{
					this.nodes.Capacity = end - start;
				}
				for (int j = start; j <= end; j++)
				{
					if (nodes[j] is TriangleMeshNode item2)
					{
						this.nodes.Add(item2);
					}
				}
			}
			for (int k = 0; k < this.nodes.Count - 1; k++)
			{
				this.nodes[k].GetPortal(this.nodes[k + 1], left, right, backwards: false);
			}
			left.Add(exactEnd);
			right.Add(exactEnd);
		}

		private void SimplifyPath(IRaycastableGraph graph, List<GraphNode> nodes, int start, int end, List<GraphNode> result, Vector3 startPoint, Vector3 endPoint)
		{
			if (graph == null)
			{
				throw new ArgumentNullException("graph");
			}
			if (start > end)
			{
				throw new ArgumentException("start >= end");
			}
			if (!graph.Linecast(startPoint, endPoint, out var hit) && hit.node == nodes[end])
			{
				graph.Linecast(startPoint, endPoint, out hit, result);
				long num = 0L;
				long num2 = 0L;
				for (int i = start; i <= end; i++)
				{
					num += nodes[i].Penalty + ((path.seeker != null) ? path.seeker.tagPenalties[nodes[i].Tag] : 0);
				}
				for (int j = 0; j < result.Count; j++)
				{
					num2 += result[j].Penalty + ((path.seeker != null) ? path.seeker.tagPenalties[result[j].Tag] : 0);
				}
				if (!((double)num * 1.4 * (double)result.Count < (double)(num2 * (end - start + 1))))
				{
					return;
				}
				result.Clear();
			}
			int num3 = start;
			int num4 = 0;
			while (true)
			{
				if (num4++ > 1000)
				{
					UnityEngine.Debug.LogError("Was the path really long or have we got cought in an infinite loop?");
					return;
				}
				if (start == end)
				{
					break;
				}
				int count = result.Count;
				int num5 = end + 1;
				int num6 = start + 1;
				bool flag = false;
				while (num5 > num6 + 1)
				{
					int num7 = (num5 + num6) / 2;
					Vector3 start2 = ((start == num3) ? startPoint : ((Vector3)nodes[start].position));
					Vector3 end2 = ((num7 == end) ? endPoint : ((Vector3)nodes[num7].position));
					if (graph.Linecast(start2, end2, out var hit2) || hit2.node != nodes[num7])
					{
						num5 = num7;
						continue;
					}
					flag = true;
					num6 = num7;
				}
				if (!flag)
				{
					result.Add(nodes[start]);
					start = num6;
					continue;
				}
				Vector3 start3 = ((start == num3) ? startPoint : ((Vector3)nodes[start].position));
				Vector3 end3 = ((num6 == end) ? endPoint : ((Vector3)nodes[num6].position));
				graph.Linecast(start3, end3, out var _, result);
				long num8 = 0L;
				long num9 = 0L;
				for (int k = start; k <= num6; k++)
				{
					num8 += nodes[k].Penalty + ((path.seeker != null) ? path.seeker.tagPenalties[nodes[k].Tag] : 0);
				}
				for (int l = count; l < result.Count; l++)
				{
					num9 += result[l].Penalty + ((path.seeker != null) ? path.seeker.tagPenalties[result[l].Tag] : 0);
				}
				if ((double)num8 * 1.4 * (double)(result.Count - count) < (double)(num9 * (num6 - start + 1)) || result[result.Count - 1] != nodes[num6])
				{
					result.RemoveRange(count, result.Count - count);
					result.Add(nodes[start]);
					start++;
				}
				else
				{
					result.RemoveAt(result.Count - 1);
					start = num6;
				}
			}
			result.Add(nodes[end]);
		}

		private void UpdateFunnelCorridor(int splitIndex, List<TriangleMeshNode> prefix)
		{
			nodes.RemoveRange(0, splitIndex);
			nodes.InsertRange(0, prefix);
			left.Clear();
			right.Clear();
			left.Add(exactStart);
			right.Add(exactStart);
			for (int i = 0; i < nodes.Count - 1; i++)
			{
				nodes[i].GetPortal(nodes[i + 1], left, right, backwards: false);
			}
			left.Add(exactEnd);
			right.Add(exactEnd);
		}

		private bool CheckForDestroyedNodes()
		{
			int i = 0;
			for (int count = nodes.Count; i < count; i++)
			{
				if (nodes[i].Destroyed)
				{
					return true;
				}
			}
			return false;
		}

		public Vector3 ClampToNavmesh(Vector3 position)
		{
			if (path.transform != null)
			{
				position = path.transform.InverseTransform(position);
			}
			ClampToNavmeshInternal(ref position);
			if (path.transform != null)
			{
				position = path.transform.Transform(position);
			}
			return position;
		}

		public Vector3 Update(Vector3 position, List<Vector3> buffer, int numCorners, out bool lastCorner, out bool requiresRepath)
		{
			if (path.transform != null)
			{
				position = path.transform.InverseTransform(position);
			}
			lastCorner = false;
			requiresRepath = false;
			if (checkForDestroyedNodesCounter >= 10)
			{
				checkForDestroyedNodesCounter = 0;
				requiresRepath |= CheckForDestroyedNodes();
			}
			else
			{
				checkForDestroyedNodesCounter++;
			}
			bool num = ClampToNavmeshInternal(ref position);
			currentPosition = position;
			if (num)
			{
				requiresRepath = true;
				lastCorner = false;
				buffer.Add(position);
			}
			else if (!FindNextCorners(position, currentNode, buffer, numCorners, out lastCorner))
			{
				UnityEngine.Debug.LogError("Failed to find next corners in the path");
				buffer.Add(position);
			}
			if (path.transform != null)
			{
				for (int i = 0; i < buffer.Count; i++)
				{
					buffer[i] = path.transform.Transform(buffer[i]);
				}
				position = path.transform.Transform(position);
			}
			return position;
		}

		private bool ClampToNavmeshInternal(ref Vector3 position)
		{
			TriangleMeshNode triangleMeshNode = nodes[currentNode];
			if (triangleMeshNode.Destroyed)
			{
				return true;
			}
			if (triangleMeshNode.ContainsPoint(position))
			{
				return false;
			}
			Queue<TriangleMeshNode> queue = navmeshClampQueue;
			List<TriangleMeshNode> list = navmeshClampList;
			Dictionary<TriangleMeshNode, TriangleMeshNode> dictionary = navmeshClampDict;
			triangleMeshNode.TemporaryFlag1 = true;
			dictionary[triangleMeshNode] = null;
			queue.Enqueue(triangleMeshNode);
			list.Add(triangleMeshNode);
			float num = float.PositiveInfinity;
			Vector3 vector = position;
			TriangleMeshNode triangleMeshNode2 = null;
			while (queue.Count > 0)
			{
				TriangleMeshNode triangleMeshNode3 = queue.Dequeue();
				Vector3 vector2 = triangleMeshNode3.ClosestPointOnNodeXZ(position);
				float num2 = VectorMath.MagnitudeXZ(vector2 - position);
				if (!(num2 <= num * 1.05f + 0.001f))
				{
					continue;
				}
				if (num2 < num)
				{
					num = num2;
					vector = vector2;
					triangleMeshNode2 = triangleMeshNode3;
				}
				for (int i = 0; i < triangleMeshNode3.connections.Length; i++)
				{
					if (triangleMeshNode3.connections[i].node is TriangleMeshNode { TemporaryFlag1: false } triangleMeshNode4)
					{
						triangleMeshNode4.TemporaryFlag1 = true;
						dictionary[triangleMeshNode4] = triangleMeshNode3;
						queue.Enqueue(triangleMeshNode4);
						list.Add(triangleMeshNode4);
					}
				}
			}
			for (int j = 0; j < list.Count; j++)
			{
				list[j].TemporaryFlag1 = false;
			}
			list.ClearFast();
			int num3 = nodes.IndexOf(triangleMeshNode2);
			position.x = vector.x;
			position.z = vector.z;
			if (num3 == -1)
			{
				List<TriangleMeshNode> list2 = navmeshClampList;
				while (num3 == -1)
				{
					list2.Add(triangleMeshNode2);
					triangleMeshNode2 = dictionary[triangleMeshNode2];
					num3 = nodes.IndexOf(triangleMeshNode2);
				}
				exactStart = position;
				UpdateFunnelCorridor(num3, list2);
				list2.ClearFast();
				currentNode = 0;
			}
			else
			{
				currentNode = num3;
			}
			dictionary.Clear();
			if (currentNode + 1 < nodes.Count)
			{
				return nodes[currentNode + 1].Destroyed;
			}
			return false;
		}

		public void FindWalls(List<Vector3> wallBuffer, float range)
		{
			FindWalls(currentNode, wallBuffer, currentPosition, range);
		}

		private void FindWalls(int nodeIndex, List<Vector3> wallBuffer, Vector3 position, float range)
		{
			if (range <= 0f)
			{
				return;
			}
			bool flag = false;
			bool flag2 = false;
			range *= range;
			position.y = 0f;
			int num = 0;
			while (!flag || !flag2)
			{
				if (!(num < 0 && flag) && !(num > 0 && flag2))
				{
					if (num < 0 && nodeIndex + num < 0)
					{
						flag = true;
					}
					else if (num > 0 && nodeIndex + num >= nodes.Count)
					{
						flag2 = true;
					}
					else
					{
						TriangleMeshNode triangleMeshNode = ((nodeIndex + num - 1 < 0) ? null : nodes[nodeIndex + num - 1]);
						TriangleMeshNode triangleMeshNode2 = nodes[nodeIndex + num];
						TriangleMeshNode triangleMeshNode3 = ((nodeIndex + num + 1 >= nodes.Count) ? null : nodes[nodeIndex + num + 1]);
						if (triangleMeshNode2.Destroyed)
						{
							break;
						}
						if ((triangleMeshNode2.ClosestPointOnNodeXZ(position) - position).sqrMagnitude > range)
						{
							if (num < 0)
							{
								flag = true;
							}
							else
							{
								flag2 = true;
							}
						}
						else
						{
							for (int i = 0; i < 3; i++)
							{
								triBuffer[i] = 0;
							}
							for (int j = 0; j < triangleMeshNode2.connections.Length; j++)
							{
								if (!(triangleMeshNode2.connections[j].node is TriangleMeshNode triangleMeshNode4))
								{
									continue;
								}
								int num2 = -1;
								for (int k = 0; k < 3; k++)
								{
									for (int l = 0; l < 3; l++)
									{
										if (triangleMeshNode2.GetVertex(k) == triangleMeshNode4.GetVertex((l + 1) % 3) && triangleMeshNode2.GetVertex((k + 1) % 3) == triangleMeshNode4.GetVertex(l))
										{
											num2 = k;
											k = 3;
											break;
										}
									}
								}
								if (num2 != -1)
								{
									triBuffer[num2] = ((triangleMeshNode4 != triangleMeshNode && triangleMeshNode4 != triangleMeshNode3) ? 1 : 2);
								}
							}
							for (int m = 0; m < 3; m++)
							{
								if (triBuffer[m] == 0)
								{
									wallBuffer.Add((Vector3)triangleMeshNode2.GetVertex(m));
									wallBuffer.Add((Vector3)triangleMeshNode2.GetVertex((m + 1) % 3));
								}
							}
						}
					}
				}
				num = ((num < 0) ? (-num) : (-num - 1));
			}
			if (path.transform != null)
			{
				for (int n = 0; n < wallBuffer.Count; n++)
				{
					wallBuffer[n] = path.transform.Transform(wallBuffer[n]);
				}
			}
		}

		private bool FindNextCorners(Vector3 origin, int startIndex, List<Vector3> funnelPath, int numCorners, out bool lastCorner)
		{
			lastCorner = false;
			if (left == null)
			{
				throw new Exception("left list is null");
			}
			if (right == null)
			{
				throw new Exception("right list is null");
			}
			if (funnelPath == null)
			{
				throw new ArgumentNullException("funnelPath");
			}
			if (left.Count != right.Count)
			{
				throw new ArgumentException("left and right lists must have equal length");
			}
			int count = left.Count;
			if (count == 0)
			{
				throw new ArgumentException("no diagonals");
			}
			if (count - startIndex < 3)
			{
				funnelPath.Add(left[count - 1]);
				lastCorner = true;
				return true;
			}
			while (left[startIndex + 1] == left[startIndex + 2] && right[startIndex + 1] == right[startIndex + 2])
			{
				startIndex++;
				if (count - startIndex <= 3)
				{
					return false;
				}
			}
			Vector3 vector = left[startIndex + 2];
			if (vector == left[startIndex + 1])
			{
				vector = right[startIndex + 2];
			}
			while (VectorMath.IsColinearXZ(origin, left[startIndex + 1], right[startIndex + 1]) || VectorMath.RightOrColinearXZ(left[startIndex + 1], right[startIndex + 1], vector) == VectorMath.RightOrColinearXZ(left[startIndex + 1], right[startIndex + 1], origin))
			{
				startIndex++;
				if (count - startIndex < 3)
				{
					funnelPath.Add(left[count - 1]);
					lastCorner = true;
					return true;
				}
				vector = left[startIndex + 2];
				if (vector == left[startIndex + 1])
				{
					vector = right[startIndex + 2];
				}
			}
			Vector3 vector2 = origin;
			Vector3 vector3 = left[startIndex + 1];
			Vector3 vector4 = right[startIndex + 1];
			int num = startIndex + 1;
			int num2 = startIndex + 1;
			for (int i = startIndex + 2; i < count; i++)
			{
				if (funnelPath.Count >= numCorners)
				{
					return true;
				}
				if (funnelPath.Count > 2000)
				{
					UnityEngine.Debug.LogWarning("Avoiding infinite loop. Remove this check if you have this long paths.");
					break;
				}
				Vector3 vector5 = left[i];
				Vector3 vector6 = right[i];
				if (VectorMath.SignedTriangleAreaTimes2XZ(vector2, vector4, vector6) >= 0f)
				{
					if (!(vector2 == vector4) && !(VectorMath.SignedTriangleAreaTimes2XZ(vector2, vector3, vector6) <= 0f))
					{
						funnelPath.Add(vector3);
						vector2 = vector3;
						int num3 = num2;
						vector3 = vector2;
						vector4 = vector2;
						num2 = num3;
						num = num3;
						i = num3;
						continue;
					}
					vector4 = vector6;
					num = i;
				}
				if (VectorMath.SignedTriangleAreaTimes2XZ(vector2, vector3, vector5) <= 0f)
				{
					if (vector2 == vector3 || VectorMath.SignedTriangleAreaTimes2XZ(vector2, vector4, vector5) >= 0f)
					{
						vector3 = vector5;
						num2 = i;
						continue;
					}
					funnelPath.Add(vector4);
					vector2 = vector4;
					int num4 = num;
					vector3 = vector2;
					vector4 = vector2;
					num2 = num4;
					num = num4;
					i = num4;
				}
			}
			lastCorner = true;
			funnelPath.Add(left[count - 1]);
			return true;
		}
	}
	public class RichSpecial : RichPathPart
	{
		public NodeLink2 nodeLink;

		public Transform first;

		public Transform second;

		public bool reverse;

		public override void OnEnterPool()
		{
			nodeLink = null;
		}

		public RichSpecial Initialize(NodeLink2 nodeLink, GraphNode first)
		{
			this.nodeLink = nodeLink;
			if (first == nodeLink.startNode)
			{
				this.first = nodeLink.StartTransform;
				second = nodeLink.EndTransform;
				reverse = false;
			}
			else
			{
				this.first = nodeLink.EndTransform;
				second = nodeLink.StartTransform;
				reverse = true;
			}
			return this;
		}
	}
	[AddComponentMenu("Pathfinding/Seeker")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_seeker.php")]
	public class Seeker : VersionedMonoBehaviour
	{
		public enum ModifierPass
		{
			PreProcess = 0,
			PostProcess = 2
		}

		public bool drawGizmos = true;

		public bool detailedGizmos;

		[HideInInspector]
		public StartEndModifier startEndModifier = new StartEndModifier();

		[HideInInspector]
		public int traversableTags = -1;

		[HideInInspector]
		public int[] tagPenalties = new int[32];

		[HideInInspector]
		public GraphMask graphMask = GraphMask.everything;

		[FormerlySerializedAs("graphMask")]
		private int graphMaskCompatibility = -1;

		public OnPathDelegate pathCallback;

		public OnPathDelegate preProcessPath;

		public OnPathDelegate postProcessPath;

		[NonSerialized]
		private List<Vector3> lastCompletedVectorPath;

		[NonSerialized]
		private List<GraphNode> lastCompletedNodePath;

		[NonSerialized]
		protected Path path;

		[NonSerialized]
		private Path prevPath;

		private readonly OnPathDelegate onPathDelegate;

		private readonly OnPathDelegate onPartialPathDelegate;

		private OnPathDelegate tmpPathCallback;

		protected uint lastPathID;

		private readonly List<IPathModifier> modifiers = new List<IPathModifier>();

		public Seeker()
		{
			onPathDelegate = OnPathComplete;
			onPartialPathDelegate = OnPartialPathComplete;
		}

		protected override void Awake()
		{
			base.Awake();
			startEndModifier.Awake(this);
		}

		public Path GetCurrentPath()
		{
			return path;
		}

		public void CancelCurrentPathRequest(bool pool = true)
		{
			if (!IsDone())
			{
				path.FailWithError("Canceled by script (Seeker.CancelCurrentPathRequest)");
				if (pool)
				{
					path.Claim(path);
					path.Release(path);
				}
			}
		}

		public void OnDestroy()
		{
			ReleaseClaimedPath();
			startEndModifier.OnDestroy(this);
		}

		private void ReleaseClaimedPath()
		{
			if (prevPath != null)
			{
				prevPath.Release(this, silent: true);
				prevPath = null;
			}
		}

		public void RegisterModifier(IPathModifier modifier)
		{
			modifiers.Add(modifier);
			modifiers.Sort((IPathModifier a, IPathModifier b) => a.Order.CompareTo(b.Order));
		}

		public void DeregisterModifier(IPathModifier modifier)
		{
			modifiers.Remove(modifier);
		}

		public void PostProcess(Path path)
		{
			RunModifiers(ModifierPass.PostProcess, path);
		}

		public void RunModifiers(ModifierPass pass, Path path)
		{
			switch (pass)
			{
			case ModifierPass.PreProcess:
			{
				if (preProcessPath != null)
				{
					preProcessPath(path);
				}
				for (int j = 0; j < modifiers.Count; j++)
				{
					modifiers[j].PreProcess(path);
				}
				break;
			}
			case ModifierPass.PostProcess:
			{
				if (postProcessPath != null)
				{
					postProcessPath(path);
				}
				for (int i = 0; i < modifiers.Count; i++)
				{
					modifiers[i].Apply(path);
				}
				break;
			}
			}
		}

		public bool IsDone()
		{
			if (path != null)
			{
				return path.PipelineState >= PathState.Returned;
			}
			return true;
		}

		private void OnPathComplete(Path path)
		{
			OnPathComplete(path, runModifiers: true, sendCallbacks: true);
		}

		private void OnPathComplete(Path p, bool runModifiers, bool sendCallbacks)
		{
			if ((p != null && p != path && sendCallbacks) || this == null || p == null || p != path)
			{
				return;
			}
			if (!path.error && runModifiers)
			{
				RunModifiers(ModifierPass.PostProcess, path);
			}
			if (sendCallbacks)
			{
				p.Claim(this);
				lastCompletedNodePath = p.path;
				lastCompletedVectorPath = p.vectorPath;
				if (tmpPathCallback != null)
				{
					tmpPathCallback(p);
				}
				if (pathCallback != null)
				{
					pathCallback(p);
				}
				if (prevPath != null)
				{
					prevPath.Release(this, silent: true);
				}
				prevPath = p;
			}
		}

		private void OnPartialPathComplete(Path p)
		{
			OnPathComplete(p, runModifiers: true, sendCallbacks: false);
		}

		private void OnMultiPathComplete(Path p)
		{
			OnPathComplete(p, runModifiers: false, sendCallbacks: true);
		}

		[Obsolete("Use ABPath.Construct(start, end, null) instead")]
		public ABPath GetNewPath(Vector3 start, Vector3 end)
		{
			return ABPath.Construct(start, end);
		}

		public Path StartPath(Vector3 start, Vector3 end)
		{
			return StartPath(start, end, null);
		}

		public Path StartPath(Vector3 start, Vector3 end, OnPathDelegate callback)
		{
			return StartPath(ABPath.Construct(start, end), callback);
		}

		public Path StartPath(Vector3 start, Vector3 end, OnPathDelegate callback, GraphMask graphMask)
		{
			return StartPath(ABPath.Construct(start, end), callback, graphMask);
		}

		public Path StartPath(Path p, OnPathDelegate callback = null)
		{
			if ((int)p.nnConstraint.graphMask == -1)
			{
				p.nnConstraint.graphMask = graphMask;
			}
			StartPathInternal(p, callback);
			return p;
		}

		public Path StartPath(Path p, OnPathDelegate callback, GraphMask graphMask)
		{
			p.nnConstraint.graphMask = graphMask;
			StartPathInternal(p, callback);
			return p;
		}

		private void StartPathInternal(Path p, OnPathDelegate callback)
		{
			if (p is MultiTargetPath multiTargetPath)
			{
				OnPathDelegate[] array = new OnPathDelegate[multiTargetPath.targetPoints.Length];
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = onPartialPathDelegate;
				}
				multiTargetPath.callbacks = array;
				p.callback = (OnPathDelegate)Delegate.Combine(p.callback, new OnPathDelegate(OnMultiPathComplete));
			}
			else
			{
				p.callback = (OnPathDelegate)Delegate.Combine(p.callback, onPathDelegate);
			}
			p.enabledTags = traversableTags;
			p.tagPenalties = tagPenalties;
			if (path != null && path.PipelineState <= PathState.Processing && path.CompleteState != PathCompleteState.Error && lastPathID == path.pathID)
			{
				path.FailWithError("Canceled path because a new one was requested.\nThis happens when a new path is requested from the seeker when one was already being calculated.\nFor example if a unit got a new order, you might request a new path directly instead of waiting for the now invalid path to be calculated. Which is probably what you want.\nIf you are getting this a lot, you might want to consider how you are scheduling path requests.");
			}
			path = p;
			tmpPathCallback = callback;
			lastPathID = path.pathID;
			RunModifiers(ModifierPass.PreProcess, path);
			AstarPath.StartPath(path);
		}

		public MultiTargetPath StartMultiTargetPath(Vector3 start, Vector3[] endPoints, bool pathsForAll, OnPathDelegate callback = null, int graphMask = -1)
		{
			MultiTargetPath multiTargetPath = MultiTargetPath.Construct(start, endPoints, null);
			multiTargetPath.pathsForAll = pathsForAll;
			StartPath(multiTargetPath, callback, graphMask);
			return multiTargetPath;
		}

		public MultiTargetPath StartMultiTargetPath(Vector3[] startPoints, Vector3 end, bool pathsForAll, OnPathDelegate callback = null, int graphMask = -1)
		{
			MultiTargetPath multiTargetPath = MultiTargetPath.Construct(startPoints, end, null);
			multiTargetPath.pathsForAll = pathsForAll;
			StartPath(multiTargetPath, callback, graphMask);
			return multiTargetPath;
		}

		[Obsolete("You can use StartPath instead of this method now. It will behave identically.")]
		public MultiTargetPath StartMultiTargetPath(MultiTargetPath p, OnPathDelegate callback = null, int graphMask = -1)
		{
			StartPath(p, callback, graphMask);
			return p;
		}

		public void OnDrawGizmos()
		{
			if (lastCompletedNodePath == null || !drawGizmos)
			{
				return;
			}
			if (detailedGizmos)
			{
				Gizmos.color = new Color(0.7f, 0.5f, 0.1f, 0.5f);
				if (lastCompletedNodePath != null)
				{
					for (int i = 0; i < lastCompletedNodePath.Count - 1; i++)
					{
						Gizmos.DrawLine((Vector3)lastCompletedNodePath[i].position, (Vector3)lastCompletedNodePath[i + 1].position);
					}
				}
			}
			Gizmos.color = new Color(0f, 1f, 0f, 1f);
			if (lastCompletedVectorPath != null)
			{
				for (int j = 0; j < lastCompletedVectorPath.Count - 1; j++)
				{
					Gizmos.DrawLine(lastCompletedVectorPath[j], lastCompletedVectorPath[j + 1]);
				}
			}
		}

		protected override int OnUpgradeSerializedData(int version, bool unityThread)
		{
			if (graphMaskCompatibility != -1)
			{
				UnityEngine.Debug.Log("Loaded " + graphMaskCompatibility + " " + graphMask.value);
				graphMask = graphMaskCompatibility;
				graphMaskCompatibility = -1;
			}
			return base.OnUpgradeSerializedData(version, unityThread);
		}
	}
	[Serializable]
	public class AstarColor
	{
		public Color _SolidColor;

		public Color _UnwalkableNode;

		public Color _BoundsHandles;

		public Color _ConnectionLowLerp;

		public Color _ConnectionHighLerp;

		public Color _MeshEdgeColor;

		public Color[] _AreaColors;

		public static Color SolidColor = new Color(0.11764706f, 0.4f, 67f / 85f, 0.9f);

		public static Color UnwalkableNode = new Color(1f, 0f, 0f, 0.5f);

		public static Color BoundsHandles = new Color(0.29f, 0.454f, 0.741f, 0.9f);

		public static Color ConnectionLowLerp = new Color(0f, 1f, 0f, 0.5f);

		public static Color ConnectionHighLerp = new Color(1f, 0f, 0f, 0.5f);

		public static Color MeshEdgeColor = new Color(0f, 0f, 0f, 0.5f);

		private static Color[] AreaColors = new Color[1];

		public static int ColorHash()
		{
			int num = SolidColor.GetHashCode() ^ UnwalkableNode.GetHashCode() ^ BoundsHandles.GetHashCode() ^ ConnectionLowLerp.GetHashCode() ^ ConnectionHighLerp.GetHashCode() ^ MeshEdgeColor.GetHashCode();
			for (int i = 0; i < AreaColors.Length; i++)
			{
				num = (7 * num) ^ AreaColors[i].GetHashCode();
			}
			return num;
		}

		public static Color GetAreaColor(uint area)
		{
			if (area >= AreaColors.Length)
			{
				return AstarMath.IntToColor((int)area, 1f);
			}
			return AreaColors[area];
		}

		public static Color GetTagColor(uint tag)
		{
			if (tag >= AreaColors.Length)
			{
				return AstarMath.IntToColor((int)tag, 1f);
			}
			return AreaColors[tag];
		}

		public void PushToStatic(AstarPath astar)
		{
			_AreaColors = _AreaColors ?? new Color[1];
			SolidColor = _SolidColor;
			UnwalkableNode = _UnwalkableNode;
			BoundsHandles = _BoundsHandles;
			ConnectionLowLerp = _ConnectionLowLerp;
			ConnectionHighLerp = _ConnectionHighLerp;
			MeshEdgeColor = _MeshEdgeColor;
			AreaColors = _AreaColors;
		}

		public AstarColor()
		{
			_SolidColor = new Color(0.11764706f, 0.4f, 67f / 85f, 0.9f);
			_UnwalkableNode = new Color(1f, 0f, 0f, 0.5f);
			_BoundsHandles = new Color(0.29f, 0.454f, 0.741f, 0.9f);
			_ConnectionLowLerp = new Color(0f, 1f, 0f, 0.5f);
			_ConnectionHighLerp = new Color(1f, 0f, 0f, 0.5f);
			_MeshEdgeColor = new Color(0f, 0f, 0f, 0.5f);
		}
	}
