			if (num4 < 0f || num4 > 1f || num5 < 0f || num5 > 1f)
			{
				intersects = false;
				return start1;
			}
			intersects = true;
			return start1 + vector * num4;
		}

		public static bool SegmentIntersectsBounds(Bounds bounds, Vector3 a, Vector3 b)
		{
			a -= bounds.center;
			b -= bounds.center;
			Vector3 vector = (a + b) * 0.5f;
			Vector3 vector2 = a - vector;
			Vector3 vector3 = new Vector3(Math.Abs(vector2.x), Math.Abs(vector2.y), Math.Abs(vector2.z));
			Vector3 extents = bounds.extents;
			if (Math.Abs(vector.x) > extents.x + vector3.x)
			{
				return false;
			}
			if (Math.Abs(vector.y) > extents.y + vector3.y)
			{
				return false;
			}
			if (Math.Abs(vector.z) > extents.z + vector3.z)
			{
				return false;
			}
			if (Math.Abs(vector.y * vector2.z - vector.z * vector2.y) > extents.y * vector3.z + extents.z * vector3.y)
			{
				return false;
			}
			if (Math.Abs(vector.x * vector2.z - vector.z * vector2.x) > extents.x * vector3.z + extents.z * vector3.x)
			{
				return false;
			}
			if (Math.Abs(vector.x * vector2.y - vector.y * vector2.x) > extents.x * vector3.y + extents.y * vector3.x)
			{
				return false;
			}
			return true;
		}

		public static float LineCircleIntersectionFactor(Vector3 circleCenter, Vector3 linePoint1, Vector3 linePoint2, float radius)
		{
			float magnitude;
			Vector3 rhs = Normalize(linePoint2 - linePoint1, out magnitude);
			Vector3 lhs = linePoint1 - circleCenter;
			float num = Vector3.Dot(lhs, rhs);
			float num2 = num * num - (lhs.sqrMagnitude - radius * radius);
			if (num2 < 0f)
			{
				num2 = 0f;
			}
			float num3 = 0f - num + Mathf.Sqrt(num2);
			if (!(magnitude > 1E-05f))
			{
				return 1f;
			}
			return num3 / magnitude;
		}

		public static bool ReversesFaceOrientations(Matrix4x4 matrix)
		{
			Vector3 lhs = matrix.MultiplyVector(new Vector3(1f, 0f, 0f));
			Vector3 rhs = matrix.MultiplyVector(new Vector3(0f, 1f, 0f));
			return Vector3.Dot(rhs: matrix.MultiplyVector(new Vector3(0f, 0f, 1f)), lhs: Vector3.Cross(lhs, rhs)) < 0f;
		}

		public static bool ReversesFaceOrientationsXZ(Matrix4x4 matrix)
		{
			Vector3 vector = matrix.MultiplyVector(new Vector3(1f, 0f, 0f));
			Vector3 vector2 = matrix.MultiplyVector(new Vector3(0f, 0f, 1f));
			return vector.x * vector2.z - vector2.x * vector.z < 0f;
		}

		public static Vector3 Normalize(Vector3 v, out float magnitude)
		{
			magnitude = v.magnitude;
			if (magnitude > 1E-05f)
			{
				return v / magnitude;
			}
			return Vector3.zero;
		}

		public static Vector2 Normalize(Vector2 v, out float magnitude)
		{
			magnitude = v.magnitude;
			if (magnitude > 1E-05f)
			{
				return v / magnitude;
			}
			return Vector2.zero;
		}

		public static Vector3 ClampMagnitudeXZ(Vector3 v, float maxMagnitude)
		{
			float num = v.x * v.x + v.z * v.z;
			if (num > maxMagnitude * maxMagnitude && maxMagnitude > 0f)
			{
				float num2 = maxMagnitude / Mathf.Sqrt(num);
				v.x *= num2;
				v.z *= num2;
			}
			return v;
		}

		public static float MagnitudeXZ(Vector3 v)
		{
			return Mathf.Sqrt(v.x * v.x + v.z * v.z);
		}
	}
	public static class AstarMath
	{
		public static float MapTo(float startMin, float startMax, float targetMin, float targetMax, float value)
		{
			return Mathf.Lerp(targetMin, targetMax, Mathf.InverseLerp(startMin, startMax, value));
		}

		public static string FormatBytesBinary(int bytes)
		{
			double num = ((bytes >= 0) ? 1.0 : (-1.0));
			bytes = Mathf.Abs(bytes);
			if (bytes < 1024)
			{
				return (double)bytes * num + " bytes";
			}
			if (bytes < 1048576)
			{
				return ((double)bytes / 1024.0 * num).ToString("0.0") + " KiB";
			}
			if (bytes < 1073741824)
			{
				return ((double)bytes / 1048576.0 * num).ToString("0.0") + " MiB";
			}
			return ((double)bytes / 1073741824.0 * num).ToString("0.0") + " GiB";
		}

		private static int Bit(int a, int b)
		{
			return (a >> b) & 1;
		}

		public static Color IntToColor(int i, float a)
		{
			int num = Bit(i, 2) + Bit(i, 3) * 2 + 1;
			int num2 = Bit(i, 1) + Bit(i, 4) * 2 + 1;
			int num3 = Bit(i, 0) + Bit(i, 5) * 2 + 1;
			return new Color((float)num * 0.25f, (float)num2 * 0.25f, (float)num3 * 0.25f, a);
		}

		public static Color HSVToRGB(float h, float s, float v)
		{
			float num = 0f;
			float num2 = 0f;
			float num3 = 0f;
			float num4 = s * v;
			float num5 = h / 60f;
			float num6 = num4 * (1f - Math.Abs(num5 % 2f - 1f));
			if (num5 < 1f)
			{
				num = num4;
				num2 = num6;
			}
			else if (num5 < 2f)
			{
				num = num6;
				num2 = num4;
			}
			else if (num5 < 3f)
			{
				num2 = num4;
				num3 = num6;
			}
			else if (num5 < 4f)
			{
				num2 = num6;
				num3 = num4;
			}
			else if (num5 < 5f)
			{
				num = num6;
				num3 = num4;
			}
			else if (num5 < 6f)
			{
				num = num4;
				num3 = num6;
			}
			float num7 = v - num4;
			num += num7;
			num2 += num7;
			num3 += num7;
			return new Color(num, num2, num3);
		}
	}
	public static class Polygon
	{
		private static readonly Dictionary<Int3, int> cached_Int3_int_dict = new Dictionary<Int3, int>();

		public static bool ContainsPointXZ(Vector3 a, Vector3 b, Vector3 c, Vector3 p)
		{
			if (VectorMath.IsClockwiseMarginXZ(a, b, p) && VectorMath.IsClockwiseMarginXZ(b, c, p))
			{
				return VectorMath.IsClockwiseMarginXZ(c, a, p);
			}
			return false;
		}

		public static bool ContainsPointXZ(Int3 a, Int3 b, Int3 c, Int3 p)
		{
			if (VectorMath.IsClockwiseOrColinearXZ(a, b, p) && VectorMath.IsClockwiseOrColinearXZ(b, c, p))
			{
				return VectorMath.IsClockwiseOrColinearXZ(c, a, p);
			}
			return false;
		}

		public static bool ContainsPoint(Int2 a, Int2 b, Int2 c, Int2 p)
		{
			if (VectorMath.IsClockwiseOrColinear(a, b, p) && VectorMath.IsClockwiseOrColinear(b, c, p))
			{
				return VectorMath.IsClockwiseOrColinear(c, a, p);
			}
			return false;
		}

		public static bool ContainsPoint(Vector2[] polyPoints, Vector2 p)
		{
			int num = polyPoints.Length - 1;
			bool flag = false;
			int num2 = 0;
			while (num2 < polyPoints.Length)
			{
				if (((polyPoints[num2].y <= p.y && p.y < polyPoints[num].y) || (polyPoints[num].y <= p.y && p.y < polyPoints[num2].y)) && p.x < (polyPoints[num].x - polyPoints[num2].x) * (p.y - polyPoints[num2].y) / (polyPoints[num].y - polyPoints[num2].y) + polyPoints[num2].x)
				{
					flag = !flag;
				}
				num = num2++;
			}
			return flag;
		}

		public static bool ContainsPointXZ(Vector3[] polyPoints, Vector3 p)
		{
			int num = polyPoints.Length - 1;
			bool flag = false;
			int num2 = 0;
			while (num2 < polyPoints.Length)
			{
				if (((polyPoints[num2].z <= p.z && p.z < polyPoints[num].z) || (polyPoints[num].z <= p.z && p.z < polyPoints[num2].z)) && p.x < (polyPoints[num].x - polyPoints[num2].x) * (p.z - polyPoints[num2].z) / (polyPoints[num].z - polyPoints[num2].z) + polyPoints[num2].x)
				{
					flag = !flag;
				}
				num = num2++;
			}
			return flag;
		}

		public static int SampleYCoordinateInTriangle(Int3 p1, Int3 p2, Int3 p3, Int3 p)
		{
			double num = (double)(p2.z - p3.z) * (double)(p1.x - p3.x) + (double)(p3.x - p2.x) * (double)(p1.z - p3.z);
			double num2 = ((double)(p2.z - p3.z) * (double)(p.x - p3.x) + (double)(p3.x - p2.x) * (double)(p.z - p3.z)) / num;
			double num3 = ((double)(p3.z - p1.z) * (double)(p.x - p3.x) + (double)(p1.x - p3.x) * (double)(p.z - p3.z)) / num;
			return (int)Math.Round(num2 * (double)p1.y + num3 * (double)p2.y + (1.0 - num2 - num3) * (double)p3.y);
		}

		public static Vector3[] ConvexHullXZ(Vector3[] points)
		{
			if (points.Length == 0)
			{
				return new Vector3[0];
			}
			List<Vector3> list = ListPool<Vector3>.Claim();
			int num = 0;
			for (int i = 1; i < points.Length; i++)
			{
				if (points[i].x < points[num].x)
				{
					num = i;
				}
			}
			int num2 = num;
			int num3 = 0;
			do
			{
				list.Add(points[num]);
				int num4 = 0;
				for (int j = 0; j < points.Length; j++)
				{
					if (num4 == num || !VectorMath.RightOrColinearXZ(points[num], points[num4], points[j]))
					{
						num4 = j;
					}
				}
				num = num4;
				num3++;
				if (num3 > 10000)
				{
					UnityEngine.Debug.LogWarning("Infinite Loop in Convex Hull Calculation");
					break;
				}
			}
			while (num != num2);
			Vector3[] result = list.ToArray();
			ListPool<Vector3>.Release(list);
			return result;
		}

		public static Vector2 ClosestPointOnTriangle(Vector2 a, Vector2 b, Vector2 c, Vector2 p)
		{
			Vector2 vector = b - a;
			Vector2 vector2 = c - a;
			Vector2 rhs = p - a;
			float num = Vector2.Dot(vector, rhs);
			float num2 = Vector2.Dot(vector2, rhs);
			if (num <= 0f && num2 <= 0f)
			{
				return a;
			}
			Vector2 rhs2 = p - b;
			float num3 = Vector2.Dot(vector, rhs2);
			float num4 = Vector2.Dot(vector2, rhs2);
			if (num3 >= 0f && num4 <= num3)
			{
				return b;
			}
			if (num >= 0f && num3 <= 0f && num * num4 - num3 * num2 <= 0f)
			{
				float num5 = num / (num - num3);
				return a + vector * num5;
			}
			Vector2 rhs3 = p - c;
			float num6 = Vector2.Dot(vector, rhs3);
			float num7 = Vector2.Dot(vector2, rhs3);
			if (num7 >= 0f && num6 <= num7)
			{
				return c;
			}
			if (num2 >= 0f && num7 <= 0f && num6 * num2 - num * num7 <= 0f)
			{
				float num8 = num2 / (num2 - num7);
				return a + vector2 * num8;
			}
			if (num4 - num3 >= 0f && num6 - num7 >= 0f && num3 * num7 - num6 * num4 <= 0f)
			{
				float num9 = (num4 - num3) / (num4 - num3 + (num6 - num7));
				return b + (c - b) * num9;
			}
			return p;
		}

		public static Vector3 ClosestPointOnTriangleXZ(Vector3 a, Vector3 b, Vector3 c, Vector3 p)
		{
			Vector2 lhs = new Vector2(b.x - a.x, b.z - a.z);
			Vector2 lhs2 = new Vector2(c.x - a.x, c.z - a.z);
			Vector2 rhs = new Vector2(p.x - a.x, p.z - a.z);
			float num = Vector2.Dot(lhs, rhs);
			float num2 = Vector2.Dot(lhs2, rhs);
			if (num <= 0f && num2 <= 0f)
			{
				return a;
			}
			Vector2 rhs2 = new Vector2(p.x - b.x, p.z - b.z);
			float num3 = Vector2.Dot(lhs, rhs2);
			float num4 = Vector2.Dot(lhs2, rhs2);
			if (num3 >= 0f && num4 <= num3)
			{
				return b;
			}
			float num5 = num * num4 - num3 * num2;
			if (num >= 0f && num3 <= 0f && num5 <= 0f)
			{
				float num6 = num / (num - num3);
				return (1f - num6) * a + num6 * b;
			}
			Vector2 rhs3 = new Vector2(p.x - c.x, p.z - c.z);
			float num7 = Vector2.Dot(lhs, rhs3);
			float num8 = Vector2.Dot(lhs2, rhs3);
			if (num8 >= 0f && num7 <= num8)
			{
				return c;
			}
			float num9 = num7 * num2 - num * num8;
			if (num2 >= 0f && num8 <= 0f && num9 <= 0f)
			{
				float num10 = num2 / (num2 - num8);
				return (1f - num10) * a + num10 * c;
			}
			float num11 = num3 * num8 - num7 * num4;
			if (num4 - num3 >= 0f && num7 - num8 >= 0f && num11 <= 0f)
			{
				float num12 = (num4 - num3) / (num4 - num3 + (num7 - num8));
				return b + (c - b) * num12;
			}
			float num13 = 1f / (num11 + num9 + num5);
			float num14 = num9 * num13;
			float num15 = num5 * num13;
			return new Vector3(p.x, (1f - num14 - num15) * a.y + num14 * b.y + num15 * c.y, p.z);
		}

		public static Vector3 ClosestPointOnTriangle(Vector3 a, Vector3 b, Vector3 c, Vector3 p)
		{
			Vector3 vector = b - a;
			Vector3 vector2 = c - a;
			Vector3 rhs = p - a;
			float num = Vector3.Dot(vector, rhs);
			float num2 = Vector3.Dot(vector2, rhs);
			if (num <= 0f && num2 <= 0f)
			{
				return a;
			}
			Vector3 rhs2 = p - b;
			float num3 = Vector3.Dot(vector, rhs2);
			float num4 = Vector3.Dot(vector2, rhs2);
			if (num3 >= 0f && num4 <= num3)
			{
				return b;
			}
			float num5 = num * num4 - num3 * num2;
			if (num >= 0f && num3 <= 0f && num5 <= 0f)
			{
				float num6 = num / (num - num3);
				return a + vector * num6;
			}
			Vector3 rhs3 = p - c;
			float num7 = Vector3.Dot(vector, rhs3);
			float num8 = Vector3.Dot(vector2, rhs3);
			if (num8 >= 0f && num7 <= num8)
			{
				return c;
			}
			float num9 = num7 * num2 - num * num8;
			if (num2 >= 0f && num8 <= 0f && num9 <= 0f)
			{
				float num10 = num2 / (num2 - num8);
				return a + vector2 * num10;
			}
			float num11 = num3 * num8 - num7 * num4;
			if (num4 - num3 >= 0f && num7 - num8 >= 0f && num11 <= 0f)
			{
				float num12 = (num4 - num3) / (num4 - num3 + (num7 - num8));
				return b + (c - b) * num12;
			}
			float num13 = 1f / (num11 + num9 + num5);
			float num14 = num9 * num13;
			float num15 = num5 * num13;
			return a + vector * num14 + vector2 * num15;
		}

		public static void CompressMesh(List<Int3> vertices, List<int> triangles, out Int3[] outVertices, out int[] outTriangles)
		{
			Dictionary<Int3, int> dictionary = cached_Int3_int_dict;
			dictionary.Clear();
			int[] array = ArrayPool<int>.Claim(vertices.Count);
			int num = 0;
			for (int i = 0; i < vertices.Count; i++)
			{
				if (!dictionary.TryGetValue(vertices[i], out var value) && !dictionary.TryGetValue(vertices[i] + new Int3(0, 1, 0), out value) && !dictionary.TryGetValue(vertices[i] + new Int3(0, -1, 0), out value))
				{
					dictionary.Add(vertices[i], num);
					array[i] = num;
					vertices[num] = vertices[i];
					num++;
				}
				else
				{
					array[i] = value;
				}
			}
			outTriangles = new int[triangles.Count];
			for (int j = 0; j < outTriangles.Length; j++)
			{
				outTriangles[j] = array[triangles[j]];
			}
			outVertices = new Int3[num];
			for (int k = 0; k < num; k++)
			{
				outVertices[k] = vertices[k];
			}
			ArrayPool<int>.Release(ref array);
		}

		public static void TraceContours(Dictionary<int, int> outline, HashSet<int> hasInEdge, Action<List<int>, bool> results)
		{
			List<int> list = ListPool<int>.Claim();
			List<int> list2 = ListPool<int>.Claim();
			list2.AddRange(outline.Keys);
			for (int i = 0; i <= 1; i++)
			{
				bool flag = i == 1;
				for (int j = 0; j < list2.Count; j++)
				{
					int num = list2[j];
					if (!flag && hasInEdge.Contains(num))
					{
						continue;
					}
					int num2 = num;
					list.Clear();
					list.Add(num2);
					while (outline.ContainsKey(num2))
					{
						int num3 = outline[num2];
						outline.Remove(num2);
						list.Add(num3);
						if (num3 == num)
						{
							break;
						}
						num2 = num3;
					}
					if (list.Count > 1)
					{
						results(list, flag);
					}
				}
			}
			ListPool<int>.Release(ref list2);
			ListPool<int>.Release(ref list);
		}

		public static void Subdivide(List<Vector3> points, List<Vector3> result, int subSegments)
		{
			for (int i = 0; i < points.Count - 1; i++)
			{
				for (int j = 0; j < subSegments; j++)
				{
					result.Add(Vector3.Lerp(points[i], points[i + 1], (float)j / (float)subSegments));
				}
			}
			result.Add(points[points.Count - 1]);
		}
	}
	[AddComponentMenu("Pathfinding/GraphUpdateScene")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_graph_update_scene.php")]
	public class GraphUpdateScene : GraphModifier
	{
		public Vector3[] points;

		private Vector3[] convexPoints;

		public bool convex = true;

		public float minBoundsHeight = 1f;

		public int penaltyDelta;

		public bool modifyWalkability;

		public bool setWalkability;

		public bool applyOnStart = true;

		public bool applyOnScan = true;

		public bool updatePhysics;

		public bool resetPenaltyOnPhysics = true;

		public bool updateErosion = true;

		public bool modifyTag;

		public int setTag;

		[HideInInspector]
		public bool legacyMode;

		private int setTagInvert;

		private bool firstApplied;

		[SerializeField]
		private int serializedVersion;

		[SerializeField]
		[FormerlySerializedAs("useWorldSpace")]
		private bool legacyUseWorldSpace;

		public void Start()
		{
			if (Application.isPlaying && !firstApplied && applyOnStart)
			{
				Apply();
			}
		}

		public override void OnPostScan()
		{
			if (applyOnScan)
			{
				Apply();
			}
		}

		public virtual void InvertSettings()
		{
			setWalkability = !setWalkability;
			penaltyDelta = -penaltyDelta;
			if (setTagInvert == 0)
			{
				setTagInvert = setTag;
				setTag = 0;
			}
			else
			{
				setTag = setTagInvert;
				setTagInvert = 0;
			}
		}

		public void RecalcConvex()
		{
			convexPoints = (convex ? Polygon.ConvexHullXZ(points) : null);
		}

		[Obsolete("World space can no longer be used as it does not work well with rotated graphs. Use transform.InverseTransformPoint to transform points to local space.", true)]
		private void ToggleUseWorldSpace()
		{
		}

		[Obsolete("The Y coordinate is no longer important. Use the position of the object instead", true)]
		public void LockToY()
		{
		}

		public Bounds GetBounds()
		{
			if (points == null || points.Length == 0)
			{
				Collider component = GetComponent<Collider>();
				Collider2D component2 = GetComponent<Collider2D>();
				Renderer component3 = GetComponent<Renderer>();
				Bounds bounds;
				if (component != null)
				{
					bounds = component.bounds;
				}
				else if (component2 != null)
				{
					bounds = component2.bounds;
					bounds.size = new Vector3(bounds.size.x, bounds.size.y, Mathf.Max(bounds.size.z, 1f));
				}
				else
				{
					if (!(component3 != null))
					{
						return new Bounds(Vector3.zero, Vector3.zero);
					}
					bounds = component3.bounds;
				}
				if (legacyMode && bounds.size.y < minBoundsHeight)
				{
					bounds.size = new Vector3(bounds.size.x, minBoundsHeight, bounds.size.z);
				}
				return bounds;
			}
			return GraphUpdateShape.GetBounds(convex ? convexPoints : points, (legacyMode && legacyUseWorldSpace) ? Matrix4x4.identity : base.transform.localToWorldMatrix, minBoundsHeight);
		}

		public void Apply()
		{
			if (AstarPath.active == null)
			{
				UnityEngine.Debug.LogError("There is no AstarPath object in the scene", this);
				return;
			}
			GraphUpdateObject graphUpdateObject;
			if (points == null || points.Length == 0)
			{
				PolygonCollider2D component = GetComponent<PolygonCollider2D>();
				if (component != null)
				{
					Vector2[] array = component.points;
					Vector3[] array2 = new Vector3[array.Length];
					for (int i = 0; i < array2.Length; i++)
					{
						Vector2 vector = array[i] + component.offset;
						array2[i] = new Vector3(vector.x, 0f, vector.y);
					}
					Matrix4x4 matrix = base.transform.localToWorldMatrix * Matrix4x4.TRS(Vector3.zero, Quaternion.Euler(-90f, 0f, 0f), Vector3.one);
					GraphUpdateShape shape = new GraphUpdateShape(array2, convex, matrix, minBoundsHeight);
					graphUpdateObject = new GraphUpdateObject(GetBounds());
					graphUpdateObject.shape = shape;
				}
				else
				{
					Bounds bounds = GetBounds();
					if (bounds.center == Vector3.zero && bounds.size == Vector3.zero)
					{
						UnityEngine.Debug.LogError("Cannot apply GraphUpdateScene, no points defined and no renderer or collider attached", this);
						return;
					}
					graphUpdateObject = new GraphUpdateObject(bounds);
				}
			}
			else
			{
				GraphUpdateShape graphUpdateShape;
				if (legacyMode && !legacyUseWorldSpace)
				{
					Vector3[] array3 = new Vector3[points.Length];
					for (int j = 0; j < points.Length; j++)
					{
						array3[j] = base.transform.TransformPoint(points[j]);
					}
					graphUpdateShape = new GraphUpdateShape(array3, convex, Matrix4x4.identity, minBoundsHeight);
				}
				else
				{
					graphUpdateShape = new GraphUpdateShape(points, convex, (legacyMode && legacyUseWorldSpace) ? Matrix4x4.identity : base.transform.localToWorldMatrix, minBoundsHeight);
				}
				graphUpdateObject = new GraphUpdateObject(graphUpdateShape.GetBounds());
				graphUpdateObject.shape = graphUpdateShape;
			}
			firstApplied = true;
			graphUpdateObject.modifyWalkability = modifyWalkability;
			graphUpdateObject.setWalkability = setWalkability;
			graphUpdateObject.addPenalty = penaltyDelta;
			graphUpdateObject.updatePhysics = updatePhysics;
			graphUpdateObject.updateErosion = updateErosion;
			graphUpdateObject.resetPenaltyOnPhysics = resetPenaltyOnPhysics;
			graphUpdateObject.modifyTag = modifyTag;
			graphUpdateObject.setTag = setTag;
			AstarPath.active.UpdateGraphs(graphUpdateObject);
		}

		private void OnDrawGizmos()
		{
			OnDrawGizmos(selected: false);
		}

		private void OnDrawGizmosSelected()
		{
			OnDrawGizmos(selected: true);
		}

		private void OnDrawGizmos(bool selected)
		{
			Color color = (selected ? new Color(0.8901961f, 0.23921569f, 0.08627451f, 1f) : new Color(0.8901961f, 0.23921569f, 0.08627451f, 0.9f));
			if (selected)
			{
				Gizmos.color = Color.Lerp(color, new Color(1f, 1f, 1f, 0.2f), 0.9f);
				Bounds bounds = GetBounds();
				Gizmos.DrawCube(bounds.center, bounds.size);
				Gizmos.DrawWireCube(bounds.center, bounds.size);
			}
			if (points == null)
			{
				return;
			}
			if (convex)
			{
				color.a *= 0.5f;
			}
			Gizmos.color = color;
			Matrix4x4 matrix4x = ((legacyMode && legacyUseWorldSpace) ? Matrix4x4.identity : base.transform.localToWorldMatrix);
			if (convex)
			{
				color.r -= 0.1f;
				color.g -= 0.2f;
				color.b -= 0.1f;
				Gizmos.color = color;
			}
			if (selected || !convex)
			{
				for (int i = 0; i < points.Length; i++)
				{
					Gizmos.DrawLine(matrix4x.MultiplyPoint3x4(points[i]), matrix4x.MultiplyPoint3x4(points[(i + 1) % points.Length]));
				}
			}
			if (convex)
			{
				if (convexPoints == null)
				{
					RecalcConvex();
				}
				Gizmos.color = (selected ? new Color(0.8901961f, 0.23921569f, 0.08627451f, 1f) : new Color(0.8901961f, 0.23921569f, 0.08627451f, 0.9f));
				for (int j = 0; j < convexPoints.Length; j++)
				{
					Gizmos.DrawLine(matrix4x.MultiplyPoint3x4(convexPoints[j]), matrix4x.MultiplyPoint3x4(convexPoints[(j + 1) % convexPoints.Length]));
				}
			}
			Vector3[] array = (convex ? convexPoints : points);
			if (selected && array != null && array.Length != 0)
			{
				Gizmos.color = new Color(1f, 1f, 1f, 0.2f);
				float num = array[0].y;
				float num2 = array[0].y;
				for (int k = 0; k < array.Length; k++)
				{
					num = Mathf.Min(num, array[k].y);
					num2 = Mathf.Max(num2, array[k].y);
				}
				float num3 = Mathf.Max(minBoundsHeight - (num2 - num), 0f) * 0.5f;
				num -= num3;
				num2 += num3;
				for (int l = 0; l < array.Length; l++)
				{
					int num4 = (l + 1) % array.Length;
					Vector3 vector = matrix4x.MultiplyPoint3x4(array[l] + Vector3.up * (num - array[l].y));
					Vector3 vector2 = matrix4x.MultiplyPoint3x4(array[l] + Vector3.up * (num2 - array[l].y));
					Vector3 to = matrix4x.MultiplyPoint3x4(array[num4] + Vector3.up * (num - array[num4].y));
					Vector3 to2 = matrix4x.MultiplyPoint3x4(array[num4] + Vector3.up * (num2 - array[num4].y));
					Gizmos.DrawLine(vector, vector2);
					Gizmos.DrawLine(vector, to);
					Gizmos.DrawLine(vector2, to2);
				}
			}
		}

		public void DisableLegacyMode()
		{
			if (!legacyMode)
			{
				return;
			}
			legacyMode = false;
			if (legacyUseWorldSpace)
			{
				legacyUseWorldSpace = false;
				for (int i = 0; i < points.Length; i++)
				{
					points[i] = base.transform.InverseTransformPoint(points[i]);
				}
				RecalcConvex();
			}
		}

		protected override void Awake()
		{
			if (serializedVersion == 0)
			{
				if (points != null && points.Length != 0)
				{
					legacyMode = true;
				}
				serializedVersion = 1;
			}
			base.Awake();
		}
	}
	public class GraphUpdateShape
	{
		private Vector3[] _points;

		private Vector3[] _convexPoints;

		private bool _convex;

		private Vector3 right = Vector3.right;

		private Vector3 forward = Vector3.forward;

		private Vector3 up = Vector3.up;

		private Vector3 origin;

		public float minimumHeight;

		public Vector3[] points
		{
			get
			{
				return _points;
			}
			set
			{
				_points = value;
				if (convex)
				{
					CalculateConvexHull();
				}
			}
		}

		public bool convex
		{
			get
			{
				return _convex;
			}
			set
			{
				if (_convex != value && value)
				{
					CalculateConvexHull();
				}
				_convex = value;
			}
		}

		public GraphUpdateShape()
		{
		}

		public GraphUpdateShape(Vector3[] points, bool convex, Matrix4x4 matrix, float minimumHeight)
		{
			this.convex = convex;
			this.points = points;
			origin = matrix.MultiplyPoint3x4(Vector3.zero);
			right = matrix.MultiplyPoint3x4(Vector3.right) - origin;
			up = matrix.MultiplyPoint3x4(Vector3.up) - origin;
			forward = matrix.MultiplyPoint3x4(Vector3.forward) - origin;
			this.minimumHeight = minimumHeight;
		}

		private void CalculateConvexHull()
		{
			_convexPoints = ((points != null) ? Polygon.ConvexHullXZ(points) : null);
		}

		public Bounds GetBounds()
		{
			return GetBounds(convex ? _convexPoints : points, right, up, forward, origin, minimumHeight);
		}

		public static Bounds GetBounds(Vector3[] points, Matrix4x4 matrix, float minimumHeight)
		{
			Vector3 vector = matrix.MultiplyPoint3x4(Vector3.zero);
			Vector3 vector2 = matrix.MultiplyPoint3x4(Vector3.right) - vector;
			Vector3 vector3 = matrix.MultiplyPoint3x4(Vector3.up) - vector;
			Vector3 vector4 = matrix.MultiplyPoint3x4(Vector3.forward) - vector;
			return GetBounds(points, vector2, vector3, vector4, vector, minimumHeight);
		}

		private static Bounds GetBounds(Vector3[] points, Vector3 right, Vector3 up, Vector3 forward, Vector3 origin, float minimumHeight)
		{
			if (points == null || points.Length == 0)
			{
				return default(Bounds);
			}
			float num = points[0].y;
			float num2 = points[0].y;
			for (int i = 0; i < points.Length; i++)
			{
				num = Mathf.Min(num, points[i].y);
				num2 = Mathf.Max(num2, points[i].y);
			}
			float num3 = Mathf.Max(minimumHeight - (num2 - num), 0f) * 0.5f;
			num -= num3;
			num2 += num3;
			Vector3 vector = right * points[0].x + up * points[0].y + forward * points[0].z;
			Vector3 vector2 = vector;
			for (int j = 0; j < points.Length; j++)
			{
				Vector3 vector3 = right * points[j].x + forward * points[j].z;
				Vector3 rhs = vector3 + up * num;
				Vector3 rhs2 = vector3 + up * num2;
				vector = Vector3.Min(vector, rhs);
				vector = Vector3.Min(vector, rhs2);
				vector2 = Vector3.Max(vector2, rhs);
				vector2 = Vector3.Max(vector2, rhs2);
			}
			return new Bounds((vector + vector2) * 0.5f + origin, vector2 - vector);
		}

		public bool Contains(GraphNode node)
		{
			return Contains((Vector3)node.position);
		}

		public bool Contains(Vector3 point)
		{
			point -= origin;
			Vector3 p = new Vector3(Vector3.Dot(point, right) / right.sqrMagnitude, 0f, Vector3.Dot(point, forward) / forward.sqrMagnitude);
			if (convex)
			{
				if (_convexPoints == null)
				{
					return false;
				}
				int i = 0;
				int num = _convexPoints.Length - 1;
				for (; i < _convexPoints.Length; i++)
				{
					if (VectorMath.RightOrColinearXZ(_convexPoints[i], _convexPoints[num], p))
					{
						return false;
					}
					num = i;
				}
				return true;
			}
			if (_points != null)
			{
				return Polygon.ContainsPointXZ(_points, p);
			}
			return false;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_animation_link.php")]
	public class AnimationLink : NodeLink2
	{
		[Serializable]
		public class LinkClip
		{
			public AnimationClip clip;

			public Vector3 velocity;

			public int loopCount = 1;

			public string name
			{
				get
				{
					if (!(clip != null))
					{
						return "";
					}
					return clip.name;
				}
			}
		}

		public string clip;

		public float animSpeed = 1f;

		public bool reverseAnim = true;

		public GameObject referenceMesh;

		public LinkClip[] sequence;

		public string boneRoot = "bn_COG_Root";

		private static Transform SearchRec(Transform tr, string name)
		{
			int childCount = tr.childCount;
			for (int i = 0; i < childCount; i++)
			{
				Transform child = tr.GetChild(i);
				if (child.name == name)
				{
					return child;
				}
				Transform transform = SearchRec(child, name);
				if (transform != null)
				{
					return transform;
				}
			}
			return null;
		}

		public void CalculateOffsets(List<Vector3> trace, out Vector3 endPosition)
		{
			endPosition = base.transform.position;
			if (referenceMesh == null)
			{
				return;
			}
			GameObject gameObject = UnityEngine.Object.Instantiate(referenceMesh, base.transform.position, base.transform.rotation);
			gameObject.hideFlags = HideFlags.HideAndDontSave;
			Transform transform = SearchRec(gameObject.transform, boneRoot);
			if (transform == null)
			{
				throw new Exception("Could not find root transform");
			}
			Animation animation = gameObject.GetComponent<Animation>();
			if (animation == null)
			{
				animation = gameObject.AddComponent<Animation>();
			}
			for (int i = 0; i < sequence.Length; i++)
			{
				animation.AddClip(sequence[i].clip, sequence[i].clip.name);
			}
			Vector3 vector = Vector3.zero;
			Vector3 position = base.transform.position;
			Vector3 vector2 = Vector3.zero;
			for (int j = 0; j < sequence.Length; j++)
			{
				LinkClip linkClip = sequence[j];
				if (linkClip == null)
				{
					endPosition = position;
					return;
				}
				animation[linkClip.clip.name].enabled = true;
				animation[linkClip.clip.name].weight = 1f;
				for (int k = 0; k < linkClip.loopCount; k++)
				{
					animation[linkClip.clip.name].normalizedTime = 0f;
					animation.Sample();
					Vector3 vector3 = transform.position - base.transform.position;
					if (j > 0)
					{
						position += vector - vector3;
					}
					else
					{
						vector2 = vector3;
					}
					for (int l = 0; l <= 20; l++)
					{
						float num = (float)l / 20f;
						animation[linkClip.clip.name].normalizedTime = num;
						animation.Sample();
						Vector3 item = position + (transform.position - base.transform.position) + linkClip.velocity * num * linkClip.clip.length;
						trace.Add(item);
					}
					position += linkClip.velocity * 1f * linkClip.clip.length;
					animation[linkClip.clip.name].normalizedTime = 1f;
					animation.Sample();
					vector = transform.position - base.transform.position;
				}
				animation[linkClip.clip.name].enabled = false;
				animation[linkClip.clip.name].weight = 0f;
			}
			position += vector - vector2;
			UnityEngine.Object.DestroyImmediate(gameObject);
			endPosition = position;
		}

		public override void OnDrawGizmosSelected()
		{
			base.OnDrawGizmosSelected();
			List<Vector3> list = ListPool<Vector3>.Claim();
			Vector3 endPosition = Vector3.zero;
			CalculateOffsets(list, out endPosition);
			Gizmos.color = Color.blue;
			for (int i = 0; i < list.Count - 1; i++)
			{
				Gizmos.DrawLine(list[i], list[i + 1]);
			}
		}
	}
	[AddComponentMenu("Pathfinding/Pathfinding Debugger")]
	[ExecuteInEditMode]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_astar_debugger.php")]
	public class AstarDebugger : VersionedMonoBehaviour
	{
		private struct GraphPoint
		{
			public float fps;

			public float memory;

			public bool collectEvent;
		}

		private struct PathTypeDebug(string name, Func<int> getSize, Func<int> getTotalCreated)
		{
			private string name = name;

			private Func<int> getSize = getSize;

			private Func<int> getTotalCreated = getTotalCreated;

			public void Print(StringBuilder text)
			{
				int num = getTotalCreated();
				if (num > 0)
				{
					text.Append("\n").Append(("  " + name).PadRight(25)).Append(getSize())
						.Append("/")
						.Append(num);
				}
			}
		}

		public int yOffset = 5;

		public bool show = true;

		public bool showInEditor;

		public bool showFPS;

		public bool showPathProfile;

		public bool showMemProfile;

		public bool showGraph;

		public int graphBufferSize = 200;

		public Font font;

		public int fontSize = 12;

		private StringBuilder text = new StringBuilder();

		private string cachedText;

		private float lastUpdate = -999f;

		private GraphPoint[] graph;

		private float delayedDeltaTime = 1f;

		private float lastCollect;

		private float lastCollectNum;

		private float delta;

		private float lastDeltaTime;

		private int allocRate;

		private int lastAllocMemory;

		private float lastAllocSet = -9999f;

		private int allocMem;

		private int collectAlloc;

		private int peakAlloc;

		private int fpsDropCounterSize = 200;

		private float[] fpsDrops;

		private Rect boxRect;

		private GUIStyle style;

		private Camera cam;

		private float graphWidth = 100f;

		private float graphHeight = 100f;

		private float graphOffset = 50f;

		private int maxVecPool;

		private int maxNodePool;

		private PathTypeDebug[] debugTypes = new PathTypeDebug[7]
		{
			new PathTypeDebug("ABPath", () => PathPool.GetSize(typeof(ABPath)), () => PathPool.GetTotalCreated(typeof(ABPath))),
			new PathTypeDebug("MultiTargetPath", () => PathPool.GetSize(typeof(MultiTargetPath)), () => PathPool.GetTotalCreated(typeof(MultiTargetPath))),
			new PathTypeDebug("RandomPath", () => PathPool.GetSize(typeof(RandomPath)), () => PathPool.GetTotalCreated(typeof(RandomPath))),
			new PathTypeDebug("FleePath", () => PathPool.GetSize(typeof(FleePath)), () => PathPool.GetTotalCreated(typeof(FleePath))),
			new PathTypeDebug("ConstantPath", () => PathPool.GetSize(typeof(ConstantPath)), () => PathPool.GetTotalCreated(typeof(ConstantPath))),
			new PathTypeDebug("FloodPath", () => PathPool.GetSize(typeof(FloodPath)), () => PathPool.GetTotalCreated(typeof(FloodPath))),
			new PathTypeDebug("FloodPathTracer", () => PathPool.GetSize(typeof(FloodPathTracer)), () => PathPool.GetTotalCreated(typeof(FloodPathTracer)))
		};

		public void Start()
		{
			base.useGUILayout = false;
			fpsDrops = new float[fpsDropCounterSize];
			cam = GetComponent<Camera>();
			if (cam == null)
			{
				cam = Camera.main;
			}
			graph = new GraphPoint[graphBufferSize];
			if (Time.unscaledDeltaTime > 0f)
			{
				for (int i = 0; i < fpsDrops.Length; i++)
				{
					fpsDrops[i] = 1f / Time.unscaledDeltaTime;
				}
			}
		}

		public void LateUpdate()
		{
			if (!show || (!Application.isPlaying && !showInEditor) || Time.unscaledDeltaTime <= 0.0001f)
			{
				return;
			}
			int num = GC.CollectionCount(0);
			if (lastCollectNum != (float)num)
			{
				lastCollectNum = num;
				delta = Time.realtimeSinceStartup - lastCollect;
				lastCollect = Time.realtimeSinceStartup;
				lastDeltaTime = Time.unscaledDeltaTime;
				collectAlloc = allocMem;
			}
			allocMem = (int)GC.GetTotalMemory(forceFullCollection: false);
			bool flag = allocMem < peakAlloc;
			peakAlloc = ((!flag) ? allocMem : peakAlloc);
			if (Time.realtimeSinceStartup - lastAllocSet > 0.3f || !Application.isPlaying)
			{
				int num2 = allocMem - lastAllocMemory;
				lastAllocMemory = allocMem;
				lastAllocSet = Time.realtimeSinceStartup;
				delayedDeltaTime = Time.unscaledDeltaTime;
				if (num2 >= 0)
				{
					allocRate = num2;
				}
			}
			if (Application.isPlaying)
			{
				fpsDrops[Time.frameCount % fpsDrops.Length] = ((Time.unscaledDeltaTime > 1E-05f) ? (1f / Time.unscaledDeltaTime) : 0f);
				int num3 = Time.frameCount % graph.Length;
				graph[num3].fps = ((Time.unscaledDeltaTime < 1E-05f) ? (1f / Time.unscaledDeltaTime) : 0f);
				graph[num3].collectEvent = flag;
				graph[num3].memory = allocMem;
			}
			if (!Application.isPlaying || !(cam != null) || !showGraph)
			{
				return;
			}
			graphWidth = (float)cam.pixelWidth * 0.8f;
			float num4 = float.PositiveInfinity;
			float b = 0f;
			float num5 = float.PositiveInfinity;
			float b2 = 0f;
			for (int i = 0; i < graph.Length; i++)
			{
				num4 = Mathf.Min(graph[i].memory, num4);
				b = Mathf.Max(graph[i].memory, b);
				num5 = Mathf.Min(graph[i].fps, num5);
				b2 = Mathf.Max(graph[i].fps, b2);
			}
			int num6 = Time.frameCount % graph.Length;
			Matrix4x4 m = Matrix4x4.TRS(new Vector3(((float)cam.pixelWidth - graphWidth) / 2f, graphOffset, 1f), Quaternion.identity, new Vector3(graphWidth, graphHeight, 1f));
			for (int j = 0; j < graph.Length - 1; j++)
			{
				if (j != num6)
				{
					DrawGraphLine(j, m, (float)j / (float)graph.Length, (float)(j + 1) / (float)graph.Length, Mathf.InverseLerp(num4, b, graph[j].memory), Mathf.InverseLerp(num4, b, graph[j + 1].memory), Color.blue);
					DrawGraphLine(j, m, (float)j / (float)graph.Length, (float)(j + 1) / (float)graph.Length, Mathf.InverseLerp(num5, b2, graph[j].fps), Mathf.InverseLerp(num5, b2, graph[j + 1].fps), Color.green);
				}
			}
		}

		private void DrawGraphLine(int index, Matrix4x4 m, float x1, float x2, float y1, float y2, Color color)
		{
			UnityEngine.Debug.DrawLine(cam.ScreenToWorldPoint(m.MultiplyPoint3x4(new Vector3(x1, y1))), cam.ScreenToWorldPoint(m.MultiplyPoint3x4(new Vector3(x2, y2))), color);
		}

		public void OnGUI()
		{
			if (!show || (!Application.isPlaying && !showInEditor))
			{
				return;
			}
			if (style == null)
			{
				style = new GUIStyle();
				style.normal.textColor = Color.white;
				style.padding = new RectOffset(5, 5, 5, 5);
			}
			if (Time.realtimeSinceStartup - lastUpdate > 0.5f || cachedText == null || !Application.isPlaying)
			{
				lastUpdate = Time.realtimeSinceStartup;
				boxRect = new Rect(5f, yOffset, 310f, 40f);
				text.Length = 0;
				text.AppendLine("A* Pathfinding Project Debugger");
				text.Append("A* Version: ").Append(AstarPath.Version.ToString());
				if (showMemProfile)
				{
					boxRect.height += 200f;
					text.AppendLine();
					text.AppendLine();
					text.Append("Currently allocated".PadRight(25));
					text.Append(((float)allocMem / 1000000f).ToString("0.0 MB"));
					text.AppendLine();
					text.Append("Peak allocated".PadRight(25));
					text.Append(((float)peakAlloc / 1000000f).ToString("0.0 MB")).AppendLine();
					text.Append("Last collect peak".PadRight(25));
					text.Append(((float)collectAlloc / 1000000f).ToString("0.0 MB")).AppendLine();
					text.Append("Allocation rate".PadRight(25));
					text.Append(((float)allocRate / 1000000f).ToString("0.0 MB")).AppendLine();
					text.Append("Collection frequency".PadRight(25));
					text.Append(delta.ToString("0.00"));
					text.Append("s\n");
					text.Append("Last collect fps".PadRight(25));
					text.Append((1f / lastDeltaTime).ToString("0.0 fps"));
					text.Append(" (");
					text.Append(lastDeltaTime.ToString("0.000 s"));
					text.Append(")");
				}
				if (showFPS)
				{
					text.AppendLine();
					text.AppendLine();
					float num = ((delayedDeltaTime > 1E-05f) ? (1f / delayedDeltaTime) : 0f);
					text.Append("FPS".PadRight(25)).Append(num.ToString("0.0 fps"));
					float num2 = float.PositiveInfinity;
					for (int i = 0; i < fpsDrops.Length; i++)
					{
						if (fpsDrops[i] < num2)
						{
							num2 = fpsDrops[i];
						}
					}
					text.AppendLine();
					text.Append(("Lowest fps (last " + fpsDrops.Length + ")").PadRight(25)).Append(num2.ToString("0.0"));
				}
				if (showPathProfile)
				{
					AstarPath active = AstarPath.active;
					text.AppendLine();
					if (active == null)
					{
						text.Append("\nNo AstarPath Object In The Scene");
					}
					else
					{
						if (ListPool<Vector3>.GetSize() > maxVecPool)
						{
							maxVecPool = ListPool<Vector3>.GetSize();
						}
						if (ListPool<GraphNode>.GetSize() > maxNodePool)
						{
							maxNodePool = ListPool<GraphNode>.GetSize();
						}
						text.Append("\nPool Sizes (size/total created)");
						for (int j = 0; j < debugTypes.Length; j++)
						{
							debugTypes[j].Print(text);
						}
					}
				}
				cachedText = text.ToString();
			}
			if (font != null)
			{
				style.font = font;
				style.fontSize = fontSize;
			}
			boxRect.height = style.CalcHeight(new GUIContent(cachedText), boxRect.width);
			GUI.Box(boxRect, "");
			GUI.Label(boxRect, cachedText, style);
			if (showGraph)
			{
				float num3 = float.PositiveInfinity;
				float num4 = 0f;
				float num5 = float.PositiveInfinity;
				float num6 = 0f;
				for (int k = 0; k < graph.Length; k++)
				{
					num3 = Mathf.Min(graph[k].memory, num3);
					num4 = Mathf.Max(graph[k].memory, num4);
					num5 = Mathf.Min(graph[k].fps, num5);
					num6 = Mathf.Max(graph[k].fps, num6);
				}
				GUI.color = Color.blue;
				float num7 = Mathf.RoundToInt(num4 / 100000f);
				GUI.Label(new Rect(5f, (float)Screen.height - AstarMath.MapTo(num3, num4, 0f + graphOffset, graphHeight + graphOffset, num7 * 1000f * 100f) - 10f, 100f, 20f), (num7 / 10f).ToString("0.0 MB"));
				num7 = Mathf.Round(num3 / 100000f);
				GUI.Label(new Rect(5f, (float)Screen.height - AstarMath.MapTo(num3, num4, 0f + graphOffset, graphHeight + graphOffset, num7 * 1000f * 100f) - 10f, 100f, 20f), (num7 / 10f).ToString("0.0 MB"));
				GUI.color = Color.green;
				num7 = Mathf.Round(num6);
				GUI.Label(new Rect(55f, (float)Screen.height - AstarMath.MapTo(num5, num6, 0f + graphOffset, graphHeight + graphOffset, num7) - 10f, 100f, 20f), num7.ToString("0 FPS"));
				num7 = Mathf.Round(num5);
				GUI.Label(new Rect(55f, (float)Screen.height - AstarMath.MapTo(num5, num6, 0f + graphOffset, graphHeight + graphOffset, num7) - 10f, 100f, 20f), num7.ToString("0 FPS"));
			}
		}
	}
	[Serializable]
	public class AutoRepathPolicy
	{
		public enum Mode
		{
			Never,
			EveryNSeconds,
			Dynamic
		}

		public Mode mode = Mode.Dynamic;

		[FormerlySerializedAs("interval")]
		public float period = 0.5f;

		public float sensitivity = 10f;

		[FormerlySerializedAs("maximumInterval")]
		public float maximumPeriod = 2f;

		public bool visualizeSensitivity;

		private Vector3 lastDestination = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);

		private float lastRepathTime = float.NegativeInfinity;

		public virtual bool ShouldRecalculatePath(Vector3 position, float radius, Vector3 destination)
		{
			if (mode == Mode.Never || float.IsPositiveInfinity(destination.x))
			{
				return false;
			}
			float num = Time.time - lastRepathTime;
			if (mode == Mode.EveryNSeconds)
			{
				return num >= period;
			}
			float num2 = (destination - lastDestination).sqrMagnitude / Mathf.Max((position - lastDestination).sqrMagnitude, radius * radius) * (sensitivity * sensitivity);
			if (num2 > 1f || float.IsNaN(num2))
			{
				return true;
			}
			if (num >= maximumPeriod * (1f - Mathf.Sqrt(num2)))
			{
				return true;
			}
			return false;
		}

		public virtual void Reset()
		{
			lastRepathTime = float.NegativeInfinity;
		}

		public virtual void DidRecalculatePath(Vector3 destination)
		{
			lastRepathTime = Time.time;
			lastDestination = destination;
		}

		public void DrawGizmos(Vector3 position, float radius)
		{
			if (visualizeSensitivity && !float.IsPositiveInfinity(lastDestination.x))
			{
				float radius2 = Mathf.Sqrt(Mathf.Max((position - lastDestination).sqrMagnitude, radius * radius) / (sensitivity * sensitivity));
				Draw.Gizmos.CircleXZ(lastDestination, radius2, Color.magenta);
			}
		}
	}
	public class BinaryHeap
	{
		private struct Tuple(uint f, PathNode node)
		{
			public PathNode node = node;

			public uint F = f;
		}

		public int numberOfItems;

		public float growthFactor = 2f;

		private const int D = 4;

		private const bool SortGScores = true;

		public const ushort NotInHeap = ushort.MaxValue;

		private Tuple[] heap;

		public bool isEmpty => numberOfItems <= 0;

		private static int RoundUpToNextMultipleMod1(int v)
		{
			return v + (4 - (v - 1) % 4) % 4;
		}

		public BinaryHeap(int capacity)
		{
			capacity = RoundUpToNextMultipleMod1(capacity);
			heap = new Tuple[capacity];
			numberOfItems = 0;
		}

		public void Clear()
		{
			for (int i = 0; i < numberOfItems; i++)
			{
				heap[i].node.heapIndex = ushort.MaxValue;
			}
			numberOfItems = 0;
		}

		internal PathNode GetNode(int i)
		{
			return heap[i].node;
		}

		internal void SetF(int i, uint f)
		{
			heap[i].F = f;
		}

		private void Expand()
		{
			int num = RoundUpToNextMultipleMod1(Math.Max(heap.Length + 4, Math.Min(65533, (int)Math.Round((float)heap.Length * growthFactor))));
			if (num > 65534)
			{
				throw new Exception("Binary Heap Size really large (>65534). A heap size this large is probably the cause of pathfinding running in an infinite loop. ");
			}
			Tuple[] array = new Tuple[num];
			heap.CopyTo(array, 0);
			heap = array;
		}

		public void Add(PathNode node)
		{
			if (node == null)
			{
				throw new ArgumentNullException("node");
			}
			if (node.heapIndex != ushort.MaxValue)
			{
				DecreaseKey(heap[node.heapIndex], node.heapIndex);
				return;
			}
			if (numberOfItems == heap.Length)
			{
				Expand();
			}
			DecreaseKey(new Tuple(0u, node), (ushort)numberOfItems);
			numberOfItems++;
		}

		private void DecreaseKey(Tuple node, ushort index)
		{
			int num = index;
			uint num2 = (node.F = node.node.F);
			uint g = node.node.G;
			while (num != 0)
			{
				int num3 = (num - 1) / 4;
				if (num2 >= heap[num3].F && (num2 != heap[num3].F || g <= heap[num3].node.G))
				{
					break;
				}
				heap[num] = heap[num3];
				heap[num].node.heapIndex = (ushort)num;
				num = num3;
			}
			heap[num] = node;
			node.node.heapIndex = (ushort)num;
		}

		public PathNode Remove()
		{
			PathNode node = heap[0].node;
			node.heapIndex = ushort.MaxValue;
			numberOfItems--;
			if (numberOfItems == 0)
			{
				return node;
			}
			Tuple tuple = heap[numberOfItems];
			uint g = tuple.node.G;
			int num = 0;
			while (true)
			{
				int num2 = num;
				uint num3 = tuple.F;
				int num4 = num2 * 4 + 1;
				if (num4 <= numberOfItems)
				{
					uint f = heap[num4].F;
					uint f2 = heap[num4 + 1].F;
					uint f3 = heap[num4 + 2].F;
					uint f4 = heap[num4 + 3].F;
					if (num4 < numberOfItems && (f < num3 || (f == num3 && heap[num4].node.G < g)))
					{
						num3 = f;
						num = num4;
					}
					if (num4 + 1 < numberOfItems && (f2 < num3 || (f2 == num3 && heap[num4 + 1].node.G < ((num == num2) ? g : heap[num].node.G))))
					{
						num3 = f2;
						num = num4 + 1;
					}
					if (num4 + 2 < numberOfItems && (f3 < num3 || (f3 == num3 && heap[num4 + 2].node.G < ((num == num2) ? g : heap[num].node.G))))
					{
						num3 = f3;
						num = num4 + 2;
					}
					if (num4 + 3 < numberOfItems && (f4 < num3 || (f4 == num3 && heap[num4 + 3].node.G < ((num == num2) ? g : heap[num].node.G))))
					{
						num = num4 + 3;
					}
				}
				if (num2 == num)
				{
					break;
				}
				heap[num2] = heap[num];
				heap[num2].node.heapIndex = (ushort)num2;
			}
			heap[num] = tuple;
			tuple.node.heapIndex = (ushort)num;
			return node;
		}

		private void Validate()
		{
			for (int i = 1; i < numberOfItems; i++)
			{
				int num = (i - 1) / 4;
				if (heap[num].F > heap[i].F)
				{
					throw new Exception("Invalid state at " + i + ":" + num + " ( " + heap[num].F + " > " + heap[i].F + " ) ");
				}
				if (heap[i].node.heapIndex != i)
				{
					throw new Exception("Invalid heap index");
				}
			}
		}

		public void Rebuild()
		{
			for (int i = 2; i < numberOfItems; i++)
			{
				int num = i;
				Tuple tuple = heap[i];
				uint f = tuple.F;
				while (num != 1)
				{
					int num2 = num / 4;
					if (f >= heap[num2].F)
					{
						break;
					}
					heap[num] = heap[num2];
					heap[num].node.heapIndex = (ushort)num;
					heap[num2] = tuple;
					heap[num2].node.heapIndex = (ushort)num2;
					num = num2;
				}
			}
		}
	}
	[JsonOptIn]
	public class GraphEditorBase
	{
		public NavGraph target;
	}
	[ExecuteInEditMode]
	public abstract class GraphModifier : VersionedMonoBehaviour
	{
		public enum EventType
		{
			PostScan = 1,
			PreScan = 2,
			LatePostScan = 4,
			PreUpdate = 8,
			PostUpdate = 0x10,
			PostCacheLoad = 0x20
		}

		private static GraphModifier root;

		private GraphModifier prev;

		private GraphModifier next;

		[SerializeField]
		[HideInInspector]
		protected ulong uniqueID;

		protected static Dictionary<ulong, GraphModifier> usedIDs = new Dictionary<ulong, GraphModifier>();

		protected static List<T> GetModifiersOfType<T>() where T : GraphModifier
		{
			GraphModifier graphModifier = root;
			List<T> list = new List<T>();
			while (graphModifier != null)
			{
				T val = graphModifier as T;
				if (val != null)
				{
					list.Add(val);
				}
				graphModifier = graphModifier.next;
			}
			return list;
		}

		public static void FindAllModifiers()
		{
			GraphModifier[] array = UnityEngine.Object.FindObjectsOfType(typeof(GraphModifier)) as GraphModifier[];
			for (int i = 0; i < array.Length; i++)
			{
				if (array[i].enabled)
				{
					array[i].OnEnable();
				}
			}
		}

		public static void TriggerEvent(EventType type)
		{
			if (!Application.isPlaying)
			{
				FindAllModifiers();
			}
			GraphModifier graphModifier = root;
			switch (type)
			{
			case EventType.PreScan:
				while (graphModifier != null)
				{
					graphModifier.OnPreScan();
					graphModifier = graphModifier.next;
				}
				return;
			case EventType.PostScan:
				while (graphModifier != null)
				{
					graphModifier.OnPostScan();
					graphModifier = graphModifier.next;
				}
				return;
			case EventType.LatePostScan:
				while (graphModifier != null)
				{
					graphModifier.OnLatePostScan();
					graphModifier = graphModifier.next;
				}
				return;
			case EventType.PreUpdate:
				while (graphModifier != null)
				{
					graphModifier.OnGraphsPreUpdate();
					graphModifier = graphModifier.next;
				}
				return;
			case EventType.PostUpdate:
				while (graphModifier != null)
				{
					graphModifier.OnGraphsPostUpdate();
					graphModifier = graphModifier.next;
				}
				return;
			case EventType.PostCacheLoad:
				break;
			default:
				return;
			}
			while (graphModifier != null)
			{
				graphModifier.OnPostCacheLoad();
				graphModifier = graphModifier.next;
			}
		}

		protected virtual void OnEnable()
		{
			RemoveFromLinkedList();
			AddToLinkedList();
			ConfigureUniqueID();
		}

		protected virtual void OnDisable()
		{
			RemoveFromLinkedList();
		}

		protected override void Awake()
		{
			base.Awake();
			ConfigureUniqueID();
		}

		private void ConfigureUniqueID()
		{
			if (usedIDs.TryGetValue(uniqueID, out var value) && value != this)
			{
				Reset();
			}
			usedIDs[uniqueID] = this;
		}

		private void AddToLinkedList()
		{
			if (root == null)
			{
				root = this;
				return;
			}
			next = root;
			root.prev = this;
			root = this;
		}

		private void RemoveFromLinkedList()
		{
			if (root == this)
			{
				root = next;
				if (root != null)
				{
					root.prev = null;
				}
			}
			else
			{
				if (prev != null)
				{
					prev.next = next;
				}
				if (next != null)
				{
					next.prev = prev;
				}
			}
			prev = null;
			next = null;
		}

		protected virtual void OnDestroy()
		{
			usedIDs.Remove(uniqueID);
		}

		public virtual void OnPostScan()
		{
		}

		public virtual void OnPreScan()
		{
		}

		public virtual void OnLatePostScan()
		{
		}

		public virtual void OnPostCacheLoad()
		{
		}

		public virtual void OnGraphsPreUpdate()
		{
		}

		public virtual void OnGraphsPostUpdate()
		{
		}

		protected override void Reset()
		{
			base.Reset();
			ulong num = (ulong)UnityEngine.Random.Range(0, int.MaxValue);
			ulong num2 = (ulong)((long)UnityEngine.Random.Range(0, int.MaxValue) << 32);
			uniqueID = num | num2;
			usedIDs[uniqueID] = this;
		}
	}
	internal class GraphUpdateProcessor
	{
		private enum GraphUpdateOrder
		{
			GraphUpdate
		}

		private struct GUOSingle
		{
			public GraphUpdateOrder order;

			public IUpdatableGraph graph;

			public GraphUpdateObject obj;
		}

		private readonly AstarPath astar;

		private Thread graphUpdateThread;

		private bool anyGraphUpdateInProgress;

		private CustomSampler asyncUpdateProfilingSampler;

		private readonly Queue<GraphUpdateObject> graphUpdateQueue = new Queue<GraphUpdateObject>();

		private readonly Queue<GUOSingle> graphUpdateQueueAsync = new Queue<GUOSingle>();

		private readonly Queue<GUOSingle> graphUpdateQueuePost = new Queue<GUOSingle>();

		private readonly Queue<GUOSingle> graphUpdateQueueRegular = new Queue<GUOSingle>();

		private readonly ManualResetEvent asyncGraphUpdatesComplete = new ManualResetEvent(initialState: true);

		private readonly AutoResetEvent graphUpdateAsyncEvent = new AutoResetEvent(initialState: false);

		private readonly AutoResetEvent exitAsyncThread = new AutoResetEvent(initialState: false);

		public bool IsAnyGraphUpdateQueued => graphUpdateQueue.Count > 0;

		public bool IsAnyGraphUpdateInProgress => anyGraphUpdateInProgress;

		public event Action OnGraphsUpdated;

		public GraphUpdateProcessor(AstarPath astar)
		{
			this.astar = astar;
		}

		public AstarWorkItem GetWorkItem()
		{
			return new AstarWorkItem(QueueGraphUpdatesInternal, ProcessGraphUpdates);
		}

		public void EnableMultithreading()
		{
			if (graphUpdateThread == null || !graphUpdateThread.IsAlive)
			{
				asyncUpdateProfilingSampler = CustomSampler.Create("Graph Update");
				graphUpdateThread = new Thread(ProcessGraphUpdatesAsync);
				graphUpdateThread.IsBackground = true;
				graphUpdateThread.Priority = System.Threading.ThreadPriority.Lowest;
				graphUpdateThread.Start();
			}
		}

		public void DisableMultithreading()
		{
			if (graphUpdateThread != null && graphUpdateThread.IsAlive)
			{
				exitAsyncThread.Set();
				if (!graphUpdateThread.Join(5000))
				{
					UnityEngine.Debug.LogError("Graph update thread did not exit in 5 seconds");
				}
				graphUpdateThread = null;
			}
		}

		public void AddToQueue(GraphUpdateObject ob)
		{
			graphUpdateQueue.Enqueue(ob);
		}

		private void QueueGraphUpdatesInternal()
		{
			while (graphUpdateQueue.Count > 0)
			{
				GraphUpdateObject graphUpdateObject = graphUpdateQueue.Dequeue();
				if (graphUpdateObject.internalStage != -2)
				{
					UnityEngine.Debug.LogError("Expected remaining graph updates to be pending");
					continue;
				}
				graphUpdateObject.internalStage = 0;
				foreach (IUpdatableGraph updateableGraph in astar.data.GetUpdateableGraphs())
				{
					NavGraph graph = updateableGraph as NavGraph;
					if (graphUpdateObject.nnConstraint == null || graphUpdateObject.nnConstraint.SuitableGraph(astar.data.GetGraphIndex(graph), graph))
					{
						GUOSingle item = new GUOSingle
						{
							order = GraphUpdateOrder.GraphUpdate,
							obj = graphUpdateObject,
							graph = updateableGraph
						};
						graphUpdateObject.internalStage++;
						graphUpdateQueueRegular.Enqueue(item);
					}
				}
			}
			GraphModifier.TriggerEvent(GraphModifier.EventType.PreUpdate);
			anyGraphUpdateInProgress = true;
		}

		private bool ProcessGraphUpdates(bool force)
		{
			if (force)
			{
				asyncGraphUpdatesComplete.WaitOne();
			}
			else if (!asyncGraphUpdatesComplete.WaitOne(0))
			{
				return false;
			}
			ProcessPostUpdates();
			if (!ProcessRegularUpdates(force))
			{
				return false;
			}
			GraphModifier.TriggerEvent(GraphModifier.EventType.PostUpdate);
			if (this.OnGraphsUpdated != null)
			{
				this.OnGraphsUpdated();
			}
			anyGraphUpdateInProgress = false;
			return true;
		}

		private bool ProcessRegularUpdates(bool force)
		{
			while (graphUpdateQueueRegular.Count > 0)
			{
				GUOSingle item = graphUpdateQueueRegular.Peek();
				GraphUpdateThreading graphUpdateThreading = item.graph.CanUpdateAsync(item.obj);
				if (force || !Application.isPlaying || graphUpdateThread == null || !graphUpdateThread.IsAlive)
				{
					graphUpdateThreading &= (GraphUpdateThreading)(-2);
				}
				if ((graphUpdateThreading & GraphUpdateThreading.UnityInit) != GraphUpdateThreading.UnityThread)
				{
					if (StartAsyncUpdatesIfQueued())
					{
						return false;
					}
					item.graph.UpdateAreaInit(item.obj);
				}
				if ((graphUpdateThreading & GraphUpdateThreading.SeparateThread) != GraphUpdateThreading.UnityThread)
				{
					graphUpdateQueueRegular.Dequeue();
					graphUpdateQueueAsync.Enqueue(item);
					if ((graphUpdateThreading & GraphUpdateThreading.UnityPost) != GraphUpdateThreading.UnityThread && StartAsyncUpdatesIfQueued())
					{
						return false;
					}
					continue;
				}
				if (StartAsyncUpdatesIfQueued())
				{
					return false;
				}
				graphUpdateQueueRegular.Dequeue();
				try
				{
					item.graph.UpdateArea(item.obj);
				}
				catch (Exception ex)
				{
					UnityEngine.Debug.LogError("Error while updating graphs\n" + ex);
				}
				if ((graphUpdateThreading & GraphUpdateThreading.UnityPost) != GraphUpdateThreading.UnityThread)
				{
					item.graph.UpdateAreaPost(item.obj);
				}
				item.obj.internalStage--;
			}
			if (StartAsyncUpdatesIfQueued())
			{
				return false;
			}
			return true;
		}

		private bool StartAsyncUpdatesIfQueued()
		{
			if (graphUpdateQueueAsync.Count > 0)
			{
				asyncGraphUpdatesComplete.Reset();
				graphUpdateAsyncEvent.Set();
				return true;
			}
			return false;
		}

		private void ProcessPostUpdates()
		{
			while (graphUpdateQueuePost.Count > 0)
			{
				GUOSingle gUOSingle = graphUpdateQueuePost.Dequeue();
				if ((gUOSingle.graph.CanUpdateAsync(gUOSingle.obj) & GraphUpdateThreading.UnityPost) != GraphUpdateThreading.UnityThread)
				{
					try
					{
						gUOSingle.graph.UpdateAreaPost(gUOSingle.obj);
					}
					catch (Exception ex)
					{
						UnityEngine.Debug.LogError("Error while updating graphs (post step)\n" + ex);
					}
				}
				gUOSingle.obj.internalStage--;
			}
		}

		private void ProcessGraphUpdatesAsync()
		{
			AutoResetEvent[] array = new AutoResetEvent[2] { graphUpdateAsyncEvent, exitAsyncThread };
			while (true)
			{
				WaitHandle[] waitHandles = array;
				if (WaitHandle.WaitAny(waitHandles) == 1)
				{
					break;
				}
				while (graphUpdateQueueAsync.Count > 0)
				{
					GUOSingle item = graphUpdateQueueAsync.Dequeue();
					try
					{
						if (item.order == GraphUpdateOrder.GraphUpdate)
						{
							item.graph.UpdateArea(item.obj);
							graphUpdateQueuePost.Enqueue(item);
							continue;
						}
						throw new NotSupportedException(item.order.ToString() ?? "");
					}
					catch (Exception ex)
					{
						UnityEngine.Debug.LogError("Exception while updating graphs:\n" + ex);
					}
				}
				asyncGraphUpdatesComplete.Set();
			}
			while (graphUpdateQueueAsync.Count > 0)
			{
				graphUpdateQueueAsync.Dequeue().obj.internalStage = -3;
			}
			asyncGraphUpdatesComplete.Set();
			Profiler.EndThreadProfiling();
		}
	}
	public static class GraphUtilities
	{
		public static List<Vector3> GetContours(NavGraph graph)
		{
			List<Vector3> result = ListPool<Vector3>.Claim();
			if (graph is INavmesh)
			{
				GetContours(graph as INavmesh, delegate(List<Int3> vertices, bool cycle)
				{
					int index = (cycle ? (vertices.Count - 1) : 0);
					for (int i = 0; i < vertices.Count; i++)
					{
						result.Add((Vector3)vertices[index]);
						result.Add((Vector3)vertices[i]);
						index = i;
					}
				});
			}
			else if (graph is GridGraph)
			{
				GetContours(graph as GridGraph, delegate(Vector3[] vertices)
				{
					int num = vertices.Length - 1;
					for (int i = 0; i < vertices.Length; i++)
					{
						result.Add(vertices[num]);
						result.Add(vertices[i]);
						num = i;
					}
				}, 0f);
			}
			return result;
		}

		public static void GetContours(INavmesh navmesh, Action<List<Int3>, bool> results)
		{
			bool[] uses = new bool[3];
			Dictionary<int, int> outline = new Dictionary<int, int>();
			Dictionary<int, Int3> vertexPositions = new Dictionary<int, Int3>();
			HashSet<int> hasInEdge = new HashSet<int>();
			navmesh.GetNodes(delegate(GraphNode _node)
			{
				TriangleMeshNode triangleMeshNode = _node as TriangleMeshNode;
				bool[] array = uses;
				bool flag;
				uses[1] = (flag = (uses[2] = false));
				array[0] = flag;
				if (triangleMeshNode != null)
				{
					for (int i = 0; i < triangleMeshNode.connections.Length; i++)
					{
						Connection connection = triangleMeshNode.connections[i];
						if (connection.shapeEdge != byte.MaxValue)
						{
							uses[connection.shapeEdge] = true;
						}
					}
					for (int j = 0; j < 3; j++)
					{
						if (!uses[j])
						{
							int i2 = j;
							int i3 = (j + 1) % triangleMeshNode.GetVertexCount();
							outline[triangleMeshNode.GetVertexIndex(i2)] = triangleMeshNode.GetVertexIndex(i3);
							hasInEdge.Add(triangleMeshNode.GetVertexIndex(i3));
							vertexPositions[triangleMeshNode.GetVertexIndex(i2)] = triangleMeshNode.GetVertex(i2);
							vertexPositions[triangleMeshNode.GetVertexIndex(i3)] = triangleMeshNode.GetVertex(i3);
						}
					}
				}
			});
			Polygon.TraceContours(outline, hasInEdge, delegate(List<int> chain, bool cycle)
			{
				List<Int3> list = ListPool<Int3>.Claim();
				for (int i = 0; i < chain.Count; i++)
				{
					list.Add(vertexPositions[chain[i]]);
				}
				results(list, cycle);
			});
		}

		public static void GetContours(GridGraph grid, Action<Vector3[]> callback, float yMergeThreshold, GridNodeBase[] nodes = null)
		{
			HashSet<GridNodeBase> hashSet = ((nodes != null) ? new HashSet<GridNodeBase>(nodes) : null);
			if (grid is LayerGridGraph layerGridGraph)
			{
				nodes = nodes ?? layerGridGraph.nodes;
			}
			nodes = nodes ?? grid.nodes;
			int[] neighbourXOffsets = grid.neighbourXOffsets;
			int[] neighbourZOffsets = grid.neighbourZOffsets;
			int[] array = ((grid.neighbours == NumNeighbours.Six) ? GridGraph.hexagonNeighbourIndices : new int[4] { 0, 1, 2, 3 });
			float num = ((grid.neighbours == NumNeighbours.Six) ? (1f / 3f) : 0.5f);
			if (nodes == null)
			{
				return;
			}
			List<Vector3> list = ListPool<Vector3>.Claim();
			HashSet<int> hashSet2 = new HashSet<int>();
			foreach (GridNodeBase gridNodeBase in nodes)
			{
				if (gridNodeBase == null || !gridNodeBase.Walkable || (gridNodeBase.HasConnectionsToAllEightNeighbours && hashSet == null))
				{
					continue;
				}
				for (int j = 0; j < array.Length; j++)
				{
					int num2 = (gridNodeBase.NodeIndex << 4) | j;
					GridNodeBase neighbourAlongDirection = gridNodeBase.GetNeighbourAlongDirection(array[j]);
					if ((neighbourAlongDirection != null && (hashSet == null || hashSet.Contains(neighbourAlongDirection))) || hashSet2.Contains(num2))
					{
						continue;
					}
					list.ClearFast();
					int num3 = j;
					GridNodeBase gridNodeBase2 = gridNodeBase;
					while (true)
					{
						int num4 = (gridNodeBase2.NodeIndex << 4) | num3;
						if (num4 == num2 && list.Count > 0)
						{
							break;
						}
						hashSet2.Add(num4);
						GridNodeBase neighbourAlongDirection2 = gridNodeBase2.GetNeighbourAlongDirection(array[num3]);
						if (neighbourAlongDirection2 == null || (hashSet != null && !hashSet.Contains(neighbourAlongDirection2)))
						{
							int num5 = array[num3];
							num3 = (num3 + 1) % array.Length;
							int num6 = array[num3];
							Vector3 vector = new Vector3((float)gridNodeBase2.XCoordinateInGrid + 0.5f, 0f, (float)gridNodeBase2.ZCoordinateInGrid + 0.5f);
							vector.x += (float)(neighbourXOffsets[num5] + neighbourXOffsets[num6]) * num;
							vector.z += (float)(neighbourZOffsets[num5] + neighbourZOffsets[num6]) * num;
							vector.y = grid.transform.InverseTransform((Vector3)gridNodeBase2.position).y;
							if (list.Count >= 2)
							{
								Vector3 vector2 = list[list.Count - 2];
								Vector3 vector3 = list[list.Count - 1] - vector2;
								Vector3 vector4 = vector - vector2;
								if (((Mathf.Abs(vector3.x) > 0.01f || Mathf.Abs(vector4.x) > 0.01f) && (Mathf.Abs(vector3.z) > 0.01f || Mathf.Abs(vector4.z) > 0.01f)) || Mathf.Abs(vector3.y) > yMergeThreshold || Mathf.Abs(vector4.y) > yMergeThreshold)
								{
									list.Add(vector);
								}
								else
								{
									list[list.Count - 1] = vector;
								}
							}
							else
							{
								list.Add(vector);
							}
						}
						else
						{
							gridNodeBase2 = neighbourAlongDirection2;
							num3 = (num3 + array.Length / 2 + 1) % array.Length;
						}
					}
					if (list.Count >= 3)
					{
						Vector3 vector5 = list[list.Count - 2];
						Vector3 vector6 = list[list.Count - 1] - vector5;
						Vector3 vector7 = list[0] - vector5;
						if (((!(Mathf.Abs(vector6.x) > 0.01f) && !(Mathf.Abs(vector7.x) > 0.01f)) || (!(Mathf.Abs(vector6.z) > 0.01f) && !(Mathf.Abs(vector7.z) > 0.01f))) && !(Mathf.Abs(vector6.y) > yMergeThreshold) && !(Mathf.Abs(vector7.y) > yMergeThreshold))
						{
							list.RemoveAt(list.Count - 1);
						}
					}
					if (list.Count >= 3)
					{
						Vector3 vector8 = list[list.Count - 1];
						Vector3 vector9 = list[0] - vector8;
						Vector3 vector10 = list[1] - vector8;
						if (((!(Mathf.Abs(vector9.x) > 0.01f) && !(Mathf.Abs(vector10.x) > 0.01f)) || (!(Mathf.Abs(vector9.z) > 0.01f) && !(Mathf.Abs(vector10.z) > 0.01f))) && !(Mathf.Abs(vector9.y) > yMergeThreshold) && !(Mathf.Abs(vector10.y) > yMergeThreshold))
						{
							list.RemoveAt(0);
						}
					}
					Vector3[] array2 = list.ToArray();
					grid.transform.Transform(array2);
					callback(array2);
				}
			}
			ListPool<Vector3>.Release(ref list);
		}
	}
	public class HierarchicalGraph
	{
		private const int Tiling = 16;

		private const int MaxChildrenPerNode = 256;

		private const int MinChildrenPerNode = 128;

		private List<GraphNode>[] children = new List<GraphNode>[0];

		private List<int>[] connections = new List<int>[0];

		private int[] areas = new int[0];

		private byte[] dirty = new byte[0];

		public Action onConnectedComponentsChanged;

		private Action<GraphNode> connectionCallback;

		private Queue<GraphNode> temporaryQueue = new Queue<GraphNode>();

		private List<GraphNode> currentChildren;

		private List<int> currentConnections;

		private int currentHierarchicalNodeIndex;

		private Stack<int> temporaryStack = new Stack<int>();

		private int numDirtyNodes;

		private GraphNode[] dirtyNodes = new GraphNode[128];

		private Stack<int> freeNodeIndices = new Stack<int>();

		private int gizmoVersion;

		public int version { get; private set; }

		public int NumConnectedComponents { get; private set; }

		public HierarchicalGraph()
		{
			connectionCallback = delegate(GraphNode neighbour)
			{
				int hierarchicalNodeIndex = neighbour.HierarchicalNodeIndex;
				if (hierarchicalNodeIndex == 0)
				{
					if (currentChildren.Count < 256 && neighbour.Walkable)
					{
						neighbour.HierarchicalNodeIndex = currentHierarchicalNodeIndex;
						temporaryQueue.Enqueue(neighbour);
						currentChildren.Add(neighbour);
					}
				}
				else if (hierarchicalNodeIndex != currentHierarchicalNodeIndex && !currentConnections.Contains(hierarchicalNodeIndex))
				{
					currentConnections.Add(hierarchicalNodeIndex);
				}
			};
			Grow();
		}

		private void Grow()
		{
			List<GraphNode>[] array = new List<GraphNode>[Math.Max(64, children.Length * 2)];
			List<int>[] array2 = new List<int>[array.Length];
			int[] array3 = new int[array.Length];
			byte[] array4 = new byte[array.Length];
			children.CopyTo(array, 0);
			connections.CopyTo(array2, 0);
			areas.CopyTo(array3, 0);
			dirty.CopyTo(array4, 0);
			for (int i = children.Length; i < array.Length; i++)
			{
				array[i] = ListPool<GraphNode>.Claim(256);
				array2[i] = new List<int>();
				if (i > 0)
				{
					freeNodeIndices.Push(i);
				}
			}
			children = array;
			connections = array2;
			areas = array3;
			dirty = array4;
		}

		private int GetHierarchicalNodeIndex()
		{
			if (freeNodeIndices.Count == 0)
			{
				Grow();
			}
			return freeNodeIndices.Pop();
		}

		internal void OnCreatedNode(GraphNode node)
		{
			if (node.NodeIndex >= dirtyNodes.Length)
			{
				GraphNode[] array = new GraphNode[Math.Max(node.NodeIndex + 1, dirtyNodes.Length * 2)];
				dirtyNodes.CopyTo(array, 0);
				dirtyNodes = array;
			}
			AddDirtyNode(node);
		}

		public void AddDirtyNode(GraphNode node)
		{
			if (node.IsHierarchicalNodeDirty)
			{
				return;
			}
			node.IsHierarchicalNodeDirty = true;
			if (numDirtyNodes < dirtyNodes.Length)
			{
				dirtyNodes[numDirtyNodes] = node;
				numDirtyNodes++;
				return;
			}
			int val = 0;
			for (int num = numDirtyNodes - 1; num >= 0; num--)
			{
				if (dirtyNodes[num].Destroyed)
				{
					numDirtyNodes--;
					dirty[dirtyNodes[num].HierarchicalNodeIndex] = 1;
					dirtyNodes[num] = dirtyNodes[numDirtyNodes];
					dirtyNodes[numDirtyNodes] = null;
				}
				else
				{
					val = Math.Max(val, dirtyNodes[num].NodeIndex);
				}
			}
			if (numDirtyNodes >= dirtyNodes.Length)
			{
				throw new Exception("Failed to compactify dirty nodes array. This should not happen. " + val + " " + numDirtyNodes + " " + dirtyNodes.Length);
			}
			AddDirtyNode(node);
		}

		public uint GetConnectedComponent(int hierarchicalNodeIndex)
		{
			return (uint)areas[hierarchicalNodeIndex];
		}

		private void RemoveHierarchicalNode(int hierarchicalNode, bool removeAdjacentSmallNodes)
		{
			freeNodeIndices.Push(hierarchicalNode);
			List<int> list = connections[hierarchicalNode];
			for (int i = 0; i < list.Count; i++)
			{
				int num = list[i];
				if (dirty[num] == 0)
				{
					if (removeAdjacentSmallNodes && children[num].Count < 128)
					{
						dirty[num] = 2;
						RemoveHierarchicalNode(num, removeAdjacentSmallNodes: false);
					}
					else
					{
						connections[num].Remove(hierarchicalNode);
					}
				}
			}
			list.Clear();
			List<GraphNode> list2 = children[hierarchicalNode];
			for (int j = 0; j < list2.Count; j++)
			{
				AddDirtyNode(list2[j]);
			}
			list2.ClearFast();
		}

		public void RecalculateIfNecessary()
		{
			if (numDirtyNodes <= 0)
			{
				return;
			}
			for (int i = 0; i < numDirtyNodes; i++)
			{
				dirty[dirtyNodes[i].HierarchicalNodeIndex] = 1;
			}
			for (int j = 1; j < dirty.Length; j++)
			{
				if (dirty[j] == 1)
				{
					RemoveHierarchicalNode(j, removeAdjacentSmallNodes: true);
				}
			}
			for (int k = 1; k < dirty.Length; k++)
			{
				dirty[k] = 0;
			}
			for (int l = 0; l < numDirtyNodes; l++)
			{
				dirtyNodes[l].HierarchicalNodeIndex = 0;
			}
			for (int m = 0; m < numDirtyNodes; m++)
			{
				GraphNode graphNode = dirtyNodes[m];
				dirtyNodes[m] = null;
				graphNode.IsHierarchicalNodeDirty = false;
				if (graphNode.HierarchicalNodeIndex == 0 && graphNode.Walkable && !graphNode.Destroyed)
				{
					FindHierarchicalNodeChildren(GetHierarchicalNodeIndex(), graphNode);
				}
			}
			numDirtyNodes = 0;
			FloodFill();
			gizmoVersion++;
		}

		public void RecalculateAll()
		{
			AstarPath.active.data.GetNodes(delegate(GraphNode node)
			{
				AddDirtyNode(node);
			});
			RecalculateIfNecessary();
		}

		private void FloodFill()
		{
			for (int i = 0; i < areas.Length; i++)
			{
				areas[i] = 0;
			}
			Stack<int> stack = temporaryStack;
			int num = 0;
			for (int j = 1; j < areas.Length; j++)
			{
				if (areas[j] != 0)
				{
					continue;
				}
				num++;
				areas[j] = num;
				stack.Push(j);
				while (stack.Count > 0)
				{
					int num2 = stack.Pop();
					List<int> list = connections[num2];
					for (int num3 = list.Count - 1; num3 >= 0; num3--)
					{
						int num4 = list[num3];
						if (areas[num4] != num)
						{
							areas[num4] = num;
							stack.Push(num4);
						}
					}
				}
			}
			NumConnectedComponents = Math.Max(1, num + 1);
			version++;
		}

		private void FindHierarchicalNodeChildren(int hierarchicalNode, GraphNode startNode)
		{
			currentChildren = children[hierarchicalNode];
			currentConnections = connections[hierarchicalNode];
			currentHierarchicalNodeIndex = hierarchicalNode;
			Queue<GraphNode> queue = temporaryQueue;
			queue.Enqueue(startNode);
			startNode.HierarchicalNodeIndex = hierarchicalNode;
			currentChildren.Add(startNode);
			while (queue.Count > 0)
			{
				queue.Dequeue().GetConnections(connectionCallback);
			}
			for (int i = 0; i < currentConnections.Count; i++)
			{
				connections[currentConnections[i]].Add(hierarchicalNode);
			}
			queue.Clear();
		}

		public void OnDrawGizmos(RetainedGizmos gizmos)
		{
			RetainedGizmos.Hasher hasher = new RetainedGizmos.Hasher(AstarPath.active);
			hasher.AddHash(gizmoVersion);
			if (gizmos.Draw(hasher))
			{
				return;
			}
			RetainedGizmos.Builder builder = ObjectPool<RetainedGizmos.Builder>.Claim();
			Vector3[] array = ArrayPool<Vector3>.Claim(areas.Length);
			for (int i = 0; i < areas.Length; i++)
			{
				Int3 zero = Int3.zero;
				List<GraphNode> list = children[i];
				if (list.Count > 0)
				{
					for (int j = 0; j < list.Count; j++)
					{
						zero += list[j].position;
					}
					zero /= (float)list.Count;
					array[i] = (Vector3)zero;
				}
			}
			for (int k = 0; k < areas.Length; k++)
			{
				if (children[k].Count <= 0)
				{
					continue;
				}
				for (int l = 0; l < connections[k].Count; l++)
				{
					if (connections[k][l] > k)
					{
						builder.DrawLine(array[k], array[connections[k][l]], Color.black);
					}
				}
			}
			builder.Submit(gizmos, hasher);
		}
	}
	public struct Int3 : IEquatable<Int3>
	{
		public int x;

		public int y;

		public int z;

		public const int Precision = 1000;

		public const float FloatPrecision = 1000f;

		public const float PrecisionFactor = 0.001f;

		public static Int3 zero => default(Int3);

		public int this[int i]
		{
			get
			{
				return i switch
				{
					1 => y, 
					0 => x, 
					_ => z, 
				};
			}
			set
			{
				switch (i)
				{
				case 0:
					x = value;
					break;
				case 1:
					y = value;
					break;
				default:
					z = value;
					break;
				}
			}
		}

		public float magnitude
		{
			get
			{
				double num = x;
				double num2 = y;
				double num3 = z;
				return (float)Math.Sqrt(num * num + num2 * num2 + num3 * num3);
			}
		}

		public int costMagnitude => (int)Math.Round(magnitude);

		public float sqrMagnitude
		{
			get
			{
				double num = x;
				double num2 = y;
				double num3 = z;
				return (float)(num * num + num2 * num2 + num3 * num3);
			}
		}

		public long sqrMagnitudeLong
		{
			get
			{
				long num = x;
				long num2 = y;
				long num3 = z;
				return num * num + num2 * num2 + num3 * num3;
			}
		}

		public Int3(Vector3 position)
		{
			x = (int)Math.Round(position.x * 1000f);
			y = (int)Math.Round(position.y * 1000f);
			z = (int)Math.Round(position.z * 1000f);
		}

		public Int3(int _x, int _y, int _z)
		{
			x = _x;
			y = _y;
			z = _z;
		}

		public static bool operator ==(Int3 lhs, Int3 rhs)
		{
			if (lhs.x == rhs.x && lhs.y == rhs.y)
			{
				return lhs.z == rhs.z;
			}
			return false;
		}

		public static bool operator !=(Int3 lhs, Int3 rhs)
		{
			if (lhs.x == rhs.x && lhs.y == rhs.y)
			{
				return lhs.z != rhs.z;
			}
			return true;
		}

		public static explicit operator Int3(Vector3 ob)
		{
			return new Int3((int)Math.Round(ob.x * 1000f), (int)Math.Round(ob.y * 1000f), (int)Math.Round(ob.z * 1000f));
		}

		public static explicit operator Vector3(Int3 ob)
		{
			return new Vector3((float)ob.x * 0.001f, (float)ob.y * 0.001f, (float)ob.z * 0.001f);
		}

		public static Int3 operator -(Int3 lhs, Int3 rhs)
		{
			lhs.x -= rhs.x;
			lhs.y -= rhs.y;
			lhs.z -= rhs.z;
			return lhs;
		}

		public static Int3 operator -(Int3 lhs)
		{
			lhs.x = -lhs.x;
			lhs.y = -lhs.y;
			lhs.z = -lhs.z;
			return lhs;
		}

		public static Int3 operator +(Int3 lhs, Int3 rhs)
		{
			lhs.x += rhs.x;
			lhs.y += rhs.y;
			lhs.z += rhs.z;
			return lhs;
		}

		public static Int3 operator *(Int3 lhs, int rhs)
		{
			lhs.x *= rhs;
			lhs.y *= rhs;
			lhs.z *= rhs;
			return lhs;
		}

		public static Int3 operator *(Int3 lhs, float rhs)
		{
			lhs.x = (int)Math.Round((float)lhs.x * rhs);
			lhs.y = (int)Math.Round((float)lhs.y * rhs);
			lhs.z = (int)Math.Round((float)lhs.z * rhs);
			return lhs;
		}

		public static Int3 operator *(Int3 lhs, double rhs)
		{
			lhs.x = (int)Math.Round((double)lhs.x * rhs);
			lhs.y = (int)Math.Round((double)lhs.y * rhs);
			lhs.z = (int)Math.Round((double)lhs.z * rhs);
			return lhs;
		}

		public static Int3 operator /(Int3 lhs, float rhs)
		{
			lhs.x = (int)Math.Round((float)lhs.x / rhs);
			lhs.y = (int)Math.Round((float)lhs.y / rhs);
			lhs.z = (int)Math.Round((float)lhs.z / rhs);
			return lhs;
		}

		public static float Angle(Int3 lhs, Int3 rhs)
		{
			double num = (double)Dot(lhs, rhs) / ((double)lhs.magnitude * (double)rhs.magnitude);
			num = ((num < -1.0) ? (-1.0) : ((num > 1.0) ? 1.0 : num));
			return (float)Math.Acos(num);
		}

		public static int Dot(Int3 lhs, Int3 rhs)
		{
			return lhs.x * rhs.x + lhs.y * rhs.y + lhs.z * rhs.z;
		}

		public static long DotLong(Int3 lhs, Int3 rhs)
		{
			return (long)lhs.x * (long)rhs.x + (long)lhs.y * (long)rhs.y + (long)lhs.z * (long)rhs.z;
		}

		public Int3 Normal2D()
		{
			return new Int3(z, y, -x);
		}

		public static implicit operator string(Int3 obj)
		{
			return obj.ToString();
		}

		public override string ToString()
		{
			return "( " + x + ", " + y + ", " + z + ")";
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			Int3 @int = (Int3)obj;
			if (x == @int.x && y == @int.y)
			{
				return z == @int.z;
			}
			return false;
		}

		public bool Equals(Int3 other)
		{
			if (x == other.x && y == other.y)
			{
				return z == other.z;
			}
			return false;
		}

		public override int GetHashCode()
		{
			return (x * 73856093) ^ (y * 19349669) ^ (z * 83492791);
		}
	}
	public struct Int2(int x, int y) : IEquatable<Int2>
	{
		public int x = x;

		public int y = y;

		public long sqrMagnitudeLong => (long)x * (long)x + (long)y * (long)y;

		public static Int2 operator -(Int2 lhs)
		{
			lhs.x = -lhs.x;
			lhs.y = -lhs.y;
			return lhs;
		}

		public static Int2 operator +(Int2 a, Int2 b)
		{
			return new Int2(a.x + b.x, a.y + b.y);
		}

		public static Int2 operator -(Int2 a, Int2 b)
		{
			return new Int2(a.x - b.x, a.y - b.y);
		}

		public static bool operator ==(Int2 a, Int2 b)
		{
			if (a.x == b.x)
			{
				return a.y == b.y;
			}
			return false;
		}

		public static bool operator !=(Int2 a, Int2 b)
		{
			if (a.x == b.x)
			{
				return a.y != b.y;
			}
			return true;
		}

		public static long DotLong(Int2 a, Int2 b)
		{
			return (long)a.x * (long)b.x + (long)a.y * (long)b.y;
		}

		public override bool Equals(object o)
		{
			if (o == null)
			{
				return false;
			}
			Int2 @int = (Int2)o;
			if (x == @int.x)
			{
				return y == @int.y;
			}
			return false;
		}

		public bool Equals(Int2 other)
		{
			if (x == other.x)
			{
				return y == other.y;
			}
			return false;
		}

		public override int GetHashCode()
		{
			return x * 49157 + y * 98317;
		}

		public static Int2 Min(Int2 a, Int2 b)
		{
			return new Int2(Math.Min(a.x, b.x), Math.Min(a.y, b.y));
		}

		public static Int2 Max(Int2 a, Int2 b)
		{
			return new Int2(Math.Max(a.x, b.x), Math.Max(a.y, b.y));
		}

		public static Int2 FromInt3XZ(Int3 o)
		{
			return new Int2(o.x, o.z);
		}

		public static Int3 ToInt3XZ(Int2 o)
		{
			return new Int3(o.x, 0, o.y);
		}

		public override string ToString()
		{
			return "(" + x + ", " + y + ")";
		}
	}
	[AddComponentMenu("Pathfinding/Link")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_node_link.php")]
	public class NodeLink : GraphModifier
	{
		public Transform end;

		public float costFactor = 1f;

		public bool oneWay;

		public bool deleteConnection;

		public Transform Start => base.transform;

		public Transform End => end;

		public override void OnPostScan()
		{
			if (AstarPath.active.isScanning)
			{
				InternalOnPostScan();
				return;
			}
			AstarPath.active.AddWorkItem(new AstarWorkItem((Func<bool, bool>)delegate
			{
				InternalOnPostScan();
				return true;
			}));
		}

		public void InternalOnPostScan()
		{
			Apply();
		}

		public override void OnGraphsPostUpdate()
		{
			if (!AstarPath.active.isScanning)
			{
				AstarPath.active.AddWorkItem(new AstarWorkItem((Func<bool, bool>)delegate
				{
					InternalOnPostScan();
					return true;
				}));
			}
		}

		public virtual void Apply()
		{
			if (Start == null || End == null || AstarPath.active == null)
			{
				return;
			}
			GraphNode node = AstarPath.active.GetNearest(Start.position).node;
			GraphNode node2 = AstarPath.active.GetNearest(End.position).node;
			if (node == null || node2 == null)
			{
				return;
			}
			if (deleteConnection)
			{
				node.RemoveConnection(node2);
				if (!oneWay)
				{
					node2.RemoveConnection(node);
				}
				return;
			}
			uint cost = (uint)Math.Round((float)(node.position - node2.position).costMagnitude * costFactor);
			node.AddConnection(node2, cost);
			if (!oneWay)
			{
				node2.AddConnection(node, cost);
			}
		}

		public void OnDrawGizmos()
		{
			if (!(Start == null) && !(End == null))
			{
				Draw.Gizmos.Bezier(Start.position, End.position, deleteConnection ? Color.red : Color.green);
			}
		}
	}
	[AddComponentMenu("Pathfinding/Link2")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_node_link2.php")]
	public class NodeLink2 : GraphModifier
	{
		protected static Dictionary<GraphNode, NodeLink2> reference = new Dictionary<GraphNode, NodeLink2>();

		public Transform end;

		public float costFactor = 1f;

		public bool oneWay;

		private GraphNode connectedNode1;

		private GraphNode connectedNode2;

		private Vector3 clamped1;

		private Vector3 clamped2;

		private bool postScanCalled;

		private static readonly Color GizmosColor = new Color(0.80784315f, 8f / 15f, 16f / 85f, 0.5f);

		private static readonly Color GizmosColorSelected = new Color(47f / 51f, 41f / 85f, 0.1254902f, 1f);

		public Transform StartTransform => base.transform;

		public Transform EndTransform => end;

		public PointNode startNode { get; private set; }

		public PointNode endNode { get; private set; }

		[Obsolete("Use startNode instead (lowercase s)")]
		public GraphNode StartNode => startNode;

		[Obsolete("Use endNode instead (lowercase e)")]
		public GraphNode EndNode => endNode;

		public static NodeLink2 GetNodeLink(GraphNode node)
		{
			reference.TryGetValue(node, out var value);
			return value;
		}

		public override void OnPostScan()
		{
			InternalOnPostScan();
		}

		public void InternalOnPostScan()
		{
			if (!(EndTransform == null) && !(StartTransform == null))
			{
				if (AstarPath.active.data.pointGraph == null)
				{
					(AstarPath.active.data.AddGraph(typeof(PointGraph)) as PointGraph).name = "PointGraph (used for node links)";
				}
				if (startNode != null && startNode.Destroyed)
				{
					reference.Remove(startNode);
					startNode = null;
				}
				if (endNode != null && endNode.Destroyed)
				{
					reference.Remove(endNode);
					endNode = null;
				}
				if (startNode == null)
				{
					startNode = AstarPath.active.data.pointGraph.AddNode((Int3)StartTransform.position);
				}
				if (endNode == null)
				{
					endNode = AstarPath.active.data.pointGraph.AddNode((Int3)EndTransform.position);
				}
				connectedNode1 = null;
				connectedNode2 = null;
				if (startNode == null || endNode == null)
				{
					startNode = null;
					endNode = null;
					return;
				}
				postScanCalled = true;
				reference[startNode] = this;
				reference[endNode] = this;
				Apply(forceNewCheck: true);
			}
		}

		public override void OnGraphsPostUpdate()
		{
			if (!AstarPath.active.isScanning)
			{
				if (connectedNode1 != null && connectedNode1.Destroyed)
				{
					connectedNode1 = null;
				}
				if (connectedNode2 != null && connectedNode2.Destroyed)
				{
					connectedNode2 = null;
				}
				if (!postScanCalled)
				{
					OnPostScan();
				}
				else
				{
					Apply(forceNewCheck: false);
				}
			}
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			if (Application.isPlaying && AstarPath.active != null && AstarPath.active.data != null && AstarPath.active.data.pointGraph != null && !AstarPath.active.isScanning)
			{
				AstarPath.active.AddWorkItem(OnGraphsPostUpdate);
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			postScanCalled = false;
			if (startNode != null)
			{
				reference.Remove(startNode);
			}
			if (endNode != null)
			{
				reference.Remove(endNode);
			}
			if (startNode != null && endNode != null)
			{
				startNode.RemoveConnection(endNode);
				endNode.RemoveConnection(startNode);
				if (connectedNode1 != null && connectedNode2 != null)
				{
					startNode.RemoveConnection(connectedNode1);
					connectedNode1.RemoveConnection(startNode);
					endNode.RemoveConnection(connectedNode2);
					connectedNode2.RemoveConnection(endNode);
				}
			}
		}

		private void RemoveConnections(GraphNode node)
		{
			node.ClearConnections(alsoReverse: true);
		}

		[ContextMenu("Recalculate neighbours")]
		private void ContextApplyForce()
		{
			if (Application.isPlaying)
			{
				Apply(forceNewCheck: true);
			}
		}

		public void Apply(bool forceNewCheck)
		{
			NNConstraint none = NNConstraint.None;
			int graphIndex = (int)startNode.GraphIndex;
			none.graphMask = ~(1 << graphIndex);
			startNode.SetPosition((Int3)StartTransform.position);
			endNode.SetPosition((Int3)EndTransform.position);
			RemoveConnections(startNode);
			RemoveConnections(endNode);
			uint cost = (uint)Mathf.RoundToInt((float)((Int3)(StartTransform.position - EndTransform.position)).costMagnitude * costFactor);
			startNode.AddConnection(endNode, cost);
			endNode.AddConnection(startNode, cost);
			if (connectedNode1 == null || forceNewCheck)
			{
				NNInfo nearest = AstarPath.active.GetNearest(StartTransform.position, none);
				connectedNode1 = nearest.node;
				clamped1 = nearest.position;
			}
			if (connectedNode2 == null || forceNewCheck)
			{
				NNInfo nearest2 = AstarPath.active.GetNearest(EndTransform.position, none);
				connectedNode2 = nearest2.node;
				clamped2 = nearest2.position;
			}
			if (connectedNode2 != null && connectedNode1 != null)
			{
				connectedNode1.AddConnection(startNode, (uint)Mathf.RoundToInt((float)((Int3)(clamped1 - StartTransform.position)).costMagnitude * costFactor));
				if (!oneWay)
				{
					connectedNode2.AddConnection(endNode, (uint)Mathf.RoundToInt((float)((Int3)(clamped2 - EndTransform.position)).costMagnitude * costFactor));
				}
				if (!oneWay)
				{
					startNode.AddConnection(connectedNode1, (uint)Mathf.RoundToInt((float)((Int3)(clamped1 - StartTransform.position)).costMagnitude * costFactor));
				}
				endNode.AddConnection(connectedNode2, (uint)Mathf.RoundToInt((float)((Int3)(clamped2 - EndTransform.position)).costMagnitude * costFactor));
			}
		}

		public virtual void OnDrawGizmosSelected()
		{
			OnDrawGizmos(selected: true);
		}

		public void OnDrawGizmos()
		{
			OnDrawGizmos(selected: false);
		}

		public void OnDrawGizmos(bool selected)
		{
			Color color = (selected ? GizmosColorSelected : GizmosColor);
			if (StartTransform != null)
			{
				Draw.Gizmos.CircleXZ(StartTransform.position, 0.4f, color);
			}
			if (EndTransform != null)
			{
				Draw.Gizmos.CircleXZ(EndTransform.position, 0.4f, color);
			}
			if (StartTransform != null && EndTransform != null)
			{
				Draw.Gizmos.Bezier(StartTransform.position, EndTransform.position, color);
				if (selected)
				{
					Vector3 normalized = Vector3.Cross(Vector3.up, EndTransform.position - StartTransform.position).normalized;
					Draw.Gizmos.Bezier(StartTransform.position + normalized * 0.1f, EndTransform.position + normalized * 0.1f, color);
					Draw.Gizmos.Bezier(StartTransform.position - normalized * 0.1f, EndTransform.position - normalized * 0.1f, color);
				}
			}
		}

		internal static void SerializeReferences(GraphSerializationContext ctx)
		{
			List<NodeLink2> modifiersOfType = GraphModifier.GetModifiersOfType<NodeLink2>();
			ctx.writer.Write(modifiersOfType.Count);
			foreach (NodeLink2 item in modifiersOfType)
			{
				ctx.writer.Write(item.uniqueID);
				ctx.SerializeNodeReference(item.startNode);
				ctx.SerializeNodeReference(item.endNode);
				ctx.SerializeNodeReference(item.connectedNode1);
				ctx.SerializeNodeReference(item.connectedNode2);
				ctx.SerializeVector3(item.clamped1);
				ctx.SerializeVector3(item.clamped2);
				ctx.writer.Write(item.postScanCalled);
			}
		}

		internal static void DeserializeReferences(GraphSerializationContext ctx)
		{
			int num = ctx.reader.ReadInt32();
			for (int i = 0; i < num; i++)
			{
				ulong key = ctx.reader.ReadUInt64();
				GraphNode graphNode = ctx.DeserializeNodeReference();
				GraphNode graphNode2 = ctx.DeserializeNodeReference();
				GraphNode graphNode3 = ctx.DeserializeNodeReference();
				GraphNode graphNode4 = ctx.DeserializeNodeReference();
				Vector3 vector = ctx.DeserializeVector3();
				Vector3 vector2 = ctx.DeserializeVector3();
				bool flag = ctx.reader.ReadBoolean();
				if (GraphModifier.usedIDs.TryGetValue(key, out var value))
				{
					NodeLink2 nodeLink = value as NodeLink2;
					if (nodeLink != null)
					{
						if (graphNode != null)
						{
							reference[graphNode] = nodeLink;
						}
						if (graphNode2 != null)
						{
							reference[graphNode2] = nodeLink;
						}
						if (nodeLink.startNode != null)
						{
							reference.Remove(nodeLink.startNode);
						}
						if (nodeLink.endNode != null)
						{
							reference.Remove(nodeLink.endNode);
						}
						nodeLink.startNode = graphNode as PointNode;
						nodeLink.endNode = graphNode2 as PointNode;
						nodeLink.connectedNode1 = graphNode3;
						nodeLink.connectedNode2 = graphNode4;
						nodeLink.postScanCalled = flag;
						nodeLink.clamped1 = vector;
						nodeLink.clamped2 = vector2;
						continue;
					}
					throw new Exception("Tried to deserialize a NodeLink2 reference, but the link was not of the correct type or it has been destroyed.\nIf a NodeLink2 is included in serialized graph data, the same NodeLink2 component must be present in the scene when loading the graph data.");
				}
				throw new Exception("Tried to deserialize a NodeLink2 reference, but the link could not be found in the scene.\nIf a NodeLink2 is included in serialized graph data, the same NodeLink2 component must be present in the scene when loading the graph data.");
			}
		}
	}
	public class NodeLink3Node : PointNode
	{
		public NodeLink3 link;

		public Vector3 portalA;

		public Vector3 portalB;

		public NodeLink3Node(AstarPath active)
			: base(active)
		{
		}

		public override bool GetPortal(GraphNode other, List<Vector3> left, List<Vector3> right, bool backwards)
		{
			if (connections.Length < 2)
			{
				return false;
			}
			if (connections.Length != 2)
			{
				throw new Exception("Invalid NodeLink3Node. Expected 2 connections, found " + connections.Length);
			}
			if (left != null)
			{
				left.Add(portalA);
				right.Add(portalB);
			}
			return true;
		}

		public GraphNode GetOther(GraphNode a)
		{
			if (connections.Length < 2)
			{
				return null;
			}
			if (connections.Length != 2)
			{
				throw new Exception("Invalid NodeLink3Node. Expected 2 connections, found " + connections.Length);
			}
			if (a != connections[0].node)
			{
				return (connections[0].node as NodeLink3Node).GetOtherInternal(this);
			}
			return (connections[1].node as NodeLink3Node).GetOtherInternal(this);
		}

		private GraphNode GetOtherInternal(GraphNode a)
		{
			if (connections.Length < 2)
			{
				return null;
			}
			if (a != connections[0].node)
			{
				return connections[0].node;
			}
			return connections[1].node;
		}
	}
	[AddComponentMenu("Pathfinding/Link3")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_node_link3.php")]
	public class NodeLink3 : GraphModifier
	{
		protected static Dictionary<GraphNode, NodeLink3> reference = new Dictionary<GraphNode, NodeLink3>();

		public Transform end;

		public float costFactor = 1f;

		public bool oneWay;

		private NodeLink3Node startNode;

		private NodeLink3Node endNode;

		private MeshNode connectedNode1;

		private MeshNode connectedNode2;

		private Vector3 clamped1;

		private Vector3 clamped2;

		private bool postScanCalled;

		private static readonly Color GizmosColor = new Color(0.80784315f, 8f / 15f, 16f / 85f, 0.5f);

		private static readonly Color GizmosColorSelected = new Color(47f / 51f, 41f / 85f, 0.1254902f, 1f);

		public Transform StartTransform => base.transform;

		public Transform EndTransform => end;

		public GraphNode StartNode => startNode;

		public GraphNode EndNode => endNode;

		public static NodeLink3 GetNodeLink(GraphNode node)
		{
			reference.TryGetValue(node, out var value);
			return value;
		}

		public override void OnPostScan()
		{
			if (AstarPath.active.isScanning)
			{
				InternalOnPostScan();
				return;
			}
			AstarPath.active.AddWorkItem(new AstarWorkItem((Func<bool, bool>)delegate
			{
				InternalOnPostScan();
				return true;
			}));
		}

		public void InternalOnPostScan()
		{
			if (AstarPath.active.data.pointGraph == null)
			{
				AstarPath.active.data.AddGraph(typeof(PointGraph));
			}
			startNode = AstarPath.active.data.pointGraph.AddNode(new NodeLink3Node(AstarPath.active), (Int3)StartTransform.position);
			startNode.link = this;
			endNode = AstarPath.active.data.pointGraph.AddNode(new NodeLink3Node(AstarPath.active), (Int3)EndTransform.position);
			endNode.link = this;
			connectedNode1 = null;
			connectedNode2 = null;
			if (startNode == null || endNode == null)
			{
				startNode = null;
				endNode = null;
				return;
			}
			postScanCalled = true;
			reference[startNode] = this;
			reference[endNode] = this;
			Apply(forceNewCheck: true);
		}

		public override void OnGraphsPostUpdate()
		{
			if (!AstarPath.active.isScanning)
			{
				if (connectedNode1 != null && connectedNode1.Destroyed)
				{
					connectedNode1 = null;
				}
				if (connectedNode2 != null && connectedNode2.Destroyed)
				{
					connectedNode2 = null;
				}
				if (!postScanCalled)
				{
					OnPostScan();
				}
				else
				{
					Apply(forceNewCheck: false);
				}
			}
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			if (Application.isPlaying && AstarPath.active != null && AstarPath.active.data != null && AstarPath.active.data.pointGraph != null)
			{
				OnGraphsPostUpdate();
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			postScanCalled = false;
			if (startNode != null)
			{
				reference.Remove(startNode);
			}
			if (endNode != null)
			{
				reference.Remove(endNode);
			}
			if (startNode != null && endNode != null)
			{
				startNode.RemoveConnection(endNode);
				endNode.RemoveConnection(startNode);
				if (connectedNode1 != null && connectedNode2 != null)
				{
					startNode.RemoveConnection(connectedNode1);
					connectedNode1.RemoveConnection(startNode);
					endNode.RemoveConnection(connectedNode2);
					connectedNode2.RemoveConnection(endNode);
				}
			}
		}

		private void RemoveConnections(GraphNode node)
		{
			node.ClearConnections(alsoReverse: true);
		}

		[ContextMenu("Recalculate neighbours")]
		private void ContextApplyForce()
		{
			if (Application.isPlaying)
			{
				Apply(forceNewCheck: true);
			}
		}

		public void Apply(bool forceNewCheck)
		{
			NNConstraint none = NNConstraint.None;
			none.distanceXZ = true;
			int graphIndex = (int)startNode.GraphIndex;
			none.graphMask = ~(1 << graphIndex);
			bool flag = true;
			NNInfo nearest = AstarPath.active.GetNearest(StartTransform.position, none);
			flag &= nearest.node == connectedNode1 && nearest.node != null;
			connectedNode1 = nearest.node as MeshNode;
			clamped1 = nearest.position;
			if (connectedNode1 != null)
			{
				UnityEngine.Debug.DrawRay((Vector3)connectedNode1.position, Vector3.up * 5f, Color.red);
			}
			NNInfo nearest2 = AstarPath.active.GetNearest(EndTransform.position, none);
			flag &= nearest2.node == connectedNode2 && nearest2.node != null;
			connectedNode2 = nearest2.node as MeshNode;
			clamped2 = nearest2.position;
			if (connectedNode2 != null)
			{
				UnityEngine.Debug.DrawRay((Vector3)connectedNode2.position, Vector3.up * 5f, Color.cyan);
			}
			if (connectedNode2 == null || connectedNode1 == null)
			{
				return;
			}
			startNode.SetPosition((Int3)StartTransform.position);
			endNode.SetPosition((Int3)EndTransform.position);
			if (flag && !forceNewCheck)
			{
				return;
			}
			RemoveConnections(startNode);
			RemoveConnections(endNode);
			uint cost = (uint)Mathf.RoundToInt((float)((Int3)(StartTransform.position - EndTransform.position)).costMagnitude * costFactor);
			startNode.AddConnection(endNode, cost);
			endNode.AddConnection(startNode, cost);
			Int3 rhs = connectedNode2.position - connectedNode1.position;
			for (int i = 0; i < connectedNode1.GetVertexCount(); i++)
			{
				Int3 vertex = connectedNode1.GetVertex(i);
				Int3 vertex2 = connectedNode1.GetVertex((i + 1) % connectedNode1.GetVertexCount());
				if (Int3.DotLong((vertex2 - vertex).Normal2D(), rhs) > 0)
				{
					continue;
				}
				for (int j = 0; j < connectedNode2.GetVertexCount(); j++)
				{
					Int3 vertex3 = connectedNode2.GetVertex(j);
					Int3 vertex4 = connectedNode2.GetVertex((j + 1) % connectedNode2.GetVertexCount());
					if (Int3.DotLong((vertex4 - vertex3).Normal2D(), rhs) >= 0 && (double)Int3.Angle(vertex4 - vertex3, vertex2 - vertex) > 2.967059810956319)
					{
						float val = 0f;
						float val2 = 1f;
						val2 = Math.Min(val2, VectorMath.ClosestPointOnLineFactor(vertex, vertex2, vertex3));
						val = Math.Max(val, VectorMath.ClosestPointOnLineFactor(vertex, vertex2, vertex4));
						if (!(val2 < val))
						{
							Vector3 vector = (Vector3)(vertex2 - vertex) * val + (Vector3)vertex;
							Vector3 vector2 = (Vector3)(vertex2 - vertex) * val2 + (Vector3)vertex;
							startNode.portalA = vector;
							startNode.portalB = vector2;
							endNode.portalA = vector2;
							endNode.portalB = vector;
							connectedNode1.AddConnection(startNode, (uint)Mathf.RoundToInt((float)((Int3)(clamped1 - StartTransform.position)).costMagnitude * costFactor));
							connectedNode2.AddConnection(endNode, (uint)Mathf.RoundToInt((float)((Int3)(clamped2 - EndTransform.position)).costMagnitude * costFactor));
							startNode.AddConnection(connectedNode1, (uint)Mathf.RoundToInt((float)((Int3)(clamped1 - StartTransform.position)).costMagnitude * costFactor));
							endNode.AddConnection(connectedNode2, (uint)Mathf.RoundToInt((float)((Int3)(clamped2 - EndTransform.position)).costMagnitude * costFactor));
							return;
						}
						UnityEngine.Debug.LogError(string.Concat("Something went wrong! ", val.ToString(), " ", val2.ToString(), " ", vertex, " ", vertex2, " ", vertex3, " ", vertex4, "\nTODO, how can this happen?"));
					}
				}
			}
		}

		public virtual void OnDrawGizmosSelected()
		{
			OnDrawGizmos(selected: true);
		}

		public void OnDrawGizmos()
		{
			OnDrawGizmos(selected: false);
		}

		public void OnDrawGizmos(bool selected)
		{
			Color color = (selected ? GizmosColorSelected : GizmosColor);
			if (StartTransform != null)
			{
				Draw.Gizmos.CircleXZ(StartTransform.position, 0.4f, color);
			}
			if (EndTransform != null)
			{
				Draw.Gizmos.CircleXZ(EndTransform.position, 0.4f, color);
			}
			if (StartTransform != null && EndTransform != null)
			{
				Draw.Gizmos.Bezier(StartTransform.position, EndTransform.position, color);
				if (selected)
				{
					Vector3 normalized = Vector3.Cross(Vector3.up, EndTransform.position - StartTransform.position).normalized;
					Draw.Gizmos.Bezier(StartTransform.position + normalized * 0.1f, EndTransform.position + normalized * 0.1f, color);
					Draw.Gizmos.Bezier(StartTransform.position - normalized * 0.1f, EndTransform.position - normalized * 0.1f, color);
				}
			}
		}
	}
	public static class PathPool
	{
		private static readonly Dictionary<Type, Stack<Path>> pool = new Dictionary<Type, Stack<Path>>();

		private static readonly Dictionary<Type, int> totalCreated = new Dictionary<Type, int>();

		public static void Pool(Path path)
		{
			lock (pool)
			{
				if (((IPathInternals)path).Pooled)
				{
					throw new ArgumentException("The path is already pooled.");
				}
				if (!pool.TryGetValue(path.GetType(), out var value))
				{
					value = new Stack<Path>();
					pool[path.GetType()] = value;
				}
				((IPathInternals)path).Pooled = true;
				((IPathInternals)path).OnEnterPool();
				value.Push(path);
			}
		}

		public static int GetTotalCreated(Type type)
		{
			if (totalCreated.TryGetValue(type, out var value))
			{
				return value;
			}
			return 0;
		}

		public static int GetSize(Type type)
		{
			if (pool.TryGetValue(type, out var value))
			{
				return value.Count;
			}
			return 0;
		}

		public static T GetPath<T>() where T : Path, new()
		{
			lock (pool)
			{
				T val;
				if (pool.TryGetValue(typeof(T), out var value) && value.Count > 0)
				{
					val = value.Pop() as T;
				}
				else
				{
					val = new T();
					if (!totalCreated.ContainsKey(typeof(T)))
					{
						totalCreated[typeof(T)] = 0;
					}
					totalCreated[typeof(T)]++;
				}
				((IPathInternals)val).Pooled = false;
				((IPathInternals)val).Reset();
				return val;
			}
		}
	}
	public class PathProcessor
	{
		public struct GraphUpdateLock(PathProcessor pathProcessor, bool block)
		{
			private PathProcessor pathProcessor = pathProcessor;

			private int id = pathProcessor.Lock(block);

			public bool Held
			{
				get
				{
					if (pathProcessor != null)
					{
						return pathProcessor.locks.Contains(id);
					}
					return false;
				}
			}

			public void Release()
			{
				pathProcessor.Unlock(id);
			}
		}

		internal readonly ThreadControlQueue queue;

		private readonly AstarPath astar;

		private readonly PathReturnQueue returnQueue;

		private readonly PathHandler[] pathHandlers;

		private readonly Thread[] threads;

		private IEnumerator threadCoroutine;

		private int nextNodeIndex = 1;

		private readonly Stack<int> nodeIndexPool = new Stack<int>();

		private readonly List<int> locks = new List<int>();

		private int nextLockID;

		private CustomSampler profilingSampler;

		public int NumThreads => pathHandlers.Length;

		public bool IsUsingMultithreading => threads != null;

		public event Action<Path> OnPathPreSearch;

		public event Action<Path> OnPathPostSearch;

		public event Action OnQueueUnblocked;

		internal PathProcessor(AstarPath astar, PathReturnQueue returnQueue, int processors, bool multithreaded)
		{
			this.astar = astar;
			this.returnQueue = returnQueue;
			if (processors < 0)
			{
				throw new ArgumentOutOfRangeException("processors");
			}
			if (!multithreaded && processors != 1)
			{
				throw new Exception("Only a single non-multithreaded processor is allowed");
			}
			queue = new ThreadControlQueue(processors);
			pathHandlers = new PathHandler[processors];
			for (int i = 0; i < processors; i++)
			{
				pathHandlers[i] = new PathHandler(i, processors);
			}
			if (multithreaded)
			{
				profilingSampler = CustomSampler.Create("Calculating Path");
				threads = new Thread[processors];
				for (int j = 0; j < processors; j++)
				{
					PathHandler pathHandler = pathHandlers[j];
					threads[j] = new Thread((ThreadStart)delegate
					{
						CalculatePathsThreaded(pathHandler);
					});
					threads[j].Name = "Pathfinding Thread " + j;
					threads[j].IsBackground = true;
					threads[j].Start();
				}
			}
			else
			{
				threadCoroutine = CalculatePaths(pathHandlers[0]);
			}
		}

		private int Lock(bool block)
		{
			queue.Block();
			if (block)
			{
				while (!queue.AllReceiversBlocked)
				{
					if (IsUsingMultithreading)
					{
						Thread.Sleep(1);
					}
					else
					{
						TickNonMultithreaded();
					}
				}
			}
			nextLockID++;
			locks.Add(nextLockID);
			return nextLockID;
		}

		private void Unlock(int id)
		{
			if (!locks.Remove(id))
			{
				throw new ArgumentException("This lock has already been released");
			}
			if (locks.Count == 0)
			{
				if (this.OnQueueUnblocked != null)
				{
					this.OnQueueUnblocked();
				}
				queue.Unblock();
			}
		}

		public GraphUpdateLock PausePathfinding(bool block)
		{
			return new GraphUpdateLock(this, block);
		}

		public void TickNonMultithreaded()
		{
			if (threadCoroutine == null)
			{
				return;
			}
			try
			{
				threadCoroutine.MoveNext();
			}
			catch (Exception ex)
			{
				threadCoroutine = null;
				if (!(ex is ThreadControlQueue.QueueTerminationException))
				{
					UnityEngine.Debug.LogException(ex);
					UnityEngine.Debug.LogError("Unhandled exception during pathfinding. Terminating.");
					queue.TerminateReceivers();
					try
					{
						queue.PopNoBlock(blockedBefore: false);
						return;
					}
					catch
					{
						return;
					}
				}
			}
		}

		public void JoinThreads()
		{
			if (threads == null)
			{
				return;
			}
			for (int i = 0; i < threads.Length; i++)
			{
				if (!threads[i].Join(200))
				{
					UnityEngine.Debug.LogError("Could not terminate pathfinding thread[" + i + "] in 200ms, trying Thread.Abort");
					threads[i].Abort();
				}
			}
		}

		public void AbortThreads()
		{
			if (threads == null)
			{
				return;
			}
			for (int i = 0; i < threads.Length; i++)
			{
				if (threads[i] != null && threads[i].IsAlive)
				{
					threads[i].Abort();
				}
			}
		}

		public int GetNewNodeIndex()
		{
			if (nodeIndexPool.Count <= 0)
			{
				return nextNodeIndex++;
			}
			return nodeIndexPool.Pop();
		}

		public void InitializeNode(GraphNode node)
		{
			if (!queue.AllReceiversBlocked)
			{
				throw new Exception("Trying to initialize a node when it is not safe to initialize any nodes. Must be done during a graph update. See http://arongranberg.com/astar/docs/graph-updates.php#direct");
			}
			for (int i = 0; i < pathHandlers.Length; i++)
			{
				pathHandlers[i].InitializeNode(node);
			}
			astar.hierarchicalGraph.OnCreatedNode(node);
		}

		public void DestroyNode(GraphNode node)
		{
			if (node.NodeIndex != -1)
			{
				nodeIndexPool.Push(node.NodeIndex);
				for (int i = 0; i < pathHandlers.Length; i++)
				{
					pathHandlers[i].DestroyNode(node);
				}
				astar.hierarchicalGraph.AddDirtyNode(node);
			}
		}

		private void CalculatePathsThreaded(PathHandler pathHandler)
		{
			try
			{
				long num = 100000L;
				long targetTick = DateTime.UtcNow.Ticks + num;
				while (true)
				{
					Path path = queue.Pop();
					IPathInternals pathInternals = path;
					pathInternals.PrepareBase(pathHandler);
					pathInternals.AdvanceState(PathState.Processing);
					if (this.OnPathPreSearch != null)
					{
						this.OnPathPreSearch(path);
					}
					long ticks = DateTime.UtcNow.Ticks;
					pathInternals.Prepare();
					if (path.CompleteState == PathCompleteState.NotCalculated)
					{
						astar.debugPathData = pathInternals.PathHandler;
						astar.debugPathID = path.pathID;
						pathInternals.Initialize();
						while (path.CompleteState == PathCompleteState.NotCalculated)
						{
							pathInternals.CalculateStep(targetTick);
							targetTick = DateTime.UtcNow.Ticks + num;
							if (queue.IsTerminating)
							{
								path.FailWithError("AstarPath object destroyed");
							}
						}
						path.duration = (float)(DateTime.UtcNow.Ticks - ticks) * 0.0001f;
					}
					pathInternals.Cleanup();
					if (path.immediateCallback != null)
					{
						path.immediateCallback(path);
					}
					if (this.OnPathPostSearch != null)
					{
						this.OnPathPostSearch(path);
					}
					returnQueue.Enqueue(path);
					pathInternals.AdvanceState(PathState.ReturnQueue);
				}
			}
			catch (Exception ex)
			{
				if (ex is ThreadAbortException || ex is ThreadControlQueue.QueueTerminationException)
				{
					if (astar.logPathResults == PathLog.Heavy)
					{
						UnityEngine.Debug.LogWarning("Shutting down pathfinding thread #" + pathHandler.threadID);
					}
					return;
				}
				UnityEngine.Debug.LogException(ex);
				UnityEngine.Debug.LogError("Unhandled exception during pathfinding. Terminating.");
				queue.TerminateReceivers();
			}
			finally
			{
				Profiler.EndThreadProfiling();
			}
			UnityEngine.Debug.LogError("Error : This part should never be reached.");
			queue.ReceiverTerminated();
		}

		private IEnumerator CalculatePaths(PathHandler pathHandler)
		{
			long maxTicks = (long)(astar.maxFrameTime * 10000f);
			long targetTick = DateTime.UtcNow.Ticks + maxTicks;
			while (true)
			{
				Path p = null;
				bool blockedBefore = false;
				while (p == null)
				{
					try
					{
						p = queue.PopNoBlock(blockedBefore);
						blockedBefore = blockedBefore || p == null;
					}
					catch (ThreadControlQueue.QueueTerminationException)
					{
						yield break;
					}
					if (p == null)
					{
						yield return null;
					}
				}
				IPathInternals ip = p;
				maxTicks = (long)(astar.maxFrameTime * 10000f);
				ip.PrepareBase(pathHandler);
				ip.AdvanceState(PathState.Processing);
				this.OnPathPreSearch?.Invoke(p);
				long ticks = DateTime.UtcNow.Ticks;
				long totalTicks = 0L;
				ip.Prepare();
				if (p.CompleteState == PathCompleteState.NotCalculated)
				{
					astar.debugPathData = ip.PathHandler;
					astar.debugPathID = p.pathID;
					ip.Initialize();
					while (p.CompleteState == PathCompleteState.NotCalculated)
					{
						ip.CalculateStep(targetTick);
						if (p.CompleteState != PathCompleteState.NotCalculated)
						{
							break;
						}
						totalTicks += DateTime.UtcNow.Ticks - ticks;
						yield return null;
						ticks = DateTime.UtcNow.Ticks;
						if (queue.IsTerminating)
						{
							p.FailWithError("AstarPath object destroyed");
						}
						targetTick = DateTime.UtcNow.Ticks + maxTicks;
					}
					totalTicks += DateTime.UtcNow.Ticks - ticks;
					p.duration = (float)totalTicks * 0.0001f;
				}
				ip.Cleanup();
				p.immediateCallback?.Invoke(p);
				this.OnPathPostSearch?.Invoke(p);
				returnQueue.Enqueue(p);
				ip.AdvanceState(PathState.ReturnQueue);
				if (DateTime.UtcNow.Ticks > targetTick)
				{
					yield return null;
					targetTick = DateTime.UtcNow.Ticks + maxTicks;
				}
			}
		}
	}
	internal class PathReturnQueue
	{
		private Queue<Path> pathReturnQueue = new Queue<Path>();

		private object pathsClaimedSilentlyBy;

		public PathReturnQueue(object pathsClaimedSilentlyBy)
		{
			this.pathsClaimedSilentlyBy = pathsClaimedSilentlyBy;
		}

		public void Enqueue(Path path)
		{
			lock (pathReturnQueue)
			{
				pathReturnQueue.Enqueue(path);
			}
		}

		public void ReturnPaths(bool timeSlice)
		{
			long num = (timeSlice ? (DateTime.UtcNow.Ticks + 10000) : 0);
			int num2 = 0;
			while (true)
			{
				Path path;
				lock (pathReturnQueue)
				{
					if (pathReturnQueue.Count == 0)
					{
						break;
					}
					path = pathReturnQueue.Dequeue();
				}
				try
				{
					((IPathInternals)path).ReturnPath();
				}
				catch (Exception exception)
				{
					UnityEngine.Debug.LogException(exception);
				}
				((IPathInternals)path).AdvanceState(PathState.Returned);
				path.Release(pathsClaimedSilentlyBy, silent: true);
				num2++;
				if (num2 > 5 && timeSlice)
				{
					num2 = 0;
					if (DateTime.UtcNow.Ticks >= num)
					{
						break;
					}
				}
			}
		}
	}
	internal class ThreadControlQueue
	{
		public class QueueTerminationException : Exception
		{
		}

		private Path head;

		private Path tail;

		private readonly object lockObj = new object();

		private readonly int numReceivers;

		private bool blocked;

		private int blockedReceivers;

		private bool starving;

		private bool terminate;

		private ManualResetEvent block = new ManualResetEvent(initialState: true);

		public bool IsEmpty => head == null;

		public bool IsTerminating => terminate;

		public bool AllReceiversBlocked
		{
			get
			{
				lock (lockObj)
				{
					return blocked && blockedReceivers == numReceivers;
				}
			}
		}

		public ThreadControlQueue(int numReceivers)
		{
			this.numReceivers = numReceivers;
		}

		public void Block()
		{
			lock (lockObj)
			{
				blocked = true;
				block.Reset();
			}
		}

		public void Unblock()
		{
			lock (lockObj)
			{
				blocked = false;
				block.Set();
			}
		}

		public void Lock()
		{
			Monitor.Enter(lockObj);
		}

		public void Unlock()
		{
			Monitor.Exit(lockObj);
		}

		public void PushFront(Path path)
		{
			lock (lockObj)
			{
				if (terminate)
				{
					return;
				}
				if (tail == null)
				{
					head = path;
					tail = path;
					if (starving && !blocked)
					{
						starving = false;
						block.Set();
					}
					else
					{
						starving = false;
					}
				}
				else
				{
					path.next = head;
					head = path;
				}
			}
		}

		public void Push(Path path)
		{
			lock (lockObj)
			{
				if (terminate)
				{
					return;
				}
				if (tail == null)
				{
					head = path;
					tail = path;
					if (starving && !blocked)
					{
						starving = false;
						block.Set();
					}
					else
					{
						starving = false;
					}
				}
				else
				{
					tail.next = path;
					tail = path;
				}
			}
		}

		private void Starving()
		{
			starving = true;
			block.Reset();
		}

		public void TerminateReceivers()
		{
			lock (lockObj)
			{
				terminate = true;
				block.Set();
			}
		}

		public Path Pop()
		{
			Monitor.Enter(lockObj);
			try
			{
				if (terminate)
				{
					blockedReceivers++;
					throw new QueueTerminationException();
				}
				if (head == null)
				{
					Starving();
				}
				while (blocked || starving)
				{
					blockedReceivers++;
					if (blockedReceivers > numReceivers)
					{
						throw new InvalidOperationException("More receivers are blocked than specified in constructor (" + blockedReceivers + " > " + numReceivers + ")");
					}
					Monitor.Exit(lockObj);
					block.WaitOne();
					Monitor.Enter(lockObj);
					if (terminate)
					{
						throw new QueueTerminationException();
					}
					blockedReceivers--;
					if (head == null)
					{
						Starving();
					}
				}
				Path result = head;
				Path next = head.next;
				if (next == null)
				{
					tail = null;
				}
				head.next = null;
				head = next;
				return result;
			}
			finally
			{
				if (Monitor.IsEntered(lockObj))
				{
					Monitor.Exit(lockObj);
				}
			}
		}

		public void ReceiverTerminated()
		{
			Monitor.Enter(lockObj);
			blockedReceivers++;
			Monitor.Exit(lockObj);
		}

		public Path PopNoBlock(bool blockedBefore)
		{
			Monitor.Enter(lockObj);
			try
			{
				if (terminate)
				{
					blockedReceivers++;
					throw new QueueTerminationException();
				}
				if (head == null)
				{
					Starving();
				}
				if (blocked || starving)
				{
					if (!blockedBefore)
					{
						blockedReceivers++;
						if (terminate)
						{
							throw new QueueTerminationException();
						}
						if (blockedReceivers != numReceivers && blockedReceivers > numReceivers)
						{
							throw new InvalidOperationException("More receivers are blocked than specified in constructor (" + blockedReceivers + " > " + numReceivers + ")");
						}
					}
					return null;
				}
				if (blockedBefore)
				{
					blockedReceivers--;
				}
				Path result = head;
				Path next = head.next;
				if (next == null)
				{
					tail = null;
				}
				head.next = null;
				head = next;
				return result;
			}
			finally
			{
				Monitor.Exit(lockObj);
			}
		}
	}
	public struct AstarWorkItem
	{
		public Action init;

		public Action<IWorkItemContext> initWithContext;

		public Func<bool, bool> update;

		public Func<IWorkItemContext, bool, bool> updateWithContext;

		public AstarWorkItem(Func<bool, bool> update)
		{
			init = null;
			initWithContext = null;
			updateWithContext = null;
			this.update = update;
		}

		public AstarWorkItem(Func<IWorkItemContext, bool, bool> update)
		{
			init = null;
			initWithContext = null;
			updateWithContext = update;
			this.update = null;
		}

		public AstarWorkItem(Action init, Func<bool, bool> update = null)
		{
			this.init = init;
			initWithContext = null;
			this.update = update;
			updateWithContext = null;
		}

		public AstarWorkItem(Action<IWorkItemContext> init, Func<IWorkItemContext, bool, bool> update = null)
