	public class PathNode
	{
		public GraphNode node;

		public PathNode parent;

		public ushort pathID;

		public ushort heapIndex = ushort.MaxValue;

		private uint flags;

		private const uint CostMask = 268435455u;

		private const int Flag1Offset = 28;

		private const uint Flag1Mask = 268435456u;

		private const int Flag2Offset = 29;

		private const uint Flag2Mask = 536870912u;

		private uint g;

		private uint h;

		public uint cost
		{
			get
			{
				return flags & 0xFFFFFFF;
			}
			set
			{
				flags = (flags & 0xF0000000u) | value;
			}
		}

		public bool flag1
		{
			get
			{
				return (flags & 0x10000000) != 0;
			}
			set
			{
				flags = (flags & 0xEFFFFFFFu) | (uint)(value ? 268435456 : 0);
			}
		}

		public bool flag2
		{
			get
			{
				return (flags & 0x20000000) != 0;
			}
			set
			{
				flags = (flags & 0xDFFFFFFFu) | (uint)(value ? 536870912 : 0);
			}
		}

		public uint G
		{
			get
			{
				return g;
			}
			set
			{
				g = value;
			}
		}

		public uint H
		{
			get
			{
				return h;
			}
			set
			{
				h = value;
			}
		}

		public uint F => g + h;

		public void UpdateG(Path path)
		{
			g = parent.g + cost + path.GetTraversalCost(node);
		}
	}
	public class PathHandler
	{
		private ushort pathID;

		public readonly int threadID;

		public readonly int totalThreadCount;

		public readonly BinaryHeap heap = new BinaryHeap(128);

		public PathNode[] nodes = new PathNode[0];

		public readonly StringBuilder DebugStringBuilder = new StringBuilder();

		public ushort PathID => pathID;

		public PathHandler(int threadID, int totalThreadCount)
		{
			this.threadID = threadID;
			this.totalThreadCount = totalThreadCount;
		}

		public void InitializeForPath(Path p)
		{
			pathID = p.pathID;
			heap.Clear();
		}

		public void DestroyNode(GraphNode node)
		{
			PathNode pathNode = GetPathNode(node);
			pathNode.node = null;
			pathNode.parent = null;
			pathNode.pathID = 0;
			pathNode.G = 0u;
			pathNode.H = 0u;
		}

		public void InitializeNode(GraphNode node)
		{
			int nodeIndex = node.NodeIndex;
			if (nodeIndex >= nodes.Length)
			{
				PathNode[] array = new PathNode[Math.Max(128, nodes.Length * 2)];
				nodes.CopyTo(array, 0);
				for (int i = nodes.Length; i < array.Length; i++)
				{
					array[i] = new PathNode();
				}
				nodes = array;
			}
			nodes[nodeIndex].node = node;
		}

		public PathNode GetPathNode(int nodeIndex)
		{
			return nodes[nodeIndex];
		}

		public PathNode GetPathNode(GraphNode node)
		{
			return nodes[node.NodeIndex];
		}

		public void ClearPathIDs()
		{
			for (int i = 0; i < nodes.Length; i++)
			{
				if (nodes[i] != null)
				{
					nodes[i].pathID = 0;
				}
			}
		}
	}
