	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_recast_tile_update.php")]
	public class RecastTileUpdate : MonoBehaviour
	{
		public static event Action<Bounds> OnNeedUpdates;

		private void Start()
		{
			ScheduleUpdate();
		}

		private void OnDestroy()
		{
			ScheduleUpdate();
		}

		public void ScheduleUpdate()
		{
			Collider component = GetComponent<Collider>();
			if (component != null)
			{
				if (RecastTileUpdate.OnNeedUpdates != null)
				{
					RecastTileUpdate.OnNeedUpdates(component.bounds);
				}
			}
			else if (RecastTileUpdate.OnNeedUpdates != null)
			{
				RecastTileUpdate.OnNeedUpdates(new Bounds(base.transform.position, Vector3.zero));
			}
		}
	}
	[AddComponentMenu("Pathfinding/Navmesh/RecastTileUpdateHandler")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_recast_tile_update_handler.php")]
	public class RecastTileUpdateHandler : MonoBehaviour
	{
		private RecastGraph graph;

		private bool[] dirtyTiles;

		private bool anyDirtyTiles;

		private float earliestDirty = float.NegativeInfinity;

		public float maxThrottlingDelay = 0.5f;

		public void SetGraph(RecastGraph graph)
		{
			this.graph = graph;
			if (graph != null)
			{
				dirtyTiles = new bool[graph.tileXCount * graph.tileZCount];
				anyDirtyTiles = false;
			}
		}

		public void ScheduleUpdate(Bounds bounds)
		{
			if (graph == null)
			{
				if (AstarPath.active != null)
				{
					SetGraph(AstarPath.active.data.recastGraph);
				}
				if (graph == null)
				{
					UnityEngine.Debug.LogError("Received tile update request (from RecastTileUpdate), but no RecastGraph could be found to handle it");
					return;
				}
			}
			int num = Mathf.CeilToInt(graph.characterRadius / graph.cellSize) + 3;
			bounds.Expand(new Vector3(num, 0f, num) * graph.cellSize * 2f);
			IntRect touchingTiles = graph.GetTouchingTiles(bounds);
			if (touchingTiles.Width * touchingTiles.Height <= 0)
			{
				return;
			}
			if (!anyDirtyTiles)
			{
				earliestDirty = Time.time;
				anyDirtyTiles = true;
			}
			for (int i = touchingTiles.ymin; i <= touchingTiles.ymax; i++)
			{
				for (int j = touchingTiles.xmin; j <= touchingTiles.xmax; j++)
				{
					dirtyTiles[i * graph.tileXCount + j] = true;
				}
			}
		}

		private void OnEnable()
		{
			RecastTileUpdate.OnNeedUpdates += ScheduleUpdate;
		}

		private void OnDisable()
		{
			RecastTileUpdate.OnNeedUpdates -= ScheduleUpdate;
		}

		private void Update()
		{
			if (anyDirtyTiles && Time.time - earliestDirty >= maxThrottlingDelay && graph != null)
			{
				UpdateDirtyTiles();
			}
		}

		public void UpdateDirtyTiles()
		{
			if (graph == null)
			{
				new InvalidOperationException("No graph is set on this object");
			}
			if (graph.tileXCount * graph.tileZCount != dirtyTiles.Length)
			{
				UnityEngine.Debug.LogError("Graph has changed dimensions. Clearing queued graph updates and resetting.");
				SetGraph(graph);
				return;
			}
			for (int i = 0; i < graph.tileZCount; i++)
			{
				for (int j = 0; j < graph.tileXCount; j++)
				{
					if (dirtyTiles[i * graph.tileXCount + j])
					{
						dirtyTiles[i * graph.tileXCount + j] = false;
						Bounds tileBounds = graph.GetTileBounds(j, i);
						tileBounds.extents *= 0.5f;
						GraphUpdateObject graphUpdateObject = new GraphUpdateObject(tileBounds);
						graphUpdateObject.nnConstraint.graphMask = 1 << (int)graph.graphIndex;
						AstarPath.active.UpdateGraphs(graphUpdateObject);
					}
				}
			}
			anyDirtyTiles = false;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_target_mover.php")]
	public class TargetMover : MonoBehaviour
	{
		public LayerMask mask;

		public Transform target;

		private IAstarAI[] ais;

		public bool onlyOnDoubleClick;

		public bool use2D;

		private Camera cam;

		public void Start()
		{
			cam = Camera.main;
			ais = UnityEngine.Object.FindObjectsOfType<MonoBehaviour>().OfType<IAstarAI>().ToArray();
			base.useGUILayout = false;
		}

		public void OnGUI()
		{
			if (onlyOnDoubleClick && cam != null && Event.current.type == EventType.MouseDown && Event.current.clickCount == 2)
			{
				UpdateTargetPosition();
			}
		}

		private void Update()
		{
			if (!onlyOnDoubleClick && cam != null)
			{
				UpdateTargetPosition();
			}
		}

		public void UpdateTargetPosition()
		{
			Vector3 vector = Vector3.zero;
			bool flag = false;
			RaycastHit hitInfo;
			if (use2D)
			{
				vector = cam.ScreenToWorldPoint(Input.mousePosition);
				vector.z = 0f;
				flag = true;
			}
			else if (Physics.Raycast(cam.ScreenPointToRay(Input.mousePosition), out hitInfo, float.PositiveInfinity, mask))
			{
				vector = hitInfo.point;
				flag = true;
			}
			if (!flag || !(vector != target.position))
			{
				return;
			}
			target.position = vector;
			if (!onlyOnDoubleClick)
			{
				return;
			}
			for (int i = 0; i < ais.Length; i++)
			{
				if (ais[i] != null)
				{
					ais[i].SearchPath();
				}
			}
		}
	}
