		}

		public override NNInfoInternal GetNearestForce(Vector3 position, NNConstraint constraint)
		{
			return GetNearestInternal(position, constraint, fastCheck: false);
		}

		private NNInfoInternal GetNearestInternal(Vector3 position, NNConstraint constraint, bool fastCheck)
		{
			if (nodes == null)
			{
				return default(NNInfoInternal);
			}
			Int3 @int = (Int3)position;
			if (optimizeForSparseGraph)
			{
				if (nearestNodeDistanceMode == NodeDistanceMode.Node)
				{
					return new NNInfoInternal(lookupTree.GetNearest(@int, fastCheck ? null : constraint));
				}
				GraphNode nearestConnection = lookupTree.GetNearestConnection(@int, fastCheck ? null : constraint, maximumConnectionLength);
				if (nearestConnection == null)
				{
					return default(NNInfoInternal);
				}
				return FindClosestConnectionPoint(nearestConnection as PointNode, position);
			}
			float num = ((constraint == null || constraint.constrainDistance) ? AstarPath.active.maxNearestNodeDistanceSqr : float.PositiveInfinity);
			num *= 1000000f;
			NNInfoInternal result = new NNInfoInternal(null);
			long num2 = long.MaxValue;
			long num3 = long.MaxValue;
			for (int i = 0; i < nodeCount; i++)
			{
				PointNode pointNode = nodes[i];
				long sqrMagnitudeLong = (@int - pointNode.position).sqrMagnitudeLong;
				if (sqrMagnitudeLong < num2)
				{
					num2 = sqrMagnitudeLong;
					result.node = pointNode;
				}
				if (sqrMagnitudeLong < num3 && (float)sqrMagnitudeLong < num && (constraint == null || constraint.Suitable(pointNode)))
				{
					num3 = sqrMagnitudeLong;
					result.constrainedNode = pointNode;
				}
			}
			if (!fastCheck)
			{
				result.node = result.constrainedNode;
			}
			result.UpdateInfo();
			return result;
		}

		private NNInfoInternal FindClosestConnectionPoint(PointNode node, Vector3 position)
		{
			Vector3 clampedPosition = (Vector3)node.position;
			Connection[] connections = node.connections;
			Vector3 vector = (Vector3)node.position;
			float num = float.PositiveInfinity;
			if (connections != null)
			{
				for (int i = 0; i < connections.Length; i++)
				{
					Vector3 lineEnd = ((Vector3)connections[i].node.position + vector) * 0.5f;
					Vector3 vector2 = VectorMath.ClosestPointOnSegment(vector, lineEnd, position);
					float sqrMagnitude = (vector2 - position).sqrMagnitude;
					if (sqrMagnitude < num)
					{
						num = sqrMagnitude;
						clampedPosition = vector2;
					}
				}
			}
			return new NNInfoInternal
			{
				node = node,
				clampedPosition = clampedPosition
			};
		}

		public PointNode AddNode(Int3 position)
		{
			return AddNode(new PointNode(active), position);
		}

		public T AddNode<T>(T node, Int3 position) where T : PointNode
		{
			if (nodes == null || nodeCount == nodes.Length)
			{
				PointNode[] array = new PointNode[(nodes != null) ? Math.Max(nodes.Length + 4, nodes.Length * 2) : 4];
				if (nodes != null)
				{
					nodes.CopyTo(array, 0);
				}
				nodes = array;
			}
			node.SetPosition(position);
			node.GraphIndex = graphIndex;
			node.Walkable = true;
			nodes[nodeCount] = node;
			nodeCount++;
			if (optimizeForSparseGraph)
			{
				AddToLookup(node);
			}
			return node;
		}

		protected static int CountChildren(Transform tr)
		{
			int num = 0;
			foreach (Transform item in tr)
			{
				num++;
				num += CountChildren(item);
			}
			return num;
		}

		protected void AddChildren(ref int c, Transform tr)
		{
			foreach (Transform item in tr)
			{
				nodes[c].position = (Int3)item.position;
				nodes[c].Walkable = true;
				nodes[c].gameObject = item.gameObject;
				c++;
				AddChildren(ref c, item);
			}
		}

		public void RebuildNodeLookup()
		{
			if (!optimizeForSparseGraph || nodes == null)
			{
				lookupTree = new PointKDTree();
			}
			else
			{
				PointKDTree pointKDTree = lookupTree;
				GraphNode[] array = nodes;
				pointKDTree.Rebuild(array, 0, nodeCount);
			}
			RebuildConnectionDistanceLookup();
		}

		public void RebuildConnectionDistanceLookup()
		{
			maximumConnectionLength = 0L;
			if (nearestNodeDistanceMode != NodeDistanceMode.Connection)
			{
				return;
			}
			for (int i = 0; i < nodeCount; i++)
			{
				PointNode pointNode = nodes[i];
				Connection[] connections = pointNode.connections;
				if (connections != null)
				{
					for (int j = 0; j < connections.Length; j++)
					{
						long sqrMagnitudeLong = (pointNode.position - connections[j].node.position).sqrMagnitudeLong;
						RegisterConnectionLength(sqrMagnitudeLong);
					}
				}
			}
		}

		private void AddToLookup(PointNode node)
		{
			lookupTree.Add(node);
		}

		public void RegisterConnectionLength(long sqrLength)
		{
			maximumConnectionLength = Math.Max(maximumConnectionLength, sqrLength);
		}

		protected virtual PointNode[] CreateNodes(int count)
		{
			PointNode[] array = new PointNode[count];
			for (int i = 0; i < nodeCount; i++)
			{
				array[i] = new PointNode(active);
			}
			return array;
		}

		protected override IEnumerable<Progress> ScanInternal()
		{
			yield return new Progress(0f, "Searching for GameObjects");
			if (root == null)
			{
				GameObject[] gos = ((searchTag != null) ? GameObject.FindGameObjectsWithTag(searchTag) : null);
				if (gos == null)
				{
					nodes = new PointNode[0];
					nodeCount = 0;
				}
				else
				{
					yield return new Progress(0.1f, "Creating nodes");
					nodeCount = gos.Length;
					nodes = CreateNodes(nodeCount);
					for (int i = 0; i < gos.Length; i++)
					{
						nodes[i].position = (Int3)gos[i].transform.position;
						nodes[i].Walkable = true;
						nodes[i].gameObject = gos[i].gameObject;
					}
				}
			}
			else if (!recursive)
			{
				nodeCount = root.childCount;
				nodes = CreateNodes(nodeCount);
				int num = 0;
				foreach (Transform item in root)
				{
					nodes[num].position = (Int3)item.position;
					nodes[num].Walkable = true;
					nodes[num].gameObject = item.gameObject;
					num++;
				}
			}
			else
			{
				nodeCount = CountChildren(root);
				nodes = CreateNodes(nodeCount);
				int c = 0;
				AddChildren(ref c, root);
			}
			yield return new Progress(0.15f, "Building node lookup");
			RebuildNodeLookup();
			foreach (Progress item2 in ConnectNodesAsync())
			{
				yield return item2.MapTo(0.15f, 0.95f);
			}
			yield return new Progress(0.95f, "Building connection distances");
			RebuildConnectionDistanceLookup();
		}

		public void ConnectNodes()
		{
			IEnumerator<Progress> enumerator = ConnectNodesAsync().GetEnumerator();
			while (enumerator.MoveNext())
			{
			}
			RebuildConnectionDistanceLookup();
		}

		private IEnumerable<Progress> ConnectNodesAsync()
		{
			if (!(maxDistance >= 0f))
			{
				yield break;
			}
			List<Connection> connections = new List<Connection>();
			List<GraphNode> candidateConnections = new List<GraphNode>();
			long maxSquaredRange;
			if (maxDistance == 0f && (limits.x == 0f || limits.y == 0f || limits.z == 0f))
			{
				maxSquaredRange = long.MaxValue;
			}
			else
			{
				maxSquaredRange = (long)(Mathf.Max(limits.x, Mathf.Max(limits.y, Mathf.Max(limits.z, maxDistance))) * 1000f) + 1;
				maxSquaredRange *= maxSquaredRange;
			}
			for (int i = 0; i < nodeCount; i++)
			{
				if (i % 512 == 0)
				{
					yield return new Progress((float)i / (float)nodeCount, "Connecting nodes");
				}
				connections.Clear();
				PointNode pointNode = nodes[i];
				if (optimizeForSparseGraph)
				{
					candidateConnections.Clear();
					lookupTree.GetInRange(pointNode.position, maxSquaredRange, candidateConnections);
					for (int j = 0; j < candidateConnections.Count; j++)
					{
						PointNode pointNode2 = candidateConnections[j] as PointNode;
						if (pointNode2 != pointNode && IsValidConnection(pointNode, pointNode2, out var dist))
						{
							connections.Add(new Connection(pointNode2, (uint)Mathf.RoundToInt(dist * 1000f)));
						}
					}
				}
				else
				{
					for (int k = 0; k < nodeCount; k++)
					{
						if (i != k)
						{
							PointNode pointNode3 = nodes[k];
							if (IsValidConnection(pointNode, pointNode3, out var dist2))
							{
								connections.Add(new Connection(pointNode3, (uint)Mathf.RoundToInt(dist2 * 1000f)));
							}
						}
					}
				}
				pointNode.connections = connections.ToArray();
				pointNode.SetConnectivityDirty();
			}
		}

		public virtual bool IsValidConnection(GraphNode a, GraphNode b, out float dist)
		{
			dist = 0f;
			if (!a.Walkable || !b.Walkable)
			{
				return false;
			}
			Vector3 vector = (Vector3)(b.position - a.position);
			if ((!Mathf.Approximately(limits.x, 0f) && Mathf.Abs(vector.x) > limits.x) || (!Mathf.Approximately(limits.y, 0f) && Mathf.Abs(vector.y) > limits.y) || (!Mathf.Approximately(limits.z, 0f) && Mathf.Abs(vector.z) > limits.z))
			{
				return false;
			}
			dist = vector.magnitude;
			if (maxDistance == 0f || dist < maxDistance)
			{
				if (raycast)
				{
					Ray ray = new Ray((Vector3)a.position, vector);
					Ray ray2 = new Ray((Vector3)b.position, -vector);
					if (use2DPhysics)
					{
						if (thickRaycast)
						{
							if (!Physics2D.CircleCast(ray.origin, thickRaycastRadius, ray.direction, dist, mask))
							{
								return !Physics2D.CircleCast(ray2.origin, thickRaycastRadius, ray2.direction, dist, mask);
							}
							return false;
						}
						if (!Physics2D.Linecast((Vector3)a.position, (Vector3)b.position, mask))
						{
							return !Physics2D.Linecast((Vector3)b.position, (Vector3)a.position, mask);
						}
						return false;
					}
					if (thickRaycast)
					{
						if (!Physics.SphereCast(ray, thickRaycastRadius, dist, mask))
						{
							return !Physics.SphereCast(ray2, thickRaycastRadius, dist, mask);
						}
						return false;
					}
					if (!Physics.Linecast((Vector3)a.position, (Vector3)b.position, mask))
					{
						return !Physics.Linecast((Vector3)b.position, (Vector3)a.position, mask);
					}
					return false;
				}
				return true;
			}
			return false;
		}

		GraphUpdateThreading IUpdatableGraph.CanUpdateAsync(GraphUpdateObject o)
		{
			return GraphUpdateThreading.UnityThread;
		}

		void IUpdatableGraph.UpdateAreaInit(GraphUpdateObject o)
		{
		}

		void IUpdatableGraph.UpdateAreaPost(GraphUpdateObject o)
		{
		}

		void IUpdatableGraph.UpdateArea(GraphUpdateObject guo)
		{
			if (nodes == null)
			{
				return;
			}
			for (int i = 0; i < nodeCount; i++)
			{
				PointNode pointNode = nodes[i];
				if (guo.bounds.Contains((Vector3)pointNode.position))
				{
					guo.WillUpdateNode(pointNode);
					guo.Apply(pointNode);
				}
			}
			if (!guo.updatePhysics)
			{
				return;
			}
			Bounds bounds = guo.bounds;
			if (thickRaycast)
			{
				bounds.Expand(thickRaycastRadius * 2f);
			}
			List<Connection> list = ListPool<Connection>.Claim();
			for (int j = 0; j < nodeCount; j++)
			{
				PointNode pointNode2 = nodes[j];
				Vector3 a = (Vector3)pointNode2.position;
				List<Connection> list2 = null;
				for (int k = 0; k < nodeCount; k++)
				{
					if (k == j)
					{
						continue;
					}
					Vector3 b = (Vector3)nodes[k].position;
					if (!VectorMath.SegmentIntersectsBounds(bounds, a, b))
					{
						continue;
					}
					PointNode pointNode3 = nodes[k];
					bool flag = pointNode2.ContainsConnection(pointNode3);
					float dist;
					bool flag2 = IsValidConnection(pointNode2, pointNode3, out dist);
					if (list2 == null && flag != flag2)
					{
						list.Clear();
						list2 = list;
						list2.AddRange(pointNode2.connections);
					}
					if (!flag && flag2)
					{
						uint cost = (uint)Mathf.RoundToInt(dist * 1000f);
						list2.Add(new Connection(pointNode3, cost));
						RegisterConnectionLength((pointNode3.position - pointNode2.position).sqrMagnitudeLong);
					}
					else
					{
						if (!flag || flag2)
						{
							continue;
						}
						for (int l = 0; l < list2.Count; l++)
						{
							if (list2[l].node == pointNode3)
							{
								list2.RemoveAt(l);
								break;
							}
						}
					}
				}
				if (list2 != null)
				{
					pointNode2.connections = list2.ToArray();
					pointNode2.SetConnectivityDirty();
				}
			}
			ListPool<Connection>.Release(ref list);
		}

		protected override void PostDeserialization(GraphSerializationContext ctx)
		{
			RebuildNodeLookup();
		}

		public override void RelocateNodes(Matrix4x4 deltaMatrix)
		{
			base.RelocateNodes(deltaMatrix);
			RebuildNodeLookup();
		}

		protected override void DeserializeSettingsCompatibility(GraphSerializationContext ctx)
		{
			base.DeserializeSettingsCompatibility(ctx);
			root = ctx.DeserializeUnityObject() as Transform;
			searchTag = ctx.reader.ReadString();
			maxDistance = ctx.reader.ReadSingle();
			limits = ctx.DeserializeVector3();
			raycast = ctx.reader.ReadBoolean();
			use2DPhysics = ctx.reader.ReadBoolean();
			thickRaycast = ctx.reader.ReadBoolean();
			thickRaycastRadius = ctx.reader.ReadSingle();
			recursive = ctx.reader.ReadBoolean();
			ctx.reader.ReadBoolean();
			mask = ctx.reader.ReadInt32();
			optimizeForSparseGraph = ctx.reader.ReadBoolean();
			ctx.reader.ReadBoolean();
		}

		protected override void SerializeExtraInfo(GraphSerializationContext ctx)
		{
			if (nodes == null)
			{
				ctx.writer.Write(-1);
			}
			ctx.writer.Write(nodeCount);
			for (int i = 0; i < nodeCount; i++)
			{
				if (nodes[i] == null)
				{
					ctx.writer.Write(-1);
					continue;
				}
				ctx.writer.Write(0);
				nodes[i].SerializeNode(ctx);
			}
		}

		protected override void DeserializeExtraInfo(GraphSerializationContext ctx)
		{
			int num = ctx.reader.ReadInt32();
			if (num == -1)
			{
				nodes = null;
				return;
			}
			nodes = new PointNode[num];
			nodeCount = num;
			for (int i = 0; i < nodes.Length; i++)
			{
				if (ctx.reader.ReadInt32() != -1)
				{
					nodes[i] = new PointNode(active);
					nodes[i].DeserializeNode(ctx);
				}
			}
		}
	}
	[JsonOptIn]
	[Preserve]
	public class RecastGraph : NavmeshBase, IUpdatableGraph
	{
		public enum RelevantGraphSurfaceMode
		{
			DoNotRequire,
			OnlyForCompletelyInsideTile,
			RequireForAll
		}

		[JsonMember]
		public float characterRadius = 1.5f;

		[JsonMember]
		public float contourMaxError = 2f;

		[JsonMember]
		public float cellSize = 0.5f;

		[JsonMember]
		public float walkableHeight = 2f;

		[JsonMember]
		public float walkableClimb = 0.5f;

		[JsonMember]
		public float maxSlope = 30f;

		[JsonMember]
		public float maxEdgeLength = 20f;

		[JsonMember]
		public float minRegionSize = 3f;

		[JsonMember]
		public int editorTileSize = 128;

		[JsonMember]
		public int tileSizeX = 128;

		[JsonMember]
		public int tileSizeZ = 128;

		[JsonMember]
		public bool useTiles = true;

		public bool scanEmptyGraph;

		[JsonMember]
		public RelevantGraphSurfaceMode relevantGraphSurfaceMode;

		[JsonMember]
		public bool rasterizeColliders;

		[JsonMember]
		public bool rasterizeMeshes = true;

		[JsonMember]
		public bool rasterizeTerrain = true;

		[JsonMember]
		public bool rasterizeTrees = true;

		[JsonMember]
		public float colliderRasterizeDetail = 10f;

		[JsonMember]
		public LayerMask mask = -1;

		[JsonMember]
		public List<string> tagMask = new List<string>();

		[JsonMember]
		public int terrainSampleSize = 3;

		[JsonMember]
		public Vector3 rotation;

		[JsonMember]
		public Vector3 forcedBoundsCenter;

		private Voxelize globalVox;

		public const int BorderVertexMask = 1;

		public const int BorderVertexOffset = 31;

		private List<NavmeshTile> stagingTiles = new List<NavmeshTile>();

		protected override bool RecalculateNormals => true;

		public override float TileWorldSizeX => (float)tileSizeX * cellSize;

		public override float TileWorldSizeZ => (float)tileSizeZ * cellSize;

		protected override float MaxTileConnectionEdgeDistance => walkableClimb;

		[Obsolete("Obsolete since this is not accurate when the graph is rotated (rotation was not supported when this property was created)")]
		public Bounds forcedBounds => new Bounds(forcedBoundsCenter, forcedBoundsSize);

		private float CellHeight => Mathf.Max(forcedBoundsSize.y / 64000f, 0.001f);

		private int CharacterRadiusInVoxels => Mathf.CeilToInt(characterRadius / cellSize - 0.1f);

		private int TileBorderSizeInVoxels => CharacterRadiusInVoxels + 3;

		private float TileBorderSizeInWorldUnits => (float)TileBorderSizeInVoxels * cellSize;

		[Obsolete("Use node.ClosestPointOnNode instead")]
		public Vector3 ClosestPointOnNode(TriangleMeshNode node, Vector3 pos)
		{
			return node.ClosestPointOnNode(pos);
		}

		[Obsolete("Use node.ContainsPoint instead")]
		public bool ContainsPoint(TriangleMeshNode node, Vector3 pos)
		{
			return node.ContainsPoint((Int3)pos);
		}

		public void SnapForceBoundsToScene()
		{
			List<RasterizationMesh> list = CollectMeshes(new Bounds(Vector3.zero, new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity)));
			if (list.Count != 0)
			{
				Bounds bounds = list[0].bounds;
				for (int i = 1; i < list.Count; i++)
				{
					bounds.Encapsulate(list[i].bounds);
					list[i].Pool();
				}
				forcedBoundsCenter = bounds.center;
				forcedBoundsSize = bounds.size;
			}
		}

		GraphUpdateThreading IUpdatableGraph.CanUpdateAsync(GraphUpdateObject o)
		{
			if (!o.updatePhysics)
			{
				return GraphUpdateThreading.SeparateThread;
			}
			return (GraphUpdateThreading)7;
		}

		void IUpdatableGraph.UpdateAreaInit(GraphUpdateObject o)
		{
			if (o.updatePhysics)
			{
				RelevantGraphSurface.UpdateAllPositions();
				IntRect touchingTiles = GetTouchingTiles(o.bounds, TileBorderSizeInWorldUnits);
				Bounds tileBounds = GetTileBounds(touchingTiles);
				tileBounds.Expand(new Vector3(1f, 0f, 1f) * TileBorderSizeInWorldUnits * 2f);
				List<RasterizationMesh> inputMeshes = CollectMeshes(tileBounds);
				if (globalVox == null)
				{
					globalVox = new Voxelize(CellHeight, cellSize, walkableClimb, walkableHeight, maxSlope, maxEdgeLength);
				}
				globalVox.inputMeshes = inputMeshes;
			}
		}

		void IUpdatableGraph.UpdateArea(GraphUpdateObject guo)
		{
			IntRect touchingTiles = GetTouchingTiles(guo.bounds, TileBorderSizeInWorldUnits);
			if (!guo.updatePhysics)
			{
				for (int i = touchingTiles.ymin; i <= touchingTiles.ymax; i++)
				{
					for (int j = touchingTiles.xmin; j <= touchingTiles.xmax; j++)
					{
						NavmeshTile graph = tiles[i * tileXCount + j];
						NavMeshGraph.UpdateArea(guo, graph);
					}
				}
				return;
			}
			Voxelize voxelize = globalVox;
			if (voxelize == null)
			{
				throw new InvalidOperationException("No Voxelizer object. UpdateAreaInit should have been called before this function.");
			}
			for (int k = touchingTiles.xmin; k <= touchingTiles.xmax; k++)
			{
				for (int l = touchingTiles.ymin; l <= touchingTiles.ymax; l++)
				{
					stagingTiles.Add(BuildTileMesh(voxelize, k, l));
				}
			}
			uint num = (uint)AstarPath.active.data.GetGraphIndex(this);
			for (int m = 0; m < stagingTiles.Count; m++)
			{
				GraphNode[] nodes = stagingTiles[m].nodes;
				GraphNode[] array = nodes;
				for (int n = 0; n < array.Length; n++)
				{
					array[n].GraphIndex = num;
				}
			}
			for (int num2 = 0; num2 < voxelize.inputMeshes.Count; num2++)
			{
				voxelize.inputMeshes[num2].Pool();
			}
			ListPool<RasterizationMesh>.Release(ref voxelize.inputMeshes);
		}

		void IUpdatableGraph.UpdateAreaPost(GraphUpdateObject guo)
		{
			for (int i = 0; i < stagingTiles.Count; i++)
			{
				NavmeshTile navmeshTile = stagingTiles[i];
				int num = navmeshTile.x + navmeshTile.z * tileXCount;
				NavmeshTile navmeshTile2 = tiles[num];
				for (int j = 0; j < navmeshTile2.nodes.Length; j++)
				{
					navmeshTile2.nodes[j].Destroy();
				}
				tiles[num] = navmeshTile;
			}
			for (int k = 0; k < stagingTiles.Count; k++)
			{
				NavmeshTile tile = stagingTiles[k];
				ConnectTileWithNeighbours(tile);
			}
			NavmeshTile[] obj = stagingTiles.ToArray();
			navmeshUpdateData.OnRecalculatedTiles(obj);
			if (OnRecalculatedTiles != null)
			{
				OnRecalculatedTiles(obj);
			}
			stagingTiles.Clear();
		}

		protected override IEnumerable<Progress> ScanInternal()
		{
			TriangleMeshNode.SetNavmeshHolder(AstarPath.active.data.GetGraphIndex(this), this);
			if (!Application.isPlaying)
			{
				RelevantGraphSurface.FindAllGraphSurfaces();
			}
			RelevantGraphSurface.UpdateAllPositions();
			foreach (Progress item in ScanAllTiles())
			{
				yield return item;
			}
		}

		public override GraphTransform CalculateTransform()
		{
			return new GraphTransform(Matrix4x4.TRS(forcedBoundsCenter, Quaternion.Euler(rotation), Vector3.one) * Matrix4x4.TRS(-forcedBoundsSize * 0.5f, Quaternion.identity, Vector3.one));
		}

		private void InitializeTileInfo()
		{
			int num = (int)(forcedBoundsSize.x / cellSize + 0.5f);
			int num2 = (int)(forcedBoundsSize.z / cellSize + 0.5f);
			if (!useTiles)
			{
				tileSizeX = num;
				tileSizeZ = num2;
			}
			else
			{
				tileSizeX = editorTileSize;
				tileSizeZ = editorTileSize;
			}
			tileXCount = (num + tileSizeX - 1) / tileSizeX;
			tileZCount = (num2 + tileSizeZ - 1) / tileSizeZ;
			if (tileXCount * tileZCount > 524288)
			{
				throw new Exception("Too many tiles (" + tileXCount * tileZCount + ") maximum is " + 524288 + "\nTry disabling ASTAR_RECAST_LARGER_TILES under the 'Optimizations' tab in the A* inspector.");
			}
			tiles = new NavmeshTile[tileXCount * tileZCount];
		}

		private List<RasterizationMesh>[] PutMeshesIntoTileBuckets(List<RasterizationMesh> meshes)
		{
			List<RasterizationMesh>[] array = new List<RasterizationMesh>[tiles.Length];
			Vector3 amount = new Vector3(1f, 0f, 1f) * TileBorderSizeInWorldUnits * 2f;
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = ListPool<RasterizationMesh>.Claim();
			}
			for (int j = 0; j < meshes.Count; j++)
			{
				RasterizationMesh rasterizationMesh = meshes[j];
				Bounds bounds = rasterizationMesh.bounds;
				bounds.Expand(amount);
				IntRect touchingTiles = GetTouchingTiles(bounds);
				for (int k = touchingTiles.ymin; k <= touchingTiles.ymax; k++)
				{
					for (int l = touchingTiles.xmin; l <= touchingTiles.xmax; l++)
					{
						array[l + k * tileXCount].Add(rasterizationMesh);
					}
				}
			}
			return array;
		}

		protected IEnumerable<Progress> ScanAllTiles()
		{
			transform = CalculateTransform();
			InitializeTileInfo();
			if (scanEmptyGraph)
			{
				FillWithEmptyTiles();
				yield break;
			}
			walkableClimb = Mathf.Min(walkableClimb, walkableHeight);
			yield return new Progress(0f, "Finding Meshes");
			Bounds bounds = transform.Transform(new Bounds(forcedBoundsSize * 0.5f, forcedBoundsSize));
			List<RasterizationMesh> meshes = CollectMeshes(bounds);
			List<RasterizationMesh>[] buckets = PutMeshesIntoTileBuckets(meshes);
			Queue<Int2> tileQueue = new Queue<Int2>();
			for (int i = 0; i < tileZCount; i++)
			{
				for (int j = 0; j < tileXCount; j++)
				{
					tileQueue.Enqueue(new Int2(j, i));
				}
			}
			ParallelWorkQueue<Int2> parallelWorkQueue = new ParallelWorkQueue<Int2>(tileQueue);
			Voxelize[] voxelizers = new Voxelize[parallelWorkQueue.threadCount];
			for (int k = 0; k < voxelizers.Length; k++)
			{
				voxelizers[k] = new Voxelize(CellHeight, cellSize, walkableClimb, walkableHeight, maxSlope, maxEdgeLength);
			}
			parallelWorkQueue.action = delegate(Int2 tile, int threadIndex)
			{
				voxelizers[threadIndex].inputMeshes = buckets[tile.x + tile.y * tileXCount];
				tiles[tile.x + tile.y * tileXCount] = BuildTileMesh(voxelizers[threadIndex], tile.x, tile.y, threadIndex);
			};
			int timeoutMillis = (Application.isPlaying ? 1 : 200);
			foreach (int item in parallelWorkQueue.Run(timeoutMillis))
			{
				yield return new Progress(Mathf.Lerp(0.1f, 0.9f, (float)item / (float)tiles.Length), "Calculated Tiles: " + item + "/" + tiles.Length);
			}
			yield return new Progress(0.9f, "Assigning Graph Indices");
			uint graphIndex = (uint)AstarPath.active.data.GetGraphIndex(this);
			GetNodes(delegate(GraphNode node)
			{
				node.GraphIndex = graphIndex;
			});
			for (int coordinateSum = 0; coordinateSum <= 1; coordinateSum++)
			{
				int direction;
				for (direction = 0; direction <= 1; direction++)
				{
					for (int num = 0; num < tiles.Length; num++)
					{
						if ((tiles[num].x + tiles[num].z) % 2 == coordinateSum)
						{
							tileQueue.Enqueue(new Int2(tiles[num].x, tiles[num].z));
						}
					}
					parallelWorkQueue = new ParallelWorkQueue<Int2>(tileQueue);
					parallelWorkQueue.action = delegate(Int2 tile, int threadIndex)
					{
						if (direction == 0 && tile.x < tileXCount - 1)
						{
							ConnectTiles(tiles[tile.x + tile.y * tileXCount], tiles[tile.x + 1 + tile.y * tileXCount]);
						}
						if (direction == 1 && tile.y < tileZCount - 1)
						{
							ConnectTiles(tiles[tile.x + tile.y * tileXCount], tiles[tile.x + (tile.y + 1) * tileXCount]);
						}
					};
					int numTilesInQueue = tileQueue.Count;
					foreach (int item2 in parallelWorkQueue.Run(timeoutMillis))
					{
						yield return new Progress(0.95f, "Connected Tiles " + (numTilesInQueue - item2) + "/" + numTilesInQueue + " (Phase " + (direction + 1 + 2 * coordinateSum) + " of 4)");
					}
				}
			}
			for (int num2 = 0; num2 < meshes.Count; num2++)
			{
				meshes[num2].Pool();
			}
			ListPool<RasterizationMesh>.Release(ref meshes);
			navmeshUpdateData.OnRecalculatedTiles(tiles);
			if (OnRecalculatedTiles != null)
			{
				OnRecalculatedTiles(tiles.Clone() as NavmeshTile[]);
			}
		}

		private List<RasterizationMesh> CollectMeshes(Bounds bounds)
		{
			List<RasterizationMesh> list = ListPool<RasterizationMesh>.Claim();
			RecastMeshGatherer recastMeshGatherer = new RecastMeshGatherer(bounds, terrainSampleSize, mask, tagMask, colliderRasterizeDetail);
			if (rasterizeMeshes)
			{
				recastMeshGatherer.CollectSceneMeshes(list);
			}
			recastMeshGatherer.CollectRecastMeshObjs(list);
			if (rasterizeTerrain)
			{
				float desiredChunkSize = cellSize * (float)Math.Max(tileSizeX, tileSizeZ);
				recastMeshGatherer.CollectTerrainMeshes(rasterizeTrees, desiredChunkSize, list);
			}
			if (rasterizeColliders)
			{
				recastMeshGatherer.CollectColliderMeshes(list);
			}
			if (list.Count == 0)
			{
				UnityEngine.Debug.LogWarning("No MeshFilters were found contained in the layers specified by the 'mask' variables");
			}
			return list;
		}

		private Bounds CalculateTileBoundsWithBorder(int x, int z)
		{
			Bounds result = default(Bounds);
			result.SetMinMax(new Vector3((float)x * TileWorldSizeX, 0f, (float)z * TileWorldSizeZ), new Vector3((float)(x + 1) * TileWorldSizeX, forcedBoundsSize.y, (float)(z + 1) * TileWorldSizeZ));
			result.Expand(new Vector3(1f, 0f, 1f) * TileBorderSizeInWorldUnits * 2f);
			return result;
		}

		protected NavmeshTile BuildTileMesh(Voxelize vox, int x, int z, int threadIndex = 0)
		{
			vox.borderSize = TileBorderSizeInVoxels;
			vox.forcedBounds = CalculateTileBoundsWithBorder(x, z);
			vox.width = tileSizeX + vox.borderSize * 2;
			vox.depth = tileSizeZ + vox.borderSize * 2;
			if (!useTiles && relevantGraphSurfaceMode == RelevantGraphSurfaceMode.OnlyForCompletelyInsideTile)
			{
				vox.relevantGraphSurfaceMode = RelevantGraphSurfaceMode.RequireForAll;
			}
			else
			{
				vox.relevantGraphSurfaceMode = relevantGraphSurfaceMode;
			}
			vox.minRegionSize = Mathf.RoundToInt(minRegionSize / (cellSize * cellSize));
			vox.Init();
			vox.VoxelizeInput(transform, CalculateTileBoundsWithBorder(x, z));
			vox.FilterLedges(vox.voxelWalkableHeight, vox.voxelWalkableClimb, vox.cellSize, vox.cellHeight);
			vox.FilterLowHeightSpans(vox.voxelWalkableHeight, vox.cellSize, vox.cellHeight);
			vox.BuildCompactField();
			vox.BuildVoxelConnections();
			vox.ErodeWalkableArea(CharacterRadiusInVoxels);
			vox.BuildDistanceField();
			vox.BuildRegions();
			VoxelContourSet cset = new VoxelContourSet();
			vox.BuildContours(contourMaxError, 1, cset, 5);
			vox.BuildPolyMesh(cset, 3, out var mesh);
			for (int i = 0; i < mesh.verts.Length; i++)
			{
				mesh.verts[i] *= 1000;
			}
			vox.transformVoxel2Graph.Transform(mesh.verts);
			return CreateTile(vox, mesh, x, z, threadIndex);
		}

		private NavmeshTile CreateTile(Voxelize vox, VoxelMesh mesh, int x, int z, int threadIndex)
		{
			if (mesh.tris == null)
			{
				throw new ArgumentNullException("mesh.tris");
			}
			if (mesh.verts == null)
			{
				throw new ArgumentNullException("mesh.verts");
			}
			if (mesh.tris.Length % 3 != 0)
			{
				throw new ArgumentException("Indices array's length must be a multiple of 3 (mesh.tris)");
			}
			if (mesh.verts.Length >= 4095)
			{
				if (tileXCount * tileZCount == 1)
				{
					throw new ArgumentException("Too many vertices per tile (more than " + 4095 + ").\n<b>Try enabling tiling in the recast graph settings.</b>\n");
				}
				throw new ArgumentException("Too many vertices per tile (more than " + 4095 + ").\n<b>Try reducing tile size or enabling ASTAR_RECAST_LARGER_TILES under the 'Optimizations' tab in the A* Inspector</b>");
			}
			NavmeshTile navmeshTile = new NavmeshTile
			{
				x = x,
				z = z,
				w = 1,
				d = 1,
				tris = mesh.tris,
				bbTree = new BBTree(),
				graph = this
			};
			navmeshTile.vertsInGraphSpace = Utility.RemoveDuplicateVertices(mesh.verts, navmeshTile.tris);
			navmeshTile.verts = (Int3[])navmeshTile.vertsInGraphSpace.Clone();
			transform.Transform(navmeshTile.verts);
			uint num = (uint)(active.data.graphs.Length + threadIndex);
			if (num > 255)
			{
				throw new Exception("Graph limit reached. Multithreaded recast calculations cannot be done because a few scratch graph indices are required.");
			}
			TriangleMeshNode.SetNavmeshHolder((int)num, navmeshTile);
			navmeshTile.nodes = new TriangleMeshNode[navmeshTile.tris.Length / 3];
			lock (active)
			{
				CreateNodes(navmeshTile.nodes, navmeshTile.tris, x + z * tileXCount, num);
			}
			navmeshTile.bbTree.RebuildFrom(navmeshTile.nodes);
			NavmeshBase.CreateNodeConnections(navmeshTile.nodes);
			TriangleMeshNode.SetNavmeshHolder((int)num, null);
			return navmeshTile;
		}

		protected override void DeserializeSettingsCompatibility(GraphSerializationContext ctx)
		{
			base.DeserializeSettingsCompatibility(ctx);
			characterRadius = ctx.reader.ReadSingle();
			contourMaxError = ctx.reader.ReadSingle();
			cellSize = ctx.reader.ReadSingle();
			ctx.reader.ReadSingle();
			walkableHeight = ctx.reader.ReadSingle();
			maxSlope = ctx.reader.ReadSingle();
			maxEdgeLength = ctx.reader.ReadSingle();
			editorTileSize = ctx.reader.ReadInt32();
			tileSizeX = ctx.reader.ReadInt32();
			nearestSearchOnlyXZ = ctx.reader.ReadBoolean();
			useTiles = ctx.reader.ReadBoolean();
			relevantGraphSurfaceMode = (RelevantGraphSurfaceMode)ctx.reader.ReadInt32();
			rasterizeColliders = ctx.reader.ReadBoolean();
			rasterizeMeshes = ctx.reader.ReadBoolean();
			rasterizeTerrain = ctx.reader.ReadBoolean();
			rasterizeTrees = ctx.reader.ReadBoolean();
			colliderRasterizeDetail = ctx.reader.ReadSingle();
			forcedBoundsCenter = ctx.DeserializeVector3();
			forcedBoundsSize = ctx.DeserializeVector3();
			mask = ctx.reader.ReadInt32();
			int num = ctx.reader.ReadInt32();
			tagMask = new List<string>(num);
			for (int i = 0; i < num; i++)
			{
				tagMask.Add(ctx.reader.ReadString());
			}
			showMeshOutline = ctx.reader.ReadBoolean();
			showNodeConnections = ctx.reader.ReadBoolean();
			terrainSampleSize = ctx.reader.ReadInt32();
			walkableClimb = ctx.DeserializeFloat(walkableClimb);
			minRegionSize = ctx.DeserializeFloat(minRegionSize);
			tileSizeZ = ctx.DeserializeInt(tileSizeX);
			showMeshSurface = ctx.reader.ReadBoolean();
		}
	}
	public class BBTree : IAstarPooledObject
	{
		private struct BBTreeBox
		{
			public IntRect rect;

			public int nodeOffset;

			public int left;

			public int right;

			public bool IsLeaf => nodeOffset >= 0;

			public BBTreeBox(IntRect rect)
			{
				nodeOffset = -1;
				this.rect = rect;
				left = (right = -1);
			}

			public BBTreeBox(int nodeOffset, IntRect rect)
			{
				this.nodeOffset = nodeOffset;
				this.rect = rect;
				left = (right = -1);
			}

			public bool Contains(Vector3 point)
			{
				Int3 @int = (Int3)point;
				return rect.Contains(@int.x, @int.z);
			}
		}

		private BBTreeBox[] tree;

		private TriangleMeshNode[] nodeLookup;

		private int count;

		private int leafNodes;

		private const int MaximumLeafSize = 4;

		public Rect Size
		{
			get
			{
				if (count == 0)
				{
					return new Rect(0f, 0f, 0f, 0f);
				}
				IntRect rect = tree[0].rect;
				return Rect.MinMaxRect((float)rect.xmin * 0.001f, (float)rect.ymin * 0.001f, (float)rect.xmax * 0.001f, (float)rect.ymax * 0.001f);
			}
		}

		public void Clear()
		{
			count = 0;
			leafNodes = 0;
			if (tree != null)
			{
				ArrayPool<BBTreeBox>.Release(ref tree);
			}
			if (nodeLookup != null)
			{
				for (int i = 0; i < nodeLookup.Length; i++)
				{
					nodeLookup[i] = null;
				}
				ArrayPool<TriangleMeshNode>.Release(ref nodeLookup);
			}
			tree = ArrayPool<BBTreeBox>.Claim(0);
			nodeLookup = ArrayPool<TriangleMeshNode>.Claim(0);
		}

		void IAstarPooledObject.OnEnterPool()
		{
			Clear();
		}

		private void EnsureCapacity(int c)
		{
			if (c > tree.Length)
			{
				BBTreeBox[] array = ArrayPool<BBTreeBox>.Claim(c);
				tree.CopyTo(array, 0);
				ArrayPool<BBTreeBox>.Release(ref tree);
				tree = array;
			}
		}

		private void EnsureNodeCapacity(int c)
		{
			if (c > nodeLookup.Length)
			{
				TriangleMeshNode[] array = ArrayPool<TriangleMeshNode>.Claim(c);
				nodeLookup.CopyTo(array, 0);
				ArrayPool<TriangleMeshNode>.Release(ref nodeLookup);
				nodeLookup = array;
			}
		}

		private int GetBox(IntRect rect)
		{
			if (count >= tree.Length)
			{
				EnsureCapacity(count + 1);
			}
			tree[count] = new BBTreeBox(rect);
			count++;
			return count - 1;
		}

		public void RebuildFrom(TriangleMeshNode[] nodes)
		{
			Clear();
			if (nodes.Length != 0)
			{
				EnsureCapacity(Mathf.CeilToInt((float)nodes.Length * 2.1f));
				EnsureNodeCapacity(Mathf.CeilToInt((float)nodes.Length * 1.1f));
				int[] array = ArrayPool<int>.Claim(nodes.Length);
				for (int i = 0; i < nodes.Length; i++)
				{
					array[i] = i;
				}
				IntRect[] array2 = ArrayPool<IntRect>.Claim(nodes.Length);
				for (int j = 0; j < nodes.Length; j++)
				{
					nodes[j].GetVertices(out var v, out var v2, out var v3);
					IntRect intRect = new IntRect(v.x, v.z, v.x, v.z).ExpandToContain(v2.x, v2.z).ExpandToContain(v3.x, v3.z);
					array2[j] = intRect;
				}
				RebuildFromInternal(nodes, array, array2, 0, nodes.Length, odd: false);
				ArrayPool<int>.Release(ref array);
				ArrayPool<IntRect>.Release(ref array2);
			}
		}

		private static int SplitByX(TriangleMeshNode[] nodes, int[] permutation, int from, int to, int divider)
		{
			int num = to;
			for (int i = from; i < num; i++)
			{
				if (nodes[permutation[i]].position.x > divider)
				{
					num--;
					int num2 = permutation[num];
					permutation[num] = permutation[i];
					permutation[i] = num2;
					i--;
				}
			}
			return num;
		}

		private static int SplitByZ(TriangleMeshNode[] nodes, int[] permutation, int from, int to, int divider)
		{
			int num = to;
			for (int i = from; i < num; i++)
			{
				if (nodes[permutation[i]].position.z > divider)
				{
					num--;
					int num2 = permutation[num];
					permutation[num] = permutation[i];
					permutation[i] = num2;
					i--;
				}
			}
			return num;
		}

		private int RebuildFromInternal(TriangleMeshNode[] nodes, int[] permutation, IntRect[] nodeBounds, int from, int to, bool odd)
		{
			IntRect rect = NodeBounds(permutation, nodeBounds, from, to);
			int box = GetBox(rect);
			if (to - from <= 4)
			{
				int num = (tree[box].nodeOffset = leafNodes * 4);
				EnsureNodeCapacity(num + 4);
				leafNodes++;
				for (int i = 0; i < 4; i++)
				{
					nodeLookup[num + i] = ((i < to - from) ? nodes[permutation[from + i]] : null);
				}
				return box;
			}
			int num2;
			if (odd)
			{
				int divider = (rect.xmin + rect.xmax) / 2;
				num2 = SplitByX(nodes, permutation, from, to, divider);
			}
			else
			{
				int divider2 = (rect.ymin + rect.ymax) / 2;
				num2 = SplitByZ(nodes, permutation, from, to, divider2);
			}
			if (num2 == from || num2 == to)
			{
				if (!odd)
				{
					int divider3 = (rect.xmin + rect.xmax) / 2;
					num2 = SplitByX(nodes, permutation, from, to, divider3);
				}
				else
				{
					int divider4 = (rect.ymin + rect.ymax) / 2;
					num2 = SplitByZ(nodes, permutation, from, to, divider4);
				}
				if (num2 == from || num2 == to)
				{
					num2 = (from + to) / 2;
				}
			}
			tree[box].left = RebuildFromInternal(nodes, permutation, nodeBounds, from, num2, !odd);
			tree[box].right = RebuildFromInternal(nodes, permutation, nodeBounds, num2, to, !odd);
			return box;
		}

		private static IntRect NodeBounds(int[] permutation, IntRect[] nodeBounds, int from, int to)
		{
			IntRect result = nodeBounds[permutation[from]];
			for (int i = from + 1; i < to; i++)
			{
				IntRect intRect = nodeBounds[permutation[i]];
				result.xmin = Math.Min(result.xmin, intRect.xmin);
				result.ymin = Math.Min(result.ymin, intRect.ymin);
				result.xmax = Math.Max(result.xmax, intRect.xmax);
				result.ymax = Math.Max(result.ymax, intRect.ymax);
			}
			return result;
		}

		[Conditional("ASTARDEBUG")]
		private static void DrawDebugRect(IntRect rect)
		{
			UnityEngine.Debug.DrawLine(new Vector3(rect.xmin, 0f, rect.ymin), new Vector3(rect.xmax, 0f, rect.ymin), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(rect.xmin, 0f, rect.ymax), new Vector3(rect.xmax, 0f, rect.ymax), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(rect.xmin, 0f, rect.ymin), new Vector3(rect.xmin, 0f, rect.ymax), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(rect.xmax, 0f, rect.ymin), new Vector3(rect.xmax, 0f, rect.ymax), Color.white);
		}

		[Conditional("ASTARDEBUG")]
		private static void DrawDebugNode(TriangleMeshNode node, float yoffset, Color color)
		{
			UnityEngine.Debug.DrawLine((Vector3)node.GetVertex(1) + Vector3.up * yoffset, (Vector3)node.GetVertex(2) + Vector3.up * yoffset, color);
			UnityEngine.Debug.DrawLine((Vector3)node.GetVertex(0) + Vector3.up * yoffset, (Vector3)node.GetVertex(1) + Vector3.up * yoffset, color);
			UnityEngine.Debug.DrawLine((Vector3)node.GetVertex(2) + Vector3.up * yoffset, (Vector3)node.GetVertex(0) + Vector3.up * yoffset, color);
		}

		public NNInfoInternal QueryClosest(Vector3 p, NNConstraint constraint, out float distance)
		{
			distance = float.PositiveInfinity;
			return QueryClosest(p, constraint, ref distance, new NNInfoInternal(null));
		}

		public NNInfoInternal QueryClosestXZ(Vector3 p, NNConstraint constraint, ref float distance, NNInfoInternal previous)
		{
			float closestSqrDist = distance * distance;
			float num = closestSqrDist;
			if (count > 0 && SquaredRectPointDistance(tree[0].rect, p) < closestSqrDist)
			{
				SearchBoxClosestXZ(0, p, ref closestSqrDist, constraint, ref previous);
				if (closestSqrDist < num)
				{
					distance = Mathf.Sqrt(closestSqrDist);
				}
			}
			return previous;
		}

		private void SearchBoxClosestXZ(int boxi, Vector3 p, ref float closestSqrDist, NNConstraint constraint, ref NNInfoInternal nnInfo)
		{
			BBTreeBox bBTreeBox = tree[boxi];
			if (bBTreeBox.IsLeaf)
			{
				TriangleMeshNode[] array = nodeLookup;
				for (int i = 0; i < 4 && array[bBTreeBox.nodeOffset + i] != null; i++)
				{
					TriangleMeshNode triangleMeshNode = array[bBTreeBox.nodeOffset + i];
					if (constraint == null || constraint.Suitable(triangleMeshNode))
					{
						Vector3 constClampedPosition = triangleMeshNode.ClosestPointOnNodeXZ(p);
						float num = (constClampedPosition.x - p.x) * (constClampedPosition.x - p.x) + (constClampedPosition.z - p.z) * (constClampedPosition.z - p.z);
						if (nnInfo.constrainedNode == null || num < closestSqrDist - 1E-06f || (num <= closestSqrDist + 1E-06f && Mathf.Abs(constClampedPosition.y - p.y) < Mathf.Abs(nnInfo.constClampedPosition.y - p.y)))
						{
							nnInfo.constrainedNode = triangleMeshNode;
							nnInfo.constClampedPosition = constClampedPosition;
							closestSqrDist = num;
						}
					}
				}
			}
			else
			{
				int first = bBTreeBox.left;
				int second = bBTreeBox.right;
				GetOrderedChildren(ref first, ref second, out var firstDist, out var secondDist, p);
				if (firstDist <= closestSqrDist)
				{
					SearchBoxClosestXZ(first, p, ref closestSqrDist, constraint, ref nnInfo);
				}
				if (secondDist <= closestSqrDist)
				{
					SearchBoxClosestXZ(second, p, ref closestSqrDist, constraint, ref nnInfo);
				}
			}
		}

		public NNInfoInternal QueryClosest(Vector3 p, NNConstraint constraint, ref float distance, NNInfoInternal previous)
		{
			float closestSqrDist = distance * distance;
			float num = closestSqrDist;
			if (count > 0 && SquaredRectPointDistance(tree[0].rect, p) < closestSqrDist)
			{
				SearchBoxClosest(0, p, ref closestSqrDist, constraint, ref previous);
				if (closestSqrDist < num)
				{
					distance = Mathf.Sqrt(closestSqrDist);
				}
			}
			return previous;
		}

		private void SearchBoxClosest(int boxi, Vector3 p, ref float closestSqrDist, NNConstraint constraint, ref NNInfoInternal nnInfo)
		{
			BBTreeBox bBTreeBox = tree[boxi];
			if (bBTreeBox.IsLeaf)
			{
				TriangleMeshNode[] array = nodeLookup;
				for (int i = 0; i < 4 && array[bBTreeBox.nodeOffset + i] != null; i++)
				{
					TriangleMeshNode triangleMeshNode = array[bBTreeBox.nodeOffset + i];
					Vector3 vector = triangleMeshNode.ClosestPointOnNode(p);
					float sqrMagnitude = (vector - p).sqrMagnitude;
					if (sqrMagnitude < closestSqrDist && (constraint == null || constraint.Suitable(triangleMeshNode)))
					{
						nnInfo.constrainedNode = triangleMeshNode;
						nnInfo.constClampedPosition = vector;
						closestSqrDist = sqrMagnitude;
					}
				}
			}
			else
			{
				int first = bBTreeBox.left;
				int second = bBTreeBox.right;
				GetOrderedChildren(ref first, ref second, out var firstDist, out var secondDist, p);
				if (firstDist < closestSqrDist)
				{
					SearchBoxClosest(first, p, ref closestSqrDist, constraint, ref nnInfo);
				}
				if (secondDist < closestSqrDist)
				{
					SearchBoxClosest(second, p, ref closestSqrDist, constraint, ref nnInfo);
				}
			}
		}

		private void GetOrderedChildren(ref int first, ref int second, out float firstDist, out float secondDist, Vector3 p)
		{
			firstDist = SquaredRectPointDistance(tree[first].rect, p);
			secondDist = SquaredRectPointDistance(tree[second].rect, p);
			if (secondDist < firstDist)
			{
				int num = first;
				first = second;
				second = num;
				float num2 = firstDist;
				firstDist = secondDist;
				secondDist = num2;
			}
		}

		public TriangleMeshNode QueryInside(Vector3 p, NNConstraint constraint)
		{
			if (count == 0 || !tree[0].Contains(p))
			{
				return null;
			}
			return SearchBoxInside(0, p, constraint);
		}

		private TriangleMeshNode SearchBoxInside(int boxi, Vector3 p, NNConstraint constraint)
		{
			BBTreeBox bBTreeBox = tree[boxi];
			if (bBTreeBox.IsLeaf)
			{
				TriangleMeshNode[] array = nodeLookup;
				for (int i = 0; i < 4 && array[bBTreeBox.nodeOffset + i] != null; i++)
				{
					TriangleMeshNode triangleMeshNode = array[bBTreeBox.nodeOffset + i];
					if (triangleMeshNode.ContainsPoint((Int3)p) && (constraint == null || constraint.Suitable(triangleMeshNode)))
					{
						return triangleMeshNode;
					}
				}
			}
			else
			{
				if (tree[bBTreeBox.left].Contains(p))
				{
					TriangleMeshNode triangleMeshNode2 = SearchBoxInside(bBTreeBox.left, p, constraint);
					if (triangleMeshNode2 != null)
					{
						return triangleMeshNode2;
					}
				}
				if (tree[bBTreeBox.right].Contains(p))
				{
					TriangleMeshNode triangleMeshNode3 = SearchBoxInside(bBTreeBox.right, p, constraint);
					if (triangleMeshNode3 != null)
					{
						return triangleMeshNode3;
					}
				}
			}
			return null;
		}

		public void OnDrawGizmos()
		{
			Gizmos.color = new Color(1f, 1f, 1f, 0.5f);
			if (count != 0)
			{
				OnDrawGizmos(0, 0);
			}
		}

		private void OnDrawGizmos(int boxi, int depth)
		{
			BBTreeBox bBTreeBox = tree[boxi];
			Vector3 vector = (Vector3)new Int3(bBTreeBox.rect.xmin, 0, bBTreeBox.rect.ymin);
			Vector3 vector2 = (Vector3)new Int3(bBTreeBox.rect.xmax, 0, bBTreeBox.rect.ymax);
			Vector3 vector3 = (vector + vector2) * 0.5f;
			Vector3 vector4 = (vector2 - vector3) * 2f;
			vector4 = new Vector3(vector4.x, 1f, vector4.z);
			vector3.y += depth * 2;
			Gizmos.color = AstarMath.IntToColor(depth, 1f);
			Gizmos.DrawCube(vector3, vector4);
			if (!bBTreeBox.IsLeaf)
			{
				OnDrawGizmos(bBTreeBox.left, depth + 1);
				OnDrawGizmos(bBTreeBox.right, depth + 1);
			}
		}

		private static bool NodeIntersectsCircle(TriangleMeshNode node, Vector3 p, float radius)
		{
			if (float.IsPositiveInfinity(radius))
			{
				return true;
			}
			return (p - node.ClosestPointOnNode(p)).sqrMagnitude < radius * radius;
		}

		private static bool RectIntersectsCircle(IntRect r, Vector3 p, float radius)
		{
			if (float.IsPositiveInfinity(radius))
			{
				return true;
			}
			Vector3 vector = p;
			p.x = Math.Max(p.x, (float)r.xmin * 0.001f);
			p.x = Math.Min(p.x, (float)r.xmax * 0.001f);
			p.z = Math.Max(p.z, (float)r.ymin * 0.001f);
			p.z = Math.Min(p.z, (float)r.ymax * 0.001f);
			return (p.x - vector.x) * (p.x - vector.x) + (p.z - vector.z) * (p.z - vector.z) < radius * radius;
		}

		private static float SquaredRectPointDistance(IntRect r, Vector3 p)
		{
			Vector3 vector = p;
			p.x = Math.Max(p.x, (float)r.xmin * 0.001f);
			p.x = Math.Min(p.x, (float)r.xmax * 0.001f);
			p.z = Math.Max(p.z, (float)r.ymin * 0.001f);
			p.z = Math.Min(p.z, (float)r.ymax * 0.001f);
			return (p.x - vector.x) * (p.x - vector.x) + (p.z - vector.z) * (p.z - vector.z);
		}
	}
	public enum HeuristicOptimizationMode
	{
		None,
		Random,
		RandomSpreadOut,
		Custom
	}
	[Serializable]
	public class EuclideanEmbedding
	{
		public HeuristicOptimizationMode mode;

		public int seed;

		public Transform pivotPointRoot;

		public int spreadOutCount = 1;

		[NonSerialized]
		public bool dirty;

		private uint[] costs = new uint[8];

		private int maxNodeIndex;

		private int pivotCount;

		private GraphNode[] pivots;

		private const uint ra = 12820163u;

		private const uint rc = 1140671485u;

		private uint rval;

		private object lockObj = new object();

		private uint GetRandom()
		{
			rval = 12820163 * rval + 1140671485;
			return rval;
		}

		private void EnsureCapacity(int index)
		{
			if (index <= maxNodeIndex)
			{
				return;
			}
			lock (lockObj)
			{
				if (index <= maxNodeIndex)
				{
					return;
				}
				if (index >= costs.Length)
				{
					uint[] array = new uint[Math.Max(index * 2, pivots.Length * 2)];
					for (int i = 0; i < costs.Length; i++)
					{
						array[i] = costs[i];
					}
					costs = array;
				}
				maxNodeIndex = index;
			}
		}

		public uint GetHeuristic(int nodeIndex1, int nodeIndex2)
		{
			nodeIndex1 *= pivotCount;
			nodeIndex2 *= pivotCount;
			if (nodeIndex1 >= costs.Length || nodeIndex2 >= costs.Length)
			{
				EnsureCapacity((nodeIndex1 > nodeIndex2) ? nodeIndex1 : nodeIndex2);
			}
			uint num = 0u;
			for (int i = 0; i < pivotCount; i++)
			{
				uint num2 = (uint)Math.Abs((int)(costs[nodeIndex1 + i] - costs[nodeIndex2 + i]));
				if (num2 > num)
				{
					num = num2;
				}
			}
			return num;
		}

		private void GetClosestWalkableNodesToChildrenRecursively(Transform tr, List<GraphNode> nodes)
		{
			foreach (Transform item in tr)
			{
				NNInfo nearest = AstarPath.active.GetNearest(item.position, NNConstraint.Default);
				if (nearest.node != null && nearest.node.Walkable)
				{
					nodes.Add(nearest.node);
				}
				GetClosestWalkableNodesToChildrenRecursively(item, nodes);
			}
		}

		private void PickNRandomNodes(int count, List<GraphNode> buffer)
		{
			int n = 0;
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				graphs[i].GetNodes(delegate(GraphNode node)
				{
					if (!node.Destroyed && node.Walkable)
					{
						n++;
						if (GetRandom() % n < count)
						{
							if (buffer.Count < count)
							{
								buffer.Add(node);
							}
							else
							{
								buffer[(int)(GetRandom() % buffer.Count)] = node;
							}
						}
					}
				});
			}
		}

		private GraphNode PickAnyWalkableNode()
		{
			NavGraph[] graphs = AstarPath.active.graphs;
			GraphNode first = null;
			for (int i = 0; i < graphs.Length; i++)
			{
				graphs[i].GetNodes(delegate(GraphNode node)
				{
					if (node != null && node.Walkable && first == null)
					{
						first = node;
					}
				});
			}
			return first;
		}

		public void RecalculatePivots()
		{
			if (mode == HeuristicOptimizationMode.None)
			{
				pivotCount = 0;
				pivots = null;
				return;
			}
			rval = (uint)seed;
			List<GraphNode> list = ListPool<GraphNode>.Claim();
			switch (mode)
			{
			case HeuristicOptimizationMode.Custom:
				if (pivotPointRoot == null)
				{
					throw new Exception("heuristicOptimizationMode is HeuristicOptimizationMode.Custom, but no 'customHeuristicOptimizationPivotsRoot' is set");
				}
				GetClosestWalkableNodesToChildrenRecursively(pivotPointRoot, list);
				break;
			case HeuristicOptimizationMode.Random:
				PickNRandomNodes(spreadOutCount, list);
				break;
			case HeuristicOptimizationMode.RandomSpreadOut:
			{
				if (pivotPointRoot != null)
				{
					GetClosestWalkableNodesToChildrenRecursively(pivotPointRoot, list);
				}
				if (list.Count == 0)
				{
					GraphNode graphNode = PickAnyWalkableNode();
					if (graphNode == null)
					{
						UnityEngine.Debug.LogError("Could not find any walkable node in any of the graphs.");
						ListPool<GraphNode>.Release(ref list);
						return;
					}
					list.Add(graphNode);
				}
				int num = spreadOutCount - list.Count;
				for (int i = 0; i < num; i++)
				{
					list.Add(null);
				}
				break;
			}
			default:
				throw new Exception("Invalid HeuristicOptimizationMode: " + mode);
			}
			pivots = list.ToArray();
			ListPool<GraphNode>.Release(ref list);
		}

		public void RecalculateCosts()
		{
			if (pivots == null)
			{
				RecalculatePivots();
			}
			if (mode == HeuristicOptimizationMode.None)
			{
				return;
			}
			pivotCount = 0;
			for (int i = 0; i < pivots.Length; i++)
			{
				if (pivots[i] != null && (pivots[i].Destroyed || !pivots[i].Walkable))
				{
					throw new Exception("Invalid pivot nodes (destroyed or unwalkable)");
				}
			}
			if (mode != HeuristicOptimizationMode.RandomSpreadOut)
			{
				for (int j = 0; j < pivots.Length; j++)
				{
					if (pivots[j] == null)
					{
						throw new Exception("Invalid pivot nodes (null)");
					}
				}
			}
			UnityEngine.Debug.Log("Recalculating costs...");
			pivotCount = pivots.Length;
			Action<int> startCostCalculation = null;
			int numComplete = 0;
			OnPathDelegate onComplete = delegate
			{
				numComplete++;
				if (numComplete == pivotCount)
				{
					ApplyGridGraphEndpointSpecialCase();
				}
			};
			startCostCalculation = delegate(int pivotIndex)
			{
				GraphNode pivot = pivots[pivotIndex];
				FloodPath floodPath = null;
				floodPath = FloodPath.Construct(pivot, onComplete);
				floodPath.immediateCallback = delegate(Path _p)
				{
					_p.Claim(this);
					MeshNode meshNode = pivot as MeshNode;
					uint costOffset = 0u;
					if (meshNode != null && meshNode.connections != null)
					{
						for (int k = 0; k < meshNode.connections.Length; k++)
						{
							costOffset = Math.Max(costOffset, meshNode.connections[k].cost);
						}
					}
					NavGraph[] graphs = AstarPath.active.graphs;
					for (int num2 = graphs.Length - 1; num2 >= 0; num2--)
					{
						graphs[num2].GetNodes(delegate(GraphNode graphNode)
						{
							int num9 = graphNode.NodeIndex * pivotCount + pivotIndex;
							EnsureCapacity(num9);
							PathNode pathNode = ((IPathInternals)floodPath).PathHandler.GetPathNode(graphNode);
							if (costOffset != 0)
							{
								costs[num9] = ((pathNode.pathID == floodPath.pathID && pathNode.parent != null) ? Math.Max(pathNode.parent.G - costOffset, 0u) : 0u);
							}
							else
							{
								costs[num9] = ((pathNode.pathID == floodPath.pathID) ? pathNode.G : 0u);
							}
						});
					}
					if (mode == HeuristicOptimizationMode.RandomSpreadOut && pivotIndex < pivots.Length - 1)
					{
						if (pivots[pivotIndex + 1] == null)
						{
							int num3 = -1;
							uint num4 = 0u;
							int num5 = maxNodeIndex / pivotCount;
							for (int num6 = 1; num6 < num5; num6++)
							{
								uint num7 = 1073741824u;
								for (int num8 = 0; num8 <= pivotIndex; num8++)
								{
									num7 = Math.Min(num7, costs[num6 * pivotCount + num8]);
								}
								GraphNode node = ((IPathInternals)floodPath).PathHandler.GetPathNode(num6).node;
								if ((num7 > num4 || num3 == -1) && node != null && !node.Destroyed && node.Walkable)
								{
									num3 = num6;
									num4 = num7;
								}
							}
							if (num3 == -1)
							{
								UnityEngine.Debug.LogError("Failed generating random pivot points for heuristic optimizations");
								return;
							}
							pivots[pivotIndex + 1] = ((IPathInternals)floodPath).PathHandler.GetPathNode(num3).node;
						}
						startCostCalculation(pivotIndex + 1);
					}
					_p.Release(this);
				};
				AstarPath.StartPath(floodPath, pushToFront: true);
			};
			if (mode != HeuristicOptimizationMode.RandomSpreadOut)
			{
				for (int num = 0; num < pivots.Length; num++)
				{
					startCostCalculation(num);
				}
			}
			else
			{
				startCostCalculation(0);
			}
			dirty = false;
		}

		private void ApplyGridGraphEndpointSpecialCase()
		{
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (!(graphs[i] is GridGraph { nodes: var nodes } gridGraph))
				{
					continue;
				}
				int num = ((gridGraph.neighbours == NumNeighbours.Four) ? 4 : ((gridGraph.neighbours == NumNeighbours.Eight) ? 8 : 6));
				for (int j = 0; j < gridGraph.depth; j++)
				{
					for (int k = 0; k < gridGraph.width; k++)
					{
						GridNodeBase gridNodeBase = nodes[j * gridGraph.width + k];
						if (gridNodeBase.Walkable)
						{
							continue;
						}
						int num2 = gridNodeBase.NodeIndex * pivotCount;
						for (int l = 0; l < pivotCount; l++)
						{
							costs[num2 + l] = uint.MaxValue;
						}
						for (int m = 0; m < num; m++)
						{
							int num3;
							int num4;
							if (gridGraph.neighbours == NumNeighbours.Six)
							{
								num3 = k + gridGraph.neighbourXOffsets[GridGraph.hexagonNeighbourIndices[m]];
								num4 = j + gridGraph.neighbourZOffsets[GridGraph.hexagonNeighbourIndices[m]];
							}
							else
							{
								num3 = k + gridGraph.neighbourXOffsets[m];
								num4 = j + gridGraph.neighbourZOffsets[m];
							}
							if (num3 < 0 || num4 < 0 || num3 >= gridGraph.width || num4 >= gridGraph.depth)
							{
								continue;
							}
							GridNodeBase gridNodeBase2 = gridGraph.nodes[num4 * gridGraph.width + num3];
							if (gridNodeBase2.Walkable)
							{
								for (int n = 0; n < pivotCount; n++)
								{
									uint val = costs[gridNodeBase2.NodeIndex * pivotCount + n] + gridGraph.neighbourCosts[m];
									costs[num2 + n] = Math.Min(costs[num2 + n], val);
								}
							}
						}
						for (int num5 = 0; num5 < pivotCount; num5++)
						{
							if (costs[num2 + num5] == uint.MaxValue)
							{
								costs[num2 + num5] = 0u;
							}
						}
					}
				}
			}
		}

		public void OnDrawGizmos()
		{
			if (pivots == null)
			{
				return;
			}
			for (int i = 0; i < pivots.Length; i++)
			{
				Gizmos.color = new Color(53f / 85f, 0.36862746f, 0.7607843f, 0.8f);
				if (pivots[i] != null && !pivots[i].Destroyed)
				{
					Gizmos.DrawCube((Vector3)pivots[i].position, Vector3.one);
				}
			}
		}
	}
