	[AddComponentMenu("Pathfinding/Modifiers/Radius Offset")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_radius_modifier.php")]
	public class RadiusModifier : MonoModifier
	{
		[Flags]
		private enum TangentType
		{
			OuterRight = 1,
			InnerRightLeft = 2,
			InnerLeftRight = 4,
			OuterLeft = 8,
			Outer = 9,
			Inner = 6
		}

		public float radius = 1f;

		public float detail = 10f;

		private float[] radi = new float[10];

		private float[] a1 = new float[10];

		private float[] a2 = new float[10];

		private bool[] dir = new bool[10];

		public override int Order => 41;

		private bool CalculateCircleInner(Vector3 p1, Vector3 p2, float r1, float r2, out float a, out float sigma)
		{
			float magnitude = (p1 - p2).magnitude;
			if (r1 + r2 > magnitude)
			{
				a = 0f;
				sigma = 0f;
				return false;
			}
			a = (float)Math.Acos((r1 + r2) / magnitude);
			sigma = (float)Math.Atan2(p2.z - p1.z, p2.x - p1.x);
			return true;
		}

		private bool CalculateCircleOuter(Vector3 p1, Vector3 p2, float r1, float r2, out float a, out float sigma)
		{
			float magnitude = (p1 - p2).magnitude;
			if (Math.Abs(r1 - r2) > magnitude)
			{
				a = 0f;
				sigma = 0f;
				return false;
			}
			a = (float)Math.Acos((r1 - r2) / magnitude);
			sigma = (float)Math.Atan2(p2.z - p1.z, p2.x - p1.x);
			return true;
		}

		private TangentType CalculateTangentType(Vector3 p1, Vector3 p2, Vector3 p3, Vector3 p4)
		{
			bool flag = VectorMath.RightOrColinearXZ(p1, p2, p3);
			bool flag2 = VectorMath.RightOrColinearXZ(p2, p3, p4);
			return (TangentType)(1 << (flag ? 2 : 0) + (flag2 ? 1 : 0));
		}

		private TangentType CalculateTangentTypeSimple(Vector3 p1, Vector3 p2, Vector3 p3)
		{
			bool flag = VectorMath.RightOrColinearXZ(p1, p2, p3);
			bool flag2 = flag;
			return (TangentType)(1 << (flag2 ? 2 : 0) + (flag ? 1 : 0));
		}

		public override void Apply(Path p)
		{
			List<Vector3> vectorPath = p.vectorPath;
			List<Vector3> list = Apply(vectorPath);
			if (list != vectorPath)
			{
				ListPool<Vector3>.Release(ref p.vectorPath);
				p.vectorPath = list;
			}
		}

		public List<Vector3> Apply(List<Vector3> vs)
		{
			if (vs == null || vs.Count < 3)
			{
				return vs;
			}
			if (radi.Length < vs.Count)
			{
				radi = new float[vs.Count];
				a1 = new float[vs.Count];
				this.a2 = new float[vs.Count];
				dir = new bool[vs.Count];
			}
			for (int i = 0; i < vs.Count; i++)
			{
				radi[i] = radius;
			}
			radi[0] = 0f;
			radi[vs.Count - 1] = 0f;
			int num = 0;
			for (int j = 0; j < vs.Count - 1; j++)
			{
				num++;
				if (num > 2 * vs.Count)
				{
					UnityEngine.Debug.LogWarning("Could not resolve radiuses, the path is too complex. Try reducing the base radius");
					break;
				}
				TangentType tangentType = ((j == 0) ? CalculateTangentTypeSimple(vs[j], vs[j + 1], vs[j + 2]) : ((j != vs.Count - 2) ? CalculateTangentType(vs[j - 1], vs[j], vs[j + 1], vs[j + 2]) : CalculateTangentTypeSimple(vs[j - 1], vs[j], vs[j + 1])));
				float a2;
				float sigma2;
				if ((tangentType & TangentType.Inner) != 0)
				{
					if (!CalculateCircleInner(vs[j], vs[j + 1], radi[j], radi[j + 1], out var a, out var sigma))
					{
						float magnitude = (vs[j + 1] - vs[j]).magnitude;
						radi[j] = magnitude * (radi[j] / (radi[j] + radi[j + 1]));
						radi[j + 1] = magnitude - radi[j];
						radi[j] *= 0.99f;
						radi[j + 1] *= 0.99f;
						j -= 2;
					}
					else if (tangentType == TangentType.InnerRightLeft)
					{
						this.a2[j] = sigma - a;
						a1[j + 1] = sigma - a + MathF.PI;
						dir[j] = true;
					}
					else
					{
						this.a2[j] = sigma + a;
						a1[j + 1] = sigma + a + MathF.PI;
						dir[j] = false;
					}
				}
				else if (!CalculateCircleOuter(vs[j], vs[j + 1], radi[j], radi[j + 1], out a2, out sigma2))
				{
					if (j == vs.Count - 2)
					{
						radi[j] = (vs[j + 1] - vs[j]).magnitude;
						radi[j] *= 0.99f;
						j--;
					}
					else
					{
						if (radi[j] > radi[j + 1])
						{
							radi[j + 1] = radi[j] - (vs[j + 1] - vs[j]).magnitude;
						}
						else
						{
							radi[j + 1] = radi[j] + (vs[j + 1] - vs[j]).magnitude;
						}
						radi[j + 1] *= 0.99f;
					}
					j--;
				}
				else if (tangentType == TangentType.OuterRight)
				{
					this.a2[j] = sigma2 - a2;
					a1[j + 1] = sigma2 - a2;
					dir[j] = true;
				}
				else
				{
					this.a2[j] = sigma2 + a2;
					a1[j + 1] = sigma2 + a2;
					dir[j] = false;
				}
			}
			List<Vector3> list = ListPool<Vector3>.Claim();
			list.Add(vs[0]);
			if (detail < 1f)
			{
				detail = 1f;
			}
			float num2 = MathF.PI * 2f / detail;
			for (int k = 1; k < vs.Count - 1; k++)
			{
				float num3 = a1[k];
				float num4 = this.a2[k];
				float num5 = radi[k];
				if (dir[k])
				{
					if (num4 < num3)
					{
						num4 += MathF.PI * 2f;
					}
					for (float num6 = num3; num6 < num4; num6 += num2)
					{
						list.Add(new Vector3((float)Math.Cos(num6), 0f, (float)Math.Sin(num6)) * num5 + vs[k]);
					}
					continue;
				}
				if (num3 < num4)
				{
					num3 += MathF.PI * 2f;
				}
				for (float num7 = num3; num7 > num4; num7 -= num2)
				{
					list.Add(new Vector3((float)Math.Cos(num7), 0f, (float)Math.Sin(num7)) * num5 + vs[k]);
				}
			}
			list.Add(vs[vs.Count - 1]);
			return list;
		}
	}
	[Serializable]
	[AddComponentMenu("Pathfinding/Modifiers/Raycast Modifier")]
	[RequireComponent(typeof(Seeker))]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_raycast_modifier.php")]
	public class RaycastModifier : MonoModifier
	{
		public enum Quality
		{
			Low,
			Medium,
			High,
			Highest
		}

		private class Filter
		{
			public Path path;

			public readonly Func<GraphNode, bool> cachedDelegate;

			public Filter()
			{
				cachedDelegate = CanTraverse;
			}

			private bool CanTraverse(GraphNode node)
			{
				return path.CanTraverse(node);
			}
		}

		public bool useRaycasting = true;

		public LayerMask mask = -1;

		[Tooltip("Checks around the line between two points, not just the exact line.\nMake sure the ground is either too far below or is not inside the mask since otherwise the raycast might always hit the ground.")]
		public bool thickRaycast;

		[Tooltip("Distance from the ray which will be checked for colliders")]
		public float thickRaycastRadius;

		[Tooltip("Check for intersections with 2D colliders instead of 3D colliders.")]
		public bool use2DPhysics;

		[Tooltip("Offset from the original positions to perform the raycast.\nCan be useful to avoid the raycast intersecting the ground or similar things you do not want to it intersect")]
		public Vector3 raycastOffset = Vector3.zero;

		[Tooltip("Use raycasting on the graphs. Only currently works with GridGraph and NavmeshGraph and RecastGraph. This is a pro version feature.")]
		public bool useGraphRaycasting;

		[Tooltip("When using the high quality mode the script will try harder to find a shorter path. This is significantly slower than the greedy low quality approach.")]
		public Quality quality = Quality.Medium;

		private static readonly int[] iterationsByQuality = new int[4] { 1, 2, 1, 3 };

		private static List<Vector3> buffer = new List<Vector3>();

		private static float[] DPCosts = new float[16];

		private static int[] DPParents = new int[16];

		private Filter cachedFilter = new Filter();

		private NNConstraint cachedNNConstraint = NNConstraint.None;

		public override int Order => 40;

		public override void Apply(Path p)
		{
			if (!useRaycasting && !useGraphRaycasting)
			{
				return;
			}
			List<Vector3> b = p.vectorPath;
			cachedFilter.path = p;
			cachedNNConstraint.graphMask = p.nnConstraint.graphMask;
			if (ValidateLine(null, null, p.vectorPath[0], p.vectorPath[p.vectorPath.Count - 1], cachedFilter.cachedDelegate, cachedNNConstraint))
			{
				Vector3 item = p.vectorPath[0];
				Vector3 item2 = p.vectorPath[p.vectorPath.Count - 1];
				b.ClearFast();
				b.Add(item);
				b.Add(item2);
			}
			else
			{
				int num = iterationsByQuality[(int)quality];
				for (int i = 0; i < num; i++)
				{
					if (i != 0)
					{
						Polygon.Subdivide(b, buffer, 3);
						Memory.Swap(ref buffer, ref b);
						buffer.ClearFast();
						b.Reverse();
					}
					b = ((quality >= Quality.High) ? ApplyDP(p, b, cachedFilter.cachedDelegate, cachedNNConstraint) : ApplyGreedy(p, b, cachedFilter.cachedDelegate, cachedNNConstraint));
				}
				if (num % 2 == 0)
				{
					b.Reverse();
				}
			}
			p.vectorPath = b;
		}

		private List<Vector3> ApplyGreedy(Path p, List<Vector3> points, Func<GraphNode, bool> filter, NNConstraint nnConstraint)
		{
			bool flag = points.Count == p.path.Count;
			int num;
			for (int i = 0; i < points.Count; i += num)
			{
				Vector3 vector = points[i];
				GraphNode n = ((flag && points[i] == (Vector3)p.path[i].position) ? p.path[i] : null);
				buffer.Add(vector);
				num = 1;
				int num2 = 2;
				while (true)
				{
					int num3 = i + num2;
					if (num3 >= points.Count)
					{
						num2 = points.Count - i;
						break;
					}
					Vector3 vector2 = points[num3];
					GraphNode n2 = ((flag && vector2 == (Vector3)p.path[num3].position) ? p.path[num3] : null);
					if (!ValidateLine(n, n2, vector, vector2, filter, nnConstraint))
					{
						break;
					}
					num = num2;
					num2 *= 2;
				}
				while (num + 1 < num2)
				{
					int num4 = (num + num2) / 2;
					int index = i + num4;
					Vector3 vector3 = points[index];
					GraphNode n3 = ((flag && vector3 == (Vector3)p.path[index].position) ? p.path[index] : null);
					if (ValidateLine(n, n3, vector, vector3, filter, nnConstraint))
					{
						num = num4;
					}
					else
					{
						num2 = num4;
					}
				}
			}
			Memory.Swap(ref buffer, ref points);
			buffer.ClearFast();
			return points;
		}

		private List<Vector3> ApplyDP(Path p, List<Vector3> points, Func<GraphNode, bool> filter, NNConstraint nnConstraint)
		{
			if (DPCosts.Length < points.Count)
			{
				DPCosts = new float[points.Count];
				DPParents = new int[points.Count];
			}
			for (int i = 0; i < DPParents.Length; i++)
			{
				DPCosts[i] = (DPParents[i] = -1);
			}
			bool flag = points.Count == p.path.Count;
			for (int j = 0; j < points.Count; j++)
			{
				float num = DPCosts[j];
				Vector3 vector = points[j];
				bool flag2 = flag && vector == (Vector3)p.path[j].position;
				for (int k = j + 1; k < points.Count; k++)
				{
					float num2 = num + (points[k] - vector).magnitude + 0.0001f;
					if (DPParents[k] == -1 || num2 < DPCosts[k])
					{
						bool flag3 = flag && points[k] == (Vector3)p.path[k].position;
						if (k != j + 1 && !ValidateLine(flag2 ? p.path[j] : null, flag3 ? p.path[k] : null, vector, points[k], filter, nnConstraint))
						{
							break;
						}
						DPCosts[k] = num2;
						DPParents[k] = j;
					}
				}
			}
			for (int num3 = points.Count - 1; num3 != -1; num3 = DPParents[num3])
			{
				buffer.Add(points[num3]);
			}
			buffer.Reverse();
			Memory.Swap(ref buffer, ref points);
			buffer.ClearFast();
			return points;
		}

		protected bool ValidateLine(GraphNode n1, GraphNode n2, Vector3 v1, Vector3 v2, Func<GraphNode, bool> filter, NNConstraint nnConstraint)
		{
			if (useRaycasting)
			{
				if (use2DPhysics)
				{
					if (thickRaycast && thickRaycastRadius > 0f && (bool)Physics2D.CircleCast(v1 + raycastOffset, thickRaycastRadius, v2 - v1, (v2 - v1).magnitude, mask))
					{
						return false;
					}
					if ((bool)Physics2D.Linecast(v1 + raycastOffset, v2 + raycastOffset, mask))
					{
						return false;
					}
				}
				else
				{
					if (Physics.Linecast(v1 + raycastOffset, v2 + raycastOffset, mask))
					{
						return false;
					}
					if (thickRaycast && thickRaycastRadius > 0f)
					{
						if (Physics.CheckSphere(v1 + raycastOffset + (v2 - v1).normalized * thickRaycastRadius, thickRaycastRadius, mask))
						{
							return false;
						}
						if (Physics.SphereCast(new Ray(v1 + raycastOffset, v2 - v1), thickRaycastRadius, (v2 - v1).magnitude, mask))
						{
							return false;
						}
					}
				}
			}
			if (useGraphRaycasting)
			{
				bool flag = n1 != null && n2 != null;
				if (n1 == null)
				{
					n1 = AstarPath.active.GetNearest(v1, nnConstraint).node;
				}
				if (n2 == null)
				{
					n2 = AstarPath.active.GetNearest(v2, nnConstraint).node;
				}
				if (n1 != null && n2 != null)
				{
					NavGraph graph = n1.Graph;
					NavGraph graph2 = n2.Graph;
					if (graph != graph2)
					{
						return false;
					}
					IRaycastableGraph raycastableGraph = graph as IRaycastableGraph;
					GridGraph gridGraph = graph as GridGraph;
					if (flag && gridGraph != null)
					{
						return !gridGraph.Linecast(n1 as GridNodeBase, n2 as GridNodeBase, filter);
					}
					GraphHitInfo hit;
					if (raycastableGraph != null)
					{
						return !raycastableGraph.Linecast(v1, v2, out hit, null, filter);
					}
				}
			}
			return true;
		}
	}
	[Serializable]
	[AddComponentMenu("Pathfinding/Modifiers/Simple Smooth")]
	[RequireComponent(typeof(Seeker))]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_simple_smooth_modifier.php")]
	public class SimpleSmoothModifier : MonoModifier
	{
		public enum SmoothType
		{
			Simple,
			Bezier,
			OffsetSimple,
			CurvedNonuniform
		}

		public SmoothType smoothType;

		[Tooltip("The number of times to subdivide (divide in half) the path segments. [0...inf] (recommended [1...10])")]
		public int subdivisions = 2;

		[Tooltip("Number of times to apply smoothing")]
		public int iterations = 2;

		[Tooltip("Determines how much smoothing to apply in each smooth iteration. 0.5 usually produces the nicest looking curves")]
		[Range(0f, 1f)]
		public float strength = 0.5f;

		[Tooltip("Toggle to divide all lines in equal length segments")]
		public bool uniformLength = true;

		[Tooltip("The length of each segment in the smoothed path. A high value yields rough paths and low value yields very smooth paths, but is slower")]
		public float maxSegmentLength = 2f;

		[Tooltip("Length factor of the bezier curves' tangents")]
		public float bezierTangentLength = 0.4f;

		[Tooltip("Offset to apply in each smoothing iteration when using Offset Simple")]
		public float offset = 0.2f;

		[Tooltip("How much to smooth the path. A higher value will give a smoother path, but might take the character far off the optimal path.")]
		public float factor = 0.1f;

		public override int Order => 50;

		public override void Apply(Path p)
		{
			if (p.vectorPath == null)
			{
				UnityEngine.Debug.LogWarning("Can't process NULL path (has another modifier logged an error?)");
				return;
			}
			List<Vector3> list = null;
			switch (smoothType)
			{
			case SmoothType.Simple:
				list = SmoothSimple(p.vectorPath);
				break;
			case SmoothType.Bezier:
				list = SmoothBezier(p.vectorPath);
				break;
			case SmoothType.OffsetSimple:
				list = SmoothOffsetSimple(p.vectorPath);
				break;
			case SmoothType.CurvedNonuniform:
				list = CurvedNonuniform(p.vectorPath);
				break;
			}
			if (list != p.vectorPath)
			{
				ListPool<Vector3>.Release(ref p.vectorPath);
				p.vectorPath = list;
			}
		}

		public List<Vector3> CurvedNonuniform(List<Vector3> path)
		{
			if (maxSegmentLength <= 0f)
			{
				UnityEngine.Debug.LogWarning("Max Segment Length is <= 0 which would cause DivByZero-exception or other nasty errors (avoid this)");
				return path;
			}
			int num = 0;
			for (int i = 0; i < path.Count - 1; i++)
			{
				float magnitude = (path[i] - path[i + 1]).magnitude;
				for (float num2 = 0f; num2 <= magnitude; num2 += maxSegmentLength)
				{
					num++;
				}
			}
			List<Vector3> list = ListPool<Vector3>.Claim(num);
			Vector3 vector = (path[1] - path[0]).normalized;
			for (int j = 0; j < path.Count - 1; j++)
			{
				float magnitude2 = (path[j] - path[j + 1]).magnitude;
				Vector3 vector2 = vector;
				Vector3 vector3 = ((j < path.Count - 2) ? ((path[j + 2] - path[j + 1]).normalized - (path[j] - path[j + 1]).normalized).normalized : (path[j + 1] - path[j]).normalized);
				Vector3 tan = vector2 * magnitude2 * factor;
				Vector3 tan2 = vector3 * magnitude2 * factor;
				Vector3 a = path[j];
				Vector3 b = path[j + 1];
				float num3 = 1f / magnitude2;
				for (float num4 = 0f; num4 <= magnitude2; num4 += maxSegmentLength)
				{
					float t = num4 * num3;
					list.Add(GetPointOnCubic(a, b, tan, tan2, t));
				}
				vector = vector3;
			}
			list[list.Count - 1] = path[path.Count - 1];
			return list;
		}

		public static Vector3 GetPointOnCubic(Vector3 a, Vector3 b, Vector3 tan1, Vector3 tan2, float t)
		{
			float num = t * t;
			float num2 = num * t;
			float num3 = 2f * num2 - 3f * num + 1f;
			float num4 = -2f * num2 + 3f * num;
			float num5 = num2 - 2f * num + t;
			float num6 = num2 - num;
			return num3 * a + num4 * b + num5 * tan1 + num6 * tan2;
		}

		public List<Vector3> SmoothOffsetSimple(List<Vector3> path)
		{
			if (path.Count <= 2 || iterations <= 0)
			{
				return path;
			}
			if (iterations > 12)
			{
				UnityEngine.Debug.LogWarning("A very high iteration count was passed, won't let this one through");
				return path;
			}
			int num = (path.Count - 2) * (int)Mathf.Pow(2f, iterations) + 2;
			List<Vector3> list = ListPool<Vector3>.Claim(num);
			List<Vector3> list2 = ListPool<Vector3>.Claim(num);
			for (int i = 0; i < num; i++)
			{
				list.Add(Vector3.zero);
				list2.Add(Vector3.zero);
			}
			for (int j = 0; j < path.Count; j++)
			{
				list[j] = path[j];
			}
			for (int k = 0; k < iterations; k++)
			{
				int num2 = (path.Count - 2) * (int)Mathf.Pow(2f, k) + 2;
				List<Vector3> list3 = list;
				list = list2;
				list2 = list3;
				for (int l = 0; l < num2 - 1; l++)
				{
					Vector3 vector = list2[l];
					Vector3 vector2 = list2[l + 1];
					Vector3 normalized = Vector3.Cross(vector2 - vector, Vector3.up).normalized;
					bool flag = false;
					bool flag2 = false;
					bool flag3 = false;
					bool flag4 = false;
					if (l != 0 && !VectorMath.IsColinearXZ(vector, vector2, list2[l - 1]))
					{
						flag3 = true;
						flag = VectorMath.RightOrColinearXZ(vector, vector2, list2[l - 1]);
					}
					if (l < num2 - 1 && !VectorMath.IsColinearXZ(vector, vector2, list2[l + 2]))
					{
						flag4 = true;
						flag2 = VectorMath.RightOrColinearXZ(vector, vector2, list2[l + 2]);
					}
					if (flag3)
					{
						list[l * 2] = vector + (flag ? (normalized * offset * 1f) : (-normalized * offset * 1f));
					}
					else
					{
						list[l * 2] = vector;
					}
					if (flag4)
					{
						list[l * 2 + 1] = vector2 + (flag2 ? (normalized * offset * 1f) : (-normalized * offset * 1f));
					}
					else
					{
						list[l * 2 + 1] = vector2;
					}
				}
				list[(path.Count - 2) * (int)Mathf.Pow(2f, k + 1) + 2 - 1] = list2[num2 - 1];
			}
			ListPool<Vector3>.Release(ref list2);
			return list;
		}

		public List<Vector3> SmoothSimple(List<Vector3> path)
		{
			if (path.Count < 2)
			{
				return path;
			}
			List<Vector3> list;
			if (uniformLength)
			{
				maxSegmentLength = Mathf.Max(maxSegmentLength, 0.005f);
				float num = 0f;
				for (int i = 0; i < path.Count - 1; i++)
				{
					num += Vector3.Distance(path[i], path[i + 1]);
				}
				list = ListPool<Vector3>.Claim(Mathf.FloorToInt(num / maxSegmentLength) + 2);
				float num2 = 0f;
				for (int j = 0; j < path.Count - 1; j++)
				{
					Vector3 a = path[j];
					Vector3 b = path[j + 1];
					float num3;
					for (num3 = Vector3.Distance(a, b); num2 < num3; num2 += maxSegmentLength)
					{
						list.Add(Vector3.Lerp(a, b, num2 / num3));
					}
					num2 -= num3;
				}
				list.Add(path[path.Count - 1]);
			}
			else
			{
				subdivisions = Mathf.Max(subdivisions, 0);
				if (subdivisions > 10)
				{
					UnityEngine.Debug.LogWarning("Very large number of subdivisions. Cowardly refusing to subdivide every segment into more than " + (1 << subdivisions) + " subsegments");
					subdivisions = 10;
				}
				int num4 = 1 << subdivisions;
				list = ListPool<Vector3>.Claim((path.Count - 1) * num4 + 1);
				Polygon.Subdivide(path, list, num4);
			}
			if (strength > 0f)
			{
				for (int k = 0; k < iterations; k++)
				{
					Vector3 vector = list[0];
					for (int l = 1; l < list.Count - 1; l++)
					{
						Vector3 vector2 = list[l];
						list[l] = Vector3.Lerp(vector2, (vector + list[l + 1]) / 2f, strength);
						vector = vector2;
					}
				}
			}
			return list;
		}

		public List<Vector3> SmoothBezier(List<Vector3> path)
		{
			if (subdivisions < 0)
			{
				subdivisions = 0;
			}
			int num = 1 << subdivisions;
			List<Vector3> list = ListPool<Vector3>.Claim();
			for (int i = 0; i < path.Count - 1; i++)
			{
				Vector3 vector = ((i != 0) ? (path[i + 1] - path[i - 1]) : (path[i + 1] - path[i]));
				Vector3 vector2 = ((i != path.Count - 2) ? (path[i] - path[i + 2]) : (path[i] - path[i + 1]));
				vector *= bezierTangentLength;
				vector2 *= bezierTangentLength;
				Vector3 vector3 = path[i];
				Vector3 p = vector3 + vector;
				Vector3 vector4 = path[i + 1];
				Vector3 p2 = vector4 + vector2;
				for (int j = 0; j < num; j++)
				{
					list.Add(AstarSplines.CubicBezier(vector3, p, p2, vector4, (float)j / (float)num));
				}
			}
			list.Add(path[path.Count - 1]);
			return list;
		}
	}
	[Serializable]
	public class StartEndModifier : PathModifier
	{
		public enum Exactness
		{
			SnapToNode,
			Original,
			Interpolate,
			ClosestOnNode,
			NodeConnection
		}

		public bool addPoints;

		public Exactness exactStartPoint = Exactness.ClosestOnNode;

		public Exactness exactEndPoint = Exactness.ClosestOnNode;

		public Func<Vector3> adjustStartPoint;

		public bool useRaycasting;

		public LayerMask mask = -1;

		public bool useGraphRaycasting;

		private List<GraphNode> connectionBuffer;

		private Action<GraphNode> connectionBufferAddDelegate;

		public override int Order => 0;

		public override void Apply(Path _p)
		{
			if (!(_p is ABPath aBPath) || aBPath.vectorPath.Count == 0)
			{
				return;
			}
			bool flag = false;
			if (aBPath.vectorPath.Count == 1 && !addPoints)
			{
				aBPath.vectorPath.Add(aBPath.vectorPath[0]);
				flag = true;
			}
			bool forceAddPoint;
			int closestConnectionIndex;
			Vector3 vector = Snap(aBPath, exactStartPoint, start: true, out forceAddPoint, out closestConnectionIndex);
			bool forceAddPoint2;
			int closestConnectionIndex2;
			Vector3 vector2 = Snap(aBPath, exactEndPoint, start: false, out forceAddPoint2, out closestConnectionIndex2);
			if (flag)
			{
				if (closestConnectionIndex == closestConnectionIndex2)
				{
					forceAddPoint = false;
					forceAddPoint2 = false;
				}
				else
				{
					forceAddPoint = false;
				}
			}
			if ((forceAddPoint || addPoints) && exactStartPoint != Exactness.SnapToNode)
			{
				aBPath.vectorPath.Insert(0, vector);
			}
			else
			{
				aBPath.vectorPath[0] = vector;
			}
			if ((forceAddPoint2 || addPoints) && exactEndPoint != Exactness.SnapToNode)
			{
				aBPath.vectorPath.Add(vector2);
			}
			else
			{
				aBPath.vectorPath[aBPath.vectorPath.Count - 1] = vector2;
			}
		}

		private Vector3 Snap(ABPath path, Exactness mode, bool start, out bool forceAddPoint, out int closestConnectionIndex)
		{
			int num = ((!start) ? (path.path.Count - 1) : 0);
			GraphNode graphNode = path.path[num];
			Vector3 vector = (Vector3)graphNode.position;
			closestConnectionIndex = 0;
			forceAddPoint = false;
			switch (mode)
			{
			case Exactness.ClosestOnNode:
				if (!start)
				{
					return path.endPoint;
				}
				return path.startPoint;
			case Exactness.SnapToNode:
				return vector;
			case Exactness.Original:
			case Exactness.Interpolate:
			case Exactness.NodeConnection:
			{
				Vector3 vector2 = ((!start) ? path.originalEndPoint : ((adjustStartPoint != null) ? adjustStartPoint() : path.originalStartPoint));
				switch (mode)
				{
				case Exactness.Original:
					return GetClampedPoint(vector, vector2, graphNode);
				case Exactness.Interpolate:
				{
					GraphNode graphNode2 = path.path[Mathf.Clamp(num + (start ? 1 : (-1)), 0, path.path.Count - 1)];
					return VectorMath.ClosestPointOnSegment(vector, (Vector3)graphNode2.position, vector2);
				}
				case Exactness.NodeConnection:
				{
					connectionBuffer = connectionBuffer ?? new List<GraphNode>();
					connectionBufferAddDelegate = connectionBufferAddDelegate ?? new Action<GraphNode>(connectionBuffer.Add);
					GraphNode graphNode2 = path.path[Mathf.Clamp(num + (start ? 1 : (-1)), 0, path.path.Count - 1)];
					graphNode.GetConnections(connectionBufferAddDelegate);
					Vector3 result = vector;
					float num2 = float.PositiveInfinity;
					for (int num3 = connectionBuffer.Count - 1; num3 >= 0; num3--)
					{
						GraphNode graphNode3 = connectionBuffer[num3];
						if (path.CanTraverse(graphNode3))
						{
							Vector3 vector3 = VectorMath.ClosestPointOnSegment(vector, (Vector3)graphNode3.position, vector2);
							float sqrMagnitude = (vector3 - vector2).sqrMagnitude;
							if (sqrMagnitude < num2)
							{
								result = vector3;
								num2 = sqrMagnitude;
								closestConnectionIndex = num3;
								forceAddPoint = graphNode3 != graphNode2;
							}
						}
					}
					connectionBuffer.Clear();
					return result;
				}
				default:
					throw new ArgumentException("Cannot reach this point, but the compiler is not smart enough to realize that.");
				}
			}
			default:
				throw new ArgumentException("Invalid mode");
			}
		}

		protected Vector3 GetClampedPoint(Vector3 from, Vector3 to, GraphNode hint)
		{
			Vector3 vector = to;
			if (useRaycasting && Physics.Linecast(from, to, out var hitInfo, mask))
			{
				vector = hitInfo.point;
			}
			if (useGraphRaycasting && hint != null && AstarData.GetGraph(hint) is IRaycastableGraph raycastableGraph && raycastableGraph.Linecast(from, vector, out var hit))
			{
				vector = hit.point;
			}
			return vector;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_navmesh_add.php")]
	public class NavmeshAdd : NavmeshClipper
	{
		public enum MeshType
		{
			Rectangle,
			CustomMesh
		}

		public MeshType type;

		public Mesh mesh;

		private Vector3[] verts;

		private int[] tris;

		public Vector2 rectangleSize = new Vector2(1f, 1f);

		public float meshScale = 1f;

		public Vector3 center;

		[FormerlySerializedAs("useRotation")]
		public bool useRotationAndScale;

		[Tooltip("Distance between positions to require an update of the navmesh\nA smaller distance gives better accuracy, but requires more updates when moving the object over time, so it is often slower.")]
		public float updateDistance = 0.4f;

		[Tooltip("How many degrees rotation that is required for an update to the navmesh. Should be between 0 and 180.")]
		public float updateRotationDistance = 10f;

		protected Transform tr;

		private Vector3 lastPosition;

		private Quaternion lastRotation;

		public static readonly Color GizmoColor = new Color(0.6039216f, 7f / 51f, 0.9372549f);

		public Vector3 Center => tr.position + (useRotationAndScale ? tr.TransformPoint(center) : center);

		public override bool RequiresUpdate()
		{
			if (!((tr.position - lastPosition).sqrMagnitude > updateDistance * updateDistance))
			{
				if (useRotationAndScale)
				{
					return Quaternion.Angle(lastRotation, tr.rotation) > updateRotationDistance;
				}
				return false;
			}
			return true;
		}

		public override void ForceUpdate()
		{
			lastPosition = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
		}

		protected override void Awake()
		{
			base.Awake();
			tr = base.transform;
		}

		internal override void NotifyUpdated()
		{
			lastPosition = tr.position;
			if (useRotationAndScale)
			{
				lastRotation = tr.rotation;
			}
		}

		[ContextMenu("Rebuild Mesh")]
		public void RebuildMesh()
		{
			if (type == MeshType.CustomMesh)
			{
				if (mesh == null)
				{
					verts = null;
					tris = null;
				}
				else
				{
					verts = mesh.vertices;
					tris = mesh.triangles;
				}
				return;
			}
			if (verts == null || verts.Length != 4 || tris == null || tris.Length != 6)
			{
				verts = new Vector3[4];
				tris = new int[6];
			}
			tris[0] = 0;
			tris[1] = 1;
			tris[2] = 2;
			tris[3] = 0;
			tris[4] = 2;
			tris[5] = 3;
			verts[0] = new Vector3((0f - rectangleSize.x) * 0.5f, 0f, (0f - rectangleSize.y) * 0.5f);
			verts[1] = new Vector3(rectangleSize.x * 0.5f, 0f, (0f - rectangleSize.y) * 0.5f);
			verts[2] = new Vector3(rectangleSize.x * 0.5f, 0f, rectangleSize.y * 0.5f);
			verts[3] = new Vector3((0f - rectangleSize.x) * 0.5f, 0f, rectangleSize.y * 0.5f);
		}

		public override Rect GetBounds(GraphTransform inverseTransform)
		{
			if (verts == null)
			{
				RebuildMesh();
			}
			Int3[] vbuffer = ArrayPool<Int3>.Claim((verts != null) ? verts.Length : 0);
			GetMesh(ref vbuffer, out var tbuffer, inverseTransform);
			Rect result = default(Rect);
			for (int i = 0; i < tbuffer.Length; i++)
			{
				Vector3 vector = (Vector3)vbuffer[tbuffer[i]];
				if (i == 0)
				{
					result = new Rect(vector.x, vector.z, 0f, 0f);
					continue;
				}
				result.xMax = Math.Max(result.xMax, vector.x);
				result.yMax = Math.Max(result.yMax, vector.z);
				result.xMin = Math.Min(result.xMin, vector.x);
				result.yMin = Math.Min(result.yMin, vector.z);
			}
			ArrayPool<Int3>.Release(ref vbuffer);
			return result;
		}

		public void GetMesh(ref Int3[] vbuffer, out int[] tbuffer, GraphTransform inverseTransform = null)
		{
			if (verts == null)
			{
				RebuildMesh();
			}
			if (verts == null)
			{
				tbuffer = ArrayPool<int>.Claim(0);
				return;
			}
			if (vbuffer == null || vbuffer.Length < verts.Length)
			{
				if (vbuffer != null)
				{
					ArrayPool<Int3>.Release(ref vbuffer);
				}
				vbuffer = ArrayPool<Int3>.Claim(verts.Length);
			}
			tbuffer = tris;
			if (useRotationAndScale)
			{
				Matrix4x4 matrix4x = Matrix4x4.TRS(tr.position + center, tr.rotation, tr.localScale * meshScale);
				for (int i = 0; i < verts.Length; i++)
				{
					Vector3 vector = matrix4x.MultiplyPoint3x4(verts[i]);
					if (inverseTransform != null)
					{
						vector = inverseTransform.InverseTransform(vector);
					}
					vbuffer[i] = (Int3)vector;
				}
				return;
			}
			Vector3 vector2 = tr.position + center;
			for (int j = 0; j < verts.Length; j++)
			{
				Vector3 vector3 = vector2 + verts[j] * meshScale;
				if (inverseTransform != null)
				{
					vector3 = inverseTransform.InverseTransform(vector3);
				}
				vbuffer[j] = (Int3)vector3;
			}
		}
	}
	public abstract class NavmeshClipper : VersionedMonoBehaviour
	{
		private static Action<NavmeshClipper> OnEnableCallback;

		private static Action<NavmeshClipper> OnDisableCallback;

		private static readonly List<NavmeshClipper> all = new List<NavmeshClipper>();

		private int listIndex = -1;

		public GraphMask graphMask = GraphMask.everything;

		public static List<NavmeshClipper> allEnabled => all;

		public static void AddEnableCallback(Action<NavmeshClipper> onEnable, Action<NavmeshClipper> onDisable)
		{
			OnEnableCallback = (Action<NavmeshClipper>)Delegate.Combine(OnEnableCallback, onEnable);
			OnDisableCallback = (Action<NavmeshClipper>)Delegate.Combine(OnDisableCallback, onDisable);
		}

		public static void RemoveEnableCallback(Action<NavmeshClipper> onEnable, Action<NavmeshClipper> onDisable)
		{
			OnEnableCallback = (Action<NavmeshClipper>)Delegate.Remove(OnEnableCallback, onEnable);
			OnDisableCallback = (Action<NavmeshClipper>)Delegate.Remove(OnDisableCallback, onDisable);
		}

		protected virtual void OnEnable()
		{
			if (OnEnableCallback != null)
			{
				OnEnableCallback(this);
			}
			listIndex = all.Count;
			all.Add(this);
		}

		protected virtual void OnDisable()
		{
			all[listIndex] = all[all.Count - 1];
			all[listIndex].listIndex = listIndex;
			all.RemoveAt(all.Count - 1);
			listIndex = -1;
			if (OnDisableCallback != null)
			{
				OnDisableCallback(this);
			}
		}

		internal abstract void NotifyUpdated();

		public abstract Rect GetBounds(GraphTransform transform);

		public abstract bool RequiresUpdate();

		public abstract void ForceUpdate();
	}
	[AddComponentMenu("Pathfinding/Navmesh/Navmesh Cut")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_navmesh_cut.php")]
	public class NavmeshCut : NavmeshClipper
	{
		public enum MeshType
		{
			Rectangle,
			Circle,
			CustomMesh
		}

		[Tooltip("Shape of the cut")]
		public MeshType type;

		[Tooltip("The contour(s) of the mesh will be extracted. This mesh should only be a 2D surface, not a volume (see documentation).")]
		public Mesh mesh;

		public Vector2 rectangleSize = new Vector2(1f, 1f);

		public float circleRadius = 1f;

		public int circleResolution = 6;

		public float height = 1f;

		[Tooltip("Scale of the custom mesh")]
		public float meshScale = 1f;

		public Vector3 center;

		[Tooltip("Distance between positions to require an update of the navmesh\nA smaller distance gives better accuracy, but requires more updates when moving the object over time, so it is often slower.")]
		public float updateDistance = 0.4f;

		[Tooltip("Only makes a split in the navmesh, but does not remove the geometry to make a hole")]
		public bool isDual;

		public bool cutsAddedGeom = true;

		[Tooltip("How many degrees rotation that is required for an update to the navmesh. Should be between 0 and 180.")]
		public float updateRotationDistance = 10f;

		[Tooltip("Includes rotation in calculations. This is slower since a lot more matrix multiplications are needed but gives more flexibility.")]
		[FormerlySerializedAs("useRotation")]
		public bool useRotationAndScale;

		private Vector3[][] contours;

		protected Transform tr;

		private Mesh lastMesh;

		private Vector3 lastPosition;

		private Quaternion lastRotation;

		private static readonly Dictionary<Int2, int> edges = new Dictionary<Int2, int>();

		private static readonly Dictionary<int, int> pointers = new Dictionary<int, int>();

		public static readonly Color GizmoColor = new Color(0.14509805f, 0.72156864f, 0.9372549f);

		protected override void Awake()
		{
			base.Awake();
			tr = base.transform;
		}

		protected override void OnEnable()
		{
			base.OnEnable();
			lastPosition = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
			lastRotation = tr.rotation;
		}

		public override void ForceUpdate()
		{
			lastPosition = new Vector3(float.PositiveInfinity, float.PositiveInfinity, float.PositiveInfinity);
		}

		public override bool RequiresUpdate()
		{
			if (!((tr.position - lastPosition).sqrMagnitude > updateDistance * updateDistance))
			{
				if (useRotationAndScale)
				{
					return Quaternion.Angle(lastRotation, tr.rotation) > updateRotationDistance;
				}
				return false;
			}
			return true;
		}

		public virtual void UsedForCut()
		{
		}

		internal override void NotifyUpdated()
		{
			lastPosition = tr.position;
			if (useRotationAndScale)
			{
				lastRotation = tr.rotation;
			}
		}

		private void CalculateMeshContour()
		{
			if (mesh == null)
			{
				return;
			}
			edges.Clear();
			pointers.Clear();
			Vector3[] vertices = mesh.vertices;
			int[] triangles = mesh.triangles;
			for (int i = 0; i < triangles.Length; i += 3)
			{
				if (VectorMath.IsClockwiseXZ(vertices[triangles[i]], vertices[triangles[i + 1]], vertices[triangles[i + 2]]))
				{
					int num = triangles[i];
					triangles[i] = triangles[i + 2];
					triangles[i + 2] = num;
				}
				edges[new Int2(triangles[i], triangles[i + 1])] = i;
				edges[new Int2(triangles[i + 1], triangles[i + 2])] = i;
				edges[new Int2(triangles[i + 2], triangles[i])] = i;
			}
			for (int j = 0; j < triangles.Length; j += 3)
			{
				for (int k = 0; k < 3; k++)
				{
					if (!edges.ContainsKey(new Int2(triangles[j + (k + 1) % 3], triangles[j + k % 3])))
					{
						pointers[triangles[j + k % 3]] = triangles[j + (k + 1) % 3];
					}
				}
			}
			List<Vector3[]> list = new List<Vector3[]>();
			List<Vector3> list2 = ListPool<Vector3>.Claim();
			for (int l = 0; l < vertices.Length; l++)
			{
				if (!pointers.ContainsKey(l))
				{
					continue;
				}
				list2.Clear();
				int num2 = l;
				do
				{
					int num3 = pointers[num2];
					if (num3 == -1)
					{
						break;
					}
					pointers[num2] = -1;
					list2.Add(vertices[num2]);
					num2 = num3;
					if (num2 == -1)
					{
						UnityEngine.Debug.LogError("Invalid Mesh '" + mesh.name + " in " + base.gameObject.name);
						break;
					}
				}
				while (num2 != l);
				if (list2.Count > 0)
				{
					list.Add(list2.ToArray());
				}
			}
			ListPool<Vector3>.Release(ref list2);
			contours = list.ToArray();
		}

		public override Rect GetBounds(GraphTransform inverseTransform)
		{
			List<List<Vector3>> list = ListPool<List<Vector3>>.Claim();
			GetContour(list);
			Rect result = default(Rect);
			for (int i = 0; i < list.Count; i++)
			{
				List<Vector3> list2 = list[i];
				for (int j = 0; j < list2.Count; j++)
				{
					Vector3 vector = inverseTransform.InverseTransform(list2[j]);
					if (j == 0)
					{
						result = new Rect(vector.x, vector.z, 0f, 0f);
						continue;
					}
					result.xMax = Math.Max(result.xMax, vector.x);
					result.yMax = Math.Max(result.yMax, vector.z);
					result.xMin = Math.Min(result.xMin, vector.x);
					result.yMin = Math.Min(result.yMin, vector.z);
				}
			}
			ListPool<List<Vector3>>.Release(ref list);
			return result;
		}

		public void GetContour(List<List<Vector3>> buffer)
		{
			if (circleResolution < 3)
			{
				circleResolution = 3;
			}
			switch (type)
			{
			case MeshType.Rectangle:
			{
				List<Vector3> list = ListPool<Vector3>.Claim();
				list.Add(new Vector3(0f - rectangleSize.x, 0f, 0f - rectangleSize.y) * 0.5f);
				list.Add(new Vector3(rectangleSize.x, 0f, 0f - rectangleSize.y) * 0.5f);
				list.Add(new Vector3(rectangleSize.x, 0f, rectangleSize.y) * 0.5f);
				list.Add(new Vector3(0f - rectangleSize.x, 0f, rectangleSize.y) * 0.5f);
				bool reverse = (rectangleSize.x < 0f) ^ (rectangleSize.y < 0f);
				TransformBuffer(list, reverse);
				buffer.Add(list);
				break;
			}
			case MeshType.Circle:
			{
				List<Vector3> list = ListPool<Vector3>.Claim(circleResolution);
				for (int k = 0; k < circleResolution; k++)
				{
					list.Add(new Vector3(Mathf.Cos((float)(k * 2) * MathF.PI / (float)circleResolution), 0f, Mathf.Sin((float)(k * 2) * MathF.PI / (float)circleResolution)) * circleRadius);
				}
				bool reverse = circleRadius < 0f;
				TransformBuffer(list, reverse);
				buffer.Add(list);
				break;
			}
			case MeshType.CustomMesh:
			{
				if (mesh != lastMesh || contours == null)
				{
					CalculateMeshContour();
					lastMesh = mesh;
				}
				if (contours == null)
				{
					break;
				}
				bool reverse = meshScale < 0f;
				for (int i = 0; i < contours.Length; i++)
				{
					Vector3[] array = contours[i];
					List<Vector3> list = ListPool<Vector3>.Claim(array.Length);
					for (int j = 0; j < array.Length; j++)
					{
						list.Add(array[j] * meshScale);
					}
					TransformBuffer(list, reverse);
					buffer.Add(list);
				}
				break;
			}
			}
		}

		private void TransformBuffer(List<Vector3> buffer, bool reverse)
		{
			Vector3 vector = center;
			if (useRotationAndScale)
			{
				Matrix4x4 localToWorldMatrix = tr.localToWorldMatrix;
				for (int i = 0; i < buffer.Count; i++)
				{
					buffer[i] = localToWorldMatrix.MultiplyPoint3x4(buffer[i] + vector);
				}
				reverse ^= VectorMath.ReversesFaceOrientationsXZ(localToWorldMatrix);
			}
			else
			{
				vector += tr.position;
				for (int j = 0; j < buffer.Count; j++)
				{
					buffer[j] += vector;
				}
			}
			if (reverse)
			{
				buffer.Reverse();
			}
		}

		public void OnDrawGizmos()
		{
			if (tr == null)
			{
				tr = base.transform;
			}
			List<List<Vector3>> list = ListPool<List<Vector3>>.Claim();
			GetContour(list);
			Gizmos.color = GizmoColor;
			for (int i = 0; i < list.Count; i++)
			{
				List<Vector3> list2 = list[i];
				for (int j = 0; j < list2.Count; j++)
				{
					Vector3 vector = list2[j];
					Vector3 to = list2[(j + 1) % list2.Count];
					Gizmos.DrawLine(vector, to);
				}
			}
			ListPool<List<Vector3>>.Release(ref list);
		}

		internal float GetY(GraphTransform transform)
		{
			return transform.InverseTransform(useRotationAndScale ? tr.TransformPoint(center) : (tr.position + center)).y;
		}

		public void OnDrawGizmosSelected()
		{
			List<List<Vector3>> list = ListPool<List<Vector3>>.Claim();
			GetContour(list);
			Color color = Color.Lerp(GizmoColor, Color.white, 0.5f);
			color.a *= 0.5f;
			Gizmos.color = color;
			NavmeshBase navmeshBase = (NavmeshBase)((AstarPath.active != null) ? (((object)AstarPath.active.data.recastGraph) ?? ((object)AstarPath.active.data.navmesh)) : null);
			GraphTransform graphTransform = ((navmeshBase != null) ? navmeshBase.transform : GraphTransform.identityTransform);
			float y = GetY(graphTransform);
			float y2 = y - height * 0.5f;
			float y3 = y + height * 0.5f;
			for (int i = 0; i < list.Count; i++)
			{
				List<Vector3> list2 = list[i];
				for (int j = 0; j < list2.Count; j++)
				{
					Vector3 vector = graphTransform.InverseTransform(list2[j]);
					Vector3 vector2 = graphTransform.InverseTransform(list2[(j + 1) % list2.Count]);
					Vector3 point = vector;
					Vector3 point2 = vector2;
					Vector3 point3 = vector;
					Vector3 point4 = vector2;
					point.y = (point2.y = y2);
					point3.y = (point4.y = y3);
					Gizmos.DrawLine(graphTransform.Transform(point), graphTransform.Transform(point2));
					Gizmos.DrawLine(graphTransform.Transform(point3), graphTransform.Transform(point4));
					Gizmos.DrawLine(graphTransform.Transform(point), graphTransform.Transform(point3));
				}
			}
			ListPool<List<Vector3>>.Release(ref list);
		}
	}
	[Serializable]
	public class NavmeshUpdates
	{
		internal class NavmeshUpdateSettings
		{
			public TileHandler handler;

			public readonly List<IntRect> forcedReloadRects = new List<IntRect>();

			private readonly NavmeshBase graph;

			public NavmeshUpdateSettings(NavmeshBase graph)
			{
				this.graph = graph;
			}

			public void Refresh(bool forceCreate = false)
			{
				if (!graph.enableNavmeshCutting)
				{
					if (handler != null)
					{
						handler.cuts.Clear();
						handler.ReloadInBounds(new IntRect(int.MinValue, int.MinValue, int.MaxValue, int.MaxValue));
						AstarPath.active.FlushGraphUpdates();
						AstarPath.active.FlushWorkItems();
						forcedReloadRects.ClearFast();
						handler = null;
					}
				}
				else if ((handler == null && (forceCreate || NavmeshClipper.allEnabled.Count > 0)) || (handler != null && !handler.isValid))
				{
					handler = new TileHandler(graph);
					for (int i = 0; i < NavmeshClipper.allEnabled.Count; i++)
					{
						AddClipper(NavmeshClipper.allEnabled[i]);
					}
					handler.CreateTileTypesFromGraph();
					forcedReloadRects.Add(new IntRect(int.MinValue, int.MinValue, int.MaxValue, int.MaxValue));
				}
			}

			public void OnRecalculatedTiles(NavmeshTile[] tiles)
			{
				Refresh();
				if (handler != null)
				{
					handler.OnRecalculatedTiles(tiles);
				}
			}

			public void AddClipper(NavmeshClipper obj)
			{
				if (obj.graphMask.Contains((int)graph.graphIndex))
				{
					Refresh(forceCreate: true);
					if (handler != null)
					{
						Rect bounds = obj.GetBounds(handler.graph.transform);
						IntRect touchingTilesInGraphSpace = handler.graph.GetTouchingTilesInGraphSpace(bounds);
						handler.cuts.Add(obj, touchingTilesInGraphSpace);
					}
				}
			}

			public void RemoveClipper(NavmeshClipper obj)
			{
				Refresh();
				if (handler != null)
				{
					GridLookup<NavmeshClipper>.Root root = handler.cuts.GetRoot(obj);
					if (root != null)
					{
						forcedReloadRects.Add(root.previousBounds);
						handler.cuts.Remove(obj);
					}
				}
			}
		}

		public float updateInterval;

		private float lastUpdateTime = float.NegativeInfinity;

		internal void OnEnable()
		{
			NavmeshClipper.AddEnableCallback(HandleOnEnableCallback, HandleOnDisableCallback);
		}

		internal void OnDisable()
		{
			NavmeshClipper.RemoveEnableCallback(HandleOnEnableCallback, HandleOnDisableCallback);
		}

		public void DiscardPending()
		{
			for (int i = 0; i < NavmeshClipper.allEnabled.Count; i++)
			{
				NavmeshClipper.allEnabled[i].NotifyUpdated();
			}
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int j = 0; j < graphs.Length; j++)
			{
				if (graphs[j] is NavmeshBase navmeshBase)
				{
					navmeshBase.navmeshUpdateData.forcedReloadRects.Clear();
				}
			}
		}

		private void HandleOnEnableCallback(NavmeshClipper obj)
		{
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] is NavmeshBase navmeshBase)
				{
					navmeshBase.navmeshUpdateData.AddClipper(obj);
				}
			}
			obj.ForceUpdate();
		}

		private void HandleOnDisableCallback(NavmeshClipper obj)
		{
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] is NavmeshBase navmeshBase)
				{
					navmeshBase.navmeshUpdateData.RemoveClipper(obj);
				}
			}
			lastUpdateTime = float.NegativeInfinity;
		}

		internal void Update()
		{
			if (AstarPath.active.isScanning)
			{
				return;
			}
			bool flag = false;
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] is NavmeshBase navmeshBase)
				{
					navmeshBase.navmeshUpdateData.Refresh();
					flag = navmeshBase.navmeshUpdateData.forcedReloadRects.Count > 0;
				}
			}
			if ((updateInterval >= 0f && Time.realtimeSinceStartup - lastUpdateTime > updateInterval) || flag)
			{
				ForceUpdate();
			}
		}

		public void ForceUpdate()
		{
			lastUpdateTime = Time.realtimeSinceStartup;
			List<NavmeshClipper> list = null;
			NavGraph[] graphs = AstarPath.active.graphs;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (!(graphs[i] is NavmeshBase navmeshBase))
				{
					continue;
				}
				navmeshBase.navmeshUpdateData.Refresh();
				TileHandler handler = navmeshBase.navmeshUpdateData.handler;
				if (handler == null)
				{
					continue;
				}
				List<IntRect> forcedReloadRects = navmeshBase.navmeshUpdateData.forcedReloadRects;
				GridLookup<NavmeshClipper>.Root allItems = handler.cuts.AllItems;
				if (forcedReloadRects.Count == 0)
				{
					bool flag = false;
					for (GridLookup<NavmeshClipper>.Root root = allItems; root != null; root = root.next)
					{
						if (root.obj.RequiresUpdate())
						{
							flag = true;
							break;
						}
					}
					if (!flag)
					{
						continue;
					}
				}
				handler.StartBatchLoad();
				for (int j = 0; j < forcedReloadRects.Count; j++)
				{
					handler.ReloadInBounds(forcedReloadRects[j]);
				}
				forcedReloadRects.ClearFast();
				if (list == null)
				{
					list = ListPool<NavmeshClipper>.Claim();
				}
				for (GridLookup<NavmeshClipper>.Root root2 = allItems; root2 != null; root2 = root2.next)
				{
					if (root2.obj.RequiresUpdate())
					{
						handler.ReloadInBounds(root2.previousBounds);
						Rect bounds = root2.obj.GetBounds(handler.graph.transform);
						IntRect touchingTilesInGraphSpace = handler.graph.GetTouchingTilesInGraphSpace(bounds);
						handler.cuts.Move(root2.obj, touchingTilesInGraphSpace);
						handler.ReloadInBounds(touchingTilesInGraphSpace);
						list.Add(root2.obj);
					}
				}
				handler.EndBatchLoad();
			}
			if (list != null)
			{
				for (int k = 0; k < list.Count; k++)
				{
					list[k].NotifyUpdated();
				}
				ListPool<NavmeshClipper>.Release(ref list);
			}
		}
	}
	[AddComponentMenu("Pathfinding/Navmesh/RelevantGraphSurface")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_relevant_graph_surface.php")]
	public class RelevantGraphSurface : VersionedMonoBehaviour
	{
		private static RelevantGraphSurface root;

		public float maxRange = 1f;

		private RelevantGraphSurface prev;

		private RelevantGraphSurface next;

		private Vector3 position;

		public Vector3 Position => position;

		public RelevantGraphSurface Next => next;

		public RelevantGraphSurface Prev => prev;

		public static RelevantGraphSurface Root => root;

		public void UpdatePosition()
		{
			position = base.transform.position;
		}

		private void OnEnable()
		{
			UpdatePosition();
			if (root == null)
			{
				root = this;
				return;
			}
			next = root;
			root.prev = this;
			root = this;
		}

		private void OnDisable()
		{
			if (root == this)
			{
				root = next;
				if (root != null)
				{
					root.prev = null;
				}
			}
			else
			{
				if (prev != null)
				{
					prev.next = next;
				}
				if (next != null)
				{
					next.prev = prev;
				}
			}
			prev = null;
			next = null;
		}

		public static void UpdateAllPositions()
		{
			RelevantGraphSurface relevantGraphSurface = root;
			while (relevantGraphSurface != null)
			{
				relevantGraphSurface.UpdatePosition();
				relevantGraphSurface = relevantGraphSurface.Next;
			}
		}

		public static void FindAllGraphSurfaces()
		{
			RelevantGraphSurface[] array = UnityEngine.Object.FindObjectsOfType(typeof(RelevantGraphSurface)) as RelevantGraphSurface[];
			for (int i = 0; i < array.Length; i++)
			{
				array[i].OnDisable();
				array[i].OnEnable();
			}
		}

		public void OnDrawGizmos()
		{
			Gizmos.color = new Color(19f / 85f, 0.827451f, 0.18039216f, 0.4f);
			Gizmos.DrawLine(base.transform.position - Vector3.up * maxRange, base.transform.position + Vector3.up * maxRange);
		}

		public void OnDrawGizmosSelected()
		{
			Gizmos.color = new Color(19f / 85f, 0.827451f, 0.18039216f);
			Gizmos.DrawLine(base.transform.position - Vector3.up * maxRange, base.transform.position + Vector3.up * maxRange);
		}
	}
