	public class FloodPath : Path
	{
		public Vector3 originalStartPoint;

		public Vector3 startPoint;

		public GraphNode startNode;

		public bool saveParents = true;

		protected Dictionary<GraphNode, GraphNode> parents;

		public override bool FloodingPath => true;

		public bool HasPathTo(GraphNode node)
		{
			if (parents != null)
			{
				return parents.ContainsKey(node);
			}
			return false;
		}

		public GraphNode GetParent(GraphNode node)
		{
			return parents[node];
		}

		public static FloodPath Construct(Vector3 start, OnPathDelegate callback = null)
		{
			FloodPath floodPath = PathPool.GetPath<FloodPath>();
			floodPath.Setup(start, callback);
			return floodPath;
		}

		public static FloodPath Construct(GraphNode start, OnPathDelegate callback = null)
		{
			if (start == null)
			{
				throw new ArgumentNullException("start");
			}
			FloodPath floodPath = PathPool.GetPath<FloodPath>();
			floodPath.Setup(start, callback);
			return floodPath;
		}

		protected void Setup(Vector3 start, OnPathDelegate callback)
		{
			base.callback = callback;
			originalStartPoint = start;
			startPoint = start;
			heuristic = Heuristic.None;
		}

		protected void Setup(GraphNode start, OnPathDelegate callback)
		{
			base.callback = callback;
			originalStartPoint = (Vector3)start.position;
			startNode = start;
			startPoint = (Vector3)start.position;
			heuristic = Heuristic.None;
		}

		protected override void Reset()
		{
			base.Reset();
			originalStartPoint = Vector3.zero;
			startPoint = Vector3.zero;
			startNode = null;
			parents = new Dictionary<GraphNode, GraphNode>();
			saveParents = true;
		}

		protected override void Prepare()
		{
			if (startNode == null)
			{
				nnConstraint.tags = enabledTags;
				NNInfo nearest = AstarPath.active.GetNearest(originalStartPoint, nnConstraint);
				startPoint = nearest.position;
				startNode = nearest.node;
			}
			else
			{
				if (startNode.Destroyed)
				{
					FailWithError("Start node has been destroyed");
					return;
				}
				startPoint = (Vector3)startNode.position;
			}
			if (startNode == null)
			{
				FailWithError("Couldn't find a close node to the start point");
			}
			else if (!CanTraverse(startNode))
			{
				FailWithError("The node closest to the start point could not be traversed");
			}
		}

		protected override void Initialize()
		{
			PathNode pathNode = pathHandler.GetPathNode(startNode);
			pathNode.node = startNode;
			pathNode.pathID = pathHandler.PathID;
			pathNode.parent = null;
			pathNode.cost = 0u;
			pathNode.G = GetTraversalCost(startNode);
			pathNode.H = CalculateHScore(startNode);
			parents[startNode] = null;
			startNode.Open(this, pathNode, pathHandler);
			base.searchedNodes++;
			if (pathHandler.heap.isEmpty)
			{
				base.CompleteState = PathCompleteState.Complete;
			}
			else
			{
				currentR = pathHandler.heap.Remove();
			}
		}

		protected override void CalculateStep(long targetTick)
		{
			int num = 0;
			while (base.CompleteState == PathCompleteState.NotCalculated)
			{
				base.searchedNodes++;
				currentR.node.Open(this, currentR, pathHandler);
				if (saveParents)
				{
					parents[currentR.node] = currentR.parent.node;
				}
				if (pathHandler.heap.isEmpty)
				{
					base.CompleteState = PathCompleteState.Complete;
					break;
				}
				currentR = pathHandler.heap.Remove();
				if (num > 500)
				{
					if (DateTime.UtcNow.Ticks >= targetTick)
					{
						break;
					}
					num = 0;
					if (base.searchedNodes > 1000000)
					{
						throw new Exception("Probable infinite loop. Over 1,000,000 nodes searched");
					}
				}
				num++;
			}
		}
	}
	public class FloodPathConstraint : NNConstraint
	{
		private readonly FloodPath path;

		public FloodPathConstraint(FloodPath path)
		{
			if (path == null)
			{
				UnityEngine.Debug.LogWarning("FloodPathConstraint should not be used with a NULL path");
			}
			this.path = path;
		}

		public override bool Suitable(GraphNode node)
		{
			if (base.Suitable(node))
			{
				return path.HasPathTo(node);
			}
			return false;
		}
	}
	public class FloodPathTracer : ABPath
	{
		protected FloodPath flood;

		protected override bool hasEndPoint => false;

		public static FloodPathTracer Construct(Vector3 start, FloodPath flood, OnPathDelegate callback = null)
		{
			FloodPathTracer floodPathTracer = PathPool.GetPath<FloodPathTracer>();
			floodPathTracer.Setup(start, flood, callback);
			return floodPathTracer;
		}

		protected void Setup(Vector3 start, FloodPath flood, OnPathDelegate callback)
		{
			this.flood = flood;
			if (flood == null || flood.PipelineState < PathState.Returned)
			{
				throw new ArgumentException("You must supply a calculated FloodPath to the 'flood' argument");
			}
			Setup(start, flood.originalStartPoint, callback);
			nnConstraint = new FloodPathConstraint(flood);
		}

		protected override void Reset()
		{
			base.Reset();
			flood = null;
		}

		protected override void Initialize()
		{
			if (startNode != null && flood.HasPathTo(startNode))
			{
				Trace(startNode);
				base.CompleteState = PathCompleteState.Complete;
			}
			else
			{
				FailWithError("Could not find valid start node");
			}
		}

		protected override void CalculateStep(long targetTick)
		{
			if (base.CompleteState != PathCompleteState.Complete)
			{
				throw new Exception("Something went wrong. At this point the path should be completed");
			}
		}

		public void Trace(GraphNode from)
		{
			GraphNode graphNode = from;
			int num = 0;
			while (graphNode != null)
			{
				path.Add(graphNode);
				vectorPath.Add((Vector3)graphNode.position);
				graphNode = flood.GetParent(graphNode);
				num++;
				if (num > 1024)
				{
					UnityEngine.Debug.LogWarning("Inifinity loop? >1024 node path. Remove this message if you really have that long paths (FloodPathTracer.cs, Trace function)");
					break;
				}
			}
		}
	}
	public class MultiTargetPath : ABPath
	{
		public enum HeuristicMode
		{
			None,
			Average,
			MovingAverage,
			Midpoint,
			MovingMidpoint,
			Sequential
		}

		public OnPathDelegate[] callbacks;

		public GraphNode[] targetNodes;

		protected int targetNodeCount;

		public bool[] targetsFound;

		public Vector3[] targetPoints;

		public Vector3[] originalTargetPoints;

		public List<Vector3>[] vectorPaths;

		public List<GraphNode>[] nodePaths;

		public bool pathsForAll = true;

		public int chosenTarget = -1;

		private int sequentialTarget;

		public HeuristicMode heuristicMode = HeuristicMode.Sequential;

		public bool inverted { get; protected set; }

		public static MultiTargetPath Construct(Vector3[] startPoints, Vector3 target, OnPathDelegate[] callbackDelegates, OnPathDelegate callback = null)
		{
			MultiTargetPath multiTargetPath = Construct(target, startPoints, callbackDelegates, callback);
			multiTargetPath.inverted = true;
			return multiTargetPath;
		}

		public static MultiTargetPath Construct(Vector3 start, Vector3[] targets, OnPathDelegate[] callbackDelegates, OnPathDelegate callback = null)
		{
			MultiTargetPath multiTargetPath = PathPool.GetPath<MultiTargetPath>();
			multiTargetPath.Setup(start, targets, callbackDelegates, callback);
			return multiTargetPath;
		}

		protected void Setup(Vector3 start, Vector3[] targets, OnPathDelegate[] callbackDelegates, OnPathDelegate callback)
		{
			inverted = false;
			base.callback = callback;
			callbacks = callbackDelegates;
			if (callbacks != null && callbacks.Length != targets.Length)
			{
				throw new ArgumentException("The targets array must have the same length as the callbackDelegates array");
			}
			targetPoints = targets;
			originalStartPoint = start;
			startPoint = start;
			startIntPoint = (Int3)start;
			if (targets.Length == 0)
			{
				FailWithError("No targets were assigned to the MultiTargetPath");
				return;
			}
			endPoint = targets[0];
			originalTargetPoints = new Vector3[targetPoints.Length];
			for (int i = 0; i < targetPoints.Length; i++)
			{
				originalTargetPoints[i] = targetPoints[i];
			}
		}

		protected override void Reset()
		{
			base.Reset();
			pathsForAll = true;
			chosenTarget = -1;
			sequentialTarget = 0;
			inverted = true;
			heuristicMode = HeuristicMode.Sequential;
		}

		protected override void OnEnterPool()
		{
			if (vectorPaths != null)
			{
				for (int i = 0; i < vectorPaths.Length; i++)
				{
					if (vectorPaths[i] != null)
					{
						ListPool<Vector3>.Release(vectorPaths[i]);
					}
				}
			}
			vectorPaths = null;
			vectorPath = null;
			if (nodePaths != null)
			{
				for (int j = 0; j < nodePaths.Length; j++)
				{
					if (nodePaths[j] != null)
					{
						ListPool<GraphNode>.Release(nodePaths[j]);
					}
				}
			}
			nodePaths = null;
			path = null;
			callbacks = null;
			targetNodes = null;
			targetsFound = null;
			targetPoints = null;
			originalTargetPoints = null;
			base.OnEnterPool();
		}

		private void ChooseShortestPath()
		{
			chosenTarget = -1;
			if (nodePaths == null)
			{
				return;
			}
			uint num = 2147483647u;
			for (int i = 0; i < nodePaths.Length; i++)
			{
				List<GraphNode> list = nodePaths[i];
				if (list != null)
				{
					uint g = pathHandler.GetPathNode(list[(!inverted) ? (list.Count - 1) : 0]).G;
					if (chosenTarget == -1 || g < num)
					{
						chosenTarget = i;
						num = g;
					}
				}
			}
		}

		private void SetPathParametersForReturn(int target)
		{
			path = nodePaths[target];
			vectorPath = vectorPaths[target];
			if (inverted)
			{
				startNode = targetNodes[target];
				startPoint = targetPoints[target];
				originalStartPoint = originalTargetPoints[target];
			}
			else
			{
				endNode = targetNodes[target];
				endPoint = targetPoints[target];
				originalEndPoint = originalTargetPoints[target];
			}
		}

		protected override void ReturnPath()
		{
			if (base.error)
			{
				if (callbacks != null)
				{
					for (int i = 0; i < callbacks.Length; i++)
					{
						if (callbacks[i] != null)
						{
							callbacks[i](this);
						}
					}
				}
				if (callback != null)
				{
					callback(this);
				}
				return;
			}
			bool flag = false;
			if (inverted)
			{
				endPoint = startPoint;
				endNode = startNode;
				originalEndPoint = originalStartPoint;
			}
			for (int j = 0; j < nodePaths.Length; j++)
			{
				if (nodePaths[j] != null)
				{
					completeState = PathCompleteState.Complete;
					flag = true;
				}
				else
				{
					completeState = PathCompleteState.Error;
				}
				if (callbacks != null && callbacks[j] != null)
				{
					SetPathParametersForReturn(j);
					callbacks[j](this);
					vectorPaths[j] = vectorPath;
				}
			}
			if (flag)
			{
				completeState = PathCompleteState.Complete;
				SetPathParametersForReturn(chosenTarget);
			}
			else
			{
				completeState = PathCompleteState.Error;
			}
			if (callback != null)
			{
				callback(this);
			}
		}

		protected void FoundTarget(PathNode nodeR, int i)
		{
			nodeR.flag1 = false;
			Trace(nodeR);
			vectorPaths[i] = vectorPath;
			nodePaths[i] = path;
			vectorPath = ListPool<Vector3>.Claim();
			path = ListPool<GraphNode>.Claim();
			targetsFound[i] = true;
			targetNodeCount--;
			if (!pathsForAll)
			{
				base.CompleteState = PathCompleteState.Complete;
				targetNodeCount = 0;
			}
			else if (targetNodeCount <= 0)
			{
				base.CompleteState = PathCompleteState.Complete;
			}
			else
			{
				RecalculateHTarget(firstTime: false);
			}
		}

		protected void RebuildOpenList()
		{
			BinaryHeap heap = pathHandler.heap;
			for (int i = 0; i < heap.numberOfItems; i++)
			{
				PathNode node = heap.GetNode(i);
				node.H = CalculateHScore(node.node);
				heap.SetF(i, node.F);
			}
			pathHandler.heap.Rebuild();
		}

		protected override void Prepare()
		{
			nnConstraint.tags = enabledTags;
			NNInfo nearest = AstarPath.active.GetNearest(startPoint, nnConstraint);
			startNode = nearest.node;
			if (startNode == null)
			{
				FailWithError("Could not find start node for multi target path");
				return;
			}
			if (!CanTraverse(startNode))
			{
				FailWithError("The node closest to the start point could not be traversed");
				return;
			}
			if (nnConstraint is PathNNConstraint pathNNConstraint)
			{
				pathNNConstraint.SetStart(nearest.node);
			}
			vectorPaths = new List<Vector3>[targetPoints.Length];
			nodePaths = new List<GraphNode>[targetPoints.Length];
			targetNodes = new GraphNode[targetPoints.Length];
			targetsFound = new bool[targetPoints.Length];
			targetNodeCount = targetPoints.Length;
			bool flag = false;
			bool flag2 = false;
			bool flag3 = false;
			for (int i = 0; i < targetPoints.Length; i++)
			{
				NNInfo nearest2 = AstarPath.active.GetNearest(targetPoints[i], nnConstraint);
				targetNodes[i] = nearest2.node;
				targetPoints[i] = nearest2.position;
				if (targetNodes[i] != null)
				{
					flag3 = true;
					endNode = targetNodes[i];
				}
				bool flag4 = false;
				if (nearest2.node != null && CanTraverse(nearest2.node))
				{
					flag = true;
				}
				else
				{
					flag4 = true;
				}
				if (nearest2.node != null && nearest2.node.Area == startNode.Area)
				{
					flag2 = true;
				}
				else
				{
					flag4 = true;
				}
				if (flag4)
				{
					targetsFound[i] = true;
					targetNodeCount--;
				}
			}
			startPoint = nearest.position;
			startIntPoint = (Int3)startPoint;
			if (!flag3)
			{
				FailWithError("Couldn't find a valid node close to the any of the end points");
			}
			else if (!flag)
			{
				FailWithError("No target nodes could be traversed");
			}
			else if (!flag2)
			{
				FailWithError("There are no valid paths to the targets");
			}
			else
			{
				RecalculateHTarget(firstTime: true);
			}
		}

		private void RecalculateHTarget(bool firstTime)
		{
			if (!pathsForAll)
			{
				heuristic = Heuristic.None;
				heuristicScale = 0f;
				return;
			}
			switch (heuristicMode)
			{
			case HeuristicMode.None:
				heuristic = Heuristic.None;
				heuristicScale = 0f;
				break;
			case HeuristicMode.Average:
				if (!firstTime)
				{
					return;
				}
				goto case HeuristicMode.MovingAverage;
			case HeuristicMode.MovingAverage:
			{
				Vector3 zero = Vector3.zero;
				int num2 = 0;
				for (int j = 0; j < targetPoints.Length; j++)
				{
					if (!targetsFound[j])
					{
						zero += (Vector3)targetNodes[j].position;
						num2++;
					}
				}
				if (num2 == 0)
				{
					throw new Exception("Should not happen");
				}
				zero /= (float)num2;
				hTarget = (Int3)zero;
				break;
			}
			case HeuristicMode.Midpoint:
				if (!firstTime)
				{
					return;
				}
				goto case HeuristicMode.MovingMidpoint;
			case HeuristicMode.MovingMidpoint:
			{
				Vector3 vector = Vector3.zero;
				Vector3 vector2 = Vector3.zero;
				bool flag = false;
				for (int k = 0; k < targetPoints.Length; k++)
				{
					if (!targetsFound[k])
					{
						if (!flag)
						{
							vector = (Vector3)targetNodes[k].position;
							vector2 = (Vector3)targetNodes[k].position;
							flag = true;
						}
						else
						{
							vector = Vector3.Min((Vector3)targetNodes[k].position, vector);
							vector2 = Vector3.Max((Vector3)targetNodes[k].position, vector2);
						}
					}
				}
				Int3 @int = (Int3)((vector + vector2) * 0.5f);
				hTarget = @int;
				break;
			}
			case HeuristicMode.Sequential:
			{
				if (!firstTime && !targetsFound[sequentialTarget])
				{
					return;
				}
				float num = 0f;
				for (int i = 0; i < targetPoints.Length; i++)
				{
					if (!targetsFound[i])
					{
						float sqrMagnitude = (targetNodes[i].position - startNode.position).sqrMagnitude;
						if (sqrMagnitude > num)
						{
							num = sqrMagnitude;
							hTarget = (Int3)targetPoints[i];
							sequentialTarget = i;
						}
					}
				}
				break;
			}
			}
			if (!firstTime)
			{
				RebuildOpenList();
			}
		}

		protected override void Initialize()
		{
			PathNode pathNode = pathHandler.GetPathNode(startNode);
			pathNode.node = startNode;
			pathNode.pathID = base.pathID;
			pathNode.parent = null;
			pathNode.cost = 0u;
			pathNode.G = GetTraversalCost(startNode);
			pathNode.H = CalculateHScore(startNode);
			for (int i = 0; i < targetNodes.Length; i++)
			{
				if (startNode == targetNodes[i])
				{
					FoundTarget(pathNode, i);
				}
				else if (targetNodes[i] != null)
				{
					pathHandler.GetPathNode(targetNodes[i]).flag1 = true;
				}
			}
			if (targetNodeCount <= 0)
			{
				base.CompleteState = PathCompleteState.Complete;
				return;
			}
			startNode.Open(this, pathNode, pathHandler);
			base.searchedNodes++;
			if (pathHandler.heap.isEmpty)
			{
				FailWithError("No open points, the start node didn't open any nodes");
			}
			else
			{
				currentR = pathHandler.heap.Remove();
			}
		}

		protected override void Cleanup()
		{
			ChooseShortestPath();
			ResetFlags();
		}

		private void ResetFlags()
		{
			if (targetNodes == null)
			{
				return;
			}
			for (int i = 0; i < targetNodes.Length; i++)
			{
				if (targetNodes[i] != null)
				{
					pathHandler.GetPathNode(targetNodes[i]).flag1 = false;
				}
			}
		}

		protected override void CalculateStep(long targetTick)
		{
			int num = 0;
			while (base.CompleteState == PathCompleteState.NotCalculated)
			{
				base.searchedNodes++;
				if (currentR.flag1)
				{
					for (int i = 0; i < targetNodes.Length; i++)
					{
						if (!targetsFound[i] && currentR.node == targetNodes[i])
						{
							FoundTarget(currentR, i);
							if (base.CompleteState != PathCompleteState.NotCalculated)
							{
								break;
							}
						}
					}
					if (targetNodeCount <= 0)
					{
						base.CompleteState = PathCompleteState.Complete;
						break;
					}
				}
				currentR.node.Open(this, currentR, pathHandler);
				if (pathHandler.heap.isEmpty)
				{
					base.CompleteState = PathCompleteState.Complete;
					break;
				}
				currentR = pathHandler.heap.Remove();
				if (num > 500)
				{
					if (DateTime.UtcNow.Ticks >= targetTick)
					{
						break;
					}
					num = 0;
				}
				num++;
			}
		}

		protected override void Trace(PathNode node)
		{
			base.Trace(node);
			if (inverted)
			{
				int num = path.Count / 2;
				for (int i = 0; i < num; i++)
				{
					GraphNode value = path[i];
					path[i] = path[path.Count - i - 1];
					path[path.Count - i - 1] = value;
				}
				for (int j = 0; j < num; j++)
				{
					Vector3 value2 = vectorPath[j];
					vectorPath[j] = vectorPath[vectorPath.Count - j - 1];
					vectorPath[vectorPath.Count - j - 1] = value2;
				}
			}
		}

		protected override string DebugString(PathLog logMode)
		{
			if (logMode == PathLog.None || (!base.error && logMode == PathLog.OnlyErrors))
			{
				return "";
			}
			StringBuilder debugStringBuilder = pathHandler.DebugStringBuilder;
			debugStringBuilder.Length = 0;
			DebugStringPrefix(logMode, debugStringBuilder);
			if (!base.error)
			{
				debugStringBuilder.Append("\nShortest path was ");
				debugStringBuilder.Append((chosenTarget == -1) ? "undefined" : nodePaths[chosenTarget].Count.ToString());
				debugStringBuilder.Append(" nodes long");
				if (logMode == PathLog.Heavy)
				{
					debugStringBuilder.Append("\nPaths (").Append(targetsFound.Length).Append("):");
					Vector3 vector;
					for (int i = 0; i < targetsFound.Length; i++)
					{
						debugStringBuilder.Append("\n\n\tPath ").Append(i).Append(" Found: ")
							.Append(targetsFound[i]);
						if (nodePaths[i] == null)
						{
							continue;
						}
						debugStringBuilder.Append("\n\t\tLength: ");
						debugStringBuilder.Append(nodePaths[i].Count);
						if (nodePaths[i][nodePaths[i].Count - 1] != null)
						{
							PathNode pathNode = pathHandler.GetPathNode(endNode);
							if (pathNode != null)
							{
								debugStringBuilder.Append("\n\t\tEnd Node");
								debugStringBuilder.Append("\n\t\t\tG: ");
								debugStringBuilder.Append(pathNode.G);
								debugStringBuilder.Append("\n\t\t\tH: ");
								debugStringBuilder.Append(pathNode.H);
								debugStringBuilder.Append("\n\t\t\tF: ");
								debugStringBuilder.Append(pathNode.F);
								debugStringBuilder.Append("\n\t\t\tPoint: ");
								vector = endPoint;
								debugStringBuilder.Append(vector.ToString());
								debugStringBuilder.Append("\n\t\t\tGraph: ");
								debugStringBuilder.Append(endNode.GraphIndex);
							}
							else
							{
								debugStringBuilder.Append("\n\t\tEnd Node: Null");
							}
						}
					}
					debugStringBuilder.Append("\nStart Node");
					debugStringBuilder.Append("\n\tPoint: ");
					vector = endPoint;
					debugStringBuilder.Append(vector.ToString());
					debugStringBuilder.Append("\n\tGraph: ");
					debugStringBuilder.Append(startNode.GraphIndex);
					debugStringBuilder.Append("\nBinary Heap size at completion: ");
					debugStringBuilder.AppendLine((pathHandler.heap == null) ? "Null" : (pathHandler.heap.numberOfItems - 2).ToString());
				}
			}
			DebugStringSuffix(logMode, debugStringBuilder);
			return debugStringBuilder.ToString();
		}
	}
	public class RandomPath : ABPath
	{
		public int searchLength;

		public int spread = 5000;

		public float aimStrength;

		private PathNode chosenNodeR;

		private PathNode maxGScoreNodeR;

		private int maxGScore;

		public Vector3 aim;

		private int nodesEvaluatedRep;

		private readonly System.Random rnd = new System.Random();

		public override bool FloodingPath => true;

		protected override bool hasEndPoint => false;

		protected override void Reset()
		{
			base.Reset();
			searchLength = 5000;
			spread = 5000;
			aimStrength = 0f;
			chosenNodeR = null;
			maxGScoreNodeR = null;
			maxGScore = 0;
			aim = Vector3.zero;
			nodesEvaluatedRep = 0;
		}

		public static RandomPath Construct(Vector3 start, int length, OnPathDelegate callback = null)
		{
			RandomPath randomPath = PathPool.GetPath<RandomPath>();
			randomPath.Setup(start, length, callback);
			return randomPath;
		}

		protected RandomPath Setup(Vector3 start, int length, OnPathDelegate callback)
		{
			base.callback = callback;
			searchLength = length;
			originalStartPoint = start;
			originalEndPoint = Vector3.zero;
			startPoint = start;
			endPoint = Vector3.zero;
			startIntPoint = (Int3)start;
			return this;
		}

		protected override void ReturnPath()
		{
			if (path != null && path.Count > 0)
			{
				endNode = path[path.Count - 1];
				endPoint = (Vector3)endNode.position;
				originalEndPoint = endPoint;
				hTarget = endNode.position;
			}
			if (callback != null)
			{
				callback(this);
			}
		}

		protected override void Prepare()
		{
			nnConstraint.tags = enabledTags;
			NNInfo nearest = AstarPath.active.GetNearest(startPoint, nnConstraint);
			startPoint = nearest.position;
			endPoint = startPoint;
			startIntPoint = (Int3)startPoint;
			hTarget = (Int3)aim;
			startNode = nearest.node;
			endNode = startNode;
			if (startNode == null || endNode == null)
			{
				FailWithError("Couldn't find close nodes to the start point");
			}
			else if (!CanTraverse(startNode))
			{
				FailWithError("The node closest to the start point could not be traversed");
			}
			else
			{
				heuristicScale = aimStrength;
			}
		}

		protected override void Initialize()
		{
			PathNode pathNode = pathHandler.GetPathNode(startNode);
			pathNode.node = startNode;
			if (searchLength + spread <= 0)
			{
				base.CompleteState = PathCompleteState.Complete;
				Trace(pathNode);
				return;
			}
			pathNode.pathID = base.pathID;
			pathNode.parent = null;
			pathNode.cost = 0u;
			pathNode.G = GetTraversalCost(startNode);
			pathNode.H = CalculateHScore(startNode);
			startNode.Open(this, pathNode, pathHandler);
			base.searchedNodes++;
			if (pathHandler.heap.isEmpty)
			{
				FailWithError("No open points, the start node didn't open any nodes");
			}
			else
			{
				currentR = pathHandler.heap.Remove();
			}
		}

		protected override void CalculateStep(long targetTick)
		{
			int num = 0;
			while (base.CompleteState == PathCompleteState.NotCalculated)
			{
				base.searchedNodes++;
				if (currentR.G >= searchLength)
				{
					if (currentR.G > searchLength + spread)
					{
						if (chosenNodeR == null)
						{
							chosenNodeR = currentR;
						}
						base.CompleteState = PathCompleteState.Complete;
						break;
					}
					nodesEvaluatedRep++;
					if (rnd.NextDouble() <= (double)(1f / (float)nodesEvaluatedRep))
					{
						chosenNodeR = currentR;
					}
				}
				else if (currentR.G > maxGScore)
				{
					maxGScore = (int)currentR.G;
					maxGScoreNodeR = currentR;
				}
				currentR.node.Open(this, currentR, pathHandler);
				if (pathHandler.heap.isEmpty)
				{
					if (chosenNodeR != null)
					{
						base.CompleteState = PathCompleteState.Complete;
					}
					else if (maxGScoreNodeR != null)
					{
						chosenNodeR = maxGScoreNodeR;
						base.CompleteState = PathCompleteState.Complete;
					}
					else
					{
						FailWithError("Not a single node found to search");
					}
					break;
				}
				currentR = pathHandler.heap.Remove();
				if (num > 500)
				{
					if (DateTime.UtcNow.Ticks >= targetTick)
					{
						return;
					}
					num = 0;
					if (base.searchedNodes > 1000000)
					{
						throw new Exception("Probable infinite loop. Over 1,000,000 nodes searched");
					}
				}
				num++;
			}
			if (base.CompleteState == PathCompleteState.Complete)
			{
				Trace(chosenNodeR);
			}
		}
	}
	public class XPath : ABPath
	{
		public PathEndingCondition endingCondition;

		public new static XPath Construct(Vector3 start, Vector3 end, OnPathDelegate callback = null)
		{
			XPath xPath = PathPool.GetPath<XPath>();
			xPath.Setup(start, end, callback);
			xPath.endingCondition = new ABPathEndingCondition(xPath);
			return xPath;
		}

		protected override void Reset()
		{
			base.Reset();
			endingCondition = null;
		}

		protected override bool EndPointGridGraphSpecialCase(GraphNode endNode)
		{
			return false;
		}

		protected override void CompletePathIfStartIsValidTarget()
		{
			PathNode pathNode = pathHandler.GetPathNode(startNode);
			if (endingCondition.TargetFound(pathNode))
			{
				ChangeEndNode(startNode);
				Trace(pathNode);
				base.CompleteState = PathCompleteState.Complete;
			}
		}

		private void ChangeEndNode(GraphNode target)
		{
			if (endNode != null && endNode != startNode)
			{
				PathNode pathNode = pathHandler.GetPathNode(endNode);
				bool flag = (pathNode.flag2 = false);
				pathNode.flag1 = flag;
			}
			endNode = target;
			endPoint = (Vector3)target.position;
		}

		protected override void CalculateStep(long targetTick)
		{
			int num = 0;
			while (base.CompleteState == PathCompleteState.NotCalculated)
			{
				base.searchedNodes++;
				if (endingCondition.TargetFound(currentR))
				{
					base.CompleteState = PathCompleteState.Complete;
					break;
				}
				currentR.node.Open(this, currentR, pathHandler);
				if (pathHandler.heap.isEmpty)
				{
					FailWithError("Searched whole area but could not find target");
					return;
				}
				currentR = pathHandler.heap.Remove();
				if (num > 500)
				{
					if (DateTime.UtcNow.Ticks >= targetTick)
					{
						return;
					}
					num = 0;
					if (base.searchedNodes > 1000000)
					{
						throw new Exception("Probable infinite loop. Over 1,000,000 nodes searched");
					}
				}
				num++;
			}
			if (base.CompleteState == PathCompleteState.Complete)
			{
				ChangeEndNode(currentR.node);
				Trace(currentR);
			}
		}
	}
	public abstract class PathEndingCondition
	{
		protected Path path;

		protected PathEndingCondition()
		{
		}

		public PathEndingCondition(Path p)
		{
			if (p == null)
			{
				throw new ArgumentNullException("p");
			}
			path = p;
		}

		public abstract bool TargetFound(PathNode node);
	}
	public class ABPathEndingCondition : PathEndingCondition
	{
		protected ABPath abPath;

		public ABPathEndingCondition(ABPath p)
		{
			if (p == null)
			{
				throw new ArgumentNullException("p");
			}
			abPath = p;
			path = p;
		}

		public override bool TargetFound(PathNode node)
		{
			return node.node == abPath.endNode;
		}
	}
	public class EndingConditionProximity : ABPathEndingCondition
	{
		public float maxDistance = 10f;

		public EndingConditionProximity(ABPath p, float maxDistance)
			: base(p)
		{
			this.maxDistance = maxDistance;
		}

		public override bool TargetFound(PathNode node)
		{
			return ((Vector3)node.node.position - abPath.originalEndPoint).sqrMagnitude <= maxDistance * maxDistance;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_block_manager.php")]
	public class BlockManager : VersionedMonoBehaviour
	{
		public enum BlockMode
		{
			AllExceptSelector,
			OnlySelector
		}

		public class TraversalProvider : ITraversalProvider
		{
			private readonly BlockManager blockManager;

			private readonly List<SingleNodeBlocker> selector;

			public BlockMode mode { get; private set; }

			public TraversalProvider(BlockManager blockManager, BlockMode mode, List<SingleNodeBlocker> selector)
			{
				if (blockManager == null)
				{
					throw new ArgumentNullException("blockManager");
				}
				if (selector == null)
				{
					throw new ArgumentNullException("selector");
				}
				this.blockManager = blockManager;
				this.mode = mode;
				this.selector = selector;
			}

			public bool CanTraverse(Path path, GraphNode node)
			{
				if (!node.Walkable || ((path.enabledTags >> (int)node.Tag) & 1) == 0)
				{
					return false;
				}
				if (mode == BlockMode.OnlySelector)
				{
					return !blockManager.NodeContainsAnyOf(node, selector);
				}
				return !blockManager.NodeContainsAnyExcept(node, selector);
			}

			public uint GetTraversalCost(Path path, GraphNode node)
			{
				return path.GetTagPenalty((int)node.Tag) + node.Penalty;
			}
		}

		private Dictionary<GraphNode, List<SingleNodeBlocker>> blocked = new Dictionary<GraphNode, List<SingleNodeBlocker>>();

		private void Start()
		{
			if (!AstarPath.active)
			{
				throw new Exception("No AstarPath object in the scene");
			}
		}

		public bool NodeContainsAnyOf(GraphNode node, List<SingleNodeBlocker> selector)
		{
			if (!blocked.TryGetValue(node, out var value))
			{
				return false;
			}
			for (int i = 0; i < value.Count; i++)
			{
				SingleNodeBlocker singleNodeBlocker = value[i];
				for (int j = 0; j < selector.Count; j++)
				{
					if ((object)singleNodeBlocker == selector[j])
					{
						return true;
					}
				}
			}
			return false;
		}

		public bool NodeContainsAnyExcept(GraphNode node, List<SingleNodeBlocker> selector)
		{
			if (!blocked.TryGetValue(node, out var value))
			{
				return false;
			}
			for (int i = 0; i < value.Count; i++)
			{
				SingleNodeBlocker singleNodeBlocker = value[i];
				bool flag = false;
				for (int j = 0; j < selector.Count; j++)
				{
					if ((object)singleNodeBlocker == selector[j])
					{
						flag = true;
						break;
					}
				}
				if (!flag)
				{
					return true;
				}
			}
			return false;
		}

		public void InternalBlock(GraphNode node, SingleNodeBlocker blocker)
		{
			AstarPath.active.AddWorkItem(new AstarWorkItem((Action)delegate
			{
				if (!blocked.TryGetValue(node, out var value))
				{
					List<SingleNodeBlocker> list = (blocked[node] = ListPool<SingleNodeBlocker>.Claim());
					value = list;
				}
				value.Add(blocker);
			}, (Func<bool, bool>)null));
		}

		public void InternalUnblock(GraphNode node, SingleNodeBlocker blocker)
		{
			AstarPath.active.AddWorkItem(new AstarWorkItem((Action)delegate
			{
				if (blocked.TryGetValue(node, out var value))
				{
					value.Remove(blocker);
					if (value.Count == 0)
					{
						blocked.Remove(node);
						ListPool<SingleNodeBlocker>.Release(ref value);
					}
				}
			}, (Func<bool, bool>)null));
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_single_node_blocker.php")]
	public class SingleNodeBlocker : VersionedMonoBehaviour
	{
		public BlockManager manager;

		public GraphNode lastBlocked { get; private set; }

		public void BlockAtCurrentPosition()
		{
			BlockAt(base.transform.position);
		}

		public void BlockAt(Vector3 position)
		{
			Unblock();
			GraphNode node = AstarPath.active.GetNearest(position, NNConstraint.None).node;
			if (node != null)
			{
				Block(node);
			}
		}

		public void Block(GraphNode node)
		{
			if (node == null)
			{
				throw new ArgumentNullException("node");
			}
			manager.InternalBlock(node, this);
			lastBlocked = node;
		}

		public void Unblock()
		{
			if (lastBlocked == null || lastBlocked.Destroyed)
			{
				lastBlocked = null;
				return;
			}
			manager.InternalUnblock(lastBlocked, this);
			lastBlocked = null;
		}
	}
	public class AstarProfiler
	{
		public class ProfilePoint
		{
			public Stopwatch watch = new Stopwatch();

			public int totalCalls;

			public long tmpBytes;

			public long totalBytes;
		}

		private static readonly Dictionary<string, ProfilePoint> profiles = new Dictionary<string, ProfilePoint>();

		private static DateTime startTime = DateTime.UtcNow;

		public static ProfilePoint[] fastProfiles;

		public static string[] fastProfileNames;

		private AstarProfiler()
		{
		}

		[Conditional("ProfileAstar")]
		public static void InitializeFastProfile(string[] profileNames)
		{
			fastProfileNames = new string[profileNames.Length + 2];
			Array.Copy(profileNames, fastProfileNames, profileNames.Length);
			fastProfileNames[fastProfileNames.Length - 2] = "__Control1__";
			fastProfileNames[fastProfileNames.Length - 1] = "__Control2__";
			fastProfiles = new ProfilePoint[fastProfileNames.Length];
			for (int i = 0; i < fastProfiles.Length; i++)
			{
				fastProfiles[i] = new ProfilePoint();
			}
		}

		[Conditional("ProfileAstar")]
		public static void StartFastProfile(int tag)
		{
			fastProfiles[tag].watch.Start();
		}

		[Conditional("ProfileAstar")]
		public static void EndFastProfile(int tag)
		{
			ProfilePoint obj = fastProfiles[tag];
			obj.totalCalls++;
			obj.watch.Stop();
		}

		[Conditional("ASTAR_UNITY_PRO_PROFILER")]
		public static void EndProfile()
		{
		}

		[Conditional("ProfileAstar")]
		public static void StartProfile(string tag)
		{
			profiles.TryGetValue(tag, out var value);
			if (value == null)
			{
				value = new ProfilePoint();
				profiles[tag] = value;
			}
			value.tmpBytes = GC.GetTotalMemory(forceFullCollection: false);
			value.watch.Start();
		}

		[Conditional("ProfileAstar")]
		public static void EndProfile(string tag)
		{
			if (!profiles.ContainsKey(tag))
			{
				UnityEngine.Debug.LogError("Can only end profiling for a tag which has already been started (tag was " + tag + ")");
				return;
			}
			ProfilePoint profilePoint = profiles[tag];
			profilePoint.totalCalls++;
			profilePoint.watch.Stop();
			profilePoint.totalBytes += GC.GetTotalMemory(forceFullCollection: false) - profilePoint.tmpBytes;
		}

		[Conditional("ProfileAstar")]
		public static void Reset()
		{
			profiles.Clear();
			startTime = DateTime.UtcNow;
			if (fastProfiles != null)
			{
				for (int i = 0; i < fastProfiles.Length; i++)
				{
					fastProfiles[i] = new ProfilePoint();
				}
			}
		}

		[Conditional("ProfileAstar")]
		public static void PrintFastResults()
		{
			if (fastProfiles == null)
			{
				return;
			}
			for (int i = 0; i < 1000; i++)
			{
			}
			double num = fastProfiles[fastProfiles.Length - 2].watch.Elapsed.TotalMilliseconds / 1000.0;
			TimeSpan timeSpan = DateTime.UtcNow - startTime;
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("============================\n\t\t\t\tProfile results:\n============================\n");
			stringBuilder.Append("Name\t\t|\tTotal Time\t|\tTotal Calls\t|\tAvg/Call\t|\tBytes");
			for (int j = 0; j < fastProfiles.Length; j++)
			{
				string text = fastProfileNames[j];
				ProfilePoint profilePoint = fastProfiles[j];
				int totalCalls = profilePoint.totalCalls;
				double num2 = profilePoint.watch.Elapsed.TotalMilliseconds - num * (double)totalCalls;
				if (totalCalls >= 1)
				{
					stringBuilder.Append("\n").Append(text.PadLeft(10)).Append("|   ");
					stringBuilder.Append(num2.ToString("0.0 ").PadLeft(10)).Append(profilePoint.watch.Elapsed.TotalMilliseconds.ToString("(0.0)").PadLeft(10)).Append("|   ");
					stringBuilder.Append(totalCalls.ToString().PadLeft(10)).Append("|   ");
					stringBuilder.Append((num2 / (double)totalCalls).ToString("0.000").PadLeft(10));
				}
			}
			stringBuilder.Append("\n\n============================\n\t\tTotal runtime: ");
			stringBuilder.Append(timeSpan.TotalSeconds.ToString("F3"));
			stringBuilder.Append(" seconds\n============================");
			UnityEngine.Debug.Log(stringBuilder.ToString());
		}

		[Conditional("ProfileAstar")]
		public static void PrintResults()
		{
			TimeSpan timeSpan = DateTime.UtcNow - startTime;
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("============================\n\t\t\t\tProfile results:\n============================\n");
			int num = 5;
			foreach (KeyValuePair<string, ProfilePoint> profile in profiles)
			{
				num = Math.Max(profile.Key.Length, num);
			}
			stringBuilder.Append(" Name ".PadRight(num)).Append("|").Append(" Total Time\t".PadRight(20))
				.Append("|")
				.Append(" Total Calls ".PadRight(20))
				.Append("|")
				.Append(" Avg/Call ".PadRight(20));
			foreach (KeyValuePair<string, ProfilePoint> profile2 in profiles)
			{
				double totalMilliseconds = profile2.Value.watch.Elapsed.TotalMilliseconds;
				int totalCalls = profile2.Value.totalCalls;
				if (totalCalls >= 1)
				{
					string key = profile2.Key;
					stringBuilder.Append("\n").Append(key.PadRight(num)).Append("| ");
					stringBuilder.Append(totalMilliseconds.ToString("0.0").PadRight(20)).Append("| ");
					stringBuilder.Append(totalCalls.ToString().PadRight(20)).Append("| ");
					stringBuilder.Append((totalMilliseconds / (double)totalCalls).ToString("0.000").PadRight(20));
					stringBuilder.Append(AstarMath.FormatBytesBinary((int)profile2.Value.totalBytes).PadLeft(10));
				}
			}
			stringBuilder.Append("\n\n============================\n\t\tTotal runtime: ");
			stringBuilder.Append(timeSpan.TotalSeconds.ToString("F3"));
			stringBuilder.Append(" seconds\n============================");
			UnityEngine.Debug.Log(stringBuilder.ToString());
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_dynamic_grid_obstacle.php")]
	public class DynamicGridObstacle : GraphModifier
	{
		private Collider coll;

		private Collider2D coll2D;

		private Transform tr;

		public float updateError = 1f;

		public float checkTime = 0.2f;

		private Bounds prevBounds;

		private Quaternion prevRotation;

		private bool prevEnabled;

		private float lastCheckTime = -9999f;

		private Queue<GraphUpdateObject> pendingGraphUpdates = new Queue<GraphUpdateObject>();

		private Bounds bounds
		{
			get
			{
				if (coll != null)
				{
					return coll.bounds;
				}
				Bounds result = coll2D.bounds;
				result.extents += new Vector3(0f, 0f, 10000f);
				return result;
			}
		}

		private bool colliderEnabled
		{
			get
			{
				if (!(coll != null))
				{
					return coll2D.enabled;
				}
				return coll.enabled;
			}
		}

		protected override void Awake()
		{
			base.Awake();
			coll = GetComponent<Collider>();
			coll2D = GetComponent<Collider2D>();
			tr = base.transform;
			if (coll == null && coll2D == null && Application.isPlaying)
			{
				throw new Exception("A collider or 2D collider must be attached to the GameObject(" + base.gameObject.name + ") for the DynamicGridObstacle to work");
			}
			prevBounds = bounds;
			prevRotation = tr.rotation;
			prevEnabled = false;
		}

		public override void OnPostScan()
		{
			if (coll == null)
			{
				Awake();
			}
			if (coll != null)
			{
				prevEnabled = colliderEnabled;
			}
		}

		private void Update()
		{
			if (!Application.isPlaying)
			{
				return;
			}
			if (coll == null && coll2D == null)
			{
				UnityEngine.Debug.LogError("Removed collider from DynamicGridObstacle", this);
				base.enabled = false;
				return;
			}
			while (pendingGraphUpdates.Count > 0 && pendingGraphUpdates.Peek().stage != GraphUpdateStage.Pending)
			{
				pendingGraphUpdates.Dequeue();
			}
			if (AstarPath.active == null || AstarPath.active.isScanning || Time.realtimeSinceStartup - lastCheckTime < checkTime || !Application.isPlaying || pendingGraphUpdates.Count > 0)
			{
				return;
			}
			lastCheckTime = Time.realtimeSinceStartup;
			if (colliderEnabled)
			{
				Bounds bounds = this.bounds;
				Quaternion rotation = tr.rotation;
				Vector3 vector = prevBounds.min - bounds.min;
				Vector3 vector2 = prevBounds.max - bounds.max;
				float num = bounds.extents.magnitude * Quaternion.Angle(prevRotation, rotation) * (MathF.PI / 180f);
				if (vector.sqrMagnitude > updateError * updateError || vector2.sqrMagnitude > updateError * updateError || num > updateError || !prevEnabled)
				{
					DoUpdateGraphs();
				}
			}
			else if (prevEnabled)
			{
				DoUpdateGraphs();
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			if (AstarPath.active != null && Application.isPlaying)
			{
				GraphUpdateObject graphUpdateObject = new GraphUpdateObject(prevBounds);
				pendingGraphUpdates.Enqueue(graphUpdateObject);
				AstarPath.active.UpdateGraphs(graphUpdateObject);
				prevEnabled = false;
			}
			pendingGraphUpdates.Clear();
		}

		public void DoUpdateGraphs()
		{
			if (coll == null && coll2D == null)
			{
				return;
			}
			Physics.SyncTransforms();
			Physics2D.SyncTransforms();
			if (!colliderEnabled)
			{
				GraphUpdateObject graphUpdateObject = new GraphUpdateObject(prevBounds);
				pendingGraphUpdates.Enqueue(graphUpdateObject);
				AstarPath.active.UpdateGraphs(graphUpdateObject);
			}
			else
			{
				Bounds bounds = this.bounds;
				Bounds b = bounds;
				b.Encapsulate(prevBounds);
				if (BoundsVolume(b) < BoundsVolume(bounds) + BoundsVolume(prevBounds))
				{
					GraphUpdateObject graphUpdateObject2 = new GraphUpdateObject(b);
					pendingGraphUpdates.Enqueue(graphUpdateObject2);
					AstarPath.active.UpdateGraphs(graphUpdateObject2);
				}
				else
				{
					GraphUpdateObject graphUpdateObject3 = new GraphUpdateObject(prevBounds);
					GraphUpdateObject graphUpdateObject4 = new GraphUpdateObject(bounds);
					pendingGraphUpdates.Enqueue(graphUpdateObject3);
					pendingGraphUpdates.Enqueue(graphUpdateObject4);
					AstarPath.active.UpdateGraphs(graphUpdateObject3);
					AstarPath.active.UpdateGraphs(graphUpdateObject4);
				}
				prevBounds = bounds;
			}
			prevEnabled = colliderEnabled;
			prevRotation = tr.rotation;
			lastCheckTime = Time.realtimeSinceStartup;
		}

		private static float BoundsVolume(Bounds b)
		{
			return Math.Abs(b.size.x * b.size.y * b.size.z);
		}
	}
	public class Funnel
	{
		public struct FunnelPortals
		{
			public List<Vector3> left;

			public List<Vector3> right;
		}

		public struct PathPart
		{
			public int startIndex;

			public int endIndex;

			public Vector3 startPoint;

			public Vector3 endPoint;

			public bool isLink;
		}

		public static List<PathPart> SplitIntoParts(Path path)
		{
			List<GraphNode> path2 = path.path;
			List<PathPart> list = ListPool<PathPart>.Claim();
			if (path2 == null || path2.Count == 0)
			{
				return list;
			}
			int i;
			for (i = 0; i < path2.Count; i++)
			{
				if (path2[i] is TriangleMeshNode || path2[i] is GridNodeBase)
				{
					PathPart item = new PathPart
					{
						startIndex = i
					};
					for (uint graphIndex = path2[i].GraphIndex; i < path2.Count && (path2[i].GraphIndex == graphIndex || path2[i] is NodeLink3Node); i++)
					{
					}
					i = (item.endIndex = i - 1);
					if (item.startIndex == 0)
					{
						item.startPoint = path.vectorPath[0];
					}
					else
					{
						item.startPoint = (Vector3)path2[item.startIndex - 1].position;
					}
					if (item.endIndex == path2.Count - 1)
					{
						item.endPoint = path.vectorPath[path.vectorPath.Count - 1];
					}
					else
					{
						item.endPoint = (Vector3)path2[item.endIndex + 1].position;
					}
					list.Add(item);
				}
				else
				{
					if (!(NodeLink2.GetNodeLink(path2[i]) != null))
					{
						throw new Exception("Unsupported node type or null node");
					}
					PathPart item2 = new PathPart
					{
						startIndex = i
					};
					uint graphIndex2 = path2[i].GraphIndex;
					for (i++; i < path2.Count && path2[i].GraphIndex == graphIndex2; i++)
					{
					}
					i--;
					if (i - item2.startIndex != 0)
					{
						if (i - item2.startIndex != 1)
						{
							throw new Exception("NodeLink2 link length greater than two (2) nodes. " + (i - item2.startIndex + 1));
						}
						item2.endIndex = i;
						item2.isLink = true;
						item2.startPoint = (Vector3)path2[item2.startIndex].position;
						item2.endPoint = (Vector3)path2[item2.endIndex].position;
						list.Add(item2);
					}
				}
			}
			return list;
		}

		public static FunnelPortals ConstructFunnelPortals(List<GraphNode> nodes, PathPart part)
		{
			if (nodes == null || nodes.Count == 0)
			{
				return new FunnelPortals
				{
					left = ListPool<Vector3>.Claim(0),
					right = ListPool<Vector3>.Claim(0)
				};
			}
			if (part.endIndex < part.startIndex || part.startIndex < 0 || part.endIndex > nodes.Count)
			{
				throw new ArgumentOutOfRangeException();
			}
			List<Vector3> list = ListPool<Vector3>.Claim(nodes.Count + 1);
			List<Vector3> list2 = ListPool<Vector3>.Claim(nodes.Count + 1);
			list.Add(part.startPoint);
			list2.Add(part.startPoint);
			for (int i = part.startIndex; i < part.endIndex; i++)
			{
				if (!nodes[i].GetPortal(nodes[i + 1], list, list2, backwards: false))
				{
					list.Add((Vector3)nodes[i].position);
					list2.Add((Vector3)nodes[i].position);
					list.Add((Vector3)nodes[i + 1].position);
					list2.Add((Vector3)nodes[i + 1].position);
				}
			}
			list.Add(part.endPoint);
			list2.Add(part.endPoint);
			return new FunnelPortals
			{
				left = list,
				right = list2
			};
		}

		public static void ShrinkPortals(FunnelPortals portals, float shrink)
		{
			if (shrink <= 1E-05f)
			{
				return;
			}
			for (int i = 0; i < portals.left.Count; i++)
			{
				Vector3 vector = portals.left[i];
				Vector3 vector2 = portals.right[i];
				float magnitude = (vector - vector2).magnitude;
				if (magnitude > 0f)
				{
					float num = Mathf.Min(shrink / magnitude, 0.4f);
					portals.left[i] = Vector3.Lerp(vector, vector2, num);
					portals.right[i] = Vector3.Lerp(vector, vector2, 1f - num);
				}
			}
		}

		private static bool UnwrapHelper(Vector3 portalStart, Vector3 portalEnd, Vector3 prevPoint, Vector3 nextPoint, ref Quaternion mRot, ref Vector3 mOffset)
		{
			if (VectorMath.IsColinear(portalStart, portalEnd, nextPoint))
			{
				return false;
			}
			Vector3 vector = portalEnd - portalStart;
			float sqrMagnitude = vector.sqrMagnitude;
			prevPoint -= Vector3.Dot(prevPoint - portalStart, vector) / sqrMagnitude * vector;
			nextPoint -= Vector3.Dot(nextPoint - portalStart, vector) / sqrMagnitude * vector;
			Quaternion quaternion = Quaternion.FromToRotation(nextPoint - portalStart, portalStart - prevPoint);
			mOffset += mRot * (portalStart - quaternion * portalStart);
			mRot *= quaternion;
			return true;
		}

		public static void Unwrap(FunnelPortals funnel, Vector2[] left, Vector2[] right)
		{
			int num = 1;
			Vector3 fromDirection = Vector3.Cross(funnel.right[1] - funnel.left[0], funnel.left[1] - funnel.left[0]);
			while (fromDirection.sqrMagnitude <= 1E-08f && num + 1 < funnel.left.Count)
			{
				num++;
				fromDirection = Vector3.Cross(funnel.right[num] - funnel.left[0], funnel.left[num] - funnel.left[0]);
			}
			left[0] = (right[0] = Vector2.zero);
			Vector3 vector = funnel.left[1];
			Vector3 vector2 = funnel.right[1];
			Vector3 prevPoint = funnel.left[0];
			Quaternion mRot = Quaternion.FromToRotation(fromDirection, Vector3.forward);
			Vector3 mOffset = mRot * -funnel.right[0];
			for (int i = 1; i < funnel.left.Count; i++)
			{
				if (UnwrapHelper(vector, vector2, prevPoint, funnel.left[i], ref mRot, ref mOffset))
				{
					prevPoint = vector;
					vector = funnel.left[i];
				}
				left[i] = mRot * funnel.left[i] + mOffset;
				if (UnwrapHelper(vector, vector2, prevPoint, funnel.right[i], ref mRot, ref mOffset))
				{
					prevPoint = vector2;
					vector2 = funnel.right[i];
				}
				right[i] = mRot * funnel.right[i] + mOffset;
			}
		}

		private static int FixFunnel(Vector2[] left, Vector2[] right, int numPortals)
		{
			if (numPortals > left.Length || numPortals > right.Length)
			{
				throw new ArgumentException("Arrays do not have as many elements as specified");
			}
			if (numPortals < 3)
			{
				return -1;
			}
			int num = 0;
			while (left[num + 1] == left[num + 2] && right[num + 1] == right[num + 2])
			{
				left[num + 1] = left[num];
				right[num + 1] = right[num];
				num++;
				if (numPortals - num < 3)
				{
					return -1;
				}
			}
			return num;
		}

		protected static Vector2 ToXZ(Vector3 p)
		{
			return new Vector2(p.x, p.z);
		}

		protected static Vector3 FromXZ(Vector2 p)
		{
			return new Vector3(p.x, 0f, p.y);
		}

		protected static bool RightOrColinear(Vector2 a, Vector2 b)
		{
			return a.x * b.y - b.x * a.y <= 0f;
		}

		protected static bool LeftOrColinear(Vector2 a, Vector2 b)
		{
			return a.x * b.y - b.x * a.y >= 0f;
		}

		public static List<Vector3> Calculate(FunnelPortals funnel, bool unwrap, bool splitAtEveryPortal)
		{
			if (funnel.left.Count != funnel.right.Count)
			{
				throw new ArgumentException("funnel.left.Count != funnel.right.Count");
			}
			Vector2[] array = ArrayPool<Vector2>.Claim(funnel.left.Count);
			Vector2[] array2 = ArrayPool<Vector2>.Claim(funnel.left.Count);
			if (unwrap)
			{
				Unwrap(funnel, array, array2);
			}
			else
			{
				for (int i = 0; i < funnel.left.Count; i++)
				{
					array[i] = ToXZ(funnel.left[i]);
					array2[i] = ToXZ(funnel.right[i]);
				}
			}
			int num = FixFunnel(array, array2, funnel.left.Count);
			List<int> list = ListPool<int>.Claim();
			if (num == -1)
			{
				list.Add(0);
				list.Add(funnel.left.Count - 1);
			}
			else
			{
				Calculate(array, array2, funnel.left.Count, num, list, int.MaxValue, out var _);
			}
			List<Vector3> list2 = ListPool<Vector3>.Claim(list.Count);
			Vector2 vector = array[0];
			int num2 = 0;
			for (int j = 0; j < list.Count; j++)
			{
				int num3 = list[j];
				if (splitAtEveryPortal)
				{
					Vector2 vector2 = ((num3 >= 0) ? array[num3] : array2[-num3]);
					for (int k = num2 + 1; k < Math.Abs(num3); k++)
					{
						if (!VectorMath.LineLineIntersectionFactor(array[k], array2[k] - array[k], vector, vector2 - vector, out var t))
						{
							t = 0.5f;
						}
						list2.Add(Vector3.Lerp(funnel.left[k], funnel.right[k], t));
					}
					num2 = Mathf.Abs(num3);
					vector = vector2;
				}
				if (num3 >= 0)
				{
					list2.Add(funnel.left[num3]);
				}
				else
				{
					list2.Add(funnel.right[-num3]);
				}
			}
			ListPool<int>.Release(ref list);
			ArrayPool<Vector2>.Release(ref array);
			ArrayPool<Vector2>.Release(ref array2);
			return list2;
		}

		private static void Calculate(Vector2[] left, Vector2[] right, int numPortals, int startIndex, List<int> funnelPath, int maxCorners, out bool lastCorner)
		{
			if (left.Length != right.Length)
			{
				throw new ArgumentException();
			}
			lastCorner = false;
			int num = startIndex;
			int num2 = startIndex + 1;
			int num3 = startIndex + 1;
			Vector2 vector = left[num];
			Vector2 vector2 = left[num3];
			Vector2 vector3 = right[num2];
			funnelPath.Add(num);
			for (int i = startIndex + 2; i < numPortals; i++)
			{
				if (funnelPath.Count >= maxCorners)
				{
					return;
				}
				if (funnelPath.Count > 2000)
				{
					UnityEngine.Debug.LogWarning("Avoiding infinite loop. Remove this check if you have this long paths.");
					break;
				}
				Vector2 vector4 = left[i];
				Vector2 vector5 = right[i];
				if (LeftOrColinear(vector3 - vector, vector5 - vector))
				{
					if (!(vector == vector3) && !RightOrColinear(vector2 - vector, vector5 - vector))
					{
						vector = (vector3 = vector2);
						i = (num = (num2 = num3));
						funnelPath.Add(num);
						continue;
					}
					vector3 = vector5;
					num2 = i;
				}
				if (RightOrColinear(vector2 - vector, vector4 - vector))
				{
					if (vector == vector2 || LeftOrColinear(vector3 - vector, vector4 - vector))
					{
						vector2 = vector4;
						num3 = i;
					}
					else
					{
						vector = (vector2 = vector3);
						i = (num = (num3 = num2));
						funnelPath.Add(-num);
					}
				}
			}
			lastCorner = true;
			funnelPath.Add(numPortals - 1);
		}
	}
	public static class GraphUpdateUtilities
	{
		public static bool UpdateGraphsNoBlock(GraphUpdateObject guo, GraphNode node1, GraphNode node2, bool alwaysRevert = false)
		{
			List<GraphNode> list = ListPool<GraphNode>.Claim();
			list.Add(node1);
			list.Add(node2);
			bool result = UpdateGraphsNoBlock(guo, list, alwaysRevert);
			ListPool<GraphNode>.Release(ref list);
			return result;
		}

		public static bool UpdateGraphsNoBlock(GraphUpdateObject guo, List<GraphNode> nodes, bool alwaysRevert = false)
		{
			PathProcessor.GraphUpdateLock graphUpdateLock = AstarPath.active.PausePathfinding();
			bool flag;
			try
			{
				AstarPath.active.FlushGraphUpdates();
				for (int i = 0; i < nodes.Count; i++)
				{
					if (!nodes[i].Walkable)
					{
						return false;
					}
				}
				guo.trackChangedNodes = true;
				AstarPath.active.UpdateGraphs(guo);
				AstarPath.active.FlushGraphUpdates();
				flag = PathUtilities.IsPathPossible(nodes);
				if (!flag || alwaysRevert)
				{
					guo.RevertFromBackup();
					AstarPath.active.hierarchicalGraph.RecalculateIfNecessary();
				}
			}
			finally
			{
				graphUpdateLock.Release();
			}
			guo.trackChangedNodes = false;
			return flag;
		}
	}
	public static class PathUtilities
	{
		private static Queue<GraphNode> BFSQueue;

		private static Dictionary<GraphNode, int> BFSMap;

		public static bool IsPathPossible(GraphNode node1, GraphNode node2)
		{
			if (node1.Walkable && node2.Walkable)
			{
				return node1.Area == node2.Area;
			}
			return false;
		}

		public static bool IsPathPossible(List<GraphNode> nodes)
		{
			if (nodes.Count == 0)
			{
				return true;
			}
			uint area = nodes[0].Area;
			for (int i = 0; i < nodes.Count; i++)
			{
				if (!nodes[i].Walkable || nodes[i].Area != area)
				{
					return false;
				}
			}
			return true;
		}

		public static bool IsPathPossible(List<GraphNode> nodes, int tagMask)
		{
			if (nodes.Count == 0)
			{
				return true;
			}
			if (((tagMask >> (int)nodes[0].Tag) & 1) == 0)
			{
				return false;
			}
			if (!IsPathPossible(nodes))
			{
				return false;
			}
			List<GraphNode> list = GetReachableNodes(nodes[0], tagMask);
			bool result = true;
			for (int i = 1; i < nodes.Count; i++)
			{
				if (!list.Contains(nodes[i]))
				{
					result = false;
					break;
				}
			}
			ListPool<GraphNode>.Release(ref list);
			return result;
		}

		public static List<GraphNode> GetReachableNodes(GraphNode seed, int tagMask = -1, Func<GraphNode, bool> filter = null)
		{
			Stack<GraphNode> dfsStack = StackPool<GraphNode>.Claim();
			List<GraphNode> reachable = ListPool<GraphNode>.Claim();
			HashSet<GraphNode> map = new HashSet<GraphNode>();
			Action<GraphNode> action = ((tagMask != -1 || filter != null) ? ((Action<GraphNode>)delegate(GraphNode node)
			{
				if (node.Walkable && ((tagMask >> (int)node.Tag) & 1) != 0 && map.Add(node) && (filter == null || filter(node)))
				{
					reachable.Add(node);
					dfsStack.Push(node);
				}
			}) : ((Action<GraphNode>)delegate(GraphNode node)
			{
				if (node.Walkable && map.Add(node))
				{
					reachable.Add(node);
					dfsStack.Push(node);
				}
			}));
			action(seed);
			while (dfsStack.Count > 0)
			{
				dfsStack.Pop().GetConnections(action);
			}
			StackPool<GraphNode>.Release(dfsStack);
			return reachable;
		}

		public static List<GraphNode> BFS(GraphNode seed, int depth, int tagMask = -1, Func<GraphNode, bool> filter = null)
		{
			BFSQueue = BFSQueue ?? new Queue<GraphNode>();
			Queue<GraphNode> que = BFSQueue;
			BFSMap = BFSMap ?? new Dictionary<GraphNode, int>();
			Dictionary<GraphNode, int> map = BFSMap;
			que.Clear();
			map.Clear();
			List<GraphNode> result = ListPool<GraphNode>.Claim();
			int currentDist = -1;
			Action<GraphNode> action = ((tagMask != -1) ? ((Action<GraphNode>)delegate(GraphNode node)
			{
				if (node.Walkable && ((tagMask >> (int)node.Tag) & 1) != 0 && !map.ContainsKey(node) && (filter == null || filter(node)))
				{
					map.Add(node, currentDist + 1);
					result.Add(node);
					que.Enqueue(node);
				}
			}) : ((Action<GraphNode>)delegate(GraphNode node)
			{
				if (node.Walkable && !map.ContainsKey(node) && (filter == null || filter(node)))
				{
					map.Add(node, currentDist + 1);
					result.Add(node);
					que.Enqueue(node);
				}
			}));
			action(seed);
			while (que.Count > 0)
			{
				GraphNode graphNode = que.Dequeue();
				currentDist = map[graphNode];
				if (currentDist >= depth)
				{
					break;
				}
				graphNode.GetConnections(action);
			}
			que.Clear();
			map.Clear();
			return result;
		}

		public static List<Vector3> GetSpiralPoints(int count, float clearance)
		{
			List<Vector3> list = ListPool<Vector3>.Claim(count);
			float num = clearance / (MathF.PI * 2f);
			float num2 = 0f;
			list.Add(InvoluteOfCircle(num, num2));
			for (int i = 0; i < count; i++)
			{
				Vector3 vector = list[list.Count - 1];
				float num3 = (0f - num2) / 2f + Mathf.Sqrt(num2 * num2 / 4f + 2f * clearance / num);
				float num4 = num2 + num3;
				float num5 = num2 + 2f * num3;
				while (num5 - num4 > 0.01f)
				{
					float num6 = (num4 + num5) / 2f;
					if ((InvoluteOfCircle(num, num6) - vector).sqrMagnitude < clearance * clearance)
					{
						num4 = num6;
					}
					else
					{
						num5 = num6;
					}
				}
				list.Add(InvoluteOfCircle(num, num5));
				num2 = num5;
			}
			return list;
		}

		private static Vector3 InvoluteOfCircle(float a, float t)
		{
			return new Vector3(a * (Mathf.Cos(t) + t * Mathf.Sin(t)), 0f, a * (Mathf.Sin(t) - t * Mathf.Cos(t)));
		}

		public static void GetPointsAroundPointWorld(Vector3 p, IRaycastableGraph g, List<Vector3> previousPoints, float radius, float clearanceRadius)
		{
			if (previousPoints.Count != 0)
			{
				Vector3 zero = Vector3.zero;
				for (int i = 0; i < previousPoints.Count; i++)
				{
					zero += previousPoints[i];
				}
				zero /= (float)previousPoints.Count;
				for (int j = 0; j < previousPoints.Count; j++)
				{
					previousPoints[j] -= zero;
				}
				GetPointsAroundPoint(p, g, previousPoints, radius, clearanceRadius);
			}
		}

		public static void GetPointsAroundPoint(Vector3 center, IRaycastableGraph g, List<Vector3> previousPoints, float radius, float clearanceRadius)
		{
			if (g == null)
			{
				throw new ArgumentNullException("g");
			}
			NNInfoInternal nearestForce = ((g as NavGraph) ?? throw new ArgumentException("g is not a NavGraph")).GetNearestForce(center, NNConstraint.Default);
			center = nearestForce.clampedPosition;
			if (nearestForce.node == null)
			{
				return;
			}
			radius = Mathf.Max(radius, 1.4142f * clearanceRadius * Mathf.Sqrt(previousPoints.Count));
			clearanceRadius *= clearanceRadius;
			for (int i = 0; i < previousPoints.Count; i++)
			{
				Vector3 vector = previousPoints[i];
				float magnitude = vector.magnitude;
				if (magnitude > 0f)
				{
					vector /= magnitude;
				}
				float num = radius;
				vector *= num;
				int num2 = 0;
				while (true)
				{
					Vector3 vector2 = center + vector;
					if (g.Linecast(center, vector2, out var hit))
					{
						if (hit.point == Vector3.zero)
						{
							num2++;
							if (num2 > 8)
							{
								previousPoints[i] = vector2;
								break;
							}
						}
						else
						{
							vector2 = hit.point;
						}
					}
					bool flag = false;
					for (float num3 = 0.1f; num3 <= 1f; num3 += 0.05f)
					{
						Vector3 vector3 = Vector3.Lerp(center, vector2, num3);
						flag = true;
						for (int j = 0; j < i; j++)
						{
							if ((previousPoints[j] - vector3).sqrMagnitude < clearanceRadius)
							{
								flag = false;
								break;
							}
						}
						if (flag || num2 > 8)
						{
							flag = true;
							previousPoints[i] = vector3;
							break;
						}
					}
					if (flag)
					{
						break;
					}
					clearanceRadius *= 0.9f;
					vector = UnityEngine.Random.onUnitSphere * Mathf.Lerp(num, radius, num2 / 5);
					vector.y = 0f;
					num2++;
				}
			}
		}

		public static List<Vector3> GetPointsOnNodes(List<GraphNode> nodes, int count, float clearanceRadius = 0f)
		{
			if (nodes == null)
			{
				throw new ArgumentNullException("nodes");
			}
			if (nodes.Count == 0)
			{
				throw new ArgumentException("no nodes passed");
			}
			List<Vector3> list = ListPool<Vector3>.Claim(count);
			clearanceRadius *= clearanceRadius;
			if (clearanceRadius > 0f || nodes[0] is TriangleMeshNode || nodes[0] is GridNode)
			{
				List<float> list2 = ListPool<float>.Claim(nodes.Count);
				float num = 0f;
				for (int i = 0; i < nodes.Count; i++)
				{
					float num2 = nodes[i].SurfaceArea();
					num2 += 0.001f;
					num += num2;
					list2.Add(num);
				}
				for (int j = 0; j < count; j++)
				{
					int num3 = 0;
					int num4 = 10;
					bool flag = false;
					while (!flag)
					{
						flag = true;
						if (num3 >= num4)
						{
							clearanceRadius *= 0.80999994f;
							num4 += 10;
							if (num4 > 100)
							{
								clearanceRadius = 0f;
							}
						}
						float item = UnityEngine.Random.value * num;
						int num5 = list2.BinarySearch(item);
						if (num5 < 0)
						{
							num5 = ~num5;
						}
						if (num5 >= nodes.Count)
						{
							flag = false;
							continue;
						}
						Vector3 vector = nodes[num5].RandomPointOnSurface();
						if (clearanceRadius > 0f)
						{
							for (int k = 0; k < list.Count; k++)
							{
								if ((list[k] - vector).sqrMagnitude < clearanceRadius)
								{
									flag = false;
									break;
								}
							}
						}
						if (flag)
						{
							list.Add(vector);
							break;
						}
						num3++;
					}
				}
				ListPool<float>.Release(ref list2);
			}
			else
			{
				for (int l = 0; l < count; l++)
				{
					list.Add(nodes[UnityEngine.Random.Range(0, nodes.Count)].RandomPointOnSurface());
				}
			}
			return list;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_procedural_grid_mover.php")]
	public class ProceduralGridMover : VersionedMonoBehaviour
	{
		public float updateDistance = 10f;

		public Transform target;

		private GridNodeBase[] buffer;

		public GridGraph graph;

		[HideInInspector]
		public int graphIndex;

		public bool updatingGraph { get; private set; }

		private void Start()
		{
			if (AstarPath.active == null)
			{
				throw new Exception("There is no AstarPath object in the scene");
			}
			if (graph == null)
			{
				if (graphIndex < 0)
				{
					throw new Exception("Graph index should not be negative");
				}
				if (graphIndex >= AstarPath.active.data.graphs.Length)
				{
					throw new Exception("The ProceduralGridMover was configured to use graph index " + graphIndex + ", but only " + AstarPath.active.data.graphs.Length + " graphs exist");
				}
				graph = AstarPath.active.data.graphs[graphIndex] as GridGraph;
				if (graph == null)
				{
					throw new Exception("The ProceduralGridMover was configured to use graph index " + graphIndex + " but that graph either does not exist or is not a GridGraph or LayerGridGraph");
				}
			}
			UpdateGraph();
		}

		private void Update()
		{
			if (graph != null)
			{
				Vector3 a = PointToGraphSpace(graph.center);
				Vector3 b = PointToGraphSpace(target.position);
				if (VectorMath.SqrDistanceXZ(a, b) > updateDistance * updateDistance)
				{
					UpdateGraph();
				}
			}
		}

		private Vector3 PointToGraphSpace(Vector3 p)
		{
			return graph.transform.InverseTransform(p);
		}

		public void UpdateGraph()
		{
			if (updatingGraph)
			{
				return;
			}
			updatingGraph = true;
			IEnumerator ie = UpdateGraphCoroutine();
			AstarPath.active.AddWorkItem(new AstarWorkItem(delegate(IWorkItemContext context, bool force)
			{
				if (force)
				{
					while (ie.MoveNext())
					{
					}
				}
				bool flag;
				try
				{
					flag = !ie.MoveNext();
				}
				catch (Exception exception)
				{
					UnityEngine.Debug.LogException(exception, this);
					flag = true;
				}
				if (flag)
				{
					updatingGraph = false;
				}
				return flag;
			}));
		}

		private IEnumerator UpdateGraphCoroutine()
		{
			Vector3 vector = PointToGraphSpace(target.position) - PointToGraphSpace(graph.center);
			vector.x = Mathf.Round(vector.x);
			vector.z = Mathf.Round(vector.z);
			vector.y = 0f;
			if (vector == Vector3.zero)
			{
				yield break;
			}
			Int2 offset = new Int2(-Mathf.RoundToInt(vector.x), -Mathf.RoundToInt(vector.z));
			graph.center += graph.transform.TransformVector(vector);
			graph.UpdateTransform();
			int width = graph.width;
			int depth = graph.depth;
			int layers = graph.LayerCount;
			GridNodeBase[] nodes = ((!(graph is LayerGridGraph layerGridGraph)) ? graph.nodes : layerGridGraph.nodes);
			if (buffer == null || buffer.Length != width * depth)
			{
				buffer = new GridNodeBase[width * depth];
			}
			int counter;
			int yieldEvery;
			if (Mathf.Abs(offset.x) <= width && Mathf.Abs(offset.y) <= depth)
			{
				IntRect recalculateRect = new IntRect(0, 0, offset.x, offset.y);
				if (recalculateRect.xmin > recalculateRect.xmax)
				{
					int xmax = recalculateRect.xmax;
					recalculateRect.xmax = width + recalculateRect.xmin;
					recalculateRect.xmin = width + xmax;
				}
				if (recalculateRect.ymin > recalculateRect.ymax)
				{
					int ymax = recalculateRect.ymax;
					recalculateRect.ymax = depth + recalculateRect.ymin;
					recalculateRect.ymin = depth + ymax;
				}
				IntRect connectionRect = recalculateRect.Expand(1);
				connectionRect = IntRect.Intersection(connectionRect, new IntRect(0, 0, width, depth));
				for (int l = 0; l < layers; l++)
				{
					int layerOffset = l * width * depth;
					for (int i = 0; i < depth; i++)
					{
						int num = i * width;
						int num2 = (i + offset.y + depth) % depth * width;
						for (int j = 0; j < width; j++)
						{
							buffer[num2 + (j + offset.x + width) % width] = nodes[layerOffset + num + j];
						}
					}
					yield return null;
					for (int k = 0; k < depth; k++)
					{
						int num3 = k * width;
						for (int m = 0; m < width; m++)
						{
							int num4 = num3 + m;
							GridNodeBase gridNodeBase = buffer[num4];
							if (gridNodeBase != null)
							{
								gridNodeBase.NodeInGridIndex = num4;
							}
							nodes[layerOffset + num4] = gridNodeBase;
						}
						int num5;
						int num6;
						if (k >= recalculateRect.ymin && k < recalculateRect.ymax)
						{
							num5 = 0;
							num6 = depth;
						}
						else
						{
							num5 = recalculateRect.xmin;
							num6 = recalculateRect.xmax;
						}
						for (int n = num5; n < num6; n++)
						{
							buffer[num3 + n]?.ClearConnections(alsoReverse: false);
						}
					}
					yield return null;
				}
				yieldEvery = 1000;
				int num7 = Mathf.Max(Mathf.Abs(offset.x), Mathf.Abs(offset.y)) * Mathf.Max(width, depth);
				yieldEvery = Mathf.Max(yieldEvery, num7 / 10);
				counter = 0;
				for (int l = 0; l < depth; l++)
				{
					int num8;
					int num9;
					if (l >= recalculateRect.ymin && l < recalculateRect.ymax)
					{
						num8 = 0;
						num9 = width;
					}
					else
					{
						num8 = recalculateRect.xmin;
						num9 = recalculateRect.xmax;
					}
					for (int num10 = num8; num10 < num9; num10++)
					{
						graph.RecalculateCell(num10, l, resetPenalties: false, resetTags: false);
					}
					counter += num9 - num8;
					if (counter > yieldEvery)
					{
						counter = 0;
						yield return null;
					}
				}
				for (int l = 0; l < depth; l++)
				{
					int num11;
					int num12;
					if (l >= connectionRect.ymin && l < connectionRect.ymax)
					{
						num11 = 0;
						num12 = width;
					}
					else
					{
						num11 = connectionRect.xmin;
						num12 = connectionRect.xmax;
					}
					for (int num13 = num11; num13 < num12; num13++)
					{
						graph.CalculateConnections(num13, l);
					}
					counter += num12 - num11;
					if (counter > yieldEvery)
					{
						counter = 0;
						yield return null;
					}
				}
				yield return null;
				for (int num14 = 0; num14 < depth; num14++)
				{
					for (int num15 = 0; num15 < width; num15++)
					{
						if (num15 == 0 || num14 == 0 || num15 == width - 1 || num14 == depth - 1)
						{
							graph.CalculateConnections(num15, num14);
						}
					}
				}
				yield break;
			}
			counter = Mathf.Max(depth * width / 20, 1000);
			yieldEvery = 0;
			for (int l = 0; l < depth; l++)
			{
				for (int num16 = 0; num16 < width; num16++)
				{
					graph.RecalculateCell(num16, l);
				}
				yieldEvery += width;
				if (yieldEvery > counter)
				{
					yieldEvery = 0;
					yield return null;
				}
			}
			for (int l = 0; l < depth; l++)
			{
				for (int num17 = 0; num17 < width; num17++)
				{
					graph.CalculateConnections(num17, l);
				}
				yieldEvery += width;
				if (yieldEvery > counter)
				{
					yieldEvery = 0;
					yield return null;
				}
			}
		}
	}
	public class Profile
	{
		private const bool PROFILE_MEM = false;

		public readonly string name;

		private readonly Stopwatch watch;

		private int counter;

		private long mem;

		private long smem;

		private int control = 1073741824;

		private const bool dontCountFirst = false;

		public int ControlValue()
		{
			return control;
		}

		public Profile(string name)
		{
			this.name = name;
			watch = new Stopwatch();
		}

		public static void WriteCSV(string path, params Profile[] profiles)
		{
		}

		public void Run(Action action)
		{
			action();
		}

		[Conditional("PROFILE")]
		public void Start()
		{
			watch.Start();
		}

		[Conditional("PROFILE")]
		public void Stop()
		{
			counter++;
			watch.Stop();
		}

		[Conditional("PROFILE")]
		public void Log()
		{
			UnityEngine.Debug.Log(ToString());
		}

		[Conditional("PROFILE")]
		public void ConsoleLog()
		{
			Console.WriteLine(ToString());
		}

		[Conditional("PROFILE")]
		public void Stop(int control)
		{
			counter++;
			watch.Stop();
			if (this.control == 1073741824)
			{
				this.control = control;
			}
			else if (this.control != control)
			{
				throw new Exception("Control numbers do not match " + this.control + " != " + control);
			}
		}

		[Conditional("PROFILE")]
		public void Control(Profile other)
		{
			if (ControlValue() != other.ControlValue())
			{
				throw new Exception("Control numbers do not match (" + name + " " + other.name + ") " + ControlValue() + " != " + other.ControlValue());
			}
		}

		public override string ToString()
		{
			return name + " #" + counter + " " + watch.Elapsed.TotalMilliseconds.ToString("0.0 ms") + " avg: " + (watch.Elapsed.TotalMilliseconds / (double)counter).ToString("0.00 ms");
		}
	}
	[ExecuteInEditMode]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_unity_reference_helper.php")]
	public class UnityReferenceHelper : MonoBehaviour
	{
		[HideInInspector]
		[SerializeField]
		private string guid;

		public string GetGUID()
		{
			return guid;
		}

		public void Awake()
		{
			Reset();
		}

		public void Reset()
		{
			if (string.IsNullOrEmpty(guid))
			{
				guid = Pathfinding.Util.Guid.NewGuid().ToString();
				UnityEngine.Debug.Log("Created new GUID - " + guid, this);
			}
			else
			{
				if (base.gameObject.scene.name == null)
				{
					return;
				}
				UnityReferenceHelper[] array = UnityEngine.Object.FindObjectsOfType(typeof(UnityReferenceHelper)) as UnityReferenceHelper[];
				foreach (UnityReferenceHelper unityReferenceHelper in array)
				{
					if (unityReferenceHelper != this && guid == unityReferenceHelper.guid)
					{
						guid = Pathfinding.Util.Guid.NewGuid().ToString();
						UnityEngine.Debug.Log("Created new GUID - " + guid, this);
						break;
					}
				}
			}
		}
	}
}
namespace Pathfinding.Legacy
{
	[RequireComponent(typeof(Seeker))]
	[AddComponentMenu("Pathfinding/Legacy/AI/Legacy AIPath (3D)")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_legacy_1_1_legacy_a_i_path.php")]
	public class LegacyAIPath : AIPath
	{
		public float forwardLook = 1f;

		public bool closestOnPathCheck = true;

		protected float minMoveScale = 0.05f;

		protected int currentWaypointIndex;

		protected Vector3 lastFoundWaypointPosition;

		protected float lastFoundWaypointTime = -9999f;

		protected new Vector3 targetDirection;

		protected override void Awake()
		{
			base.Awake();
			if (rvoController != null)
			{
				if (rvoController is LegacyRVOController)
				{
					(rvoController as LegacyRVOController).enableRotation = false;
				}
				else
				{
					UnityEngine.Debug.LogError("The LegacyAIPath component only works with the legacy RVOController, not the latest one. Please upgrade this component", this);
				}
			}
		}

		protected override void OnPathComplete(Path _p)
		{
			if (!(_p is ABPath aBPath))
			{
				throw new Exception("This function only handles ABPaths, do not use special path types");
			}
			waitingForPathCalculation = false;
			aBPath.Claim(this);
			if (aBPath.error)
			{
				aBPath.Release(this);
				return;
			}
			if (path != null)
			{
				path.Release(this);
			}
			path = aBPath;
			currentWaypointIndex = 0;
			base.reachedEndOfPath = false;
			if (closestOnPathCheck)
			{
				Vector3 vector = ((Time.time - lastFoundWaypointTime < 0.3f) ? lastFoundWaypointPosition : aBPath.originalStartPoint);
				Vector3 vector2 = GetFeetPosition() - vector;
				float magnitude = vector2.magnitude;
				vector2 /= magnitude;
				int num = (int)(magnitude / pickNextWaypointDist);
				for (int i = 0; i <= num; i++)
				{
					CalculateVelocity(vector);
					vector += vector2;
				}
			}
		}

		protected override void Update()
		{
			if (canMove)
			{
				Vector3 vector = CalculateVelocity(GetFeetPosition());
				RotateTowards(targetDirection);
				if (rvoController != null)
				{
					rvoController.Move(vector);
				}
				else if (controller != null)
				{
					controller.SimpleMove(vector);
				}
				else if (rigid != null)
				{
					rigid.AddForce(vector);
				}
				else
				{
					tr.Translate(vector * Time.deltaTime, Space.World);
				}
			}
		}

		protected float XZSqrMagnitude(Vector3 a, Vector3 b)
		{
			float num = b.x - a.x;
			float num2 = b.z - a.z;
			return num * num + num2 * num2;
		}

		protected new Vector3 CalculateVelocity(Vector3 currentPosition)
		{
			if (path == null || path.vectorPath == null || path.vectorPath.Count == 0)
			{
				return Vector3.zero;
			}
			List<Vector3> vectorPath = path.vectorPath;
			if (vectorPath.Count == 1)
			{
				vectorPath.Insert(0, currentPosition);
			}
			if (currentWaypointIndex >= vectorPath.Count)
			{
				currentWaypointIndex = vectorPath.Count - 1;
			}
			if (currentWaypointIndex <= 1)
			{
				currentWaypointIndex = 1;
			}
			while (currentWaypointIndex < vectorPath.Count - 1 && XZSqrMagnitude(vectorPath[currentWaypointIndex], currentPosition) < pickNextWaypointDist * pickNextWaypointDist)
			{
				lastFoundWaypointPosition = currentPosition;
				lastFoundWaypointTime = Time.time;
				currentWaypointIndex++;
			}
			Vector3 vector = vectorPath[currentWaypointIndex] - vectorPath[currentWaypointIndex - 1];
			vector = CalculateTargetPoint(currentPosition, vectorPath[currentWaypointIndex - 1], vectorPath[currentWaypointIndex]) - currentPosition;
			vector.y = 0f;
			float magnitude = vector.magnitude;
			float num = Mathf.Clamp01(magnitude / slowdownDistance);
			targetDirection = vector;
			if (currentWaypointIndex == vectorPath.Count - 1 && magnitude <= endReachedDistance)
			{
				if (!base.reachedEndOfPath)
				{
					base.reachedEndOfPath = true;
					OnTargetReached();
				}
				return Vector3.zero;
			}
			Vector3 forward = tr.forward;
			float a = Vector3.Dot(vector.normalized, forward);
			float num2 = maxSpeed * Mathf.Max(a, minMoveScale) * num;
			if (Time.deltaTime > 0f)
			{
				num2 = Mathf.Clamp(num2, 0f, magnitude / (Time.deltaTime * 2f));
			}
			return forward * num2;
		}

		protected void RotateTowards(Vector3 dir)
		{
			if (!(dir == Vector3.zero))
			{
				Quaternion a = tr.rotation;
				Quaternion b = Quaternion.LookRotation(dir);
				Vector3 eulerAngles = Quaternion.Slerp(a, b, base.turningSpeed * Time.deltaTime).eulerAngles;
				eulerAngles.z = 0f;
				eulerAngles.x = 0f;
				a = Quaternion.Euler(eulerAngles);
				tr.rotation = a;
			}
		}

		protected Vector3 CalculateTargetPoint(Vector3 p, Vector3 a, Vector3 b)
		{
			a.y = p.y;
			b.y = p.y;
			float magnitude = (a - b).magnitude;
			if (magnitude == 0f)
			{
				return a;
			}
			float num = Mathf.Clamp01(VectorMath.ClosestPointOnLineFactor(a, b, p));
			float magnitude2 = ((b - a) * num + a - p).magnitude;
			float num2 = Mathf.Clamp(forwardLook - magnitude2, 0f, forwardLook) / magnitude;
			num2 = Mathf.Clamp(num2 + num, 0f, 1f);
			return (b - a) * num2 + a;
		}
	}
	[RequireComponent(typeof(Seeker))]
	[AddComponentMenu("Pathfinding/Legacy/AI/Legacy RichAI (3D, for navmesh)")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_legacy_1_1_legacy_rich_a_i.php")]
	public class LegacyRichAI : RichAI
	{
		public bool preciseSlowdown = true;

		public bool raycastingForGroundPlacement;

		private new Vector3 velocity;

		private Vector3 lastTargetPoint;

		private Vector3 currentTargetDirection;

		private static float deltaTime;

		protected override void Awake()
		{
			base.Awake();
			if (rvoController != null)
			{
				if (rvoController is LegacyRVOController)
				{
					(rvoController as LegacyRVOController).enableRotation = false;
				}
				else
				{
					UnityEngine.Debug.LogError("The LegacyRichAI component only works with the legacy RVOController, not the latest one. Please upgrade this component", this);
				}
			}
		}

		protected override void Update()
		{
			deltaTime = Mathf.Min(Time.smoothDeltaTime * 2f, Time.deltaTime);
			if (richPath != null)
			{
				RichPathPart currentPart = richPath.GetCurrentPart();
				if (currentPart is RichFunnel richFunnel)
				{
					Vector3 vector = UpdateTarget(richFunnel);
					if (Time.frameCount % 5 == 0 && wallForce > 0f && wallDist > 0f)
					{
						wallBuffer.Clear();
						richFunnel.FindWalls(wallBuffer, wallDist);
					}
					int num = 0;
					Vector3 vector2 = nextCorners[num];
					Vector3 lhs = vector2 - vector;
					lhs.y = 0f;
					if (Vector3.Dot(lhs, currentTargetDirection) < 0f && nextCorners.Count - num > 1)
					{
						num++;
						vector2 = nextCorners[num];
					}
					if (vector2 != lastTargetPoint)
					{
						currentTargetDirection = vector2 - vector;
						currentTargetDirection.y = 0f;
						currentTargetDirection.Normalize();
						lastTargetPoint = vector2;
					}
					lhs = vector2 - vector;
					lhs.y = 0f;
					float num2 = (distanceToSteeringTarget = lhs.magnitude);
					lhs = ((num2 == 0f) ? Vector3.zero : (lhs / num2));
					Vector3 lhs2 = lhs;
					Vector3 vector3 = Vector3.zero;
					if (wallForce > 0f && wallDist > 0f)
					{
						float num3 = 0f;
						float num4 = 0f;
						for (int i = 0; i < wallBuffer.Count; i += 2)
						{
							float sqrMagnitude = (VectorMath.ClosestPointOnSegment(wallBuffer[i], wallBuffer[i + 1], tr.position) - vector).sqrMagnitude;
							if (!(sqrMagnitude > wallDist * wallDist))
							{
								Vector3 normalized = (wallBuffer[i + 1] - wallBuffer[i]).normalized;
								float num5 = Vector3.Dot(lhs, normalized) * (1f - Math.Max(0f, 2f * (sqrMagnitude / (wallDist * wallDist)) - 1f));
								if (num5 > 0f)
								{
									num4 = Math.Max(num4, num5);
								}
								else
								{
									num3 = Math.Max(num3, 0f - num5);
								}
							}
						}
						vector3 = Vector3.Cross(Vector3.up, lhs) * (num4 - num3);
					}
					bool flag = lastCorner && nextCorners.Count - num == 1;
					if (flag)
					{
						if (slowdownTime < 0.001f)
						{
							slowdownTime = 0.001f;
						}
						Vector3 vector4 = vector2 - vector;
						vector4.y = 0f;
						lhs = ((!preciseSlowdown) ? (2f * (vector4 - slowdownTime * velocity) / (slowdownTime * slowdownTime)) : ((6f * vector4 - 4f * slowdownTime * velocity) / (slowdownTime * slowdownTime)));
						lhs = Vector3.ClampMagnitude(lhs, acceleration);
						vector3 *= Math.Min(num2 / 0.5f, 1f);
						if (num2 < endReachedDistance)
						{
							NextPart();
						}
					}
					else
					{
						lhs *= acceleration;
					}
					velocity += (lhs + vector3 * wallForce) * deltaTime;
					if (slowWhenNotFacingTarget)
					{
						float a = (Vector3.Dot(lhs2, tr.forward) + 0.5f) * (2f / 3f);
						float a2 = Mathf.Sqrt(velocity.x * velocity.x + velocity.z * velocity.z);
						float y = velocity.y;
						velocity.y = 0f;
						float num6 = Mathf.Min(a2, maxSpeed * Mathf.Max(a, 0.2f));
						velocity = Vector3.Lerp(tr.forward * num6, velocity.normalized * num6, Mathf.Clamp(flag ? (num2 * 2f) : 0f, 0.5f, 1f));
						velocity.y = y;
					}
					else
					{
						float num7 = Mathf.Sqrt(velocity.x * velocity.x + velocity.z * velocity.z);
						num7 = maxSpeed / num7;
						if (num7 < 1f)
						{
							velocity.x *= num7;
							velocity.z *= num7;
						}
					}
					if (flag)
					{
						Vector3 trotdir = Vector3.Lerp(velocity, currentTargetDirection, Math.Max(1f - num2 * 2f, 0f));
						RotateTowards(trotdir);
					}
					else
					{
						RotateTowards(velocity);
					}
					velocity += deltaTime * gravity;
					if (rvoController != null && rvoController.enabled)
					{
						tr.position = vector;
						rvoController.Move(velocity);
					}
					else if (controller != null && controller.enabled)
					{
						tr.position = vector;
						controller.Move(velocity * deltaTime);
					}
					else
					{
						float y2 = vector.y;
						vector += velocity * deltaTime;
						vector = RaycastPosition(vector, y2);
						tr.position = vector;
					}
				}
				else if (rvoController != null && rvoController.enabled)
				{
					rvoController.Move(Vector3.zero);
				}
				if (currentPart is RichSpecial && !base.traversingOffMeshLink)
				{
					StartCoroutine(TraverseSpecial(currentPart as RichSpecial));
				}
			}
			else if (rvoController != null && rvoController.enabled)
			{
				rvoController.Move(Vector3.zero);
			}
			else if (!(controller != null) || !controller.enabled)
			{
				tr.position = RaycastPosition(tr.position, tr.position.y);
			}
			UpdateVelocity();
			lastDeltaTime = Time.deltaTime;
		}

		private new Vector3 RaycastPosition(Vector3 position, float lasty)
		{
			if (raycastingForGroundPlacement)
			{
				float num = Mathf.Max(height * 0.5f, lasty - position.y + height * 0.5f);
				if (Physics.Raycast(position + Vector3.up * num, Vector3.down, out var hitInfo, num, groundMask) && hitInfo.distance < num)
				{
					position = hitInfo.point;
					velocity.y = 0f;
				}
			}
			return position;
		}

		private bool RotateTowards(Vector3 trotdir)
		{
			trotdir.y = 0f;
			if (trotdir != Vector3.zero)
			{
				Quaternion quaternion = tr.rotation;
				Vector3 eulerAngles = Quaternion.LookRotation(trotdir).eulerAngles;
				Vector3 eulerAngles2 = quaternion.eulerAngles;
				eulerAngles2.y = Mathf.MoveTowardsAngle(eulerAngles2.y, eulerAngles.y, rotationSpeed * deltaTime);
				tr.rotation = Quaternion.Euler(eulerAngles2);
				return Mathf.Abs(eulerAngles2.y - eulerAngles.y) < 5f;
			}
			return false;
		}
	}
	[AddComponentMenu("Pathfinding/Legacy/Local Avoidance/Legacy RVO Controller")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_legacy_1_1_legacy_r_v_o_controller.php")]
	public class LegacyRVOController : RVOController
	{
		[Tooltip("Layer mask for the ground. The RVOController will raycast down to check for the ground to figure out where to place the agent")]
		public new LayerMask mask = -1;

		public new bool enableRotation = true;

		public new float rotationSpeed = 30f;

		public void Update()
		{
			if (base.rvoAgent != null)
			{
				Vector3 vector = tr.position + CalculateMovementDelta(Time.deltaTime);
				if ((int)mask != 0 && Physics.Raycast(vector + Vector3.up * base.height * 0.5f, Vector3.down, out var hitInfo, float.PositiveInfinity, mask))
				{
					vector.y = hitInfo.point.y;
				}
				else
				{
					vector.y = 0f;
				}
				tr.position = vector + Vector3.up * (base.height * 0.5f - base.center);
				if (enableRotation && base.velocity != Vector3.zero)
				{
					base.transform.rotation = Quaternion.Lerp(base.transform.rotation, Quaternion.LookRotation(base.velocity), Time.deltaTime * rotationSpeed * Mathf.Min(base.velocity.magnitude, 0.2f));
				}
			}
		}
	}
