	{
	}
	public class JsonOptInAttribute : Attribute
	{
	}
	public class TinyJsonSerializer
	{
		private StringBuilder output = new StringBuilder();

		private Dictionary<Type, Action<object>> serializers = new Dictionary<Type, Action<object>>();

		private static readonly CultureInfo invariantCulture = CultureInfo.InvariantCulture;

		public static void Serialize(object obj, StringBuilder output)
		{
			TinyJsonSerializer tinyJsonSerializer = new TinyJsonSerializer();
			tinyJsonSerializer.output = output;
			tinyJsonSerializer.Serialize(obj);
		}

		private TinyJsonSerializer()
		{
			serializers[typeof(float)] = delegate(object v)
			{
				output.Append(((float)v).ToString("R", invariantCulture));
			};
			serializers[typeof(bool)] = delegate(object v)
			{
				output.Append(((bool)v) ? "true" : "false");
			};
			serializers[typeof(Version)] = (serializers[typeof(uint)] = (serializers[typeof(int)] = delegate(object v)
			{
				output.Append(v.ToString());
			}));
			serializers[typeof(string)] = delegate(object v)
			{
				output.AppendFormat("\"{0}\"", v.ToString().Replace("\"", "\\\""));
			};
			serializers[typeof(Vector2)] = delegate(object v)
			{
				output.AppendFormat("{{ \"x\": {0}, \"y\": {1} }}", ((Vector2)v).x.ToString("R", invariantCulture), ((Vector2)v).y.ToString("R", invariantCulture));
			};
			serializers[typeof(Vector3)] = delegate(object v)
			{
				output.AppendFormat("{{ \"x\": {0}, \"y\": {1}, \"z\": {2} }}", ((Vector3)v).x.ToString("R", invariantCulture), ((Vector3)v).y.ToString("R", invariantCulture), ((Vector3)v).z.ToString("R", invariantCulture));
			};
			serializers[typeof(Pathfinding.Util.Guid)] = delegate(object v)
			{
				output.AppendFormat("{{ \"value\": \"{0}\" }}", v.ToString());
			};
			serializers[typeof(LayerMask)] = delegate(object v)
			{
				output.AppendFormat("{{ \"value\": {0} }}", ((int)(LayerMask)v).ToString());
			};
		}

		private void Serialize(object obj)
		{
			if (obj == null)
			{
				output.Append("null");
				return;
			}
			Type type = obj.GetType();
			Type typeInfo = WindowsStoreCompatibility.GetTypeInfo(type);
			if (serializers.ContainsKey(type))
			{
				serializers[type](obj);
				return;
			}
			if (typeInfo.IsEnum)
			{
				output.Append("\"" + obj.ToString() + "\"");
				return;
			}
			if (obj is IList)
			{
				output.Append("[");
				IList list = obj as IList;
				for (int i = 0; i < list.Count; i++)
				{
					if (i != 0)
					{
						output.Append(", ");
					}
					Serialize(list[i]);
				}
				output.Append("]");
				return;
			}
			if (obj is UnityEngine.Object)
			{
				SerializeUnityObject(obj as UnityEngine.Object);
				return;
			}
			bool flag = typeInfo.GetCustomAttributes(typeof(JsonOptInAttribute), inherit: true).Length != 0;
			output.Append("{");
			bool flag2 = false;
			do
			{
				FieldInfo[] fields = type.GetFields(BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
				foreach (FieldInfo fieldInfo in fields)
				{
					if (!(fieldInfo.DeclaringType != type) && ((!flag && fieldInfo.IsPublic) || fieldInfo.GetCustomAttributes(typeof(JsonMemberAttribute), inherit: true).Length != 0))
					{
						if (flag2)
						{
							output.Append(", ");
						}
						flag2 = true;
						output.AppendFormat("\"{0}\": ", fieldInfo.Name);
						Serialize(fieldInfo.GetValue(obj));
					}
				}
				type = type.BaseType;
			}
			while (!(type == null));
			output.Append("}");
		}

		private void QuotedField(string name, string contents)
		{
			output.AppendFormat("\"{0}\": \"{1}\"", name, contents);
		}

		private void SerializeUnityObject(UnityEngine.Object obj)
		{
			if (obj == null)
			{
				Serialize(null);
				return;
			}
			output.Append("{");
			string name = obj.name;
			QuotedField("Name", name);
			output.Append(", ");
			QuotedField("Type", obj.GetType().FullName);
			UnityEngine.Component component = obj as UnityEngine.Component;
			GameObject gameObject = obj as GameObject;
			if (component != null || gameObject != null)
			{
				if (component != null && gameObject == null)
				{
					gameObject = component.gameObject;
				}
				UnityReferenceHelper unityReferenceHelper = gameObject.GetComponent<UnityReferenceHelper>();
				if (unityReferenceHelper == null)
				{
					UnityEngine.Debug.Log("Adding UnityReferenceHelper to Unity Reference '" + obj.name + "'");
					unityReferenceHelper = gameObject.AddComponent<UnityReferenceHelper>();
				}
				unityReferenceHelper.Reset();
				output.Append(", ");
				QuotedField("GUID", unityReferenceHelper.GetGUID().ToString());
			}
			output.Append("}");
		}
	}
	public class TinyJsonDeserializer
	{
		private TextReader reader;

		private GameObject contextRoot;

		private static readonly NumberFormatInfo numberFormat = NumberFormatInfo.InvariantInfo;

		private StringBuilder builder = new StringBuilder();

		public static object Deserialize(string text, Type type, object populate = null, GameObject contextRoot = null)
		{
			return new TinyJsonDeserializer
			{
				reader = new StringReader(text),
				contextRoot = contextRoot
			}.Deserialize(type, populate);
		}

		private object Deserialize(Type tp, object populate = null)
		{
			Type typeInfo = WindowsStoreCompatibility.GetTypeInfo(tp);
			if (typeInfo.IsEnum)
			{
				return Enum.Parse(tp, EatField());
			}
			if (TryEat('n'))
			{
				Eat("ull");
				TryEat(',');
				return null;
			}
			if (object.Equals(tp, typeof(float)))
			{
				return float.Parse(EatField(), numberFormat);
			}
			if (object.Equals(tp, typeof(int)))
			{
				return int.Parse(EatField(), numberFormat);
			}
			if (object.Equals(tp, typeof(uint)))
			{
				return uint.Parse(EatField(), numberFormat);
			}
			if (object.Equals(tp, typeof(bool)))
			{
				return bool.Parse(EatField());
			}
			if (object.Equals(tp, typeof(string)))
			{
				return EatField();
			}
			if (object.Equals(tp, typeof(Version)))
			{
				return new Version(EatField());
			}
			if (object.Equals(tp, typeof(Vector2)))
			{
				Eat("{");
				Vector2 vector = default(Vector2);
				EatField();
				vector.x = float.Parse(EatField(), numberFormat);
				EatField();
				vector.y = float.Parse(EatField(), numberFormat);
				Eat("}");
				return vector;
			}
			if (object.Equals(tp, typeof(Vector3)))
			{
				Eat("{");
				Vector3 vector2 = default(Vector3);
				EatField();
				vector2.x = float.Parse(EatField(), numberFormat);
				EatField();
				vector2.y = float.Parse(EatField(), numberFormat);
				EatField();
				vector2.z = float.Parse(EatField(), numberFormat);
				Eat("}");
				return vector2;
			}
			if (object.Equals(tp, typeof(Pathfinding.Util.Guid)))
			{
				Eat("{");
				EatField();
				Pathfinding.Util.Guid guid = Pathfinding.Util.Guid.Parse(EatField());
				Eat("}");
				return guid;
			}
			if (object.Equals(tp, typeof(LayerMask)))
			{
				Eat("{");
				EatField();
				LayerMask layerMask = int.Parse(EatField());
				Eat("}");
				return layerMask;
			}
			if (object.Equals(tp, typeof(List<string>)))
			{
				IList list = new List<string>();
				Eat("[");
				while (!TryEat(']'))
				{
					list.Add(Deserialize(typeof(string)));
					TryEat(',');
				}
				return list;
			}
			if (typeInfo.IsArray)
			{
				List<object> list2 = new List<object>();
				Eat("[");
				while (!TryEat(']'))
				{
					list2.Add(Deserialize(tp.GetElementType()));
					TryEat(',');
				}
				Array array = Array.CreateInstance(tp.GetElementType(), list2.Count);
				list2.ToArray().CopyTo(array, 0);
				return array;
			}
			if (object.Equals(tp, typeof(Mesh)) || object.Equals(tp, typeof(Texture2D)) || object.Equals(tp, typeof(Transform)) || object.Equals(tp, typeof(GameObject)))
			{
				return DeserializeUnityObject();
			}
			object obj = populate ?? Activator.CreateInstance(tp);
			Eat("{");
			while (!TryEat('}'))
			{
				string name = EatField();
				Type type = tp;
				FieldInfo fieldInfo = null;
				while (fieldInfo == null && type != null)
				{
					fieldInfo = type.GetField(name, BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic);
					type = type.BaseType;
				}
				if (fieldInfo == null)
				{
					SkipFieldData();
				}
				else
				{
					fieldInfo.SetValue(obj, Deserialize(fieldInfo.FieldType));
				}
				TryEat(',');
			}
			return obj;
		}

		private UnityEngine.Object DeserializeUnityObject()
		{
			Eat("{");
			UnityEngine.Object result = DeserializeUnityObjectInner();
			Eat("}");
			return result;
		}

		private UnityEngine.Object DeserializeUnityObjectInner()
		{
			string text = EatField();
			if (text == "InstanceID")
			{
				EatField();
				text = EatField();
			}
			if (text != "Name")
			{
				throw new Exception("Expected 'Name' field");
			}
			string text2 = EatField();
			if (text2 == null)
			{
				return null;
			}
			if (EatField() != "Type")
			{
				throw new Exception("Expected 'Type' field");
			}
			string text3 = EatField();
			if (text3.IndexOf(',') != -1)
			{
				text3 = text3.Substring(0, text3.IndexOf(','));
			}
			Type type = WindowsStoreCompatibility.GetTypeInfo(typeof(AstarPath)).Assembly.GetType(text3);
			type = type ?? WindowsStoreCompatibility.GetTypeInfo(typeof(Transform)).Assembly.GetType(text3);
			if (object.Equals(type, null))
			{
				UnityEngine.Debug.LogError("Could not find type '" + text3 + "'. Cannot deserialize Unity reference");
				return null;
			}
			EatWhitespace();
			if ((ushort)reader.Peek() == 34)
			{
				if (EatField() != "GUID")
				{
					throw new Exception("Expected 'GUID' field");
				}
				string text4 = EatField();
				UnityReferenceHelper[] componentsInChildren;
				if (contextRoot != null)
				{
					componentsInChildren = contextRoot.GetComponentsInChildren<UnityReferenceHelper>(includeInactive: true);
					foreach (UnityReferenceHelper unityReferenceHelper in componentsInChildren)
					{
						if (unityReferenceHelper.GetGUID() == text4)
						{
							if (object.Equals(type, typeof(GameObject)))
							{
								return unityReferenceHelper.gameObject;
							}
							return unityReferenceHelper.GetComponent(type);
						}
					}
				}
				componentsInChildren = UnityEngine.Object.FindObjectsOfType<UnityReferenceHelper>(includeInactive: true);
				foreach (UnityReferenceHelper unityReferenceHelper2 in componentsInChildren)
				{
					if (unityReferenceHelper2.GetGUID() == text4)
					{
						if (object.Equals(type, typeof(GameObject)))
						{
							return unityReferenceHelper2.gameObject;
						}
						return unityReferenceHelper2.GetComponent(type);
					}
				}
			}
			if (!string.IsNullOrEmpty(text2))
			{
				UnityEngine.Object[] array = Resources.LoadAll(text2, type);
				for (int j = 0; j < array.Length; j++)
				{
					if (array[j].name == text2 || array.Length == 1)
					{
						return array[j];
					}
				}
			}
			return null;
		}

		private void EatWhitespace()
		{
			while (char.IsWhiteSpace((char)reader.Peek()))
			{
				reader.Read();
			}
		}

		private void Eat(string s)
		{
			EatWhitespace();
			for (int i = 0; i < s.Length; i++)
			{
				char c = (char)reader.Read();
				if (c != s[i])
				{
					throw new Exception("Expected '" + s[i] + "' found '" + c + "'\n\n..." + reader.ReadLine());
				}
			}
		}

		private string EatUntil(string c, bool inString)
		{
			builder.Length = 0;
			bool flag = false;
			while (true)
			{
				int num = reader.Peek();
				if (!flag && (ushort)num == 34)
				{
					inString = !inString;
				}
				char c2 = (char)num;
				if (num == -1)
				{
					throw new Exception("Unexpected EOF");
				}
				if (!flag && c2 == '\\')
				{
					flag = true;
					reader.Read();
					continue;
				}
				if (!inString && c.IndexOf(c2) != -1)
				{
					break;
				}
				builder.Append(c2);
				reader.Read();
				flag = false;
			}
			return builder.ToString();
		}

		private bool TryEat(char c)
		{
			EatWhitespace();
			if ((ushort)reader.Peek() == c)
			{
				reader.Read();
				return true;
			}
			return false;
		}

		private string EatField()
		{
			string result = EatUntil("\",}]", TryEat('"'));
			TryEat('"');
			TryEat(':');
			TryEat(',');
			return result;
		}

		private void SkipFieldData()
		{
			int num = 0;
			while (true)
			{
				EatUntil(",{}[]", inString: false);
				switch ((char)(ushort)reader.Peek())
				{
				case '[':
				case '{':
					num++;
					break;
				case ']':
				case '}':
					num--;
					if (num < 0)
					{
						return;
					}
					break;
				case ',':
					if (num == 0)
					{
						reader.Read();
						return;
					}
					break;
				default:
					throw new Exception("Should not reach this part");
				}
				reader.Read();
			}
		}
	}
