	public static class ArrayPool<T>
	{
		private const int MaximumExactArrayLength = 256;

		private static readonly Stack<T[]>[] pool = new Stack<T[]>[31];

		private static readonly Stack<T[]>[] exactPool = new Stack<T[]>[257];

		public static T[] Claim(int minimumLength)
		{
			if (minimumLength <= 0)
			{
				return ClaimWithExactLength(0);
			}
			int i;
			for (i = 0; 1 << i < minimumLength && i < 30; i++)
			{
			}
			if (i == 30)
			{
				throw new ArgumentException("Too high minimum length");
			}
			lock (pool)
			{
				if (pool[i] == null)
				{
					pool[i] = new Stack<T[]>();
				}
				if (pool[i].Count > 0)
				{
					return pool[i].Pop();
				}
			}
			return new T[1 << i];
		}

		public static T[] ClaimWithExactLength(int length)
		{
			if (length != 0 && (length & (length - 1)) == 0)
			{
				return Claim(length);
			}
			if (length <= 256)
			{
				lock (pool)
				{
					Stack<T[]> stack = exactPool[length];
					if (stack != null && stack.Count > 0)
					{
						return stack.Pop();
					}
				}
			}
			return new T[length];
		}

		public static void Release(ref T[] array, bool allowNonPowerOfTwo = false)
		{
			if (array == null)
			{
				return;
			}
			if (array.GetType() != typeof(T[]))
			{
				throw new ArgumentException("Expected array type " + typeof(T[]).Name + " but found " + array.GetType().Name + "\nAre you using the correct generic class?\n");
			}
			bool flag = array.Length != 0 && (array.Length & (array.Length - 1)) == 0;
			if (!flag && !allowNonPowerOfTwo && array.Length != 0)
			{
				throw new ArgumentException("Length is not a power of 2");
			}
			lock (pool)
			{
				if (flag)
				{
					int i;
					for (i = 0; 1 << i < array.Length && i < 30; i++)
					{
					}
					if (pool[i] == null)
					{
						pool[i] = new Stack<T[]>();
					}
					pool[i].Push(array);
				}
				else if (array.Length <= 256)
				{
					Stack<T[]> stack = exactPool[array.Length];
					if (stack == null)
					{
						stack = (exactPool[array.Length] = new Stack<T[]>());
					}
					stack.Push(array);
				}
			}
			array = null;
		}
	}
	public static class ListExtensions
	{
		public static T[] ToArrayFromPool<T>(this List<T> list)
		{
			T[] array = ArrayPool<T>.ClaimWithExactLength(list.Count);
			for (int i = 0; i < array.Length; i++)
			{
				array[i] = list[i];
			}
			return array;
		}

		public static void ClearFast<T>(this List<T> list)
		{
			if (list.Count * 2 < list.Capacity)
			{
				list.RemoveRange(0, list.Count);
			}
			else
			{
				list.Clear();
			}
		}
	}
	public class Draw
	{
		public static readonly Draw Debug = new Draw
		{
			gizmos = false
		};

		public static readonly Draw Gizmos = new Draw
		{
			gizmos = true
		};

		private bool gizmos;

		private Matrix4x4 matrix = Matrix4x4.identity;

		private void SetColor(Color color)
		{
			if (gizmos && UnityEngine.Gizmos.color != color)
			{
				UnityEngine.Gizmos.color = color;
			}
		}

		public void Polyline(List<Vector3> points, Color color, bool cycle = false)
		{
			for (int i = 0; i < points.Count - 1; i++)
			{
				Line(points[i], points[i + 1], color);
			}
			if (cycle && points.Count > 1)
			{
				Line(points[points.Count - 1], points[0], color);
			}
		}

		public void Line(Vector3 a, Vector3 b, Color color)
		{
			SetColor(color);
			if (gizmos)
			{
				UnityEngine.Gizmos.DrawLine(matrix.MultiplyPoint3x4(a), matrix.MultiplyPoint3x4(b));
			}
			else
			{
				UnityEngine.Debug.DrawLine(matrix.MultiplyPoint3x4(a), matrix.MultiplyPoint3x4(b), color);
			}
		}

		public void CircleXZ(Vector3 center, float radius, Color color, float startAngle = 0f, float endAngle = MathF.PI * 2f)
		{
			int num = 40;
			while (startAngle > endAngle)
			{
				startAngle -= MathF.PI * 2f;
			}
			Vector3 vector = new Vector3(Mathf.Cos(startAngle) * radius, 0f, Mathf.Sin(startAngle) * radius);
			for (int i = 0; i <= num; i++)
			{
				Vector3 vector2 = new Vector3(Mathf.Cos(Mathf.Lerp(startAngle, endAngle, (float)i / (float)num)) * radius, 0f, Mathf.Sin(Mathf.Lerp(startAngle, endAngle, (float)i / (float)num)) * radius);
				Line(center + vector, center + vector2, color);
				vector = vector2;
			}
		}

		public void Cylinder(Vector3 position, Vector3 up, float height, float radius, Color color)
		{
			Vector3 normalized = Vector3.Cross(up, Vector3.one).normalized;
			matrix = Matrix4x4.TRS(position, Quaternion.LookRotation(normalized, up), new Vector3(radius, height, radius));
			CircleXZ(Vector3.zero, 1f, color);
			if (height > 0f)
			{
				CircleXZ(Vector3.up, 1f, color);
				Line(new Vector3(1f, 0f, 0f), new Vector3(1f, 1f, 0f), color);
				Line(new Vector3(-1f, 0f, 0f), new Vector3(-1f, 1f, 0f), color);
				Line(new Vector3(0f, 0f, 1f), new Vector3(0f, 1f, 1f), color);
				Line(new Vector3(0f, 0f, -1f), new Vector3(0f, 1f, -1f), color);
			}
			matrix = Matrix4x4.identity;
		}

		public void CrossXZ(Vector3 position, Color color, float size = 1f)
		{
			size *= 0.5f;
			Line(position - Vector3.right * size, position + Vector3.right * size, color);
			Line(position - Vector3.forward * size, position + Vector3.forward * size, color);
		}

		public void Bezier(Vector3 a, Vector3 b, Color color)
		{
			Vector3 vector = b - a;
			if (!(vector == Vector3.zero))
			{
				Vector3 rhs = Vector3.Cross(Vector3.up, vector);
				Vector3 normalized = Vector3.Cross(vector, rhs).normalized;
				normalized *= vector.magnitude * 0.1f;
				Vector3 p = a + normalized;
				Vector3 p2 = b + normalized;
				Vector3 a2 = a;
				for (int i = 1; i <= 20; i++)
				{
					float t = (float)i / 20f;
					Vector3 vector2 = AstarSplines.CubicBezier(a, p, p2, b, t);
					Line(a2, vector2, color);
					a2 = vector2;
				}
			}
		}
	}
	public static class ListPool<T>
	{
		private static readonly List<List<T>> pool = new List<List<T>>();

		private static readonly List<List<T>> largePool = new List<List<T>>();

		private static readonly HashSet<List<T>> inPool = new HashSet<List<T>>();

		private const int MaxCapacitySearchLength = 8;

		private const int LargeThreshold = 5000;

		private const int MaxLargePoolSize = 8;

		public static List<T> Claim()
		{
			lock (pool)
			{
				if (pool.Count > 0)
				{
					List<T> list = pool[pool.Count - 1];
					pool.RemoveAt(pool.Count - 1);
					inPool.Remove(list);
					return list;
				}
				return new List<T>();
			}
		}

		private static int FindCandidate(List<List<T>> pool, int capacity)
		{
			List<T> list = null;
			int result = -1;
			for (int i = 0; i < pool.Count && i < 8; i++)
			{
				List<T> list2 = pool[pool.Count - 1 - i];
				if ((list == null || list2.Capacity > list.Capacity) && list2.Capacity < capacity * 16)
				{
					list = list2;
					result = pool.Count - 1 - i;
					if (list.Capacity >= capacity)
					{
						return result;
					}
				}
			}
			return result;
		}

		public static List<T> Claim(int capacity)
		{
			lock (pool)
			{
				List<List<T>> list = pool;
				int num = FindCandidate(pool, capacity);
				if (capacity > 5000)
				{
					int num2 = FindCandidate(largePool, capacity);
					if (num2 != -1)
					{
						list = largePool;
						num = num2;
					}
				}
				if (num == -1)
				{
					return new List<T>(capacity);
				}
				List<T> list2 = list[num];
				inPool.Remove(list2);
				list[num] = list[list.Count - 1];
				list.RemoveAt(list.Count - 1);
				return list2;
			}
		}

		public static void Warmup(int count, int size)
		{
			lock (pool)
			{
				List<T>[] array = new List<T>[count];
				for (int i = 0; i < count; i++)
				{
					array[i] = Claim(size);
				}
				for (int j = 0; j < count; j++)
				{
					Release(array[j]);
				}
			}
		}

		public static void Release(ref List<T> list)
		{
			Release(list);
			list = null;
		}

		public static void Release(List<T> list)
		{
			list.ClearFast();
			lock (pool)
			{
				if (list.Capacity > 5000)
				{
					largePool.Add(list);
					if (largePool.Count > 8)
					{
						largePool.RemoveAt(0);
					}
				}
				else
				{
					pool.Add(list);
				}
			}
		}

		public static void Clear()
		{
			lock (pool)
			{
				pool.Clear();
			}
		}

		public static int GetSize()
		{
			return pool.Count;
		}
	}
	public static class MovementUtilities
	{
		public static Vector2 ClampVelocity(Vector2 velocity, float maxSpeed, float slowdownFactor, bool slowWhenNotFacingTarget, Vector2 forward)
		{
			float num = maxSpeed * slowdownFactor;
			if (slowWhenNotFacingTarget && (forward.x != 0f || forward.y != 0f))
			{
				float magnitude;
				Vector2 lhs = VectorMath.Normalize(velocity, out magnitude);
				float num2 = Vector2.Dot(lhs, forward);
				float num3 = Mathf.Clamp(num2 + 0.707f, 0.2f, 1f);
				num *= num3;
				magnitude = Mathf.Min(magnitude, num);
				float f = Mathf.Min(Mathf.Acos(Mathf.Clamp(num2, -1f, 1f)), (20f + 180f * (1f - slowdownFactor * slowdownFactor)) * (MathF.PI / 180f));
				float num4 = Mathf.Sin(f);
				float num5 = Mathf.Cos(f);
				num4 *= Mathf.Sign(lhs.x * forward.y - lhs.y * forward.x);
				return new Vector2(forward.x * num5 + forward.y * num4, forward.y * num5 - forward.x * num4) * magnitude;
			}
			return Vector2.ClampMagnitude(velocity, num);
		}

		public static Vector2 CalculateAccelerationToReachPoint(Vector2 deltaPosition, Vector2 targetVelocity, Vector2 currentVelocity, float forwardsAcceleration, float rotationSpeed, float maxSpeed, Vector2 forwardsVector)
		{
			if (forwardsAcceleration <= 0f)
			{
				return Vector2.zero;
			}
			float magnitude = currentVelocity.magnitude;
			float a = magnitude * rotationSpeed * (MathF.PI / 180f);
			a = Mathf.Max(a, forwardsAcceleration);
			deltaPosition = VectorMath.ComplexMultiplyConjugate(deltaPosition, forwardsVector);
			targetVelocity = VectorMath.ComplexMultiplyConjugate(targetVelocity, forwardsVector);
			currentVelocity = VectorMath.ComplexMultiplyConjugate(currentVelocity, forwardsVector);
			float num = 1f / (forwardsAcceleration * forwardsAcceleration);
			float num2 = 1f / (a * a);
			if (targetVelocity == Vector2.zero)
			{
				float num3 = 0.01f;
				float num4 = 10f;
				while (num4 - num3 > 0.01f)
				{
					float num5 = (num4 + num3) * 0.5f;
					Vector2 vector = (6f * deltaPosition - 4f * num5 * currentVelocity) / (num5 * num5);
					Vector2 vector2 = 6f * (num5 * currentVelocity - 2f * deltaPosition) / (num5 * num5 * num5);
					Vector2 vector3 = vector + vector2 * num5;
					if (vector.x * vector.x * num + vector.y * vector.y * num2 > 1f || vector3.x * vector3.x * num + vector3.y * vector3.y * num2 > 1f)
					{
						num3 = num5;
					}
					else
					{
						num4 = num5;
					}
				}
				Vector2 a2 = (6f * deltaPosition - 4f * num4 * currentVelocity) / (num4 * num4);
				a2.y *= 2f;
				float num6 = a2.x * a2.x * num + a2.y * a2.y * num2;
				if (num6 > 1f)
				{
					a2 /= Mathf.Sqrt(num6);
				}
				return VectorMath.ComplexMultiply(a2, forwardsVector);
			}
			float magnitude2;
			Vector2 vector4 = VectorMath.Normalize(targetVelocity, out magnitude2);
			float magnitude3 = deltaPosition.magnitude;
			Vector2 a3 = ((deltaPosition - vector4 * Math.Min(0.5f * magnitude3 * magnitude2 / (magnitude + magnitude2), maxSpeed * 1.5f)).normalized * maxSpeed - currentVelocity) * 10f;
			float num7 = a3.x * a3.x * num + a3.y * a3.y * num2;
			if (num7 > 1f)
			{
				a3 /= Mathf.Sqrt(num7);
			}
			return VectorMath.ComplexMultiply(a3, forwardsVector);
		}
	}
