				{
					array = new Int3[7];
					clipOut = new Int3[7];
					size = new Int2(((Int3)vector).x, ((Int3)vector).y);
				}
				Int3[] vbuffer = null;
				for (int k = -1; k < list3.Count; k++)
				{
					Int3[] array2;
					int[] tbuffer;
