						int num = Math.Min(int2.y, Math.Min(int3.y, int4.y));
						int num2 = Math.Max(int2.y, Math.Max(int3.y, int4.y));
						list4.Clear();
						bool flag = false;
						for (int m = 0; m < list5.Count; m++)
