									{
										DelaunayTriangle delaunayTriangle = polygon.Triangles[num9];
										list7.Add(dictionary[delaunayTriangle.Points._0]);
										list7.Add(dictionary[delaunayTriangle.Points._1]);
										list7.Add(dictionary[delaunayTriangle.Points._2]);
