			{
				list2[num10].UsedForCut();
			}
			ListPool<Int3>.Release(ref list6);
			ListPool<int>.Release(ref list7);
			ListPool<int>.Release(ref list4);
			for (int num11 = 0; num11 < list5.Count; num11++)
			{
				ListPool<IntPoint>.Release(list5[num11].contour);
			}
			ListPool<Cut>.Release(ref list5);
			ListPool<NavmeshCut>.Release(ref list2);
			return result;
		}

		private static List<Cut> PrepareNavmeshCutsForCutting(List<NavmeshCut> navmeshCuts, GraphTransform transform, IntRect cutSpaceBounds, int perturbate, bool anyNavmeshAdds)
		{
			System.Random random = null;
			if (perturbate > 0)
			{
				random = new System.Random();
			}
			List<List<Vector3>> list = ListPool<List<Vector3>>.Claim();
			List<Cut> list2 = ListPool<Cut>.Claim();
			for (int i = 0; i < navmeshCuts.Count; i++)
			{
				Int2 @int = new Int2(0, 0);
				if (perturbate > 0)
				{
					@int.x = random.Next() % 6 * perturbate - 3 * perturbate;
					if (@int.x >= 0)
					{
						@int.x++;
					}
					@int.y = random.Next() % 6 * perturbate - 3 * perturbate;
					if (@int.y >= 0)
					{
						@int.y++;
					}
				}
				list.Clear();
				navmeshCuts[i].GetContour(list);
				int num = (int)(navmeshCuts[i].GetY(transform) * 1000f);
				for (int j = 0; j < list.Count; j++)
				{
					List<Vector3> list3 = list[j];
					if (list3.Count == 0)
					{
						UnityEngine.Debug.LogError("A NavmeshCut component had a zero length contour. Ignoring that contour.");
						continue;
					}
					List<IntPoint> list4 = ListPool<IntPoint>.Claim(list3.Count);
					for (int k = 0; k < list3.Count; k++)
					{
						Int3 int2 = (Int3)transform.InverseTransform(list3[k]);
						if (perturbate > 0)
						{
							int2.x += @int.x;
							int2.z += @int.y;
						}
						list4.Add(new IntPoint(int2.x, int2.z));
					}
					IntRect bounds = new IntRect((int)list4[0].X, (int)list4[0].Y, (int)list4[0].X, (int)list4[0].Y);
					for (int l = 0; l < list4.Count; l++)
					{
						IntPoint intPoint = list4[l];
						bounds = bounds.ExpandToContain((int)intPoint.X, (int)intPoint.Y);
					}
					Cut cut = new Cut();
					int num2 = (int)(navmeshCuts[i].height * 0.5f * 1000f);
					cut.boundsY = new Int2(num - num2, num + num2);
					cut.bounds = bounds;
					cut.isDual = navmeshCuts[i].isDual;
					cut.cutsAddedGeom = navmeshCuts[i].cutsAddedGeom;
					cut.contour = list4;
					list2.Add(cut);
				}
			}
			ListPool<List<Vector3>>.Release(ref list);
			return list2;
		}

		private static void PoolPolygon(Pathfinding.Poly2Tri.Polygon polygon, Stack<Pathfinding.Poly2Tri.Polygon> pool)
		{
			if (polygon.Holes != null)
			{
				for (int i = 0; i < polygon.Holes.Count; i++)
				{
					polygon.Holes[i].Points.Clear();
					polygon.Holes[i].ClearTriangles();
					if (polygon.Holes[i].Holes != null)
					{
						polygon.Holes[i].Holes.Clear();
					}
					pool.Push(polygon.Holes[i]);
				}
			}
			polygon.ClearTriangles();
			if (polygon.Holes != null)
			{
				polygon.Holes.Clear();
			}
			polygon.Points.Clear();
			pool.Push(polygon);
		}

		private void CutAll(List<IntPoint> poly, List<int> intersectingCutIndices, List<Cut> cuts, PolyTree result)
		{
			clipper.Clear();
			clipper.AddPolygon(poly, PolyType.ptSubject);
			for (int i = 0; i < intersectingCutIndices.Count; i++)
			{
				clipper.AddPolygon(cuts[intersectingCutIndices[i]].contour, PolyType.ptClip);
			}
			result.Clear();
			clipper.Execute(ClipType.ctDifference, result, PolyFillType.pftNonZero, PolyFillType.pftNonZero);
		}

		private void CutDual(List<IntPoint> poly, List<int> tmpIntersectingCuts, List<Cut> cuts, bool hasDual, List<List<IntPoint>> intermediateResult, PolyTree result)
		{
			clipper.Clear();
			clipper.AddPolygon(poly, PolyType.ptSubject);
			for (int i = 0; i < tmpIntersectingCuts.Count; i++)
			{
				if (cuts[tmpIntersectingCuts[i]].isDual)
				{
					clipper.AddPolygon(cuts[tmpIntersectingCuts[i]].contour, PolyType.ptClip);
				}
			}
			clipper.Execute(ClipType.ctIntersection, intermediateResult, PolyFillType.pftEvenOdd, PolyFillType.pftNonZero);
			clipper.Clear();
			if (intermediateResult != null)
			{
				for (int j = 0; j < intermediateResult.Count; j++)
				{
					clipper.AddPolygon(intermediateResult[j], Clipper.Orientation(intermediateResult[j]) ? PolyType.ptClip : PolyType.ptSubject);
				}
			}
			for (int k = 0; k < tmpIntersectingCuts.Count; k++)
			{
				if (!cuts[tmpIntersectingCuts[k]].isDual)
				{
					clipper.AddPolygon(cuts[tmpIntersectingCuts[k]].contour, PolyType.ptClip);
				}
			}
			result.Clear();
			clipper.Execute(ClipType.ctDifference, result, PolyFillType.pftEvenOdd, PolyFillType.pftNonZero);
		}

		private void CutExtra(List<IntPoint> poly, List<IntPoint> extraClipShape, PolyTree result)
		{
			clipper.Clear();
			clipper.AddPolygon(poly, PolyType.ptSubject);
			clipper.AddPolygon(extraClipShape, PolyType.ptClip);
			result.Clear();
			clipper.Execute(ClipType.ctIntersection, result, PolyFillType.pftEvenOdd, PolyFillType.pftNonZero);
		}

		private int ClipAgainstRectangle(Int3[] clipIn, Int3[] clipOut, Int2 size)
		{
			int num = simpleClipper.ClipPolygon(clipIn, 3, clipOut, 1, 0, 0);
			if (num == 0)
			{
				return num;
			}
			num = simpleClipper.ClipPolygon(clipOut, num, clipIn, -1, size.x, 0);
			if (num == 0)
			{
				return num;
			}
			num = simpleClipper.ClipPolygon(clipIn, num, clipOut, 1, 0, 2);
			if (num == 0)
			{
				return num;
			}
			return simpleClipper.ClipPolygon(clipOut, num, clipIn, -1, size.y, 2);
		}

		private static void CopyMesh(Int3[] vertices, int[] triangles, List<Int3> outVertices, List<int> outTriangles)
		{
			outTriangles.Capacity = Math.Max(outTriangles.Capacity, triangles.Length);
			outVertices.Capacity = Math.Max(outVertices.Capacity, vertices.Length);
			for (int i = 0; i < vertices.Length; i++)
			{
				outVertices.Add(vertices[i]);
			}
			for (int j = 0; j < triangles.Length; j++)
			{
				outTriangles.Add(triangles[j]);
			}
		}

		private void DelaunayRefinement(Int3[] verts, int[] tris, ref int tCount, bool delaunay, bool colinear)
		{
			if (tCount % 3 != 0)
			{
				throw new ArgumentException("Triangle array length must be a multiple of 3");
			}
			Dictionary<Int2, int> dictionary = cached_Int2_int_dict;
			dictionary.Clear();
			for (int i = 0; i < tCount; i += 3)
			{
				if (!VectorMath.IsClockwiseXZ(verts[tris[i]], verts[tris[i + 1]], verts[tris[i + 2]]))
				{
					int num = tris[i];
					tris[i] = tris[i + 2];
					tris[i + 2] = num;
				}
				dictionary[new Int2(tris[i], tris[i + 1])] = i + 2;
				dictionary[new Int2(tris[i + 1], tris[i + 2])] = i;
				dictionary[new Int2(tris[i + 2], tris[i])] = i + 1;
			}
			for (int j = 0; j < tCount; j += 3)
			{
				for (int k = 0; k < 3; k++)
				{
					if (!dictionary.TryGetValue(new Int2(tris[j + (k + 1) % 3], tris[j + k % 3]), out var value))
					{
						continue;
					}
					Int3 @int = verts[tris[j + (k + 2) % 3]];
					Int3 int2 = verts[tris[j + (k + 1) % 3]];
					Int3 int3 = verts[tris[j + (k + 3) % 3]];
					Int3 int4 = verts[tris[value]];
					@int.y = 0;
					int2.y = 0;
					int3.y = 0;
					int4.y = 0;
					bool flag = false;
					if (!VectorMath.RightOrColinearXZ(@int, int3, int4) || VectorMath.RightXZ(@int, int2, int4))
					{
						if (!colinear)
						{
							continue;
						}
						flag = true;
					}
					if (colinear && VectorMath.SqrDistancePointSegmentApproximate(@int, int4, int2) < 9f && !dictionary.ContainsKey(new Int2(tris[j + (k + 2) % 3], tris[j + (k + 1) % 3])) && !dictionary.ContainsKey(new Int2(tris[j + (k + 1) % 3], tris[value])))
					{
						tCount -= 3;
						int num2 = value / 3 * 3;
						tris[j + (k + 1) % 3] = tris[value];
						if (num2 != tCount)
						{
							tris[num2] = tris[tCount];
							tris[num2 + 1] = tris[tCount + 1];
							tris[num2 + 2] = tris[tCount + 2];
							dictionary[new Int2(tris[num2], tris[num2 + 1])] = num2 + 2;
							dictionary[new Int2(tris[num2 + 1], tris[num2 + 2])] = num2;
							dictionary[new Int2(tris[num2 + 2], tris[num2])] = num2 + 1;
							tris[tCount] = 0;
							tris[tCount + 1] = 0;
							tris[tCount + 2] = 0;
						}
						else
						{
							tCount += 3;
						}
						dictionary[new Int2(tris[j], tris[j + 1])] = j + 2;
						dictionary[new Int2(tris[j + 1], tris[j + 2])] = j;
						dictionary[new Int2(tris[j + 2], tris[j])] = j + 1;
					}
					else if (delaunay && !flag)
					{
						float num3 = Int3.Angle(int2 - @int, int3 - @int);
						if (Int3.Angle(int2 - int4, int3 - int4) > MathF.PI * 2f - 2f * num3)
						{
							tris[j + (k + 1) % 3] = tris[value];
							int num4 = value / 3 * 3;
							int num5 = value - num4;
							tris[num4 + (num5 - 1 + 3) % 3] = tris[j + (k + 2) % 3];
							dictionary[new Int2(tris[j], tris[j + 1])] = j + 2;
							dictionary[new Int2(tris[j + 1], tris[j + 2])] = j;
							dictionary[new Int2(tris[j + 2], tris[j])] = j + 1;
							dictionary[new Int2(tris[num4], tris[num4 + 1])] = num4 + 2;
							dictionary[new Int2(tris[num4 + 1], tris[num4 + 2])] = num4;
							dictionary[new Int2(tris[num4 + 2], tris[num4])] = num4 + 1;
						}
					}
				}
			}
		}

		public void ClearTile(int x, int z)
		{
			if (AstarPath.active == null || x < 0 || z < 0 || x >= tileXCount || z >= tileZCount)
			{
				return;
			}
			AstarPath.active.AddWorkItem(new AstarWorkItem(delegate(IWorkItemContext context, bool force)
			{
				graph.ReplaceTile(x, z, new Int3[0], new int[0]);
				activeTileTypes[x + z * tileXCount] = null;
				if (!isBatching)
				{
					context.SetGraphDirty(graph);
				}
				return true;
			}));
		}

		public void ReloadInBounds(Bounds bounds)
		{
			ReloadInBounds(graph.GetTouchingTiles(bounds));
		}

		public void ReloadInBounds(IntRect tiles)
		{
			tiles = IntRect.Intersection(tiles, new IntRect(0, 0, tileXCount - 1, tileZCount - 1));
			if (!tiles.IsValid())
			{
				return;
			}
			for (int i = tiles.ymin; i <= tiles.ymax; i++)
			{
				for (int j = tiles.xmin; j <= tiles.xmax; j++)
				{
					ReloadTile(j, i);
				}
			}
		}

		public void ReloadTile(int x, int z)
		{
			if (x >= 0 && z >= 0 && x < tileXCount && z < tileZCount)
			{
				int num = x + z * tileXCount;
				if (activeTileTypes[num] != null)
				{
					LoadTile(activeTileTypes[num], x, z, activeTileRotations[num], activeTileOffsets[num]);
				}
			}
		}

		public void LoadTile(TileType tile, int x, int z, int rotation, int yoffset)
		{
			if (tile == null)
			{
				throw new ArgumentNullException("tile");
			}
			if (AstarPath.active == null)
			{
				return;
			}
			int index = x + z * tileXCount;
			rotation %= 4;
			if (isBatching && reloadedInBatch[index] && activeTileOffsets[index] == yoffset && activeTileRotations[index] == rotation && activeTileTypes[index] == tile)
			{
				return;
			}
			reloadedInBatch[index] |= isBatching;
			activeTileOffsets[index] = yoffset;
			activeTileRotations[index] = rotation;
			activeTileTypes[index] = tile;
			AstarPath.active.AddWorkItem(new AstarWorkItem(delegate(IWorkItemContext context, bool force)
			{
				if (activeTileOffsets[index] != yoffset || activeTileRotations[index] != rotation || activeTileTypes[index] != tile)
				{
					return true;
				}
				GraphModifier.TriggerEvent(GraphModifier.EventType.PreUpdate);
				tile.Load(out var verts, out var tris, rotation, yoffset);
				CuttingResult cuttingResult = CutPoly(verts, tris, null, graph.transform, new IntRect(x, z, x + tile.Width - 1, z + tile.Depth - 1));
				int tCount = cuttingResult.tris.Length;
				DelaunayRefinement(cuttingResult.verts, cuttingResult.tris, ref tCount, delaunay: true, colinear: false);
				if (tCount != cuttingResult.tris.Length)
				{
					cuttingResult.tris = Memory.ShrinkArray(cuttingResult.tris, tCount);
				}
				int num = ((rotation % 2 == 0) ? tile.Width : tile.Depth);
				int num2 = ((rotation % 2 == 0) ? tile.Depth : tile.Width);
				if (num != 1 || num2 != 1)
				{
					throw new Exception("Only tiles of width = depth = 1 are supported at this time");
				}
				graph.ReplaceTile(x, z, cuttingResult.verts, cuttingResult.tris);
				if (!isBatching)
				{
					context.SetGraphDirty(graph);
				}
				return true;
			}));
		}
	}
	public class Checksum
	{
		public static uint GetChecksum(byte[] arr, uint hash)
		{
			hash ^= 0x811C9DC5u;
			for (int i = 0; i < arr.Length; i++)
			{
				hash = (hash ^ arr[i]) * 16777619;
			}
			return hash;
		}
	}
	public static class Memory
	{
		public static void MemSet<T>(T[] array, T value, int byteSize) where T : struct
		{
			if (array == null)
			{
				throw new ArgumentNullException("array");
			}
			int num = 32;
			int i = 0;
			int num2;
			for (num2 = Math.Min(num, array.Length); i < num2; i++)
			{
				array[i] = value;
			}
			num2 = array.Length;
			while (i < num2)
			{
				Buffer.BlockCopy(array, 0, array, i * byteSize, Math.Min(num, num2 - i) * byteSize);
				i += num;
				num *= 2;
			}
		}

		public static void MemSet<T>(T[] array, T value, int totalSize, int byteSize) where T : struct
		{
			if (array == null)
			{
				throw new ArgumentNullException("array");
			}
			int num = 32;
			int i = 0;
			int num2;
			for (num2 = Math.Min(num, totalSize); i < num2; i++)
			{
				array[i] = value;
			}
			num2 = totalSize;
			while (i < num2)
			{
				Buffer.BlockCopy(array, 0, array, i * byteSize, Math.Min(num, totalSize - i) * byteSize);
				i += num;
				num *= 2;
			}
		}

		public static T[] ShrinkArray<T>(T[] arr, int newLength)
		{
			newLength = Math.Min(newLength, arr.Length);
			T[] array = new T[newLength];
			Array.Copy(arr, array, newLength);
			return array;
		}

		public static void Swap<T>(ref T a, ref T b)
		{
			T val = a;
			a = b;
			b = val;
		}
	}
	public class ParallelWorkQueue<T>
	{
		public Action<T, int> action;

		public readonly int threadCount;

		private readonly Queue<T> queue;

		private readonly int initialCount;

		private ManualResetEvent[] waitEvents;

		private Exception innerException;

		public ParallelWorkQueue(Queue<T> queue)
		{
			this.queue = queue;
			initialCount = queue.Count;
			threadCount = Math.Min(initialCount, Math.Max(1, AstarPath.CalculateThreadCount(ThreadCount.AutomaticHighLoad)));
		}

		public IEnumerable<int> Run(int progressTimeoutMillis)
		{
			if (initialCount != queue.Count)
			{
				throw new InvalidOperationException("Queue has been modified since the constructor");
			}
			if (initialCount == 0)
			{
				yield break;
			}
			waitEvents = new ManualResetEvent[threadCount];
			for (int i = 0; i < waitEvents.Length; i++)
			{
				waitEvents[i] = new ManualResetEvent(initialState: false);
				ThreadPool.QueueUserWorkItem(delegate(object threadIndex)
				{
					RunTask((int)threadIndex);
				}, i);
			}
			while (true)
			{
				WaitHandle[] waitHandles = waitEvents;
				if (WaitHandle.WaitAll(waitHandles, progressTimeoutMillis))
				{
					break;
				}
				int count;
				lock (queue)
				{
					count = queue.Count;
				}
				yield return initialCount - count;
			}
			if (innerException == null)
			{
				yield break;
			}
			throw innerException;
		}

		private void RunTask(int threadIndex)
		{
			try
			{
				while (true)
				{
					T arg;
					lock (queue)
					{
						if (queue.Count == 0)
						{
							break;
						}
						arg = queue.Dequeue();
					}
					action(arg, threadIndex);
				}
			}
			catch (Exception ex)
			{
				innerException = ex;
				lock (queue)
				{
					queue.Clear();
				}
			}
			finally
			{
				waitEvents[threadIndex].Set();
			}
		}
	}
	public struct Guid
	{
		private const string hex = "0123456789ABCDEF";

		public static readonly Guid zero = new Guid(new byte[16]);

		public static readonly string zeroString = new Guid(new byte[16]).ToString();

		private readonly ulong _a;

		private readonly ulong _b;

		private static System.Random random = new System.Random();

		private static StringBuilder text;

		public Guid(byte[] bytes)
		{
			ulong num = bytes[0] | ((ulong)bytes[1] << 8) | ((ulong)bytes[2] << 16) | ((ulong)bytes[3] << 24) | ((ulong)bytes[4] << 32) | ((ulong)bytes[5] << 40) | ((ulong)bytes[6] << 48) | ((ulong)bytes[7] << 56);
			ulong num2 = bytes[8] | ((ulong)bytes[9] << 8) | ((ulong)bytes[10] << 16) | ((ulong)bytes[11] << 24) | ((ulong)bytes[12] << 32) | ((ulong)bytes[13] << 40) | ((ulong)bytes[14] << 48) | ((ulong)bytes[15] << 56);
			_a = (BitConverter.IsLittleEndian ? num : SwapEndianness(num));
			_b = (BitConverter.IsLittleEndian ? num2 : SwapEndianness(num2));
		}

		public Guid(string str)
		{
			_a = 0uL;
			_b = 0uL;
			if (str.Length < 32)
			{
				throw new FormatException("Invalid Guid format");
			}
			int num = 0;
			int num2 = 0;
			int num3 = 60;
			while (num < 16)
			{
				if (num2 >= str.Length)
				{
					throw new FormatException("Invalid Guid format. String too short");
				}
				char c = str[num2];
				if (c != '-')
				{
					int num4 = "0123456789ABCDEF".IndexOf(char.ToUpperInvariant(c));
					if (num4 == -1)
					{
						throw new FormatException("Invalid Guid format : " + c + " is not a hexadecimal character");
					}
					_a |= (ulong)((long)num4 << num3);
					num3 -= 4;
					num++;
				}
				num2++;
			}
			num3 = 60;
			while (num < 32)
			{
				if (num2 >= str.Length)
				{
					throw new FormatException("Invalid Guid format. String too short");
				}
				char c2 = str[num2];
				if (c2 != '-')
				{
					int num5 = "0123456789ABCDEF".IndexOf(char.ToUpperInvariant(c2));
					if (num5 == -1)
					{
						throw new FormatException("Invalid Guid format : " + c2 + " is not a hexadecimal character");
					}
					_b |= (ulong)((long)num5 << num3);
					num3 -= 4;
					num++;
				}
				num2++;
			}
		}

		public static Guid Parse(string input)
		{
			return new Guid(input);
		}

		private static ulong SwapEndianness(ulong value)
		{
			ulong num = value & 0xFF;
			ulong num2 = (value >> 8) & 0xFF;
			ulong num3 = (value >> 16) & 0xFF;
			ulong num4 = (value >> 24) & 0xFF;
			ulong num5 = (value >> 32) & 0xFF;
			ulong num6 = (value >> 40) & 0xFF;
			ulong num7 = (value >> 48) & 0xFF;
			ulong num8 = (value >> 56) & 0xFF;
			return (num << 56) | (num2 << 48) | (num3 << 40) | (num4 << 32) | (num5 << 24) | (num6 << 16) | (num7 << 8) | num8;
		}

		public byte[] ToByteArray()
		{
			byte[] array = new byte[16];
			byte[] bytes = BitConverter.GetBytes((!BitConverter.IsLittleEndian) ? SwapEndianness(_a) : _a);
			byte[] bytes2 = BitConverter.GetBytes((!BitConverter.IsLittleEndian) ? SwapEndianness(_b) : _b);
			for (int i = 0; i < 8; i++)
			{
				array[i] = bytes[i];
				array[i + 8] = bytes2[i];
			}
			return array;
		}

		public static Guid NewGuid()
		{
			byte[] array = new byte[16];
			random.NextBytes(array);
			return new Guid(array);
		}

		public static bool operator ==(Guid lhs, Guid rhs)
		{
			if (lhs._a == rhs._a)
			{
				return lhs._b == rhs._b;
			}
			return false;
		}

		public static bool operator !=(Guid lhs, Guid rhs)
		{
			if (lhs._a == rhs._a)
			{
				return lhs._b != rhs._b;
			}
			return true;
		}

		public override bool Equals(object _rhs)
		{
			if (!(_rhs is Guid guid))
			{
				return false;
			}
			if (_a == guid._a)
			{
				return _b == guid._b;
			}
			return false;
		}

		public override int GetHashCode()
		{
			ulong num = _a ^ _b;
			return (int)(num >> 32) ^ (int)num;
		}

		public override string ToString()
		{
			if (text == null)
			{
				text = new StringBuilder();
			}
			lock (text)
			{
				text.Length = 0;
				text.Append(_a.ToString("x16")).Append('-').Append(_b.ToString("x16"));
				return text.ToString();
			}
		}
	}
	public class GraphGizmoHelper : IAstarPooledObject, IDisposable
	{
		private RetainedGizmos gizmos;

		private PathHandler debugData;

		private ushort debugPathID;

		private GraphDebugMode debugMode;

		private bool showSearchTree;

		private float debugFloor;

		private float debugRoof;

		private Vector3 drawConnectionStart;

		private Color drawConnectionColor;

		private readonly Action<GraphNode> drawConnection;

		public RetainedGizmos.Hasher hasher { get; private set; }

		public RetainedGizmos.Builder builder { get; private set; }

		public GraphGizmoHelper()
		{
			drawConnection = DrawConnection;
		}

		public void Init(AstarPath active, RetainedGizmos.Hasher hasher, RetainedGizmos gizmos)
		{
			if (active != null)
			{
				debugData = active.debugPathData;
				debugPathID = active.debugPathID;
				debugMode = active.debugMode;
				debugFloor = active.debugFloor;
				debugRoof = active.debugRoof;
				showSearchTree = active.showSearchTree && debugData != null;
			}
			this.gizmos = gizmos;
			this.hasher = hasher;
			builder = ObjectPool<RetainedGizmos.Builder>.Claim();
		}

		public void OnEnterPool()
		{
			RetainedGizmos.Builder obj = builder;
			ObjectPool<RetainedGizmos.Builder>.Release(ref obj);
			builder = null;
			debugData = null;
		}

		public void DrawConnections(GraphNode node)
		{
			if (showSearchTree)
			{
				if (InSearchTree(node, debugData, debugPathID) && debugData.GetPathNode(node).parent != null)
				{
					builder.DrawLine((Vector3)node.position, (Vector3)debugData.GetPathNode(node).parent.node.position, NodeColor(node));
				}
			}
			else
			{
				drawConnectionColor = NodeColor(node);
				drawConnectionStart = (Vector3)node.position;
				node.GetConnections(drawConnection);
			}
		}

		private void DrawConnection(GraphNode other)
		{
			builder.DrawLine(drawConnectionStart, Vector3.Lerp((Vector3)other.position, drawConnectionStart, 0.5f), drawConnectionColor);
		}

		public Color NodeColor(GraphNode node)
		{
			if (showSearchTree && !InSearchTree(node, debugData, debugPathID))
			{
				return Color.clear;
			}
			if (node.Walkable)
			{
				switch (debugMode)
				{
				case GraphDebugMode.Areas:
					return AstarColor.GetAreaColor(node.Area);
				case GraphDebugMode.HierarchicalNode:
					return AstarColor.GetTagColor((uint)node.HierarchicalNodeIndex);
				case GraphDebugMode.Penalty:
					return Color.Lerp(AstarColor.ConnectionLowLerp, AstarColor.ConnectionHighLerp, ((float)node.Penalty - debugFloor) / (debugRoof - debugFloor));
				case GraphDebugMode.Tags:
					return AstarColor.GetTagColor(node.Tag);
				case GraphDebugMode.SolidColor:
					return AstarColor.SolidColor;
				default:
					if (debugData != null)
					{
						PathNode pathNode = debugData.GetPathNode(node);
						return Color.Lerp(t: (((debugMode == GraphDebugMode.G) ? ((float)pathNode.G) : ((debugMode != GraphDebugMode.H) ? ((float)pathNode.F) : ((float)pathNode.H))) - debugFloor) / (debugRoof - debugFloor), a: AstarColor.ConnectionLowLerp, b: AstarColor.ConnectionHighLerp);
					}
					return AstarColor.SolidColor;
				}
			}
			return AstarColor.UnwalkableNode;
		}

		public static bool InSearchTree(GraphNode node, PathHandler handler, ushort pathID)
		{
			return handler.GetPathNode(node).pathID == pathID;
		}

		public void DrawWireTriangle(Vector3 a, Vector3 b, Vector3 c, Color color)
		{
			builder.DrawLine(a, b, color);
			builder.DrawLine(b, c, color);
			builder.DrawLine(c, a, color);
		}

		public void DrawTriangles(Vector3[] vertices, Color[] colors, int numTriangles)
		{
			List<int> list = ListPool<int>.Claim(numTriangles);
			for (int i = 0; i < numTriangles * 3; i++)
			{
				list.Add(i);
			}
			builder.DrawMesh(gizmos, vertices, list, colors);
			ListPool<int>.Release(ref list);
		}

		public void DrawWireTriangles(Vector3[] vertices, Color[] colors, int numTriangles)
		{
			for (int i = 0; i < numTriangles; i++)
			{
				DrawWireTriangle(vertices[i * 3], vertices[i * 3 + 1], vertices[i * 3 + 2], colors[i * 3]);
			}
		}

		public void Submit()
		{
			builder.Submit(gizmos, hasher);
		}

		void IDisposable.Dispose()
		{
			GraphGizmoHelper obj = this;
			Submit();
			ObjectPool<GraphGizmoHelper>.Release(ref obj);
		}
	}
	public class RetainedGizmos
	{
		public struct Hasher
		{
			private ulong hash;

			private bool includePathSearchInfo;

			private bool includeAreaInfo;

			private PathHandler debugData;

			public ulong Hash => hash;

			public Hasher(AstarPath active)
			{
				hash = 0uL;
				debugData = active.debugPathData;
				includePathSearchInfo = debugData != null && (active.debugMode == GraphDebugMode.F || active.debugMode == GraphDebugMode.G || active.debugMode == GraphDebugMode.H || active.showSearchTree);
				includeAreaInfo = active.debugMode == GraphDebugMode.Areas;
				AddHash((int)active.debugMode);
				AddHash(active.debugFloor.GetHashCode());
				AddHash(active.debugRoof.GetHashCode());
				AddHash(AstarColor.ColorHash());
			}

			public void AddHash(int hash)
			{
				this.hash = (1572869 * this.hash) ^ (ulong)hash;
			}

			public void HashNode(GraphNode node)
			{
				AddHash(node.GetGizmoHashCode());
				if (includeAreaInfo)
				{
					AddHash((int)node.Area);
				}
				if (includePathSearchInfo)
				{
					PathNode pathNode = debugData.GetPathNode(node.NodeIndex);
					AddHash(pathNode.pathID);
					AddHash((pathNode.pathID == debugData.PathID) ? 1 : 0);
					AddHash((int)pathNode.F);
				}
			}
		}

		public class Builder : IAstarPooledObject
		{
			private List<Vector3> lines = new List<Vector3>();

			private List<Color32> lineColors = new List<Color32>();

			private List<Mesh> meshes = new List<Mesh>();

			public void DrawMesh(RetainedGizmos gizmos, Vector3[] vertices, List<int> triangles, Color[] colors)
			{
				Mesh mesh = gizmos.GetMesh();
				mesh.vertices = vertices;
				mesh.SetTriangles(triangles, 0);
				mesh.colors = colors;
				mesh.UploadMeshData(markNoLongerReadable: false);
				meshes.Add(mesh);
			}

			public void DrawWireCube(GraphTransform tr, Bounds bounds, Color color)
			{
				Vector3 min = bounds.min;
				Vector3 max = bounds.max;
				DrawLine(tr.Transform(new Vector3(min.x, min.y, min.z)), tr.Transform(new Vector3(max.x, min.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, min.y, min.z)), tr.Transform(new Vector3(max.x, min.y, max.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, min.y, max.z)), tr.Transform(new Vector3(min.x, min.y, max.z)), color);
				DrawLine(tr.Transform(new Vector3(min.x, min.y, max.z)), tr.Transform(new Vector3(min.x, min.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(min.x, max.y, min.z)), tr.Transform(new Vector3(max.x, max.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, max.y, min.z)), tr.Transform(new Vector3(max.x, max.y, max.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, max.y, max.z)), tr.Transform(new Vector3(min.x, max.y, max.z)), color);
				DrawLine(tr.Transform(new Vector3(min.x, max.y, max.z)), tr.Transform(new Vector3(min.x, max.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(min.x, min.y, min.z)), tr.Transform(new Vector3(min.x, max.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, min.y, min.z)), tr.Transform(new Vector3(max.x, max.y, min.z)), color);
				DrawLine(tr.Transform(new Vector3(max.x, min.y, max.z)), tr.Transform(new Vector3(max.x, max.y, max.z)), color);
				DrawLine(tr.Transform(new Vector3(min.x, min.y, max.z)), tr.Transform(new Vector3(min.x, max.y, max.z)), color);
			}

			public void DrawLine(Vector3 start, Vector3 end, Color color)
			{
				lines.Add(start);
				lines.Add(end);
				Color32 item = color;
				lineColors.Add(item);
				lineColors.Add(item);
			}

			public void Submit(RetainedGizmos gizmos, Hasher hasher)
			{
				SubmitLines(gizmos, hasher.Hash);
				SubmitMeshes(gizmos, hasher.Hash);
			}

			private void SubmitMeshes(RetainedGizmos gizmos, ulong hash)
			{
				for (int i = 0; i < meshes.Count; i++)
				{
					gizmos.meshes.Add(new MeshWithHash
					{
						hash = hash,
						mesh = meshes[i],
						lines = false
					});
					gizmos.existingHashes.Add(hash);
				}
			}

			private void SubmitLines(RetainedGizmos gizmos, ulong hash)
			{
				int num = (lines.Count + 32766 - 1) / 32766;
				for (int i = 0; i < num; i++)
				{
					int num2 = 32766 * i;
					int num3 = Mathf.Min(num2 + 32766, lines.Count);
					int num4 = num3 - num2;
					List<Vector3> list = ListPool<Vector3>.Claim(num4 * 2);
					List<Color32> list2 = ListPool<Color32>.Claim(num4 * 2);
					List<Vector3> list3 = ListPool<Vector3>.Claim(num4 * 2);
					List<Vector2> list4 = ListPool<Vector2>.Claim(num4 * 2);
					List<int> list5 = ListPool<int>.Claim(num4 * 3);
					for (int j = num2; j < num3; j++)
					{
						Vector3 item = lines[j];
						list.Add(item);
						list.Add(item);
						Color32 item2 = lineColors[j];
						list2.Add(item2);
						list2.Add(item2);
						list4.Add(new Vector2(0f, 0f));
						list4.Add(new Vector2(1f, 0f));
					}
					for (int k = num2; k < num3; k += 2)
					{
						Vector3 item3 = lines[k + 1] - lines[k];
						list3.Add(item3);
						list3.Add(item3);
						list3.Add(item3);
						list3.Add(item3);
					}
					int num5 = 0;
					int num6 = 0;
					while (num5 < num4 * 3)
					{
						list5.Add(num6);
						list5.Add(num6 + 1);
						list5.Add(num6 + 2);
						list5.Add(num6 + 1);
						list5.Add(num6 + 3);
						list5.Add(num6 + 2);
						num5 += 6;
						num6 += 4;
					}
					Mesh mesh = gizmos.GetMesh();
					mesh.SetVertices(list);
					mesh.SetTriangles(list5, 0);
					mesh.SetColors(list2);
					mesh.SetNormals(list3);
					mesh.SetUVs(0, list4);
					mesh.UploadMeshData(markNoLongerReadable: false);
					ListPool<Vector3>.Release(ref list);
					ListPool<Color32>.Release(ref list2);
					ListPool<Vector3>.Release(ref list3);
					ListPool<Vector2>.Release(ref list4);
					ListPool<int>.Release(ref list5);
					gizmos.meshes.Add(new MeshWithHash
					{
						hash = hash,
						mesh = mesh,
						lines = true
					});
					gizmos.existingHashes.Add(hash);
				}
			}

			void IAstarPooledObject.OnEnterPool()
			{
				lines.Clear();
				lineColors.Clear();
				meshes.Clear();
			}
		}

		private struct MeshWithHash
		{
			public ulong hash;

			public Mesh mesh;

			public bool lines;
		}

		private List<MeshWithHash> meshes = new List<MeshWithHash>();

		private HashSet<ulong> usedHashes = new HashSet<ulong>();

		private HashSet<ulong> existingHashes = new HashSet<ulong>();

		private Stack<Mesh> cachedMeshes = new Stack<Mesh>();

		public Material surfaceMaterial;

		public Material lineMaterial;

		public GraphGizmoHelper GetSingleFrameGizmoHelper(AstarPath active)
		{
			Hasher hasher = default(Hasher);
			hasher.AddHash(Time.realtimeSinceStartup.GetHashCode());
			Draw(hasher);
			return GetGizmoHelper(active, hasher);
		}

		public GraphGizmoHelper GetGizmoHelper(AstarPath active, Hasher hasher)
		{
			GraphGizmoHelper graphGizmoHelper = ObjectPool<GraphGizmoHelper>.Claim();
			graphGizmoHelper.Init(active, hasher, this);
			return graphGizmoHelper;
		}

		private void PoolMesh(Mesh mesh)
		{
			mesh.Clear();
			cachedMeshes.Push(mesh);
		}

		private Mesh GetMesh()
		{
			if (cachedMeshes.Count > 0)
			{
				return cachedMeshes.Pop();
			}
			return new Mesh
			{
				hideFlags = HideFlags.DontSave
			};
		}

		public bool HasCachedMesh(Hasher hasher)
		{
			return existingHashes.Contains(hasher.Hash);
		}

		public bool Draw(Hasher hasher)
		{
			usedHashes.Add(hasher.Hash);
			return HasCachedMesh(hasher);
		}

		public void DrawExisting()
		{
			for (int i = 0; i < meshes.Count; i++)
			{
				usedHashes.Add(meshes[i].hash);
			}
		}

		public void FinalizeDraw()
		{
			RemoveUnusedMeshes(meshes);
			Plane[] planes = GeometryUtility.CalculateFrustumPlanes(Camera.current);
			if (surfaceMaterial == null || lineMaterial == null)
			{
				return;
			}
			for (int i = 0; i <= 1; i++)
			{
				Material material = ((i == 0) ? surfaceMaterial : lineMaterial);
				for (int j = 0; j < material.passCount; j++)
				{
					material.SetPass(j);
					for (int k = 0; k < meshes.Count; k++)
					{
						if (meshes[k].lines == (material == lineMaterial) && GeometryUtility.TestPlanesAABB(planes, meshes[k].mesh.bounds))
						{
							Graphics.DrawMeshNow(meshes[k].mesh, Matrix4x4.identity);
						}
					}
				}
			}
			usedHashes.Clear();
		}

		public void ClearCache()
		{
			usedHashes.Clear();
			RemoveUnusedMeshes(meshes);
			while (cachedMeshes.Count > 0)
			{
				UnityEngine.Object.DestroyImmediate(cachedMeshes.Pop());
			}
		}

		private void RemoveUnusedMeshes(List<MeshWithHash> meshList)
		{
			int num = 0;
			int num2 = 0;
			while (num < meshList.Count)
			{
				if (num2 == meshList.Count)
				{
					num2--;
					meshList.RemoveAt(num2);
				}
				else if (usedHashes.Contains(meshList[num2].hash))
				{
					meshList[num] = meshList[num2];
					num++;
					num2++;
				}
				else
				{
					PoolMesh(meshList[num2].mesh);
					existingHashes.Remove(meshList[num2].hash);
					num2++;
				}
			}
		}
	}
}
