	public class Simulator
	{
		internal class WorkerContext
		{
			public Agent.VOBuffer vos = new Agent.VOBuffer(16);

			public const int KeepCount = 3;

			public Vector2[] bestPos = new Vector2[3];

			public float[] bestSizes = new float[3];

			public float[] bestScores = new float[4];

			public Vector2[] samplePos = new Vector2[50];

			public float[] sampleSize = new float[50];
		}

		private class Worker
		{
			public int start;

			public int end;

			private readonly ManualResetEventSlim runFlag = new ManualResetEventSlim(initialState: false);

			private readonly ManualResetEventSlim waitFlag = new ManualResetEventSlim(initialState: true);

			private readonly Simulator simulator;

			private int task;

			private bool terminate;

			private WorkerContext context = new WorkerContext();

			public Worker(Simulator sim)
			{
				simulator = sim;
				Thread thread = new Thread(Run);
				thread.IsBackground = true;
				thread.Name = "RVO Simulator Thread";
				thread.Start();
			}

			public void Execute(int task)
			{
				this.task = task;
				waitFlag.Reset();
				runFlag.Set();
			}

			public void WaitOne()
			{
				if (!terminate)
				{
					waitFlag.Wait();
				}
			}

			public void Terminate()
			{
				WaitOne();
				terminate = true;
				Execute(-1);
			}

			public void Run()
			{
				runFlag.Wait();
				runFlag.Reset();
				while (!terminate)
				{
					try
					{
						List<Agent> agents = simulator.GetAgents();
						if (task == 0)
						{
							for (int i = start; i < end; i++)
							{
								agents[i].CalculateNeighbours();
								agents[i].CalculateVelocity(context);
							}
						}
						else if (task == 1)
						{
							for (int j = start; j < end; j++)
							{
								agents[j].BufferSwitch();
							}
						}
						else
						{
							if (task != 2)
							{
								UnityEngine.Debug.LogError("Invalid Task Number: " + task);
								throw new Exception("Invalid Task Number: " + task);
							}
							simulator.BuildQuadtree();
						}
					}
					catch (Exception message)
					{
						UnityEngine.Debug.LogError(message);
					}
					waitFlag.Set();
					runFlag.Wait();
					runFlag.Reset();
				}
			}
		}

		private readonly bool doubleBuffering = true;

		private float desiredDeltaTime = 0.05f;

		private readonly Worker[] workers;

		private List<Agent> agents;

		public List<ObstacleVertex> obstacles;

		private float deltaTime;

		private float lastStep = -99999f;

		private bool doUpdateObstacles;

		private bool doCleanObstacles;

		public float symmetryBreakingBias = 0.1f;

		public readonly MovementPlane movementPlane;

		private WorkerContext coroutineWorkerContext = new WorkerContext();

		public RVOQuadtree Quadtree { get; private set; }

		public float DeltaTime => deltaTime;

		public bool Multithreading
		{
			get
			{
				if (workers != null)
				{
					return workers.Length != 0;
				}
				return false;
			}
		}

		public float DesiredDeltaTime
		{
			get
			{
				return desiredDeltaTime;
			}
			set
			{
				desiredDeltaTime = Math.Max(value, 0f);
			}
		}

		public List<Agent> GetAgents()
		{
			return agents;
		}

		public List<ObstacleVertex> GetObstacles()
		{
			return obstacles;
		}

		public Simulator(int workers, bool doubleBuffering, MovementPlane movementPlane)
		{
			this.workers = new Worker[workers];
			this.doubleBuffering = doubleBuffering;
			DesiredDeltaTime = 1f;
			this.movementPlane = movementPlane;
			Quadtree = new RVOQuadtree();
			for (int i = 0; i < workers; i++)
			{
				this.workers[i] = new Worker(this);
			}
			agents = new List<Agent>();
			obstacles = new List<ObstacleVertex>();
		}

		public void ClearAgents()
		{
			BlockUntilSimulationStepIsDone();
			for (int i = 0; i < agents.Count; i++)
			{
				agents[i].simulator = null;
			}
			agents.Clear();
		}

		public void OnDestroy()
		{
			if (workers != null)
			{
				for (int i = 0; i < workers.Length; i++)
				{
					workers[i].Terminate();
				}
			}
		}

		public IAgent AddAgent(IAgent agent)
		{
			if (agent == null)
			{
				throw new ArgumentNullException("Agent must not be null");
			}
			if (!(agent is Agent agent2))
			{
				throw new ArgumentException("The agent must be of type Agent. Agent was of type " + agent.GetType());
			}
			if (agent2.simulator != null && agent2.simulator == this)
			{
				throw new ArgumentException("The agent is already in the simulation");
			}
			if (agent2.simulator != null)
			{
				throw new ArgumentException("The agent is already added to another simulation");
			}
			agent2.simulator = this;
			BlockUntilSimulationStepIsDone();
			agents.Add(agent2);
			return agent;
		}

		[Obsolete("Use AddAgent(Vector2,float) instead")]
		public IAgent AddAgent(Vector3 position)
		{
			return AddAgent(new Vector2(position.x, position.z), position.y);
		}

		public IAgent AddAgent(Vector2 position, float elevationCoordinate)
		{
			return AddAgent(new Agent(position, elevationCoordinate));
		}

		public void RemoveAgent(IAgent agent)
		{
			if (agent == null)
			{
				throw new ArgumentNullException("Agent must not be null");
			}
			if (!(agent is Agent agent2))
			{
				throw new ArgumentException("The agent must be of type Agent. Agent was of type " + agent.GetType());
			}
			if (agent2.simulator != this)
			{
				throw new ArgumentException("The agent is not added to this simulation");
			}
			BlockUntilSimulationStepIsDone();
			agent2.simulator = null;
			if (!agents.Remove(agent2))
			{
				throw new ArgumentException("Critical Bug! This should not happen. Please report this.");
			}
		}

		public ObstacleVertex AddObstacle(ObstacleVertex v)
		{
			if (v == null)
			{
				throw new ArgumentNullException("Obstacle must not be null");
			}
			BlockUntilSimulationStepIsDone();
			obstacles.Add(v);
			UpdateObstacles();
			return v;
		}

		public ObstacleVertex AddObstacle(Vector3[] vertices, float height, bool cycle = true)
		{
			return AddObstacle(vertices, height, Matrix4x4.identity, RVOLayer.DefaultObstacle, cycle);
		}

		public ObstacleVertex AddObstacle(Vector3[] vertices, float height, Matrix4x4 matrix, RVOLayer layer = RVOLayer.DefaultObstacle, bool cycle = true)
		{
			if (vertices == null)
			{
				throw new ArgumentNullException("Vertices must not be null");
			}
			if (vertices.Length < 2)
			{
				throw new ArgumentException("Less than 2 vertices in an obstacle");
			}
			ObstacleVertex obstacleVertex = null;
			ObstacleVertex obstacleVertex2 = null;
			BlockUntilSimulationStepIsDone();
			for (int i = 0; i < vertices.Length; i++)
			{
				ObstacleVertex obstacleVertex3 = new ObstacleVertex
				{
					prev = obstacleVertex2,
					layer = layer,
					height = height
				};
				if (obstacleVertex == null)
				{
					obstacleVertex = obstacleVertex3;
				}
				else
				{
					obstacleVertex2.next = obstacleVertex3;
				}
				obstacleVertex2 = obstacleVertex3;
			}
			if (cycle)
			{
				obstacleVertex2.next = obstacleVertex;
				obstacleVertex.prev = obstacleVertex2;
			}
			UpdateObstacle(obstacleVertex, vertices, matrix);
			obstacles.Add(obstacleVertex);
			return obstacleVertex;
		}

		public ObstacleVertex AddObstacle(Vector3 a, Vector3 b, float height)
		{
			ObstacleVertex obstacleVertex = new ObstacleVertex();
			ObstacleVertex obstacleVertex2 = new ObstacleVertex();
			obstacleVertex.layer = RVOLayer.DefaultObstacle;
			obstacleVertex2.layer = RVOLayer.DefaultObstacle;
			obstacleVertex.prev = obstacleVertex2;
			obstacleVertex2.prev = obstacleVertex;
			obstacleVertex.next = obstacleVertex2;
			obstacleVertex2.next = obstacleVertex;
			obstacleVertex.position = a;
			obstacleVertex2.position = b;
			obstacleVertex.height = height;
			obstacleVertex2.height = height;
			obstacleVertex2.ignore = true;
			obstacleVertex.dir = new Vector2(b.x - a.x, b.z - a.z).normalized;
			obstacleVertex2.dir = -obstacleVertex.dir;
			BlockUntilSimulationStepIsDone();
			obstacles.Add(obstacleVertex);
			UpdateObstacles();
			return obstacleVertex;
		}

		public void UpdateObstacle(ObstacleVertex obstacle, Vector3[] vertices, Matrix4x4 matrix)
		{
			if (vertices == null)
			{
				throw new ArgumentNullException("Vertices must not be null");
			}
			if (obstacle == null)
			{
				throw new ArgumentNullException("Obstacle must not be null");
			}
			if (vertices.Length < 2)
			{
				throw new ArgumentException("Less than 2 vertices in an obstacle");
			}
			bool flag = matrix == Matrix4x4.identity;
			BlockUntilSimulationStepIsDone();
			int num = 0;
			ObstacleVertex obstacleVertex = obstacle;
			do
			{
				if (num >= vertices.Length)
				{
					UnityEngine.Debug.DrawLine(obstacleVertex.prev.position, obstacleVertex.position, Color.red);
					throw new ArgumentException("Obstacle has more vertices than supplied for updating (" + vertices.Length + " supplied)");
				}
				obstacleVertex.position = (flag ? vertices[num] : matrix.MultiplyPoint3x4(vertices[num]));
				obstacleVertex = obstacleVertex.next;
				num++;
			}
			while (obstacleVertex != obstacle && obstacleVertex != null);
			obstacleVertex = obstacle;
			do
			{
				if (obstacleVertex.next == null)
				{
					obstacleVertex.dir = Vector2.zero;
				}
				else
				{
					Vector3 vector = obstacleVertex.next.position - obstacleVertex.position;
					obstacleVertex.dir = new Vector2(vector.x, vector.z).normalized;
				}
				obstacleVertex = obstacleVertex.next;
			}
			while (obstacleVertex != obstacle && obstacleVertex != null);
			ScheduleCleanObstacles();
			UpdateObstacles();
		}

		private void ScheduleCleanObstacles()
		{
			doCleanObstacles = true;
		}

		private void CleanObstacles()
		{
		}

		public void RemoveObstacle(ObstacleVertex v)
		{
			if (v == null)
			{
				throw new ArgumentNullException("Vertex must not be null");
			}
			BlockUntilSimulationStepIsDone();
			obstacles.Remove(v);
			UpdateObstacles();
		}

		public void UpdateObstacles()
		{
			doUpdateObstacles = true;
		}

		private void BuildQuadtree()
		{
			Quadtree.Clear();
			if (agents.Count > 0)
			{
				Rect bounds = Rect.MinMaxRect(agents[0].position.x, agents[0].position.y, agents[0].position.x, agents[0].position.y);
				for (int i = 1; i < agents.Count; i++)
				{
					Vector2 position = agents[i].position;
					bounds = Rect.MinMaxRect(Mathf.Min(bounds.xMin, position.x), Mathf.Min(bounds.yMin, position.y), Mathf.Max(bounds.xMax, position.x), Mathf.Max(bounds.yMax, position.y));
				}
				Quadtree.SetBounds(bounds);
				for (int j = 0; j < agents.Count; j++)
				{
					Quadtree.Insert(agents[j]);
				}
			}
			Quadtree.CalculateSpeeds();
		}

		private void BlockUntilSimulationStepIsDone()
		{
			if (Multithreading && doubleBuffering)
			{
				for (int i = 0; i < workers.Length; i++)
				{
					workers[i].WaitOne();
				}
			}
		}

		private void PreCalculation()
		{
			for (int i = 0; i < agents.Count; i++)
			{
				agents[i].PreCalculation();
			}
		}

		private void CleanAndUpdateObstaclesIfNecessary()
		{
			if (doCleanObstacles)
			{
				CleanObstacles();
				doCleanObstacles = false;
				doUpdateObstacles = true;
			}
			if (doUpdateObstacles)
			{
				doUpdateObstacles = false;
			}
		}

		public void Update()
		{
			if (lastStep < 0f)
			{
				lastStep = Time.time;
				deltaTime = DesiredDeltaTime;
			}
			if (!(Time.time - lastStep >= DesiredDeltaTime))
			{
				return;
			}
			deltaTime = Time.time - lastStep;
			lastStep = Time.time;
			deltaTime = Math.Max(deltaTime, 0.0005f);
			if (Multithreading)
			{
				if (doubleBuffering)
				{
					for (int i = 0; i < workers.Length; i++)
					{
						workers[i].WaitOne();
					}
					for (int j = 0; j < agents.Count; j++)
					{
						agents[j].PostCalculation();
					}
				}
				PreCalculation();
				CleanAndUpdateObstaclesIfNecessary();
				BuildQuadtree();
				for (int k = 0; k < workers.Length; k++)
				{
					workers[k].start = k * agents.Count / workers.Length;
					workers[k].end = (k + 1) * agents.Count / workers.Length;
				}
				for (int l = 0; l < workers.Length; l++)
				{
					workers[l].Execute(1);
				}
				for (int m = 0; m < workers.Length; m++)
				{
					workers[m].WaitOne();
				}
				for (int n = 0; n < workers.Length; n++)
				{
					workers[n].Execute(0);
				}
				if (!doubleBuffering)
				{
					for (int num = 0; num < workers.Length; num++)
					{
						workers[num].WaitOne();
					}
					for (int num2 = 0; num2 < agents.Count; num2++)
					{
						agents[num2].PostCalculation();
					}
				}
			}
			else
			{
				PreCalculation();
				CleanAndUpdateObstaclesIfNecessary();
				BuildQuadtree();
				for (int num3 = 0; num3 < agents.Count; num3++)
				{
					agents[num3].BufferSwitch();
				}
				for (int num4 = 0; num4 < agents.Count; num4++)
				{
					agents[num4].CalculateNeighbours();
					agents[num4].CalculateVelocity(coroutineWorkerContext);
				}
				for (int num5 = 0; num5 < agents.Count; num5++)
				{
					agents[num5].PostCalculation();
				}
			}
		}
	}
	public struct Line
	{
		public Vector2 point;

		public Vector2 dir;
	}
	public class RVOQuadtree
	{
		private struct Node
		{
			public int child00;

			public Agent linkedList;

			public byte count;

			public float maxSpeed;

			public void Add(Agent agent)
			{
				agent.next = linkedList;
				linkedList = agent;
			}

			public void Distribute(Node[] nodes, Rect r)
			{
				Vector2 center = r.center;
				while (linkedList != null)
				{
					Agent next = linkedList.next;
					int num = child00 + ((linkedList.position.x > center.x) ? 2 : 0) + ((linkedList.position.y > center.y) ? 1 : 0);
					nodes[num].Add(linkedList);
					linkedList = next;
				}
				count = 0;
			}

			public float CalculateMaxSpeed(Node[] nodes, int index)
			{
				if (child00 == index)
				{
					for (Agent next = linkedList; next != null; next = next.next)
					{
						maxSpeed = Math.Max(maxSpeed, next.CalculatedSpeed);
					}
				}
				else
				{
					maxSpeed = Math.Max(nodes[child00].CalculateMaxSpeed(nodes, child00), nodes[child00 + 1].CalculateMaxSpeed(nodes, child00 + 1));
					maxSpeed = Math.Max(maxSpeed, nodes[child00 + 2].CalculateMaxSpeed(nodes, child00 + 2));
					maxSpeed = Math.Max(maxSpeed, nodes[child00 + 3].CalculateMaxSpeed(nodes, child00 + 3));
				}
				return maxSpeed;
			}
		}

		private struct QuadtreeQuery
		{
			public Vector2 p;

			public float speed;

			public float timeHorizon;

			public float agentRadius;

			public float maxRadius;

			public Agent agent;

			public Node[] nodes;

			public void QueryRec(int i, Rect r)
			{
				float num = Math.Min(Math.Max((nodes[i].maxSpeed + speed) * timeHorizon, agentRadius) + agentRadius, maxRadius);
				if (nodes[i].child00 == i)
				{
					for (Agent agent = nodes[i].linkedList; agent != null; agent = agent.next)
					{
						float num2 = this.agent.InsertAgentNeighbour(agent, num * num);
						if (num2 < maxRadius * maxRadius)
						{
							maxRadius = Mathf.Sqrt(num2);
						}
					}
					return;
				}
				Vector2 center = r.center;
				if (p.x - num < center.x)
				{
					if (p.y - num < center.y)
					{
						QueryRec(nodes[i].child00, Rect.MinMaxRect(r.xMin, r.yMin, center.x, center.y));
						num = Math.Min(num, maxRadius);
					}
					if (p.y + num > center.y)
					{
						QueryRec(nodes[i].child00 + 1, Rect.MinMaxRect(r.xMin, center.y, center.x, r.yMax));
						num = Math.Min(num, maxRadius);
					}
				}
				if (p.x + num > center.x)
				{
					if (p.y - num < center.y)
					{
						QueryRec(nodes[i].child00 + 2, Rect.MinMaxRect(center.x, r.yMin, r.xMax, center.y));
						num = Math.Min(num, maxRadius);
					}
					if (p.y + num > center.y)
					{
						QueryRec(nodes[i].child00 + 3, Rect.MinMaxRect(center.x, center.y, r.xMax, r.yMax));
					}
				}
			}
		}

		private const int LeafSize = 15;

		private float maxRadius;

		private Node[] nodes = new Node[16];

		private int filledNodes = 1;

		private Rect bounds;

		public void Clear()
		{
			nodes[0] = default(Node);
			filledNodes = 1;
			maxRadius = 0f;
		}

		public void SetBounds(Rect r)
		{
			bounds = r;
		}

		private int GetNodeIndex()
		{
			if (filledNodes + 4 >= nodes.Length)
			{
				Node[] array = new Node[nodes.Length * 2];
				for (int i = 0; i < nodes.Length; i++)
				{
					array[i] = nodes[i];
				}
				nodes = array;
			}
			nodes[filledNodes] = default(Node);
			nodes[filledNodes].child00 = filledNodes;
			filledNodes++;
			nodes[filledNodes] = default(Node);
			nodes[filledNodes].child00 = filledNodes;
			filledNodes++;
			nodes[filledNodes] = default(Node);
			nodes[filledNodes].child00 = filledNodes;
			filledNodes++;
			nodes[filledNodes] = default(Node);
			nodes[filledNodes].child00 = filledNodes;
			filledNodes++;
			return filledNodes - 4;
		}

		public void Insert(Agent agent)
		{
			int num = 0;
			Rect r = bounds;
			Vector2 vector = new Vector2(agent.position.x, agent.position.y);
			agent.next = null;
			maxRadius = Math.Max(agent.radius, maxRadius);
			int num2 = 0;
			while (true)
			{
				num2++;
				if (nodes[num].child00 == num)
				{
					if (nodes[num].count < 15 || num2 > 10)
					{
						break;
					}
					nodes[num].child00 = GetNodeIndex();
					nodes[num].Distribute(nodes, r);
				}
				if (nodes[num].child00 == num)
				{
					continue;
				}
				Vector2 center = r.center;
				if (vector.x > center.x)
				{
					if (vector.y > center.y)
					{
						num = nodes[num].child00 + 3;
						r = Rect.MinMaxRect(center.x, center.y, r.xMax, r.yMax);
					}
					else
					{
						num = nodes[num].child00 + 2;
						r = Rect.MinMaxRect(center.x, r.yMin, r.xMax, center.y);
					}
				}
				else if (vector.y > center.y)
				{
					num = nodes[num].child00 + 1;
					r = Rect.MinMaxRect(r.xMin, center.y, center.x, r.yMax);
				}
				else
				{
					num = nodes[num].child00;
					r = Rect.MinMaxRect(r.xMin, r.yMin, center.x, center.y);
				}
			}
			nodes[num].Add(agent);
			nodes[num].count++;
		}

		public void CalculateSpeeds()
		{
			nodes[0].CalculateMaxSpeed(nodes, 0);
		}

		public void Query(Vector2 p, float speed, float timeHorizon, float agentRadius, Agent agent)
		{
			QuadtreeQuery quadtreeQuery = default(QuadtreeQuery);
			quadtreeQuery.p = p;
			quadtreeQuery.speed = speed;
			quadtreeQuery.timeHorizon = timeHorizon;
			quadtreeQuery.maxRadius = float.PositiveInfinity;
			quadtreeQuery.agentRadius = agentRadius;
			quadtreeQuery.agent = agent;
			quadtreeQuery.nodes = nodes;
			quadtreeQuery.QueryRec(0, bounds);
		}

		public void DebugDraw()
		{
			DebugDrawRec(0, bounds);
		}

		private void DebugDrawRec(int i, Rect r)
		{
			UnityEngine.Debug.DrawLine(new Vector3(r.xMin, 0f, r.yMin), new Vector3(r.xMax, 0f, r.yMin), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(r.xMax, 0f, r.yMin), new Vector3(r.xMax, 0f, r.yMax), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(r.xMax, 0f, r.yMax), new Vector3(r.xMin, 0f, r.yMax), Color.white);
			UnityEngine.Debug.DrawLine(new Vector3(r.xMin, 0f, r.yMax), new Vector3(r.xMin, 0f, r.yMin), Color.white);
			if (nodes[i].child00 != i)
			{
				Vector2 center = r.center;
				DebugDrawRec(nodes[i].child00 + 3, Rect.MinMaxRect(center.x, center.y, r.xMax, r.yMax));
				DebugDrawRec(nodes[i].child00 + 2, Rect.MinMaxRect(center.x, r.yMin, r.xMax, center.y));
				DebugDrawRec(nodes[i].child00 + 1, Rect.MinMaxRect(r.xMin, center.y, center.x, r.yMax));
				DebugDrawRec(nodes[i].child00, Rect.MinMaxRect(r.xMin, r.yMin, center.x, center.y));
			}
			for (Agent agent = nodes[i].linkedList; agent != null; agent = agent.next)
			{
				Vector2 position = nodes[i].linkedList.position;
				UnityEngine.Debug.DrawLine(new Vector3(position.x, 0f, position.y) + Vector3.up, new Vector3(agent.position.x, 0f, agent.position.y) + Vector3.up, new Color(1f, 1f, 0f, 0.5f));
			}
		}
	}
	[AddComponentMenu("Pathfinding/Local Avoidance/RVO Controller")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_r_v_o_1_1_r_v_o_controller.php")]
	public class RVOController : VersionedMonoBehaviour
	{
		[SerializeField]
		[FormerlySerializedAs("radius")]
		internal float radiusBackingField = 0.5f;

		[SerializeField]
		[FormerlySerializedAs("height")]
		private float heightBackingField = 2f;

		[SerializeField]
		[FormerlySerializedAs("center")]
		private float centerBackingField = 1f;

		[Tooltip("A locked unit cannot move. Other units will still avoid it. But avoidance quality is not the best")]
		public bool locked;

		[Tooltip("Automatically set #locked to true when desired velocity is approximately zero")]
		public bool lockWhenNotMoving;

		[Tooltip("How far into the future to look for collisions with other agents (in seconds)")]
		public float agentTimeHorizon = 2f;

		[Tooltip("How far into the future to look for collisions with obstacles (in seconds)")]
		public float obstacleTimeHorizon = 2f;

		[Tooltip("Max number of other agents to take into account.\nA smaller value can reduce CPU load, a higher value can lead to better local avoidance quality.")]
		public int maxNeighbours = 10;

		public RVOLayer layer = RVOLayer.DefaultAgent;

		[EnumFlag]
		public RVOLayer collidesWith = (RVOLayer)(-1);

		[HideInInspector]
		[Obsolete]
		public float wallAvoidForce = 1f;

		[HideInInspector]
		[Obsolete]
		public float wallAvoidFalloff = 1f;

		[Tooltip("How strongly other agents will avoid this agent")]
		[Range(0f, 1f)]
		public float priority = 0.5f;

		protected Transform tr;

		[SerializeField]
		[FormerlySerializedAs("ai")]
		private IAstarAI aiBackingField;

		public bool debug;

		public float radius
		{
			get
			{
				if (ai != null)
				{
					return ai.radius;
				}
				return radiusBackingField;
			}
			set
			{
				if (ai != null)
				{
					ai.radius = value;
				}
				radiusBackingField = value;
			}
		}

		public float height
		{
			get
			{
				if (ai != null)
				{
					return ai.height;
				}
				return heightBackingField;
			}
			set
			{
				if (ai != null)
				{
					ai.height = value;
				}
				heightBackingField = value;
			}
		}

		public float center
		{
			get
			{
				if (ai != null)
				{
					return ai.height / 2f;
				}
				return centerBackingField;
			}
			set
			{
				centerBackingField = value;
			}
		}

		[Obsolete("This field is obsolete in version 4.0 and will not affect anything. Use the LegacyRVOController if you need the old behaviour")]
		public LayerMask mask
		{
			get
			{
				return 0;
			}
			set
			{
			}
		}

		[Obsolete("This field is obsolete in version 4.0 and will not affect anything. Use the LegacyRVOController if you need the old behaviour")]
		public bool enableRotation
		{
			get
			{
				return false;
			}
			set
			{
			}
		}

		[Obsolete("This field is obsolete in version 4.0 and will not affect anything. Use the LegacyRVOController if you need the old behaviour")]
		public float rotationSpeed
		{
			get
			{
				return 0f;
			}
			set
			{
			}
		}

		[Obsolete("This field is obsolete in version 4.0 and will not affect anything. Use the LegacyRVOController if you need the old behaviour")]
		public float maxSpeed
		{
			get
			{
				return 0f;
			}
			set
			{
			}
		}

		public MovementPlane movementPlane
		{
			get
			{
				if (simulator != null)
				{
					return simulator.movementPlane;
				}
				if ((bool)RVOSimulator.active)
				{
					return RVOSimulator.active.movementPlane;
				}
				return MovementPlane.XZ;
			}
		}

		public IAgent rvoAgent { get; private set; }

		public Simulator simulator { get; private set; }

		protected IAstarAI ai
		{
			get
			{
				if (aiBackingField as MonoBehaviour == null)
				{
					aiBackingField = null;
				}
				return aiBackingField;
			}
			set
			{
				aiBackingField = value;
			}
		}

		public Vector3 position => To3D(rvoAgent.Position, rvoAgent.ElevationCoordinate);

		public Vector3 velocity
		{
			get
			{
				float num = ((Time.deltaTime > 0.0001f) ? Time.deltaTime : 0.02f);
				return CalculateMovementDelta(num) / num;
			}
			set
			{
				rvoAgent.ForceSetVelocity(To2D(value));
			}
		}

		public Vector3 CalculateMovementDelta(float deltaTime)
		{
			if (rvoAgent == null)
			{
				return Vector3.zero;
			}
			return To3D(Vector2.ClampMagnitude(rvoAgent.CalculatedTargetPoint - To2D((ai != null) ? ai.position : tr.position), rvoAgent.CalculatedSpeed * deltaTime), 0f);
		}

		public Vector3 CalculateMovementDelta(Vector3 position, float deltaTime)
		{
			return To3D(Vector2.ClampMagnitude(rvoAgent.CalculatedTargetPoint - To2D(position), rvoAgent.CalculatedSpeed * deltaTime), 0f);
		}

		public void SetCollisionNormal(Vector3 normal)
		{
			rvoAgent.SetCollisionNormal(To2D(normal));
		}

		[Obsolete("Set the 'velocity' property instead")]
		public void ForceSetVelocity(Vector3 velocity)
		{
			this.velocity = velocity;
		}

		public Vector2 To2D(Vector3 p)
		{
			float elevation;
			return To2D(p, out elevation);
		}

		public Vector2 To2D(Vector3 p, out float elevation)
		{
			if (movementPlane == MovementPlane.XY)
			{
				elevation = 0f - p.z;
				return new Vector2(p.x, p.y);
			}
			elevation = p.y;
			return new Vector2(p.x, p.z);
		}

		public Vector3 To3D(Vector2 p, float elevationCoordinate)
		{
			if (movementPlane == MovementPlane.XY)
			{
				return new Vector3(p.x, p.y, 0f - elevationCoordinate);
			}
			return new Vector3(p.x, elevationCoordinate, p.y);
		}

		private void OnDisable()
		{
			if (simulator != null)
			{
				simulator.RemoveAgent(rvoAgent);
			}
		}

		private void OnEnable()
		{
			tr = base.transform;
			ai = GetComponent<IAstarAI>();
			AIBase aIBase = ai as AIBase;
			if (aIBase != null)
			{
				aIBase.FindComponents();
			}
			if (RVOSimulator.active == null)
			{
				UnityEngine.Debug.LogError("No RVOSimulator component found in the scene. Please add one.");
				base.enabled = false;
				return;
			}
			simulator = RVOSimulator.active.GetSimulator();
			if (rvoAgent != null)
			{
				simulator.AddAgent(rvoAgent);
				return;
			}
			rvoAgent = simulator.AddAgent(Vector2.zero, 0f);
			rvoAgent.PreCalculationCallback = UpdateAgentProperties;
		}

		protected void UpdateAgentProperties()
		{
			Vector3 localScale = tr.localScale;
			rvoAgent.Radius = Mathf.Max(0.001f, radius * localScale.x);
			rvoAgent.AgentTimeHorizon = agentTimeHorizon;
			rvoAgent.ObstacleTimeHorizon = obstacleTimeHorizon;
			rvoAgent.Locked = locked;
			rvoAgent.MaxNeighbours = maxNeighbours;
			rvoAgent.DebugDraw = debug;
			rvoAgent.Layer = layer;
			rvoAgent.CollidesWith = collidesWith;
			rvoAgent.Priority = priority;
			rvoAgent.Position = To2D((ai != null) ? ai.position : tr.position, out var elevation);
			if (movementPlane == MovementPlane.XZ)
			{
				rvoAgent.Height = height * localScale.y;
				rvoAgent.ElevationCoordinate = elevation + (center - 0.5f * height) * localScale.y;
			}
			else
			{
				rvoAgent.Height = 1f;
				rvoAgent.ElevationCoordinate = 0f;
			}
		}

		public void SetTarget(Vector3 pos, float speed, float maxSpeed)
		{
			if (simulator != null)
			{
				rvoAgent.SetTarget(To2D(pos), speed, maxSpeed);
				if (lockWhenNotMoving)
				{
					locked = speed < 0.001f;
				}
			}
		}

		public void Move(Vector3 vel)
		{
			if (simulator != null)
			{
				Vector2 vector = To2D(vel);
				float magnitude = vector.magnitude;
				rvoAgent.SetTarget(To2D((ai != null) ? ai.position : tr.position) + vector, magnitude, magnitude);
				if (lockWhenNotMoving)
				{
					locked = magnitude < 0.001f;
				}
			}
		}

		[Obsolete("Use transform.position instead, the RVOController can now handle that without any issues.")]
		public void Teleport(Vector3 pos)
		{
			tr.position = pos;
		}

		private void OnDrawGizmos()
		{
			tr = base.transform;
			if (ai == null)
			{
				Color color = AIBase.ShapeGizmoColor * (locked ? 0.5f : 1f);
				Vector3 vector = base.transform.position;
				Vector3 localScale = tr.localScale;
				if (movementPlane == MovementPlane.XY)
				{
					Draw.Gizmos.Cylinder(vector, Vector3.forward, 0f, radius * localScale.x, color);
				}
				else
				{
					Draw.Gizmos.Cylinder(vector + To3D(Vector2.zero, center - height * 0.5f) * localScale.y, To3D(Vector2.zero, 1f), height * localScale.y, radius * localScale.x, color);
				}
			}
		}

		protected override int OnUpgradeSerializedData(int version, bool unityThread)
		{
			if (version <= 1)
			{
				if (!unityThread)
				{
					return -1;
				}
				if (base.transform.localScale.y != 0f)
				{
					centerBackingField /= Mathf.Abs(base.transform.localScale.y);
				}
				if (base.transform.localScale.y != 0f)
				{
					heightBackingField /= Mathf.Abs(base.transform.localScale.y);
				}
				if (base.transform.localScale.x != 0f)
				{
					radiusBackingField /= Mathf.Abs(base.transform.localScale.x);
				}
			}
			return 2;
		}
	}
	[AddComponentMenu("Pathfinding/Local Avoidance/RVO Navmesh")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_r_v_o_1_1_r_v_o_navmesh.php")]
	public class RVONavmesh : GraphModifier
	{
		public float wallHeight = 5f;

		private readonly List<ObstacleVertex> obstacles = new List<ObstacleVertex>();

		private Simulator lastSim;

		public override void OnPostCacheLoad()
		{
			OnLatePostScan();
		}

		public override void OnGraphsPostUpdate()
		{
			OnLatePostScan();
		}

		public override void OnLatePostScan()
		{
			if (!Application.isPlaying)
			{
				return;
			}
			RemoveObstacles();
			NavGraph[] graphs = AstarPath.active.graphs;
			RVOSimulator active = RVOSimulator.active;
			if (active == null)
			{
				throw new NullReferenceException("No RVOSimulator could be found in the scene. Please add one to any GameObject");
			}
			lastSim = active.GetSimulator();
			for (int i = 0; i < graphs.Length; i++)
			{
				RecastGraph recastGraph = graphs[i] as RecastGraph;
				INavmesh navmesh = graphs[i] as INavmesh;
				GridGraph gridGraph = graphs[i] as GridGraph;
				if (recastGraph != null)
				{
					NavmeshTile[] tiles = recastGraph.GetTiles();
					foreach (NavmeshTile navmesh2 in tiles)
					{
						AddGraphObstacles(lastSim, navmesh2);
					}
				}
				else if (navmesh != null)
				{
					AddGraphObstacles(lastSim, navmesh);
				}
				else if (gridGraph != null)
				{
					AddGraphObstacles(lastSim, gridGraph);
				}
			}
		}

		protected override void OnDisable()
		{
			base.OnDisable();
			RemoveObstacles();
		}

		public void RemoveObstacles()
		{
			if (lastSim != null)
			{
				for (int i = 0; i < obstacles.Count; i++)
				{
					lastSim.RemoveObstacle(obstacles[i]);
				}
				lastSim = null;
			}
			obstacles.Clear();
		}

		private void AddGraphObstacles(Simulator sim, GridGraph grid)
		{
			bool reverse = Vector3.Dot(grid.transform.TransformVector(Vector3.up), (sim.movementPlane == MovementPlane.XY) ? Vector3.back : Vector3.up) > 0f;
			GraphUtilities.GetContours(grid, delegate(Vector3[] vertices)
			{
				if (reverse)
				{
					Array.Reverse(vertices);
				}
				obstacles.Add(sim.AddObstacle(vertices, wallHeight));
			}, wallHeight * 0.4f);
		}

		private void AddGraphObstacles(Simulator simulator, INavmesh navmesh)
		{
			GraphUtilities.GetContours(navmesh, delegate(List<Int3> vertices, bool cycle)
			{
				Vector3[] array = new Vector3[vertices.Count];
				for (int i = 0; i < array.Length; i++)
				{
					array[i] = (Vector3)vertices[i];
				}
				ListPool<Int3>.Release(vertices);
				obstacles.Add(simulator.AddObstacle(array, wallHeight, cycle));
			});
		}
	}
	public abstract class RVOObstacle : VersionedMonoBehaviour
	{
		public enum ObstacleVertexWinding
		{
			KeepOut,
			KeepIn
		}

		public ObstacleVertexWinding obstacleMode;

		public RVOLayer layer = RVOLayer.DefaultObstacle;

		protected Simulator sim;

		private List<ObstacleVertex> addedObstacles;

		private List<Vector3[]> sourceObstacles;

		private bool gizmoDrawing;

		private List<Vector3[]> gizmoVerts;

		private ObstacleVertexWinding _obstacleMode;

		private Matrix4x4 prevUpdateMatrix;

		protected abstract bool ExecuteInEditor { get; }

		protected abstract bool LocalCoordinates { get; }

		protected abstract bool StaticObstacle { get; }

		protected abstract float Height { get; }

		protected abstract void CreateObstacles();

		protected abstract bool AreGizmosDirty();

		public void OnDrawGizmos()
		{
			OnDrawGizmos(selected: false);
		}

		public void OnDrawGizmosSelected()
		{
			OnDrawGizmos(selected: true);
		}

		public void OnDrawGizmos(bool selected)
		{
			gizmoDrawing = true;
			Gizmos.color = new Color(0.615f, 1f, 0.06f, selected ? 1f : 0.7f);
			MovementPlane movementPlane = ((RVOSimulator.active != null) ? RVOSimulator.active.movementPlane : MovementPlane.XZ);
			Vector3 vector = ((movementPlane == MovementPlane.XZ) ? Vector3.up : (-Vector3.forward));
			if (gizmoVerts == null || AreGizmosDirty() || _obstacleMode != obstacleMode)
			{
				_obstacleMode = obstacleMode;
				if (gizmoVerts == null)
				{
					gizmoVerts = new List<Vector3[]>();
				}
				else
				{
					gizmoVerts.Clear();
				}
				CreateObstacles();
			}
			Matrix4x4 matrix = GetMatrix();
			for (int i = 0; i < gizmoVerts.Count; i++)
			{
				Vector3[] array = gizmoVerts[i];
				int num = 0;
				int num2 = array.Length - 1;
				while (num < array.Length)
				{
					Gizmos.DrawLine(matrix.MultiplyPoint3x4(array[num]), matrix.MultiplyPoint3x4(array[num2]));
					num2 = num++;
				}
				if (!selected)
				{
					continue;
				}
				int num3 = 0;
				int num4 = array.Length - 1;
				while (num3 < array.Length)
				{
					Vector3 vector2 = matrix.MultiplyPoint3x4(array[num4]);
					Vector3 vector3 = matrix.MultiplyPoint3x4(array[num3]);
					if (movementPlane != MovementPlane.XY)
					{
						Gizmos.DrawLine(vector2 + vector * Height, vector3 + vector * Height);
						Gizmos.DrawLine(vector2, vector2 + vector * Height);
					}
					Vector3 vector4 = (vector2 + vector3) * 0.5f;
					Vector3 normalized = (vector3 - vector2).normalized;
					if (!(normalized == Vector3.zero))
					{
						Vector3 vector5 = Vector3.Cross(vector, normalized);
						Gizmos.DrawLine(vector4, vector4 + vector5);
						Gizmos.DrawLine(vector4 + vector5, vector4 + vector5 * 0.5f + normalized * 0.5f);
						Gizmos.DrawLine(vector4 + vector5, vector4 + vector5 * 0.5f - normalized * 0.5f);
					}
					num4 = num3++;
				}
			}
			gizmoDrawing = false;
		}

		protected virtual Matrix4x4 GetMatrix()
		{
			if (!LocalCoordinates)
			{
				return Matrix4x4.identity;
			}
			return base.transform.localToWorldMatrix;
		}

		public void OnDisable()
		{
			if (addedObstacles != null)
			{
				if (sim == null)
				{
					throw new Exception("This should not happen! Make sure you are not overriding the OnEnable function");
				}
				for (int i = 0; i < addedObstacles.Count; i++)
				{
					sim.RemoveObstacle(addedObstacles[i]);
				}
			}
		}

		public void OnEnable()
		{
			if (addedObstacles == null)
			{
				return;
			}
			if (sim == null)
			{
				throw new Exception("This should not happen! Make sure you are not overriding the OnDisable function");
			}
			for (int i = 0; i < addedObstacles.Count; i++)
			{
				ObstacleVertex obstacleVertex = addedObstacles[i];
				ObstacleVertex obstacleVertex2 = obstacleVertex;
				do
				{
					obstacleVertex.layer = layer;
					obstacleVertex = obstacleVertex.next;
				}
				while (obstacleVertex != obstacleVertex2);
				sim.AddObstacle(addedObstacles[i]);
			}
		}

		public void Start()
		{
			addedObstacles = new List<ObstacleVertex>();
			sourceObstacles = new List<Vector3[]>();
			prevUpdateMatrix = GetMatrix();
			CreateObstacles();
		}

		public void Update()
		{
			Matrix4x4 matrix = GetMatrix();
			if (matrix != prevUpdateMatrix)
			{
				for (int i = 0; i < addedObstacles.Count; i++)
				{
					sim.UpdateObstacle(addedObstacles[i], sourceObstacles[i], matrix);
				}
				prevUpdateMatrix = matrix;
			}
		}

		protected void FindSimulator()
		{
			if (RVOSimulator.active == null)
			{
				throw new InvalidOperationException("No RVOSimulator could be found in the scene. Please add one to any GameObject");
			}
			sim = RVOSimulator.active.GetSimulator();
		}

		protected void AddObstacle(Vector3[] vertices, float height)
		{
			if (vertices == null)
			{
				throw new ArgumentNullException("Vertices Must Not Be Null");
			}
			if (height < 0f)
			{
				throw new ArgumentOutOfRangeException("Height must be non-negative");
			}
			if (vertices.Length < 2)
			{
				throw new ArgumentException("An obstacle must have at least two vertices");
			}
			if (sim == null)
			{
				FindSimulator();
			}
			if (gizmoDrawing)
			{
				Vector3[] array = new Vector3[vertices.Length];
				WindCorrectly(vertices);
				Array.Copy(vertices, array, vertices.Length);
				gizmoVerts.Add(array);
			}
			else if (vertices.Length == 2)
			{
				AddObstacleInternal(vertices, height);
			}
			else
			{
				WindCorrectly(vertices);
				AddObstacleInternal(vertices, height);
			}
		}

		private void AddObstacleInternal(Vector3[] vertices, float height)
		{
			addedObstacles.Add(sim.AddObstacle(vertices, height, GetMatrix(), layer));
			sourceObstacles.Add(vertices);
		}

		private void WindCorrectly(Vector3[] vertices)
		{
			int num = 0;
			float num2 = float.PositiveInfinity;
			Matrix4x4 matrix = GetMatrix();
			for (int i = 0; i < vertices.Length; i++)
			{
				float x = matrix.MultiplyPoint3x4(vertices[i]).x;
				if (x < num2)
				{
					num = i;
					num2 = x;
				}
			}
			Vector3 a = matrix.MultiplyPoint3x4(vertices[(num - 1 + vertices.Length) % vertices.Length]);
			Vector3 b = matrix.MultiplyPoint3x4(vertices[num]);
			Vector3 c = matrix.MultiplyPoint3x4(vertices[(num + 1) % vertices.Length]);
			MovementPlane movementPlane = ((sim != null) ? sim.movementPlane : (RVOSimulator.active ? RVOSimulator.active.movementPlane : MovementPlane.XZ));
			if (movementPlane == MovementPlane.XY)
			{
				a.z = a.y;
				b.z = b.y;
				c.z = c.y;
			}
			if (VectorMath.IsClockwiseXZ(a, b, c) != (obstacleMode == ObstacleVertexWinding.KeepIn))
			{
				Array.Reverse(vertices);
			}
		}
	}
	[ExecuteInEditMode]
	[AddComponentMenu("Pathfinding/Local Avoidance/RVO Simulator")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_r_v_o_1_1_r_v_o_simulator.php")]
	public class RVOSimulator : VersionedMonoBehaviour
	{
		[Tooltip("Desired FPS for rvo simulation. It is usually not necessary to run a crowd simulation at a very high fps.\nUsually 10-30 fps is enough, but can be increased for better quality.\nThe rvo simulation will never run at a higher fps than the game")]
		public int desiredSimulationFPS = 20;

		[Tooltip("Number of RVO worker threads. If set to None, no multithreading will be used.")]
		public ThreadCount workerThreads = ThreadCount.Two;

		[Tooltip("Calculate local avoidance in between frames.\nThis can increase jitter in the agents' movement so use it only if you really need the performance boost. It will also reduce the responsiveness of the agents to the commands you send to them.")]
		public bool doubleBuffering;

		[Tooltip("Bias agents to pass each other on the right side.\nIf the desired velocity of an agent puts it on a collision course with another agent or an obstacle its desired velocity will be rotated this number of radians (1 radian is approximately 57°) to the right. This helps to break up symmetries and makes it possible to resolve some situations much faster.\n\nWhen many agents have the same goal this can however have the side effect that the group clustered around the target point may as a whole start to spin around the target point.")]
		[Range(0f, 0.2f)]
		public float symmetryBreakingBias = 0.1f;

		[Tooltip("Determines if the XY (2D) or XZ (3D) plane is used for movement")]
		public MovementPlane movementPlane;

		public bool drawObstacles;

		private Simulator simulator;

		public static RVOSimulator active { get; private set; }

		public Simulator GetSimulator()
		{
			if (simulator == null)
			{
				Awake();
			}
			return simulator;
		}

		private void OnEnable()
		{
			active = this;
		}

		protected override void Awake()
		{
			base.Awake();
			active = this;
			if (simulator == null && Application.isPlaying)
			{
				int workers = AstarPath.CalculateThreadCount(workerThreads);
				simulator = new Simulator(workers, doubleBuffering, movementPlane);
			}
		}

		private void Update()
		{
			if (Application.isPlaying)
			{
				if (desiredSimulationFPS < 1)
				{
					desiredSimulationFPS = 1;
				}
				Simulator obj = GetSimulator();
				obj.DesiredDeltaTime = 1f / (float)desiredSimulationFPS;
				obj.symmetryBreakingBias = symmetryBreakingBias;
				obj.Update();
			}
		}

		private void OnDestroy()
		{
			active = null;
			if (simulator != null)
			{
				simulator.OnDestroy();
			}
		}
	}
	[AddComponentMenu("Pathfinding/Local Avoidance/Square Obstacle")]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_r_v_o_1_1_r_v_o_square_obstacle.php")]
	public class RVOSquareObstacle : RVOObstacle
	{
		public float height = 1f;

		public Vector2 size = Vector3.one;

		public Vector2 center = Vector3.zero;

		protected override bool StaticObstacle => false;

		protected override bool ExecuteInEditor => true;

		protected override bool LocalCoordinates => true;

		protected override float Height => height;

		protected override bool AreGizmosDirty()
		{
			return false;
		}

		protected override void CreateObstacles()
		{
			size.x = Mathf.Abs(size.x);
			size.y = Mathf.Abs(size.y);
			height = Mathf.Abs(height);
			Vector3[] array = new Vector3[4]
			{
				new Vector3(1f, 0f, -1f),
				new Vector3(1f, 0f, 1f),
				new Vector3(-1f, 0f, 1f),
				new Vector3(-1f, 0f, -1f)
			};
			for (int i = 0; i < array.Length; i++)
			{
				array[i].Scale(new Vector3(size.x * 0.5f, 0f, size.y * 0.5f));
				array[i] += new Vector3(center.x, 0f, center.y);
			}
			AddObstacle(array, height);
		}
	}
}
namespace Pathfinding.RVO.Sampled
{
	public class Agent : IAgent
	{
		internal struct VO
		{
			private Vector2 line1;

			private Vector2 line2;

			private Vector2 dir1;

			private Vector2 dir2;

			private Vector2 cutoffLine;

			private Vector2 cutoffDir;

			private Vector2 circleCenter;

			private bool colliding;

			private float radius;

			private float weightFactor;

			private float weightBonus;

			private Vector2 segmentStart;

			private Vector2 segmentEnd;

			private bool segment;

			public VO(Vector2 center, Vector2 offset, float radius, float inverseDt, float inverseDeltaTime)
			{
				weightFactor = 1f;
				weightBonus = 0f;
				circleCenter = center * inverseDt + offset;
				weightFactor = 4f * Mathf.Exp(0f - Sqr(center.sqrMagnitude / (radius * radius))) + 1f;
				if (center.magnitude < radius)
				{
					colliding = true;
					line1 = center.normalized * (center.magnitude - radius - 0.001f) * 0.3f * inverseDeltaTime;
					dir1 = new Vector2(line1.y, 0f - line1.x).normalized;
					line1 += offset;
					cutoffDir = Vector2.zero;
					cutoffLine = Vector2.zero;
					dir2 = Vector2.zero;
					line2 = Vector2.zero;
					this.radius = 0f;
				}
				else
				{
					colliding = false;
					center *= inverseDt;
					radius *= inverseDt;
					Vector2 vector = center + offset;
					float num = center.magnitude - radius + 0.001f;
					cutoffLine = center.normalized * num;
					cutoffDir = new Vector2(0f - cutoffLine.y, cutoffLine.x).normalized;
					cutoffLine += offset;
					float num2 = Mathf.Atan2(0f - center.y, 0f - center.x);
					float num3 = Mathf.Abs(Mathf.Acos(radius / center.magnitude));
					this.radius = radius;
					line1 = new Vector2(Mathf.Cos(num2 + num3), Mathf.Sin(num2 + num3));
					dir1 = new Vector2(line1.y, 0f - line1.x);
					line2 = new Vector2(Mathf.Cos(num2 - num3), Mathf.Sin(num2 - num3));
					dir2 = new Vector2(line2.y, 0f - line2.x);
					line1 = line1 * radius + vector;
					line2 = line2 * radius + vector;
				}
				segmentStart = Vector2.zero;
				segmentEnd = Vector2.zero;
				segment = false;
			}

			public static VO SegmentObstacle(Vector2 segmentStart, Vector2 segmentEnd, Vector2 offset, float radius, float inverseDt, float inverseDeltaTime)
			{
				VO result = new VO
				{
					weightFactor = 1f,
					weightBonus = Mathf.Max(radius, 1f) * 40f
				};
				Vector3 vector = VectorMath.ClosestPointOnSegment(segmentStart, segmentEnd, Vector2.zero);
				if (vector.magnitude <= radius)
				{
					result.colliding = true;
					result.line1 = vector.normalized * (vector.magnitude - radius) * 0.3f * inverseDeltaTime;
					result.dir1 = new Vector2(result.line1.y, 0f - result.line1.x).normalized;
					result.line1 += offset;
					result.cutoffDir = Vector2.zero;
					result.cutoffLine = Vector2.zero;
					result.dir2 = Vector2.zero;
					result.line2 = Vector2.zero;
					result.radius = 0f;
					result.segmentStart = Vector2.zero;
					result.segmentEnd = Vector2.zero;
					result.segment = false;
				}
				else
				{
					result.colliding = false;
					segmentStart *= inverseDt;
					segmentEnd *= inverseDt;
					radius *= inverseDt;
					Vector2 vector2 = (result.cutoffDir = (segmentEnd - segmentStart).normalized);
					result.cutoffLine = segmentStart + new Vector2(0f - vector2.y, vector2.x) * radius;
					result.cutoffLine += offset;
					float sqrMagnitude = segmentStart.sqrMagnitude;
					Vector2 vector3 = -VectorMath.ComplexMultiply(segmentStart, new Vector2(radius, Mathf.Sqrt(Mathf.Max(0f, sqrMagnitude - radius * radius)))) / sqrMagnitude;
					float sqrMagnitude2 = segmentEnd.sqrMagnitude;
					Vector2 vector4 = -VectorMath.ComplexMultiply(segmentEnd, new Vector2(radius, 0f - Mathf.Sqrt(Mathf.Max(0f, sqrMagnitude2 - radius * radius)))) / sqrMagnitude2;
					result.line1 = segmentStart + vector3 * radius + offset;
					result.line2 = segmentEnd + vector4 * radius + offset;
					result.dir1 = new Vector2(vector3.y, 0f - vector3.x);
					result.dir2 = new Vector2(vector4.y, 0f - vector4.x);
					result.segmentStart = segmentStart;
					result.segmentEnd = segmentEnd;
					result.radius = radius;
					result.segment = true;
				}
				return result;
			}

			public static float SignedDistanceFromLine(Vector2 a, Vector2 dir, Vector2 p)
			{
				return (p.x - a.x) * dir.y - dir.x * (p.y - a.y);
			}

			public Vector2 ScaledGradient(Vector2 p, out float weight)
			{
				Vector2 result = Gradient(p, out weight);
				if (weight > 0f)
				{
					result *= 2f * weightFactor;
					weight *= 2f * weightFactor;
					weight += 1f + weightBonus;
				}
				return result;
			}

			public Vector2 Gradient(Vector2 p, out float weight)
			{
				if (colliding)
				{
					float num = SignedDistanceFromLine(line1, dir1, p);
					if (num >= 0f)
					{
						weight = num;
						return new Vector2(0f - dir1.y, dir1.x);
					}
					weight = 0f;
					return new Vector2(0f, 0f);
				}
				float num2 = SignedDistanceFromLine(cutoffLine, cutoffDir, p);
				if (num2 <= 0f)
				{
					weight = 0f;
					return Vector2.zero;
				}
				float num3 = SignedDistanceFromLine(line1, dir1, p);
				float num4 = SignedDistanceFromLine(line2, dir2, p);
				if (num3 >= 0f && num4 >= 0f)
				{
					Vector2 result;
					if (Vector2.Dot(p - line1, dir1) > 0f && Vector2.Dot(p - line2, dir2) < 0f)
					{
						if (!segment)
						{
							result = VectorMath.Normalize(p - circleCenter, out var magnitude);
							weight = radius - magnitude;
							return result;
						}
						if (num2 < radius)
						{
							Vector2 vector = VectorMath.ClosestPointOnSegment(segmentStart, segmentEnd, p);
							result = VectorMath.Normalize(p - vector, out var magnitude2);
							weight = radius - magnitude2;
							return result;
						}
					}
					if (segment && num2 < num3 && num2 < num4)
					{
						weight = num2;
						return new Vector2(0f - cutoffDir.y, cutoffDir.x);
					}
					if (num3 < num4)
					{
						weight = num3;
						result = new Vector2(0f - dir1.y, dir1.x);
					}
					else
					{
						weight = num4;
						result = new Vector2(0f - dir2.y, dir2.x);
					}
					return result;
				}
				weight = 0f;
				return Vector2.zero;
			}
		}

		internal class VOBuffer
		{
			public VO[] buffer;

			public int length;

			public void Clear()
			{
				length = 0;
			}

			public VOBuffer(int n)
			{
				buffer = new VO[n];
				length = 0;
			}

			public void Add(VO vo)
			{
				if (length >= buffer.Length)
				{
					VO[] array = new VO[buffer.Length * 2];
					buffer.CopyTo(array, 0);
					buffer = array;
				}
				buffer[length++] = vo;
			}
		}

		internal float radius;

		internal float height;

		internal float desiredSpeed;

		internal float maxSpeed;

		internal float agentTimeHorizon;

		internal float obstacleTimeHorizon;

		internal bool locked;

		private RVOLayer layer;

		private RVOLayer collidesWith;

		private int maxNeighbours;

		internal Vector2 position;

		private float elevationCoordinate;

		private Vector2 currentVelocity;

		private Vector2 desiredTargetPointInVelocitySpace;

		private Vector2 desiredVelocity;

		private Vector2 nextTargetPoint;

		private float nextDesiredSpeed;

		private float nextMaxSpeed;

		private Vector2 collisionNormal;

		private bool manuallyControlled;

		private bool debugDraw;

		internal Agent next;

		private float calculatedSpeed;

		private Vector2 calculatedTargetPoint;

		internal Simulator simulator;

		private List<Agent> neighbours = new List<Agent>();

		private List<float> neighbourDists = new List<float>();

		private List<ObstacleVertex> obstaclesBuffered = new List<ObstacleVertex>();

		private List<ObstacleVertex> obstacles = new List<ObstacleVertex>();

		private const float DesiredVelocityWeight = 0.1f;

		private const float WallWeight = 5f;

		public Vector2 Position { get; set; }

		public float ElevationCoordinate { get; set; }

		public Vector2 CalculatedTargetPoint { get; private set; }

		public float CalculatedSpeed { get; private set; }

		public bool Locked { get; set; }

		public float Radius { get; set; }

		public float Height { get; set; }

		public float AgentTimeHorizon { get; set; }

		public float ObstacleTimeHorizon { get; set; }

		public int MaxNeighbours { get; set; }

		public int NeighbourCount { get; private set; }

		public RVOLayer Layer { get; set; }

		public RVOLayer CollidesWith { get; set; }

		public bool DebugDraw
		{
			get
			{
				return debugDraw;
			}
			set
			{
				debugDraw = value && simulator != null && !simulator.Multithreading;
			}
		}

		public float Priority { get; set; }

		public Action PreCalculationCallback { private get; set; }

		public List<ObstacleVertex> NeighbourObstacles => null;

		public void SetTarget(Vector2 targetPoint, float desiredSpeed, float maxSpeed)
		{
			maxSpeed = Math.Max(maxSpeed, 0f);
			desiredSpeed = Math.Min(Math.Max(desiredSpeed, 0f), maxSpeed);
			nextTargetPoint = targetPoint;
			nextDesiredSpeed = desiredSpeed;
			nextMaxSpeed = maxSpeed;
		}

		public void SetCollisionNormal(Vector2 normal)
		{
			collisionNormal = normal;
		}

		public void ForceSetVelocity(Vector2 velocity)
		{
			Vector2 vector = (CalculatedTargetPoint = position + velocity * 1000f);
			nextTargetPoint = vector;
			float num = (CalculatedSpeed = velocity.magnitude);
			nextDesiredSpeed = num;
			manuallyControlled = true;
		}

		public Agent(Vector2 pos, float elevationCoordinate)
		{
			AgentTimeHorizon = 2f;
			ObstacleTimeHorizon = 2f;
			Height = 5f;
			Radius = 5f;
			MaxNeighbours = 10;
			Locked = false;
			Position = pos;
			ElevationCoordinate = elevationCoordinate;
			Layer = RVOLayer.DefaultAgent;
			CollidesWith = (RVOLayer)(-1);
			Priority = 0.5f;
			CalculatedTargetPoint = pos;
			CalculatedSpeed = 0f;
			SetTarget(pos, 0f, 0f);
		}

		public void BufferSwitch()
		{
			radius = Radius;
			height = Height;
			maxSpeed = nextMaxSpeed;
			desiredSpeed = nextDesiredSpeed;
			agentTimeHorizon = AgentTimeHorizon;
			obstacleTimeHorizon = ObstacleTimeHorizon;
			maxNeighbours = MaxNeighbours;
			locked = Locked && !manuallyControlled;
			position = Position;
			elevationCoordinate = ElevationCoordinate;
			collidesWith = CollidesWith;
			layer = Layer;
			if (locked)
			{
				desiredTargetPointInVelocitySpace = position;
				desiredVelocity = (currentVelocity = Vector2.zero);
				return;
			}
			desiredTargetPointInVelocitySpace = nextTargetPoint - position;
			currentVelocity = (CalculatedTargetPoint - position).normalized * CalculatedSpeed;
			desiredVelocity = desiredTargetPointInVelocitySpace.normalized * desiredSpeed;
			if (collisionNormal != Vector2.zero)
			{
				collisionNormal.Normalize();
				float num = Vector2.Dot(currentVelocity, collisionNormal);
				if (num < 0f)
				{
					currentVelocity -= collisionNormal * num;
				}
				collisionNormal = Vector2.zero;
			}
		}

		public void PreCalculation()
		{
			if (PreCalculationCallback != null)
			{
				PreCalculationCallback();
			}
		}

		public void PostCalculation()
		{
			if (!manuallyControlled)
			{
				CalculatedTargetPoint = calculatedTargetPoint;
				CalculatedSpeed = calculatedSpeed;
			}
			List<ObstacleVertex> list = obstaclesBuffered;
			obstaclesBuffered = obstacles;
			obstacles = list;
			manuallyControlled = false;
		}

		public void CalculateNeighbours()
		{
			neighbours.Clear();
			neighbourDists.Clear();
			if (MaxNeighbours > 0 && !locked)
			{
				simulator.Quadtree.Query(position, maxSpeed, agentTimeHorizon, radius, this);
			}
			NeighbourCount = neighbours.Count;
		}

		private static float Sqr(float x)
		{
			return x * x;
		}

		internal float InsertAgentNeighbour(Agent agent, float rangeSq)
		{
			if (this == agent || (agent.layer & collidesWith) == 0)
			{
				return rangeSq;
			}
			float sqrMagnitude = (agent.position - position).sqrMagnitude;
			if (sqrMagnitude < rangeSq)
			{
				if (neighbours.Count < maxNeighbours)
				{
					neighbours.Add(null);
					neighbourDists.Add(float.PositiveInfinity);
				}
				int num = neighbours.Count - 1;
				if (sqrMagnitude < neighbourDists[num])
				{
					while (num != 0 && sqrMagnitude < neighbourDists[num - 1])
					{
						neighbours[num] = neighbours[num - 1];
						neighbourDists[num] = neighbourDists[num - 1];
						num--;
					}
					neighbours[num] = agent;
					neighbourDists[num] = sqrMagnitude;
				}
				if (neighbours.Count == maxNeighbours)
				{
					rangeSq = neighbourDists[neighbourDists.Count - 1];
				}
			}
			return rangeSq;
		}

		private static Vector3 FromXZ(Vector2 p)
		{
			return new Vector3(p.x, 0f, p.y);
		}

		private static Vector2 ToXZ(Vector3 p)
		{
			return new Vector2(p.x, p.z);
		}

		private Vector2 To2D(Vector3 p, out float elevation)
		{
			if (simulator.movementPlane == MovementPlane.XY)
			{
				elevation = 0f - p.z;
				return new Vector2(p.x, p.y);
			}
			elevation = p.y;
			return new Vector2(p.x, p.z);
		}

		private static void DrawVO(Vector2 circleCenter, float radius, Vector2 origin)
		{
			float num = Mathf.Atan2((origin - circleCenter).y, (origin - circleCenter).x);
			float num2 = radius / (origin - circleCenter).magnitude;
			float num3 = ((num2 <= 1f) ? Mathf.Abs(Mathf.Acos(num2)) : 0f);
			Draw.Debug.CircleXZ(FromXZ(circleCenter), radius, Color.black, num - num3, num + num3);
			Vector2 p = new Vector2(Mathf.Cos(num - num3), Mathf.Sin(num - num3)) * radius;
			Vector2 p2 = new Vector2(Mathf.Cos(num + num3), Mathf.Sin(num + num3)) * radius;
			Vector2 p3 = -new Vector2(0f - p.y, p.x);
			Vector2 p4 = new Vector2(0f - p2.y, p2.x);
			p += circleCenter;
			p2 += circleCenter;
			UnityEngine.Debug.DrawRay(FromXZ(p), FromXZ(p3).normalized * 100f, Color.black);
			UnityEngine.Debug.DrawRay(FromXZ(p2), FromXZ(p4).normalized * 100f, Color.black);
		}

		internal void CalculateVelocity(Simulator.WorkerContext context)
		{
			if (manuallyControlled)
			{
				return;
			}
			if (locked)
			{
				calculatedSpeed = 0f;
				calculatedTargetPoint = position;
				return;
			}
			VOBuffer vos = context.vos;
			vos.Clear();
			GenerateObstacleVOs(vos);
			GenerateNeighbourAgentVOs(vos);
			if (!BiasDesiredVelocity(vos, ref desiredVelocity, ref desiredTargetPointInVelocitySpace, simulator.symmetryBreakingBias))
			{
				calculatedTargetPoint = desiredTargetPointInVelocitySpace + position;
				calculatedSpeed = desiredSpeed;
				if (DebugDraw)
				{
					Draw.Debug.CrossXZ(FromXZ(calculatedTargetPoint), Color.white);
				}
				return;
			}
			Vector2 zero = Vector2.zero;
			zero = GradientDescent(vos, currentVelocity, desiredVelocity);
			if (DebugDraw)
			{
				Draw.Debug.CrossXZ(FromXZ(zero + position), Color.white);
			}
			calculatedTargetPoint = position + zero;
			calculatedSpeed = Mathf.Min(zero.magnitude, maxSpeed);
		}

		private static Color Rainbow(float v)
		{
			Color result = new Color(v, 0f, 0f);
			if (result.r > 1f)
			{
				result.g = result.r - 1f;
				result.r = 1f;
			}
			if (result.g > 1f)
			{
				result.b = result.g - 1f;
				result.g = 1f;
			}
			return result;
		}

		private void GenerateObstacleVOs(VOBuffer vos)
		{
			float num = maxSpeed * obstacleTimeHorizon;
			for (int i = 0; i < simulator.obstacles.Count; i++)
			{
				ObstacleVertex obstacleVertex = simulator.obstacles[i];
				ObstacleVertex obstacleVertex2 = obstacleVertex;
				do
				{
					if (obstacleVertex2.ignore || (obstacleVertex2.layer & collidesWith) == 0)
					{
						obstacleVertex2 = obstacleVertex2.next;
						continue;
					}
					float elevation;
					Vector2 vector = To2D(obstacleVertex2.position, out elevation);
					float elevation2;
					Vector2 vector2 = To2D(obstacleVertex2.next.position, out elevation2);
					Vector2 normalized = (vector2 - vector).normalized;
					float num2 = VO.SignedDistanceFromLine(vector, normalized, position);
					if (num2 >= -0.01f && num2 < num)
					{
						float t = Vector2.Dot(position - vector, vector2 - vector) / (vector2 - vector).sqrMagnitude;
						float num3 = Mathf.Lerp(elevation, elevation2, t);
						if ((Vector2.Lerp(vector, vector2, t) - position).sqrMagnitude < num * num && (simulator.movementPlane == MovementPlane.XY || (elevationCoordinate <= num3 + obstacleVertex2.height && elevationCoordinate + height >= num3)))
						{
							vos.Add(VO.SegmentObstacle(vector2 - position, vector - position, Vector2.zero, radius * 0.01f, 1f / ObstacleTimeHorizon, 1f / simulator.DeltaTime));
						}
					}
					obstacleVertex2 = obstacleVertex2.next;
				}
				while (obstacleVertex2 != obstacleVertex && obstacleVertex2 != null && obstacleVertex2.next != null);
			}
		}

		private void GenerateNeighbourAgentVOs(VOBuffer vos)
		{
			float num = 1f / agentTimeHorizon;
			Vector2 a = currentVelocity;
			for (int i = 0; i < neighbours.Count; i++)
			{
				Agent agent = neighbours[i];
				if (agent == this)
				{
					continue;
				}
				float num2 = Math.Min(elevationCoordinate + height, agent.elevationCoordinate + agent.height);
				float num3 = Math.Max(elevationCoordinate, agent.elevationCoordinate);
				if (!(num2 - num3 < 0f))
				{
					float num4 = radius + agent.radius;
					Vector2 vector = agent.position - position;
					float num5 = ((!agent.locked && !agent.manuallyControlled) ? ((!(agent.Priority > 1E-05f) && !(Priority > 1E-05f)) ? 0.5f : (agent.Priority / (Priority + agent.Priority))) : 1f);
					Vector2 b = Vector2.Lerp(agent.currentVelocity, agent.desiredVelocity, 2f * num5 - 1f);
					Vector2 vector2 = Vector2.Lerp(a, b, num5);
					vos.Add(new VO(vector, vector2, num4, num, 1f / simulator.DeltaTime));
					if (DebugDraw)
					{
						DrawVO(position + vector * num + vector2, num4 * num, position + vector2);
					}
				}
			}
		}

		private Vector2 GradientDescent(VOBuffer vos, Vector2 sampleAround1, Vector2 sampleAround2)
		{
			float score;
			Vector2 vector = Trace(vos, sampleAround1, out score);
			if (DebugDraw)
			{
				Draw.Debug.CrossXZ(FromXZ(vector + position), Color.yellow, 0.5f);
			}
			float score2;
			Vector2 vector2 = Trace(vos, sampleAround2, out score2);
			if (DebugDraw)
			{
				Draw.Debug.CrossXZ(FromXZ(vector2 + position), Color.magenta, 0.5f);
			}
			if (!(score < score2))
			{
				return vector2;
			}
			return vector;
		}

		private static bool BiasDesiredVelocity(VOBuffer vos, ref Vector2 desiredVelocity, ref Vector2 targetPointInVelocitySpace, float maxBiasRadians)
		{
			float magnitude = desiredVelocity.magnitude;
			float num = 0f;
			for (int i = 0; i < vos.length; i++)
			{
				vos.buffer[i].Gradient(desiredVelocity, out var weight);
				num = Mathf.Max(num, weight);
			}
			bool result = num > 0f;
			if (magnitude < 0.001f)
			{
				return result;
			}
			float num2 = Mathf.Min(maxBiasRadians, num / magnitude);
			desiredVelocity += new Vector2(desiredVelocity.y, 0f - desiredVelocity.x) * num2;
			targetPointInVelocitySpace += new Vector2(targetPointInVelocitySpace.y, 0f - targetPointInVelocitySpace.x) * num2;
			return result;
		}

		private Vector2 EvaluateGradient(VOBuffer vos, Vector2 p, out float value)
		{
			Vector2 result = Vector2.zero;
			value = 0f;
			for (int i = 0; i < vos.length; i++)
			{
				float weight;
				Vector2 vector = vos.buffer[i].ScaledGradient(p, out weight);
				if (weight > value)
				{
					value = weight;
					result = vector;
				}
			}
			Vector2 vector2 = desiredVelocity - p;
			float magnitude = vector2.magnitude;
			if (magnitude > 0.0001f)
			{
				result += vector2 * (0.1f / magnitude);
				value += magnitude * 0.1f;
			}
			float sqrMagnitude = p.sqrMagnitude;
			if (sqrMagnitude > desiredSpeed * desiredSpeed)
			{
				float num = Mathf.Sqrt(sqrMagnitude);
				if (num > maxSpeed)
				{
					value += 3f * (num - maxSpeed);
					result -= 3f * (p / num);
				}
				float num2 = 0.2f;
				value += num2 * (num - desiredSpeed);
				result -= num2 * (p / num);
			}
			return result;
		}

		private Vector2 Trace(VOBuffer vos, Vector2 p, out float score)
		{
			float num = Mathf.Max(radius, 0.2f * desiredSpeed);
			float num2 = float.PositiveInfinity;
			Vector2 result = p;
			for (int i = 0; i < 50; i++)
			{
				float x = 1f - (float)i / 50f;
				x = Sqr(x) * num;
				float value;
				Vector2 vector = EvaluateGradient(vos, p, out value);
				if (value < num2)
				{
					num2 = value;
					result = p;
				}
				vector.Normalize();
				vector *= x;
				Vector2 vector2 = p;
				p += vector;
				if (DebugDraw)
				{
					UnityEngine.Debug.DrawLine(FromXZ(vector2 + position), FromXZ(p + position), Rainbow((float)i * 0.1f) * new Color(1f, 1f, 1f, 1f));
				}
			}
			score = num2;
			return result;
		}
	}
}
namespace Pathfinding.Examples
{
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_turn_based_a_i.php")]
	public class TurnBasedAI : VersionedMonoBehaviour
	{
		public int movementPoints = 2;

		public BlockManager blockManager;

		public SingleNodeBlocker blocker;

		public GraphNode targetNode;

		public BlockManager.TraversalProvider traversalProvider;

		private void Start()
		{
			blocker.BlockAtCurrentPosition();
		}

		protected override void Awake()
		{
			base.Awake();
			traversalProvider = new BlockManager.TraversalProvider(blockManager, BlockManager.BlockMode.AllExceptSelector, new List<SingleNodeBlocker> { blocker });
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_group_controller.php")]
	public class GroupController : MonoBehaviour
	{
		public GUIStyle selectionBox;

		public bool adjustCamera = true;

		private Vector2 start;

		private Vector2 end;

		private bool wasDown;

		private List<RVOExampleAgent> selection = new List<RVOExampleAgent>();

		private Simulator sim;

		private Camera cam;

		private const float rad2Deg = 180f / MathF.PI;

		public void Start()
		{
			cam = Camera.main;
			RVOSimulator active = RVOSimulator.active;
			if (active == null)
			{
				base.enabled = false;
				throw new Exception("No RVOSimulator in the scene. Please add one");
			}
			sim = active.GetSimulator();
		}

		public void Update()
		{
			if (adjustCamera)
			{
				List<Agent> agents = sim.GetAgents();
				float num = 0f;
				for (int i = 0; i < agents.Count; i++)
				{
					float num2 = Mathf.Max(Mathf.Abs(agents[i].Position.x), Mathf.Abs(agents[i].Position.y));
					if (num2 > num)
					{
						num = num2;
					}
				}
				float a = num / Mathf.Tan(cam.fieldOfView * (MathF.PI / 180f) / 2f);
				float b = num / Mathf.Tan(Mathf.Atan(Mathf.Tan(cam.fieldOfView * (MathF.PI / 180f) / 2f) * cam.aspect));
				float a2 = Mathf.Max(a, b) * 1.1f;
				a2 = Mathf.Max(a2, 20f);
				a2 = Mathf.Min(a2, cam.farClipPlane - 1f);
				cam.transform.position = Vector3.Lerp(cam.transform.position, new Vector3(0f, a2, 0f), Time.smoothDeltaTime * 2f);
			}
			if (Input.GetKey(KeyCode.A) && Input.GetKeyDown(KeyCode.Mouse0))
			{
				Order();
			}
		}

		private void OnGUI()
		{
			if (Event.current.type == EventType.MouseUp && Event.current.button == 0 && !Input.GetKey(KeyCode.A))
			{
				Select(start, end);
				wasDown = false;
			}
			if (Event.current.type == EventType.MouseDrag && Event.current.button == 0)
			{
				end = Event.current.mousePosition;
				if (!wasDown)
				{
					start = end;
					wasDown = true;
				}
			}
			if (Input.GetKey(KeyCode.A))
			{
				wasDown = false;
			}
			if (wasDown)
			{
				Rect position = Rect.MinMaxRect(Mathf.Min(start.x, end.x), Mathf.Min(start.y, end.y), Mathf.Max(start.x, end.x), Mathf.Max(start.y, end.y));
				if (position.width > 4f && position.height > 4f)
				{
					GUI.Box(position, "", selectionBox);
				}
			}
		}

		public void Order()
		{
			if (Physics.Raycast(cam.ScreenPointToRay(Input.mousePosition), out var hitInfo))
			{
				float num = 0f;
				for (int i = 0; i < selection.Count; i++)
				{
					num += selection[i].GetComponent<RVOController>().radius;
				}
				float num2 = num / MathF.PI;
				num2 *= 2f;
				for (int j = 0; j < selection.Count; j++)
				{
					float num3 = MathF.PI * 2f * (float)j / (float)selection.Count;
					Vector3 target = hitInfo.point + new Vector3(Mathf.Cos(num3), 0f, Mathf.Sin(num3)) * num2;
					selection[j].SetTarget(target);
					selection[j].SetColor(GetColor(num3));
					selection[j].RecalculatePath();
				}
			}
		}

		public void Select(Vector2 _start, Vector2 _end)
		{
			_start.y = (float)Screen.height - _start.y;
			_end.y = (float)Screen.height - _end.y;
			Vector2 vector = Vector2.Min(_start, _end);
			Vector2 vector2 = Vector2.Max(_start, _end);
			if ((vector2 - vector).sqrMagnitude < 16f)
			{
				return;
			}
			selection.Clear();
			RVOExampleAgent[] array = UnityEngine.Object.FindObjectsOfType(typeof(RVOExampleAgent)) as RVOExampleAgent[];
			for (int i = 0; i < array.Length; i++)
			{
				Vector2 vector3 = cam.WorldToScreenPoint(array[i].transform.position);
				if (vector3.x > vector.x && vector3.y > vector.y && vector3.x < vector2.x && vector3.y < vector2.y)
				{
					selection.Add(array[i]);
				}
			}
		}

		public Color GetColor(float angle)
		{
			return AstarMath.HSVToRGB(angle * (180f / MathF.PI), 0.8f, 0.6f);
		}
	}
	[RequireComponent(typeof(MeshFilter))]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_lightweight_r_v_o.php")]
	public class LightweightRVO : MonoBehaviour
	{
		public enum RVOExampleType
		{
			Circle,
			Line,
			Point,
			RandomStreams,
			Crossing
		}

		public int agentCount = 100;

		public float exampleScale = 100f;

		public RVOExampleType type;

		public float radius = 3f;

		public float maxSpeed = 2f;

		public float agentTimeHorizon = 10f;

		[HideInInspector]
		public float obstacleTimeHorizon = 10f;

		public int maxNeighbours = 10;

		public Vector3 renderingOffset = Vector3.up * 0.1f;

		public bool debug;

		private Mesh mesh;

		private Simulator sim;

		private List<IAgent> agents;

		private List<Vector3> goals;

		private List<Color> colors;

		private Vector3[] verts;

		private Vector2[] uv;

		private int[] tris;

		private Color[] meshColors;

		private Vector2[] interpolatedVelocities;

		private Vector2[] interpolatedRotations;

		public void Start()
		{
			mesh = new Mesh();
			RVOSimulator rVOSimulator = UnityEngine.Object.FindObjectOfType(typeof(RVOSimulator)) as RVOSimulator;
			if (rVOSimulator == null)
			{
				UnityEngine.Debug.LogError("No RVOSimulator could be found in the scene. Please add a RVOSimulator component to any GameObject");
				return;
			}
			sim = rVOSimulator.GetSimulator();
			GetComponent<MeshFilter>().mesh = mesh;
			CreateAgents(agentCount);
		}

		public void OnGUI()
		{
			if (GUILayout.Button("2"))
			{
				CreateAgents(2);
			}
			if (GUILayout.Button("10"))
			{
				CreateAgents(10);
			}
			if (GUILayout.Button("100"))
			{
				CreateAgents(100);
			}
			if (GUILayout.Button("500"))
			{
				CreateAgents(500);
			}
			if (GUILayout.Button("1000"))
			{
				CreateAgents(1000);
			}
			if (GUILayout.Button("5000"))
			{
				CreateAgents(5000);
			}
			GUILayout.Space(5f);
			if (GUILayout.Button("Random Streams"))
			{
				type = RVOExampleType.RandomStreams;
				CreateAgents((agents != null) ? agents.Count : 100);
			}
			if (GUILayout.Button("Line"))
			{
				type = RVOExampleType.Line;
				CreateAgents((agents != null) ? Mathf.Min(agents.Count, 100) : 10);
			}
			if (GUILayout.Button("Circle"))
			{
				type = RVOExampleType.Circle;
				CreateAgents((agents != null) ? agents.Count : 100);
			}
			if (GUILayout.Button("Point"))
			{
				type = RVOExampleType.Point;
				CreateAgents((agents != null) ? agents.Count : 100);
			}
			if (GUILayout.Button("Crossing"))
			{
				type = RVOExampleType.Crossing;
				CreateAgents((agents != null) ? agents.Count : 100);
			}
		}

		private float uniformDistance(float radius)
		{
			float num = UnityEngine.Random.value + UnityEngine.Random.value;
			if (num > 1f)
			{
				return radius * (2f - num);
			}
			return radius * num;
		}

		public void CreateAgents(int num)
		{
			agentCount = num;
			agents = new List<IAgent>(agentCount);
			goals = new List<Vector3>(agentCount);
			colors = new List<Color>(agentCount);
			sim.ClearAgents();
			if (type == RVOExampleType.Circle)
			{
				float num2 = Mathf.Sqrt((float)agentCount * radius * radius * 4f / MathF.PI) * exampleScale * 0.05f;
				for (int i = 0; i < agentCount; i++)
				{
					Vector3 vector = new Vector3(Mathf.Cos((float)i * MathF.PI * 2f / (float)agentCount), 0f, Mathf.Sin((float)i * MathF.PI * 2f / (float)agentCount)) * num2 * (1f + UnityEngine.Random.value * 0.01f);
					IAgent item = sim.AddAgent(new Vector2(vector.x, vector.z), vector.y);
					agents.Add(item);
					goals.Add(-vector);
					colors.Add(AstarMath.HSVToRGB((float)i * 360f / (float)agentCount, 0.8f, 0.6f));
				}
			}
			else if (type == RVOExampleType.Line)
			{
				for (int j = 0; j < agentCount; j++)
				{
					Vector3 vector2 = new Vector3((float)((j % 2 == 0) ? 1 : (-1)) * exampleScale, 0f, (float)(j / 2) * radius * 2.5f);
					IAgent item2 = sim.AddAgent(new Vector2(vector2.x, vector2.z), vector2.y);
					agents.Add(item2);
					goals.Add(new Vector3(0f - vector2.x, vector2.y, vector2.z));
					colors.Add((j % 2 == 0) ? Color.red : Color.blue);
				}
			}
			else if (type == RVOExampleType.Point)
			{
				for (int k = 0; k < agentCount; k++)
				{
					Vector3 vector3 = new Vector3(Mathf.Cos((float)k * MathF.PI * 2f / (float)agentCount), 0f, Mathf.Sin((float)k * MathF.PI * 2f / (float)agentCount)) * exampleScale;
					IAgent item3 = sim.AddAgent(new Vector2(vector3.x, vector3.z), vector3.y);
					agents.Add(item3);
					goals.Add(new Vector3(0f, vector3.y, 0f));
					colors.Add(AstarMath.HSVToRGB((float)k * 360f / (float)agentCount, 0.8f, 0.6f));
				}
			}
			else if (type == RVOExampleType.RandomStreams)
			{
				float num3 = Mathf.Sqrt((float)agentCount * radius * radius * 4f / MathF.PI) * exampleScale * 0.05f;
				for (int l = 0; l < agentCount; l++)
				{
					float f = UnityEngine.Random.value * MathF.PI * 2f;
					float num4 = UnityEngine.Random.value * MathF.PI * 2f;
					Vector3 vector4 = new Vector3(Mathf.Cos(f), 0f, Mathf.Sin(f)) * uniformDistance(num3);
					IAgent item4 = sim.AddAgent(new Vector2(vector4.x, vector4.z), vector4.y);
					agents.Add(item4);
					goals.Add(new Vector3(Mathf.Cos(num4), 0f, Mathf.Sin(num4)) * uniformDistance(num3));
					colors.Add(AstarMath.HSVToRGB(num4 * 57.29578f, 0.8f, 0.6f));
				}
			}
			else if (type == RVOExampleType.Crossing)
			{
				float num5 = exampleScale * radius * 0.5f;
				int a = (int)Mathf.Sqrt((float)agentCount / 25f);
				a = Mathf.Max(a, 2);
				for (int m = 0; m < agentCount; m++)
				{
					float num6 = (float)(m % a) / (float)a * MathF.PI * 2f;
					float num7 = num5 * ((float)(m / (a * 10) + 1) + 0.3f * UnityEngine.Random.value);
					Vector3 vector5 = new Vector3(Mathf.Cos(num6), 0f, Mathf.Sin(num6)) * num7;
					IAgent agent = sim.AddAgent(new Vector2(vector5.x, vector5.z), vector5.y);
					agent.Priority = ((m % a == 0) ? 1f : 0.01f);
					agents.Add(agent);
					goals.Add(-vector5.normalized * num5 * 3f);
					colors.Add(AstarMath.HSVToRGB(num6 * 57.29578f, 0.8f, 0.6f));
				}
			}
			SetAgentSettings();
			verts = new Vector3[4 * agents.Count];
			uv = new Vector2[verts.Length];
			tris = new int[agents.Count * 2 * 3];
			meshColors = new Color[verts.Length];
		}

		private void SetAgentSettings()
		{
			for (int i = 0; i < agents.Count; i++)
			{
				IAgent agent = agents[i];
				agent.Radius = radius;
				agent.AgentTimeHorizon = agentTimeHorizon;
				agent.ObstacleTimeHorizon = obstacleTimeHorizon;
				agent.MaxNeighbours = maxNeighbours;
				agent.DebugDraw = i == 0 && debug;
			}
		}

		public void Update()
		{
			if (agents == null || mesh == null)
			{
				return;
			}
			if (agents.Count != goals.Count)
			{
				UnityEngine.Debug.LogError("Agent count does not match goal count");
				return;
			}
			SetAgentSettings();
			if (interpolatedVelocities == null || interpolatedVelocities.Length < agents.Count)
			{
				Vector2[] array = new Vector2[agents.Count];
				Vector2[] array2 = new Vector2[agents.Count];
				if (interpolatedVelocities != null)
				{
					for (int i = 0; i < interpolatedVelocities.Length; i++)
					{
						array[i] = interpolatedVelocities[i];
					}
				}
				if (interpolatedRotations != null)
				{
					for (int j = 0; j < interpolatedRotations.Length; j++)
					{
						array2[j] = interpolatedRotations[j];
					}
				}
				interpolatedVelocities = array;
				interpolatedRotations = array2;
			}
			for (int k = 0; k < agents.Count; k++)
			{
				IAgent agent = agents[k];
				Vector2 position = agent.Position;
				Vector2 vector = Vector2.ClampMagnitude(agent.CalculatedTargetPoint - position, agent.CalculatedSpeed * Time.deltaTime);
				position += vector;
				agent.Position = position;
				agent.ElevationCoordinate = 0f;
				Vector2 vector2 = new Vector2(goals[k].x, goals[k].z);
				float magnitude = (vector2 - position).magnitude;
				agent.SetTarget(vector2, Mathf.Min(magnitude, maxSpeed), maxSpeed * 1.1f);
				interpolatedVelocities[k] += vector;
				if (interpolatedVelocities[k].magnitude > maxSpeed * 0.1f)
				{
					interpolatedVelocities[k] = Vector2.ClampMagnitude(interpolatedVelocities[k], maxSpeed * 0.1f);
					interpolatedRotations[k] = Vector2.Lerp(interpolatedRotations[k], interpolatedVelocities[k], agent.CalculatedSpeed * Time.deltaTime * 4f);
				}
				Vector3 vector3 = new Vector3(interpolatedRotations[k].x, 0f, interpolatedRotations[k].y).normalized * agent.Radius;
				if (vector3 == Vector3.zero)
				{
					vector3 = new Vector3(0f, 0f, agent.Radius);
				}
				Vector3 vector4 = Vector3.Cross(Vector3.up, vector3);
				Vector3 vector5 = new Vector3(agent.Position.x, agent.ElevationCoordinate, agent.Position.y) + renderingOffset;
				int num = 4 * k;
				int num2 = 6 * k;
				verts[num] = vector5 + vector3 - vector4;
				verts[num + 1] = vector5 + vector3 + vector4;
				verts[num + 2] = vector5 - vector3 + vector4;
				verts[num + 3] = vector5 - vector3 - vector4;
				uv[num] = new Vector2(0f, 1f);
				uv[num + 1] = new Vector2(1f, 1f);
				uv[num + 2] = new Vector2(1f, 0f);
				uv[num + 3] = new Vector2(0f, 0f);
				meshColors[num] = colors[k];
				meshColors[num + 1] = colors[k];
				meshColors[num + 2] = colors[k];
				meshColors[num + 3] = colors[k];
				tris[num2] = num;
				tris[num2 + 1] = num + 1;
				tris[num2 + 2] = num + 2;
				tris[num2 + 3] = num;
				tris[num2 + 4] = num + 2;
				tris[num2 + 5] = num + 3;
			}
			mesh.Clear();
			mesh.vertices = verts;
			mesh.uv = uv;
			mesh.colors = meshColors;
			mesh.triangles = tris;
			mesh.RecalculateNormals();
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_r_v_o_agent_placer.php")]
	public class RVOAgentPlacer : MonoBehaviour
	{
		public int agents = 100;

		public float ringSize = 100f;

		public LayerMask mask;

		public GameObject prefab;

		public Vector3 goalOffset;

		public float repathRate = 1f;

		private const float rad2Deg = 180f / MathF.PI;

		private IEnumerator Start()
		{
			yield return null;
			for (int i = 0; i < agents; i++)
			{
				float num = (float)i / (float)agents * MathF.PI * 2f;
				Vector3 vector = new Vector3((float)Math.Cos(num), 0f, (float)Math.Sin(num)) * ringSize;
				Vector3 target = -vector + goalOffset;
				GameObject gameObject = UnityEngine.Object.Instantiate(prefab, Vector3.zero, Quaternion.Euler(0f, num + 180f, 0f));
				RVOExampleAgent component = gameObject.GetComponent<RVOExampleAgent>();
				if (component == null)
				{
					UnityEngine.Debug.LogError("Prefab does not have an RVOExampleAgent component attached");
					break;
				}
				gameObject.transform.parent = base.transform;
				gameObject.transform.position = vector;
				component.repathRate = repathRate;
				component.SetTarget(target);
				component.SetColor(GetColor(num));
			}
		}

		public Color GetColor(float angle)
		{
			return AstarMath.HSVToRGB(angle * (180f / MathF.PI), 0.8f, 0.6f);
		}
	}
	[RequireComponent(typeof(RVOController))]
	[RequireComponent(typeof(Seeker))]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_r_v_o_example_agent.php")]
	public class RVOExampleAgent : MonoBehaviour
	{
		public float repathRate = 1f;

		private float nextRepath;

		private Vector3 target;

		private bool canSearchAgain = true;

		private RVOController controller;

		public float maxSpeed = 10f;

		private Path path;

		private List<Vector3> vectorPath;

		private int wp;

		public float moveNextDist = 1f;

		public float slowdownDistance = 1f;

		public LayerMask groundMask;

		private Seeker seeker;

		private MeshRenderer[] rends;

		public void Awake()
		{
			seeker = GetComponent<Seeker>();
			controller = GetComponent<RVOController>();
		}

		public void SetTarget(Vector3 target)
		{
			this.target = target;
			RecalculatePath();
		}

		public void SetColor(Color color)
		{
			if (rends == null)
			{
				rends = GetComponentsInChildren<MeshRenderer>();
			}
			MeshRenderer[] array = rends;
			foreach (MeshRenderer meshRenderer in array)
			{
				Color color2 = meshRenderer.material.GetColor("_TintColor");
				AnimationCurve curve = AnimationCurve.Linear(0f, color2.r, 1f, color.r);
				AnimationCurve curve2 = AnimationCurve.Linear(0f, color2.g, 1f, color.g);
				AnimationCurve curve3 = AnimationCurve.Linear(0f, color2.b, 1f, color.b);
				AnimationClip animationClip = new AnimationClip();
				animationClip.legacy = true;
				animationClip.SetCurve("", typeof(Material), "_TintColor.r", curve);
				animationClip.SetCurve("", typeof(Material), "_TintColor.g", curve2);
				animationClip.SetCurve("", typeof(Material), "_TintColor.b", curve3);
				Animation animation = meshRenderer.gameObject.GetComponent<Animation>();
				if (animation == null)
				{
					animation = meshRenderer.gameObject.AddComponent<Animation>();
				}
				animationClip.wrapMode = WrapMode.Once;
				animation.AddClip(animationClip, "ColorAnim");
				animation.Play("ColorAnim");
			}
		}

		public void RecalculatePath()
		{
			canSearchAgain = false;
			nextRepath = Time.time + repathRate * (UnityEngine.Random.value + 0.5f);
			seeker.StartPath(base.transform.position, target, OnPathComplete);
		}

		public void OnPathComplete(Path _p)
		{
			ABPath aBPath = _p as ABPath;
			canSearchAgain = true;
			if (path != null)
			{
				path.Release(this);
			}
			path = aBPath;
			aBPath.Claim(this);
			if (aBPath.error)
			{
				wp = 0;
				vectorPath = null;
				return;
			}
			Vector3 originalStartPoint = aBPath.originalStartPoint;
			Vector3 position = base.transform.position;
			originalStartPoint.y = position.y;
			float magnitude = (position - originalStartPoint).magnitude;
			wp = 0;
			vectorPath = aBPath.vectorPath;
			if (!(moveNextDist > 0f))
			{
				return;
			}
			for (float num = 0f; num <= magnitude; num += moveNextDist * 0.6f)
			{
				wp--;
				Vector3 vector = originalStartPoint + (position - originalStartPoint) * num;
				Vector3 vector2;
				do
				{
					wp++;
					vector2 = vectorPath[wp];
				}
				while (controller.To2D(vector - vector2).sqrMagnitude < moveNextDist * moveNextDist && wp != vectorPath.Count - 1);
			}
		}

		public void Update()
		{
			if (Time.time >= nextRepath && canSearchAgain)
			{
				RecalculatePath();
			}
			Vector3 position = base.transform.position;
			if (vectorPath != null && vectorPath.Count != 0)
			{
				while ((controller.To2D(position - vectorPath[wp]).sqrMagnitude < moveNextDist * moveNextDist && wp != vectorPath.Count - 1) || wp == 0)
				{
					wp++;
				}
				Vector3 vector = vectorPath[wp - 1];
				Vector3 vector2 = vectorPath[wp];
				float value = VectorMath.LineCircleIntersectionFactor(controller.To2D(base.transform.position), controller.To2D(vector), controller.To2D(vector2), moveNextDist);
				value = Mathf.Clamp01(value);
				Vector3 vector3 = Vector3.Lerp(vector, vector2, value);
				float num = controller.To2D(vector3 - position).magnitude + controller.To2D(vector3 - vector2).magnitude;
				for (int i = wp; i < vectorPath.Count - 1; i++)
				{
					num += controller.To2D(vectorPath[i + 1] - vectorPath[i]).magnitude;
				}
				Vector3 pos = (vector3 - position).normalized * num + position;
				float speed = Mathf.Clamp01(num / slowdownDistance) * maxSpeed;
				UnityEngine.Debug.DrawLine(base.transform.position, vector3, Color.red);
				controller.SetTarget(pos, speed, maxSpeed);
			}
			else
			{
				controller.SetTarget(position, maxSpeed, maxSpeed);
			}
			Vector3 vector4 = controller.CalculateMovementDelta(Time.deltaTime);
			position += vector4;
			if (Time.deltaTime > 0f && vector4.magnitude / Time.deltaTime > 0.01f)
			{
				Quaternion rotation = base.transform.rotation;
				Quaternion b = Quaternion.LookRotation(vector4, controller.To3D(Vector2.zero, 1f));
				if (controller.movementPlane == MovementPlane.XY)
				{
					b *= Quaternion.Euler(-90f, 180f, 0f);
				}
				base.transform.rotation = Quaternion.Slerp(rotation, b, Time.deltaTime * 5f);
			}
			if (controller.movementPlane == MovementPlane.XZ && Physics.Raycast(position + Vector3.up, Vector3.down, out var hitInfo, 2f, groundMask))
			{
				position.y = hitInfo.point.y;
			}
			base.transform.position = position;
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_procedural_world.php")]
	public class ProceduralWorld : MonoBehaviour
	{
		public enum RotationRandomness
		{
			AllAxes,
			Y
		}

		[Serializable]
		public class ProceduralPrefab
		{
			public GameObject prefab;

			public float density;

			public float perlin;

			public float perlinPower = 1f;

			public Vector2 perlinOffset = Vector2.zero;

			public float perlinScale = 1f;

			public float random = 1f;

			public RotationRandomness randomRotation;

			public bool singleFixed;
		}

		private class ProceduralTile
		{
			private int x;

			private int z;

			private System.Random rnd;

			private ProceduralWorld world;

			private Transform root;

			private IEnumerator ie;

			public bool destroyed { get; private set; }

			public ProceduralTile(ProceduralWorld world, int x, int z)
			{
				this.x = x;
				this.z = z;
				this.world = world;
				rnd = new System.Random((x * 10007) ^ (z * 36007));
			}

			public IEnumerator Generate()
			{
				ie = InternalGenerate();
				GameObject gameObject = new GameObject("Tile " + x + " " + z);
				root = gameObject.transform;
				while (ie != null && root != null && ie.MoveNext())
				{
					yield return ie.Current;
				}
				ie = null;
			}

			public void ForceFinish()
			{
				while (ie != null && root != null && ie.MoveNext())
				{
				}
				ie = null;
			}

			private Vector3 RandomInside()
			{
				return new Vector3
				{
					x = ((float)x + (float)rnd.NextDouble()) * world.tileSize,
					z = ((float)z + (float)rnd.NextDouble()) * world.tileSize
				};
			}

			private Vector3 RandomInside(float px, float pz)
			{
				return new Vector3
				{
					x = (px + (float)rnd.NextDouble() / (float)world.subTiles) * world.tileSize,
					z = (pz + (float)rnd.NextDouble() / (float)world.subTiles) * world.tileSize
				};
			}

			private Quaternion RandomYRot(ProceduralPrefab prefab)
			{
				if (prefab.randomRotation != RotationRandomness.AllAxes)
				{
					return Quaternion.Euler(0f, 360f * (float)rnd.NextDouble(), 0f);
				}
				return Quaternion.Euler(360f * (float)rnd.NextDouble(), 360f * (float)rnd.NextDouble(), 360f * (float)rnd.NextDouble());
			}

			private IEnumerator InternalGenerate()
			{
				UnityEngine.Debug.Log("Generating tile " + x + ", " + z);
				int counter = 0;
				float[,] ditherMap = new float[world.subTiles + 2, world.subTiles + 2];
				for (int i = 0; i < world.prefabs.Length; i++)
				{
					ProceduralPrefab pref = world.prefabs[i];
					if (pref.singleFixed)
					{
						UnityEngine.Object.Instantiate(position: new Vector3(((float)x + 0.5f) * world.tileSize, 0f, ((float)z + 0.5f) * world.tileSize), original: pref.prefab, rotation: Quaternion.identity).transform.parent = root;
						continue;
					}
					float subSize = world.tileSize / (float)world.subTiles;
					for (int j = 0; j < world.subTiles; j++)
					{
						for (int k = 0; k < world.subTiles; k++)
						{
							ditherMap[j + 1, k + 1] = 0f;
						}
					}
					for (int sx = 0; sx < world.subTiles; sx++)
					{
						for (int sz = 0; sz < world.subTiles; sz++)
						{
							float px = (float)x + (float)sx / (float)world.subTiles;
							float pz = (float)z + (float)sz / (float)world.subTiles;
							float b = Mathf.Pow(Mathf.PerlinNoise((px + pref.perlinOffset.x) * pref.perlinScale, (pz + pref.perlinOffset.y) * pref.perlinScale), pref.perlinPower);
							float num = pref.density * Mathf.Lerp(1f, b, pref.perlin) * Mathf.Lerp(1f, (float)rnd.NextDouble(), pref.random);
							float num2 = subSize * subSize * num + ditherMap[sx + 1, sz + 1];
							int count = Mathf.RoundToInt(num2);
							ditherMap[sx + 1 + 1, sz + 1] += 0.4375f * (num2 - (float)count);
							ditherMap[sx + 1 - 1, sz + 1 + 1] += 0.1875f * (num2 - (float)count);
							ditherMap[sx + 1, sz + 1 + 1] += 0.3125f * (num2 - (float)count);
							ditherMap[sx + 1 + 1, sz + 1 + 1] += 0.0625f * (num2 - (float)count);
							for (int l = 0; l < count; l++)
							{
								Vector3 position = RandomInside(px, pz);
								UnityEngine.Object.Instantiate(pref.prefab, position, RandomYRot(pref)).transform.parent = root;
								counter++;
								if (counter % 2 == 0)
								{
									yield return null;
								}
							}
						}
					}
				}
				yield return null;
				yield return null;
				if (Application.HasProLicense() && world.staticBatching)
				{
					StaticBatchingUtility.Combine(root.gameObject);
				}
			}

			public void Destroy()
			{
				if (root != null)
				{
					UnityEngine.Debug.Log("Destroying tile " + x + ", " + z);
					UnityEngine.Object.Destroy(root.gameObject);
					root = null;
				}
				ie = null;
			}
		}

		public Transform target;

		public ProceduralPrefab[] prefabs;

		public int range = 1;

		public int disableAsyncLoadWithinRange = 1;

		public float tileSize = 100f;

		public int subTiles = 20;

		public bool staticBatching;

		private Queue<IEnumerator> tileGenerationQueue = new Queue<IEnumerator>();

		private Dictionary<Int2, ProceduralTile> tiles = new Dictionary<Int2, ProceduralTile>();

		private void Start()
		{
			Update();
			AstarPath.active.Scan();
			StartCoroutine(GenerateTiles());
		}

		private void Update()
		{
			Int2 @int = new Int2(Mathf.RoundToInt((target.position.x - tileSize * 0.5f) / tileSize), Mathf.RoundToInt((target.position.z - tileSize * 0.5f) / tileSize));
			range = ((range < 1) ? 1 : range);
			bool flag = true;
			while (flag)
			{
				flag = false;
				foreach (KeyValuePair<Int2, ProceduralTile> tile in tiles)
				{
					if (Mathf.Abs(tile.Key.x - @int.x) > range || Mathf.Abs(tile.Key.y - @int.y) > range)
					{
						tile.Value.Destroy();
						tiles.Remove(tile.Key);
						flag = true;
						break;
					}
				}
			}
			for (int i = @int.x - range; i <= @int.x + range; i++)
			{
				for (int j = @int.y - range; j <= @int.y + range; j++)
				{
					if (!tiles.ContainsKey(new Int2(i, j)))
					{
						ProceduralTile proceduralTile = new ProceduralTile(this, i, j);
						IEnumerator enumerator2 = proceduralTile.Generate();
						enumerator2.MoveNext();
						tileGenerationQueue.Enqueue(enumerator2);
						tiles.Add(new Int2(i, j), proceduralTile);
					}
				}
			}
			for (int k = @int.x - disableAsyncLoadWithinRange; k <= @int.x + disableAsyncLoadWithinRange; k++)
			{
				for (int l = @int.y - disableAsyncLoadWithinRange; l <= @int.y + disableAsyncLoadWithinRange; l++)
				{
					tiles[new Int2(k, l)].ForceFinish();
				}
			}
		}

		private IEnumerator GenerateTiles()
		{
			while (true)
			{
				if (tileGenerationQueue.Count > 0)
				{
					IEnumerator routine = tileGenerationQueue.Dequeue();
					yield return StartCoroutine(routine);
				}
				yield return null;
			}
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_bezier_mover.php")]
	public class BezierMover : MonoBehaviour
	{
		public Transform[] points;

		public float speed = 1f;

		public float tiltAmount = 1f;

		private float time;

		private Vector3 Position(float t)
		{
			int num = points.Length;
			int num2 = Mathf.FloorToInt(t) % num;
			return AstarSplines.CatmullRom(points[(num2 - 1 + num) % num].position, points[num2].position, points[(num2 + 1) % num].position, points[(num2 + 2) % num].position, t - (float)Mathf.FloorToInt(t));
		}

		private void Update()
		{
			float num = time;
			float num2 = time + 1f;
			while (num2 - num > 0.0001f)
			{
				float num3 = (num + num2) / 2f;
				if ((Position(num3) - base.transform.position).sqrMagnitude > speed * Time.deltaTime * (speed * Time.deltaTime))
				{
					num2 = num3;
				}
				else
				{
					num = num3;
				}
			}
			time = (num + num2) / 2f;
			Vector3 vector = Position(time);
			Vector3 vector2 = Position(time + 0.001f);
			base.transform.position = vector;
			Vector3 vector3 = Position(time + 0.15f);
			Vector3 vector4 = ((Position(time + 0.15f + 0.001f) - vector3).normalized - (vector2 - vector).normalized) / (vector3 - vector).magnitude;
			Vector3 upwards = new Vector3(0f, 1f / (tiltAmount + 1E-05f), 0f) + vector4;
			base.transform.rotation = Quaternion.LookRotation(vector2 - vector, upwards);
		}

		private void OnDrawGizmos()
		{
			if (points.Length < 3)
			{
				return;
			}
			for (int i = 0; i < points.Length; i++)
			{
				if (points[i] == null)
				{
					return;
				}
			}
			Gizmos.color = Color.white;
			Vector3 vector = Position(0f);
			for (int j = 0; j < points.Length; j++)
			{
				for (int k = 1; k <= 100; k++)
				{
					Vector3 vector2 = Position((float)j + (float)k / 100f);
					Gizmos.DrawLine(vector, vector2);
					vector = vector2;
				}
			}
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_local_space_rich_a_i.php")]
	public class LocalSpaceRichAI : RichAI
	{
		public LocalSpaceGraph graph;

		private void RefreshTransform()
		{
			graph.Refresh();
			richPath.transform = graph.transformation;
			movementPlane = graph.transformation;
		}

		protected override void Start()
		{
			RefreshTransform();
			base.Start();
		}

		protected override void CalculatePathRequestEndpoints(out Vector3 start, out Vector3 end)
		{
			RefreshTransform();
			base.CalculatePathRequestEndpoints(out start, out end);
			start = graph.transformation.InverseTransform(start);
			end = graph.transformation.InverseTransform(end);
		}

		protected override void Update()
		{
			RefreshTransform();
			base.Update();
		}
	}
