	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_mine_bot_animation.php")]
	public class MineBotAnimation : VersionedMonoBehaviour
	{
		public Animator anim;

		public GameObject endOfPathEffect;

		private bool isAtDestination;

		private IAstarAI ai;

		private Transform tr;

		protected Vector3 lastTarget;

		protected override void Awake()
		{
			base.Awake();
			ai = GetComponent<IAstarAI>();
			tr = GetComponent<Transform>();
		}

		private void OnTargetReached()
		{
			if (endOfPathEffect != null && Vector3.Distance(tr.position, lastTarget) > 1f)
			{
				UnityEngine.Object.Instantiate(endOfPathEffect, tr.position, tr.rotation);
				lastTarget = tr.position;
			}
		}

		protected void Update()
		{
			if (ai.reachedEndOfPath)
			{
				if (!isAtDestination)
				{
					OnTargetReached();
				}
				isAtDestination = true;
			}
			else
			{
				isAtDestination = false;
			}
			Vector3 vector = tr.InverseTransformDirection(ai.velocity);
			vector.y = 0f;
			anim.SetFloat("NormalizedSpeed", vector.magnitude / anim.transform.lossyScale.x);
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_object_placer.php")]
	public class ObjectPlacer : MonoBehaviour
	{
		public GameObject go;

		public bool direct;

		public bool issueGUOs = true;

		private void Update()
		{
			if (Input.GetKeyDown("p"))
			{
				PlaceObject();
			}
			if (Input.GetKeyDown("r"))
			{
				StartCoroutine(RemoveObject());
			}
		}

		public void PlaceObject()
		{
			if (!Physics.Raycast(Camera.main.ScreenPointToRay(Input.mousePosition), out var hitInfo, float.PositiveInfinity))
			{
				return;
			}
			Vector3 point = hitInfo.point;
			GameObject gameObject = UnityEngine.Object.Instantiate(go, point, Quaternion.identity);
			if (issueGUOs)
			{
				GraphUpdateObject ob = new GraphUpdateObject(gameObject.GetComponent<Collider>().bounds);
				AstarPath.active.UpdateGraphs(ob);
				if (direct)
				{
					AstarPath.active.FlushGraphUpdates();
				}
			}
		}

		public IEnumerator RemoveObject()
		{
			if (!Physics.Raycast(Camera.main.ScreenPointToRay(Input.mousePosition), out var hitInfo, float.PositiveInfinity) || hitInfo.collider.isTrigger || hitInfo.transform.gameObject.name == "Ground")
			{
				yield break;
			}
			Bounds b = hitInfo.collider.bounds;
			UnityEngine.Object.Destroy(hitInfo.collider);
			UnityEngine.Object.Destroy(hitInfo.collider.gameObject);
			if (issueGUOs)
			{
				yield return new WaitForEndOfFrame();
				GraphUpdateObject ob = new GraphUpdateObject(b);
				AstarPath.active.UpdateGraphs(ob);
				if (direct)
				{
					AstarPath.active.FlushGraphUpdates();
				}
			}
		}
	}
	[ExecuteInEditMode]
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_snap_to_node.php")]
	public class SnapToNode : MonoBehaviour
	{
		private void Update()
		{
			if (base.transform.hasChanged && AstarPath.active != null)
			{
				GraphNode node = AstarPath.active.GetNearest(base.transform.position, NNConstraint.None).node;
				if (node != null)
				{
					base.transform.position = (Vector3)node.position;
					base.transform.hasChanged = false;
				}
			}
		}
	}
	[HelpURL("http://arongranberg.com/astar/documentation/stable/class_pathfinding_1_1_examples_1_1_animation_link_traverser.php")]
	public class AnimationLinkTraverser : VersionedMonoBehaviour
	{
		public Animation anim;

		private RichAI ai;

		private void OnEnable()
		{
			ai = GetComponent<RichAI>();
			if (ai != null)
			{
				RichAI richAI = ai;
				richAI.onTraverseOffMeshLink = (Func<RichSpecial, IEnumerator>)Delegate.Combine(richAI.onTraverseOffMeshLink, new Func<RichSpecial, IEnumerator>(TraverseOffMeshLink));
			}
		}

		private void OnDisable()
		{
			if (ai != null)
			{
				RichAI richAI = ai;
				richAI.onTraverseOffMeshLink = (Func<RichSpecial, IEnumerator>)Delegate.Remove(richAI.onTraverseOffMeshLink, new Func<RichSpecial, IEnumerator>(TraverseOffMeshLink));
			}
		}

		protected virtual IEnumerator TraverseOffMeshLink(RichSpecial rs)
		{
			AnimationLink link = rs.nodeLink as AnimationLink;
			if (link == null)
			{
				UnityEngine.Debug.LogError("Unhandled RichSpecial");
				yield break;
			}
			while (true)
			{
				Quaternion rotation = ai.rotation;
				Quaternion quaternion = ai.SimulateRotationTowards(rs.first.forward, ai.rotationSpeed * Time.deltaTime);
				if (rotation == quaternion)
				{
					break;
				}
				ai.FinalizeMovement(ai.position, quaternion);
				yield return null;
			}
			base.transform.parent.position = base.transform.position;
			base.transform.parent.rotation = base.transform.rotation;
			base.transform.localPosition = Vector3.zero;
			base.transform.localRotation = Quaternion.identity;
			if (rs.reverse && link.reverseAnim)
			{
				anim[link.clip].speed = 0f - link.animSpeed;
				anim[link.clip].normalizedTime = 1f;
				anim.Play(link.clip);
				anim.Sample();
			}
			else
			{
				anim[link.clip].speed = link.animSpeed;
				anim.Rewind(link.clip);
				anim.Play(link.clip);
			}
			base.transform.parent.position -= base.transform.position - base.transform.parent.position;
			yield return new WaitForSeconds(Mathf.Abs(anim[link.clip].length / link.animSpeed));
		}
	}
}
